-- Poems batch 425
INSERT OR IGNORE INTO poems (id,title,author,dynasty,collection,collection_id,rhythmic,tags,excerpt,length,source_path,paragraphs) VALUES
('yuanqu-6394','陶学士醉写风光好・三煞','戴善甫','元','元曲','yuanqu','','[]','贱妾煞是展污了个经天纬地真英俊，为国于民大宰臣。',130,'元曲/yuanqu.json','["贱妾煞是展污了个经天纬地真英俊，为国于民大宰臣。", "(陶谷云)酒后疏狂，惹此一场是非。", "(正旦唱)贱妾煞不识高低，不知远近，不辨贤愚，不别清浑。", "这的是天注定的是非，天指引的前程。", "天匹配的婚姻，咱兀的教太守主婚。", "(陶谷云)可着谁做媒人？(正旦唱)则这〔风光好〕是媒人。"]'),
('yuanqu-6395','陶学士醉写风光好・二煞','戴善甫','元','元曲','yuanqu','','[]','此别后我专想着你玉堂金马怀离恨，谁再与野草闲花作近邻。',126,'元曲/yuanqu.json','["此别后我专想着你玉堂金马怀离恨，谁再与野草闲花作近邻。", "(陶谷云)我今别处寻个前程，便来取你。", "(正旦唱)我等你那取我的轩车，赠咱的官品。", "我也待显耀乡间，改换我这家门。", "学士怎肯似那等穷酸饿醋，得一个及第成名，却又早负德辜恩。", "则要你言而有信，休担阁了少年人。"]'),
('yuanqu-6396','陶学士醉写风光好・黄钟煞','戴善甫','元','元曲','yuanqu','','[]','你可休"一春鱼雁无音信"，却教我"千里关山劳梦魂。',128,'元曲/yuanqu.json','["你可休\"一春鱼雁无音信\"，却教我\"千里关山劳梦魂。", "\"我和你两情调两意肯，这谐合有气分。", "我觑了暗地哂，全不见没事狠，绸缪处直恁亲，临相别也怀恨。", "若还家独门身，被儿底少温存，怕不想旧日人，要圆成要寻问，则这续断鸾胶语句儿真，便是我锦片前程敢可也盼的准。", "(下)。"]'),
('yuanqu-6397','陶学士醉写风光好・中吕/粉蝶儿','戴善甫','元','元曲','yuanqu','','[]','一自当时，向烟花簿豁除了名氏。',57,'元曲/yuanqu.json','["一自当时，向烟花簿豁除了名氏。", "打叠起狂荡心儿，专等那七香车，五花诰，绝无人至。", "一路上寻思，莫不他翻悔了这门亲事？。"]'),
('yuanqu-6398','陶学士醉写风光好・醉春风','戴善甫','元','元曲','yuanqu','','[]','我则想学士寄音书，却早是钱王传令旨。',54,'元曲/yuanqu.json','["我则想学士寄音书，却早是钱王传令旨。", "他全然不知俺至诚心，消不得半张儿纸，纸。", "到今日如今，见时相见，是谁不是。"]'),
('yuanqu-6399','陶学士醉写风光好・迎仙客','戴善甫','元','元曲','yuanqu','','[]','我心恐恐入内门，战兢兢步阶址，这里错行了眼前轻是死。',112,'元曲/yuanqu.json','["我心恐恐入内门，战兢兢步阶址，这里错行了眼前轻是死。", "如今我也上丹墀，朝帝子。", "我暗暗地冷笑孜孜，兀良抵多少长亭畔迎宣使。", "(做见科，云)大王叩头。", "(钱王云)你是秦弱兰，当初怎生认的陆学士来？(正旦云)大王听妾身慢说一遍。", "(唱)。"]'),
('yuanqu-6400','陶学士醉写风光好・石榴花','戴善甫','元','元曲','yuanqu','','[]','他从去年宣命下京师，韩太守接着时。',77,'元曲/yuanqu.json','["他从去年宣命下京师，韩太守接着时。", "他则是冷丁丁清耿耿并无私，轩昂气志，捻断吟髭。", "妾身向筵前过盏无迁次，他面皮上刮下冰澌。", "那妖娆乐妓勤伏侍，他一件件尽推辞。"]'),
('yuanqu-6401','陶学士醉写风光好・斗鹌鹑','戴善甫','元','元曲','yuanqu','','[]','他见不的妙舞宫腰，听不的俺清歌皓齿。',105,'元曲/yuanqu.json','["他见不的妙舞宫腰，听不的俺清歌皓齿。", "(钱王云)他席间怎生发怒来？(正旦唱)他袖拂了金杯，手推开玉卮。", "(钱王云)后来又怎生看上你来？(正旦唱)妾向馆驿里别妆个美貌姿。", "俺两个相见时，则他那旧性全无。", "共妾身新婚燕尔。"]'),
('yuanqu-6402','陶学士醉写风光好・上小楼','戴善甫','元','元曲','yuanqu','','[]','他许我夫人位次。',143,'元曲/yuanqu.json','["他许我夫人位次。", "妾除了烟花名字。", "再不曾披着带着。", "官员祗候，褙子冠儿。", "(钱王云)你自离了陶学士，再曾迎新送旧么？(正旦唱)我这些时，甚的是，茶坊酒肆，每日价冷清清为他守志。", "(钱王呼一净官上，指云)秦弱兰，这个是陶学士么？(净官悲云)小娘子，兀的不想杀我也。", "(正旦云)这不是陶学士。", "(唱)。"]'),
('yuanqu-6403','陶学士醉写风光好・幺篇','戴善甫','元','元曲','yuanqu','','[]','他生的端严相貌，尊崇举上。',56,'元曲/yuanqu.json','["他生的端严相貌，尊崇举上。", "几曾见这般眼暗头昏，地惨天愁，抹泪揉眵。", "觑绝时，这君子，其实不是，却怎生没半星儿相似。"]'),
('yuanqu-6404','陶学士醉写风光好・鲍老作','戴善甫','元','元曲','yuanqu','','[]','则见他人丛里叠扑着个幽。',12,'元曲/yuanqu.json','["则见他人丛里叠扑着个幽。"]'),
('yuanqu-6405','陶学士醉写风光好・哨遍','戴善甫','元','元曲','yuanqu','','[]','对着这千乘当今帝子，等教我一星星数说你乔行止。',134,'元曲/yuanqu.json','["对着这千乘当今帝子，等教我一星星数说你乔行止。", "我为你截日离了官司，再不当火院家私，便弄针黹。", "每日价胭憔粉悴，玉减香消，专等你那音书至，今日全无一字。", "都泪淹破腮颊，病瘦损腰肢。", "则这腕儿上慢松子的金钏是相知，身儿上宽绰了罗衣是正明师。", "你这般背约违期，负德辜恩，怎生意思？。"]'),
('yuanqu-6406','陶学士醉写风光好・耍孩儿','戴善甫','元','元曲','yuanqu','','[]','枉了我一年独守冰霜志，指望你封妻荫子。',79,'元曲/yuanqu.json','["枉了我一年独守冰霜志，指望你封妻荫子。", "我并不想东风卖笑倚门时，毕罗了采笔题诗。", "再不向泥金扇底歌新曲，日玉堂前舞柘枝。", "我自离了莺花市，无半星儿点污，一打儿瑕疵。"]'),
('yuanqu-6407','陶学士醉写风光好・三煞','戴善甫','元','元曲','yuanqu','','[]','你那些假古忄敞原来是妆谎子，你无诚无信无终始。',68,'元曲/yuanqu.json','["你那些假古忄敞原来是妆谎子，你无诚无信无终始。", "我则道你是铺眉苦眼真君子。", "你最是昧己瞒心泼小儿，许下俺调琴瑟，今日似难鸣孤掌，不线的单丝。"]'),
('yuanqu-6408','陶学士醉写风光好・二煞','戴善甫','元','元曲','yuanqu','','[]','我正是忒坎坷，自怨咨，九重天忽有君恩至。',85,'元曲/yuanqu.json','["我正是忒坎坷，自怨咨，九重天忽有君恩至。", "正是一湾死水全无浪，也有春风摆动时。", "不甫能寻着尔。", "(出风光好词科，云)大王，这是他亲笔写下的。", "(唱)这是他诳君的招状，亲笔的情词。"]'),
('yuanqu-6409','陶学士醉写风光好・煞尾','戴善甫','元','元曲','yuanqu','','[]','公堂上坐着相公，阶直下列着武士。',367,'元曲/yuanqu.json','["公堂上坐着相公，阶直下列着武士。", "我这里尽场分说心间事，拚两个双棒儿阶前觅一个死。", "(做撞阶科)(钱王云)住、住、住！秦弱兰留性命，逗你耍哩。", "(陶谷云)姐姐，间别无恙。", "则被你想杀我也。", "(钱王云)秦弱兰，陶学士为你回不的汴京。", "你两口儿且在我杭州居住。", "等我朝京，见了大宋主人。", "奏过还着陶学士复旧职。", "那其间驷马轩车，五花官诰，都是你的。", "(正旦拜科，云)多谢了大王。", "(钱王云)古人有言：\"乐莫乐兮新相知，悲莫悲兮生别离。", "\"今日你两个夫妻会合，便当杀羊宰马，做个庆喜筵席。", "(词云)当日个有意江南降李主，故书隐语显文章。", "岂谓彼中有识者，独眠孤馆早参详。", "故教此女来狐媚，恼乱春风学士肠。", "驿亭巧把姻缘结，新词留下好风光。", "此心愧报难回汴，只得潜身且寄杭。", "专待君恩重召取，那其间同驾香车入画堂。", "半世孤高占仕路，一天风月动词场。", "若道钟情非我辈，因何千载说高唐。"]'),
('yuanqu-6410','正宫・鹦鹉曲寄故人和韵','吕济民','元','元曲','yuanqu','','[]','心猿意马羁难住，举酒处记送别那《梁父》。',35,'元曲/yuanqu.json','["心猿意马羁难住，举酒处记送别那《梁父》。", "想人生碌碌纷纷，几度落红飞雨。"]'),
('yuanqu-6411','幺・瞬息间地北天南，又是便鸿书去。问多娇芳信何期？笑指到玉梅吐处。','吕济民','元','元曲','yuanqu','','[]','朱颜绿鬓难留住，调弄了几拙讷的儿父。',33,'元曲/yuanqu.json','["朱颜绿鬓难留住，调弄了几拙讷的儿父。", "算光阴咫只风波，恍着暮晴朝雨。"]'),
('yuanqu-6413','双调・蟾宫曲赠楚云','吕济民','元','元曲','yuanqu','','[]','寄襄王雁字安排，出岫无心，蔽月多才。',142,'元曲/yuanqu.json','["寄襄王雁字安排，出岫无心，蔽月多才。", "目极潇湘，家迷秦岭，梦到天台。", "浮碧汉阴睛体态，逐西风聚散情怀，卷又还开，去又还来。", "雨罢巫山，飞下阳台。", "赠玉香可人儿暖玉生香，弄玉团香，惜玉怜香。", "画蛾眉玉鉴遗香，伴才郎玉枕留香，捧酒卮玉容喷香，摘花枝玉指偷香。", "问玉何香，料玉多香。", "见玉思香，买玉寻香。"]'),
('yuanqu-6414','神奴儿大闹开封府・仙吕/点绛唇','无名氏','元','元曲','yuanqu','','[]','我可也自小心直，使钱不会，学经纪。',32,'元曲/yuanqu.json','["我可也自小心直，使钱不会，学经纪。", "但能勾无是无非，便休说黄金贵。"]'),
('yuanqu-6415','神奴儿大闹开封府・天下乐','无名氏','元','元曲','yuanqu','','[]','你便有那万件事也合看着我的面皮，你可便情也波知，谁敢道是欺负你，我见他嗔忿忿怒从心上起。',214,'元曲/yuanqu.json','["你便有那万件事也合看着我的面皮，你可便情也波知，谁敢道是欺负你，我见他嗔忿忿怒从心上起。", "(搽旦云)李二，今日好歹要分了这家私罢。", "(李德义云)哥哥，你向着嫂嫂，弟兄上无一些儿情分。", "你则守着这不贤慧的嫂子住，分开了这家私罢。", "(正末云)兄弟，你恰才入门来，说你嫂嫂不曾还你的礼，如今可要分家私。", "(唱)你打破盆则论盆，休的要缠麻头续麻尾，(大旦云)既然小叔和婶子要分开这家私呵，依着他分开了罢。", "(正末云)噤声！(唱)连你也迎风儿簸簸箕。"]'),
('yuanqu-6416','神奴儿大闹开封府・那吒令','无名氏','元','元曲','yuanqu','','[]','你哥哥劝你，休烦天恼地；大嫂你靠这壁，休推天抢地；孩儿这里耍哩，休啼天哭地。',76,'元曲/yuanqu.json','["你哥哥劝你，休烦天恼地；大嫂你靠这壁，休推天抢地；孩儿这里耍哩，休啼天哭地。", "(带云)李大员外、二员外，(唱)俺须是亲手足，您须是亲妯娌，有甚么话不投机。"]'),
('yuanqu-6417','神奴儿大闹开封府・鹊踏枝','无名氏','元','元曲','yuanqu','','[]','丈夫的失了尊卑，媳妇儿不贤慧。',79,'元曲/yuanqu.json','["丈夫的失了尊卑，媳妇儿不贤慧。", "他两个一上一下，直留支剌，唱叫扬疾。", "(搽旦叫科，云)天哟，欺负俺两口儿也！(正末云)噤声！(唱)那里也赵礼让肥，你可甚家有贤妻。"]'),
('yuanqu-6418','神奴儿大闹开封府・寄生草','无名氏','元','元曲','yuanqu','','[]','我和你须是亲兄弟，又不是厮认义。',120,'元曲/yuanqu.json','["我和你须是亲兄弟，又不是厮认义。", "你今日不相识的故意为相识，你可便不亲的结托为亲戚。", "兄弟也，你可怎生全不知尽让您这哥哥意？(搽旦云)俺倒不言语，他倒说长道短的。", "李二，你还不打他哩。", "(正末唱)你这般揎拳捋袖为因何？枉惹的街坊每耻笑，着亲邻每议。"]'),
('yuanqu-6419','神奴儿大闹开封府・后庭花','无名氏','元','元曲','yuanqu','','[]','您哥哥为人无改移，我这里便要写待写着个甚的？(李德义云)你若无兄弟情呵，留着这妇人罢。',173,'元曲/yuanqu.json','["您哥哥为人无改移，我这里便要写待写着个甚的？(李德义云)你若无兄弟情呵，留着这妇人罢。", "(正末唱)不争我便恋着他恩义，怎肯着我弟兄每分在两下里。", "(搽旦云)李二，你看你哥哥口里便强，手里可不肯写那休书哩。", "(李德义云)哥哥，不必作难，你写了休书罢。", "(正末唱)兄弟你莫嫌迟，你与我疾忙研墨，我手擎着纸共笔，索将他来便舍弃。", "则消的我别主媒，再寻一个年少的。"]'),
('yuanqu-6420','神奴儿大闹开封府・柳叶儿','无名氏','元','元曲','yuanqu','','[]','在那里别寻一个同胞兄弟，媳妇儿是墙上泥皮，可不说相随百步尚有徘徊意。',93,'元曲/yuanqu.json','["在那里别寻一个同胞兄弟，媳妇儿是墙上泥皮，可不说相随百步尚有徘徊意。", "(大旦云)员外，咱是儿女夫妻，你怎下的休了我也？(正末唱)我须索依着他那主意，疾忙的休离，大嫂也，你便休题道儿女夫妻。"]'),
('yuanqu-6421','神奴儿大闹开封府・赚煞尾','无名氏','元','元曲','yuanqu','','[]','你常存着见官的心，准备着告人的意。',152,'元曲/yuanqu.json','["你常存着见官的心，准备着告人的意。", "则你那状本儿如瓶注水，俺亲弟兄看成做了五眼鸡。", "(搽旦云)俺若欺负你，头上有天哩。", "(正末唱)你也须索念着好门风祖亡留遗，今日为他谁觅闹寻非，却不道湛湛青天不可欺。", "你就那般瞒心昧已，就这般生忿忤逆，(云)人间私语，天闻若雷，休言不报也。", "(唱)敢只争来早与来迟。", "(作气死下)。"]'),
('yuanqu-6422','神奴儿大闹开封府・梁州第七','无名氏','元','元曲','yuanqu','','[]','你莫不大街上逢着甚么驴马？你莫不小巷里撞着甚么车乘？则我这好言好语无心听。',259,'元曲/yuanqu.json','["你莫不大街上逢着甚么驴马？你莫不小巷里撞着甚么车乘？则我这好言好语无心听。", "我将你来厮将厮领，同坐同行。", "眼睛儿般照觑，气命儿般看承。", "他行坐里陪着一个笑脸儿相迎，待飞腾则恨我肋下没稍翎。", "教我便来来去去脚似撺梭，我可便笃笃末末身如这翻饼，哎哟天那！好教我便慌慌速速手似捞铃。", "(云)想必哥哥等不得，回家去了。", "我且到家中看咱。", "(大旦上，云)院公你来了也。", "(正末慌科)(唱)则听的，叫咱一声。", "水浇般不由我浑身冷，我待悔来教我悔不定。", "(大旦云)神奴孩儿在那里？(正末唱)告嫂嫂休忙且暂停，(大旦云，做哭科)(正末唱)省可里两泪如倾。"]'),
('yuanqu-6423','神奴儿大闹开封府・四块玉','无名氏','元','元曲','yuanqu','','[]','一壁厢说与厢长，一壁厢报与坊正，恨不的翻过那物穰人稠卧牛城，(做叫云)街衢巷陌，张三李四，赵大王二。',113,'元曲/yuanqu.json','["一壁厢说与厢长，一壁厢报与坊正，恨不的翻过那物穰人稠卧牛城，(做叫云)街衢巷陌，张三李四，赵大王二。", "(唱)你若见的可便也合通个名姓。", "不见了小舍人，可教俺也便待怎生？(带云)两房头则觑着哥哥一个哩。", "(唱)呆老子也我只索与他偿命。"]'),
('yuanqu-6424','神奴儿大闹开封府・黄钟尾','无名氏','元','元曲','yuanqu','','[]','我这里潜踪蹑足临芳径，我与你破步撩衣近小亭。',110,'元曲/yuanqu.json','["我这里潜踪蹑足临芳径，我与你破步撩衣近小亭。", "见孩儿，世不曾，不由我，不悲哽，天色寒，风力冷，夜迢迢，星耿耿，忽的阴，忽的晴。", "我则道神奴儿在曲槛闲行，(带云)兀的不是哥哥来了也。", "(唱)哎！却原来是云破月来花弄影。", "(同下)。"]'),
('yuanqu-6425','神奴儿大闹开封府・中吕/粉蝶儿','无名氏','元','元曲','yuanqu','','[]','这厮每败坏风俗，搅的俺一家儿不成活路，那吃敲才百计亏图。',68,'元曲/yuanqu.json','["这厮每败坏风俗，搅的俺一家儿不成活路，那吃敲才百计亏图。", "则他那长舌妻，杀人的贼，教我就怎生轻恕。", "待和他厮结着衣服，拣一个大衙门将他告去。"]'),
('yuanqu-6426','神奴儿大闹开封府・醉春风','无名氏','元','元曲','yuanqu','','[]','他和我做杀死冤仇，我和他决无干罢处。',93,'元曲/yuanqu.json','["他和我做杀死冤仇，我和他决无干罢处。", "(正末叫冤屈科)(大旦云)且休叫，休叫。", "(正末唱)我可便豁恶气连叫了两三声，嫂嫂也你休将这口来堵，堵。", "饶你这舌辩如苏秦，口强似陆贾，我看你怎生般分诉。"]'),
('yuanqu-6427','神奴儿大闹开封府・红绣鞋','无名氏','元','元曲','yuanqu','','[]','你也不索硬打挣去街坊上幺喝，神奴儿死尸骸只在这水沟里埋伏，(搽旦做慌科，云)谁和你说在水沟里埋着？如今在那里？在那里？(正末唱)孩儿也向那梦儿里依本画葫芦。',103,'元曲/yuanqu.json','["你也不索硬打挣去街坊上幺喝，神奴儿死尸骸只在这水沟里埋伏，(搽旦做慌科，云)谁和你说在水沟里埋着？如今在那里？在那里？(正末唱)孩儿也向那梦儿里依本画葫芦。", "他为甚的便慌笃速，一句句紧支吾？您正是贼儿胆底虚。"]'),
('yuanqu-6428','神奴儿大闹开封府・迎仙客','无名氏','元','元曲','yuanqu','','[]','又不曾下甚雨水，因甚这般湿泥淤？(搽旦云)是泼下的恶水。',194,'元曲/yuanqu.json','["又不曾下甚雨水，因甚这般湿泥淤？(搽旦云)是泼下的恶水。", "(正末唱)你道是水沙儿谁人糁上土？(搽旦云)见这块儿凹，扫了些粪草土儿填上，又洒了些水儿。", "俺家的勾当，要你管着我？(正末唱)这石板为甚撅开？(搽旦云)天睛开水道，下雨不足弯泥。", "我开沟来，开沟来！(正末唱)这水路因何当住？(搽旦云)雨下的紧了，怎么不漫出水来？神奴儿在那里？你自寻么？(正末唱)不索你便将我来催促，我与你便慢慢寻将去。"]'),
('yuanqu-6429','神奴儿大闹开封府・石榴花','无名氏','元','元曲','yuanqu','','[]','俺哥哥死尽七不曾把灵除，(外郎云)这妇人必定有奸夫。',241,'元曲/yuanqu.json','["俺哥哥死尽七不曾把灵除，(外郎云)这妇人必定有奸夫。", "(正末唱)俺嫂嫂可无倚靠现持服。", "(外郎云)怎生勒杀亲儿来？(正末唱)当日个为孩儿撒拗便啼哭，(外郎云)那小厮哭，可为甚么？(正末唱)他待要长街市上耍去，(外郎云)谁领将他去来(正末唱)只老汉和他步步相逐。", "(外郎云)你领他到那里去？(正末云)哥哥要傀儡耍，老汉说我买去。", "(唱)转回头百般的无寻处，(外郎云)你可在那里寻他来？(正末唱)绕着这前街后巷两头寻觑。", "(外郎云)你曾问人来么？(正末唱)撞着这个那个多曾分付，神奴儿端的见来无。"]'),
('yuanqu-6430','神奴儿大闹开封府・斗鹌鹑','无名氏','元','元曲','yuanqu','','[]','绕着那土市街头，(外郎云)你寻到多早晚来？(正末唱)直走到天昏日暮。',138,'元曲/yuanqu.json','["绕着那土市街头，(外郎云)你寻到多早晚来？(正末唱)直走到天昏日暮。", "(外郎云)你可多早晚回家去？(正末唱)老汉还家时才过初更，比到来恰交二鼓。", "(带云)其时朦胧睡里，梦见神奴儿也曾道来。", "(唱)他道婶子也把咽喉紧紧的掐住，勒的他一命卒。", "可怜那做爷的命掩黄泉，做儿的又身归也那地府。"]'),
('yuanqu-6431','神奴儿大闹开封府・上小楼','无名氏','元','元曲','yuanqu','','[]','李二也天生狠毒，可便的心生嫉妒。',89,'元曲/yuanqu.json','["李二也天生狠毒，可便的心生嫉妒。", "俺家里偌大的房屋，许富的家私，则觑着神奴。", "(外郎云)李二根前有甚么小的？(正末唱)那李二呵也无男，也无女，单则是一夫一妇，你可便着谁来抵当门户？。"]'),
('yuanqu-6432','神奴儿大闹开封府・幺篇','无名氏','元','元曲','yuanqu','','[]','做儿的不是义儿，做母的也不是义母。',71,'元曲/yuanqu.json','["做儿的不是义儿，做母的也不是义母。", "想着他咽苦吐甘，偎干就湿，怎生抬举。", "休说道十月怀耽，长立成卜，且则说三年乳哺，怎下的生割断他那子母每肠肚？。"]'),
('yuanqu-6433','神奴儿大闹开封府・十二月','无名氏','元','元曲','yuanqu','','[]','俺嫂嫂与员外从小里媳妇，他可便掌把着门闾。',55,'元曲/yuanqu.json','["俺嫂嫂与员外从小里媳妇，他可便掌把着门闾。", "你道他将亲来所图，你道他抵盗那财物。", "这公事凭谁做主，都是他二嫂妆诬。"]'),
('yuanqu-6434','神奴儿大闹开封府・尧民歌','无名氏','元','元曲','yuanqu','','[]','呀！他是个好人家平白地指着奸夫，(外郎云)我好歹要这桩事断的明白。',116,'元曲/yuanqu.json','["呀！他是个好人家平白地指着奸夫，(外郎云)我好歹要这桩事断的明白。", "(正末唱)哎，你一个水晶塔官人忒胡突。", "便待要罗织就这文书，全不问实和虚。", "(外郎云)你快与我招了者。", "(正末唱)则管你招也波伏，外郎呵自窨付，兀良可是他做来也那不曾做？。"]'),
('yuanqu-6435','神奴儿大闹开封府・耍孩儿','无名氏','元','元曲','yuanqu','','[]','你可甚平生正直无私曲？我道您纯面搅则是一盆糊。',88,'元曲/yuanqu.json','["你可甚平生正直无私曲？我道您纯面搅则是一盆糊。", "若无钱怎挝得你这登闻鼓？便做道受官厅党太尉能察雁，那里也昌平县狄梁公敢断虎。", "一个个都吞声儿就牢狱，一任俺冤仇似海，怎当的官法如垆。"]'),
('yuanqu-6436','神奴儿大闹开封府・煞尾','无名氏','元','元曲','yuanqu','','[]','凭着我纸儿上写着这一一的犯由，怀儿里揣着这重重的痛苦。',231,'元曲/yuanqu.json','["凭着我纸儿上写着这一一的犯由，怀儿里揣着这重重的痛苦。", "只待他包龙图来到南衙府，拚的个接马头一气儿叫道有二千声屈。", "(下)(大旦云)天那，着谁人与我做主也？(下)(外郎云)李二，你是个原告，出去随衙听候。", "(李德义云)理会的。", "(同搽旦下)(外郎云)张千，你伏侍我一日，辛苦了，不曾吃饭。", "张千，你自吃饭去。", "如今新官下马，我待接新官去也。", "(下)(孤云)你看么，断事一日，饭也不曾吃。", "外郎和张千都去了，着一个抬抬这卓子也好。", "罢、罢、罢，我自家端着这卓子罢，(做掇卓科，下)。"]'),
('yuanqu-6437','神奴儿大闹开封府・双调/新水令','无名氏','元','元曲','yuanqu','','[]','恰才个上西延奉诏赏三军，这回来敢辞劳顿。',44,'元曲/yuanqu.json','["恰才个上西延奉诏赏三军，这回来敢辞劳顿。", "乘驿马，到仪门，避不的远路风尘，望南衙内急忙进。"]'),
('yuanqu-6438','神奴儿大闹开封府・庆东原','无名氏','元','元曲','yuanqu','','[]','谁主意把你家私竞？(大旦云)是小叔叔来。',240,'元曲/yuanqu.json','["谁主意把你家私竞？(大旦云)是小叔叔来。", "(正末云)李德义你听得么？(唱)谁气的男儿命不存？(大旦云)也是小叔叔来。", "(正末云)李德义你听得么？(唱)却原来将亲兄气杀都是伊生忿。", "(李德义云)大人，不干小的事。", "都是我这嫂嫂，他不和六亲，气杀俺哥哥，勒杀孩儿，都是他来。", "(正末唱)你道他不和六亲？(李德义云)大人若不信，则问街坊邻舍便是。", "(正末唱)噤声！索问甚么街坊四邻？(带云)李德义，你若不招呵。", "(唱)一顿打敢着你死有十分。", "(带云)兀那李德义。", "(唱)我则问你状内词因，不要你将枝稍隐。"]'),
('yuanqu-6439','神奴儿大闹开封府・搅筝琶','无名氏','元','元曲','yuanqu','','[]','只你这批头棍，屈打死那平民。',486,'元曲/yuanqu.json','["只你这批头棍，屈打死那平民。", "现如今暴骨停尸，是坐着那一款罪犯招因？小叔儿和嫂嫂干寻衅，令史每死也波钱亲，背地里揣与些金银。", "休想那正眼儿敢觑着原告人，我将你拔树连根。", "(云)这桩事，必然暗昧。", "兀那李德义，你那侄儿那里去了？(李德义云)是俺嫂嫂同奸夫所算了他来。", "(正末云)兀那李阿陈，说你那词因。", "(大旦云)告大人息雷霆之怒，罢虎狼之威。", "小妇人与李大是儿女夫妻。", "当日李二要分另家私，李大便道：俺是敕赐的义门李家，三辈儿不曾分另，你如何要分另？一口气气杀俺丈夫。", "有神奴孩儿，要街市上耍去，院公引的孩儿到州桥左侧。", "孩儿要傀儡儿耍子，院公买傀儡儿去了，不期李二撞见孩儿，抱的家去，婶子将孩儿勒死了。", "我与院公寻去，他倒说我有奸夫，所算了孩儿。", "不由分诉，拖到宫中，三推六问，吊拷绷扒，屈打成招。", "今日投至见大人，似那拨云见日，昏镜重明。", "柔软莫过溪涧水，不平地上也高声。", "大人怀揣万古轩辕镜，照察我这衔冤负屈情。", "(正末云)兀那司吏，这妇人口内词因，怎生和这状子上不同那？(外郎云)大人，他都是那揭帖上学定了的，休听他说。", "这妇人有奸夫，勒杀亲儿，都是他来。", "(正末云)兀那李阿陈，我再问你咱。", "(唱)。"]'),
('yuanqu-6440','神奴儿大闹开封府・雁儿落','无名氏','元','元曲','yuanqu','','[]','你莫不是李员外娶的后婚？(大旦云)俺是绾角儿夫妻，持过公婆孝服，埋殡夫主，每自的浇茶奠酒上坟哩。',105,'元曲/yuanqu.json','["你莫不是李员外娶的后婚？(大旦云)俺是绾角儿夫妻，持过公婆孝服，埋殡夫主，每自的浇茶奠酒上坟哩。", "我家是敕赐义门李氏，怎敢辱抹家门？大人可怜见。", "(正末唱)他道是绾角儿成秦晋。", "他去那公婆行持孝服，他将亲夫主才埋殡。"]'),
('yuanqu-6441','神奴儿大闹开封府・得胜令','无名氏','元','元曲','yuanqu','','[]','每日价浇茶奠酒上新坟，怎肯贪图淫欲辱家门。',72,'元曲/yuanqu.json','["每日价浇茶奠酒上新坟，怎肯贪图淫欲辱家门。", "你道他所算了孩儿命，我道来须是他嫡母亲。", "想着他生身，他曾受十月怀耽孕，抬举得成人，他也曾有三年乳哺恩。"]'),
('yuanqu-6442','神奴儿大闹开封府・沉醉东风','无名氏','元','元曲','yuanqu','','[]','他去那原告人十分觑问，眼见的那被告人九分关亲。',76,'元曲/yuanqu.json','["他去那原告人十分觑问，眼见的那被告人九分关亲。", "他将李阿陈相哀悯，他去那李二行百般的施仇恨，料应来必有个缘因。", "我见他两次三番如丧神，早难道肋底下插柴自稳。"]'),
('yuanqu-6443','神奴儿大闹开封府・甜水令','无名氏','元','元曲','yuanqu','','[]','好教我便烦烦恼恼，忄敝忄敝焦焦，嗔嗔忿忿，都变做了笑欣欣。',58,'元曲/yuanqu.json','["好教我便烦烦恼恼，忄敝忄敝焦焦，嗔嗔忿忿，都变做了笑欣欣。", "我这里亲举霜毫，写道牒文，使颗印信，将着去衙门外把火烧焚。"]'),
('yuanqu-6444','神奴儿大闹开封府・收江南','无名氏','元','元曲','yuanqu','','[]','呀！谁着你个逆风儿点火落的这自烧身，便不念自家骨肉自家亲，也须知举头三尺有灵神。',67,'元曲/yuanqu.json','["呀！谁着你个逆风儿点火落的这自烧身，便不念自家骨肉自家亲，也须知举头三尺有灵神。", "今日到南衙来勘问，才见得我老龙图就似那一轮明镜不容尘。"]'),
('yuanqu-6445','王月英元夜留鞋记・仙吕/赏花时','无名氏','元','元曲','yuanqu','','[]','谁知道半霎相看百种愁，则被那一点相思两处勾。',128,'元曲/yuanqu.json','["谁知道半霎相看百种愁，则被那一点相思两处勾。", "(郭华云)小娘子，这胭脂粉不见好，还有高的换些与我。", "(正旦唱)他把这脂粉作因由。", "(云)秀才，这是上等的胭脂粉哩。", "(郭华云)看小娘子分上，便不好也收了去。", "(正旦唱)我见他趋前退后，待言语却又早紧低头。", "(同梅香下)。"]'),
('yuanqu-6446','王月英元夜留鞋记・仙吕/点绛唇','无名氏','元','元曲','yuanqu','','[]','独守香闺，懒临阶砌。',25,'元曲/yuanqu.json','["独守香闺，懒临阶砌。", "慵梳洗，湿透罗衣，总是愁人泪。"]'),
('yuanqu-6447','王月英元夜留鞋记・油葫芦','无名氏','元','元曲','yuanqu','','[]','瘦损春风玉一围，九十日韶光能有几？席前花影坐间移。',143,'元曲/yuanqu.json','["瘦损春风玉一围，九十日韶光能有几？席前花影坐间移。", "(梅香云)想姐姐这般丰韵，自然有个俊俏的郎君作对哩。", "(正旦唱)你道是鸾凰自有鸾凰配，鸳鸯自有鸳鸯对。", "(梅香云)姐姐，说便是这等说，只是你年纪儿小，那喜事还早哩。", "(正旦唱)你道我年纪小，喜事迟。", "我则怕镜中人老偏容易，常言道，花也有未开期。"]'),
('yuanqu-6448','王月英元夜留鞋记・天下乐','无名氏','元','元曲','yuanqu','','[]','我则怕一去朱颜唤不回，误了我这佳期待怎的？若得个俏书生早招做女婿，暗暗的接了财，悄悄的受了礼，便落的虚名儿则是美。',91,'元曲/yuanqu.json','["我则怕一去朱颜唤不回，误了我这佳期待怎的？若得个俏书生早招做女婿，暗暗的接了财，悄悄的受了礼，便落的虚名儿则是美。", "(梅香云)姐姐，这等事你不明对我说，怎生得个成就日子那？(正旦唱)。"]'),
('yuanqu-6449','王月英元夜留鞋记・那吒令','无名氏','元','元曲','yuanqu','','[]','这件事，天知地知；这件事，神知鬼知；这件事，心知腹知。',43,'元曲/yuanqu.json','["这件事，天知地知；这件事，神知鬼知；这件事，心知腹知。", "口里言，心中计，休得便走漏天机。"]'),
('yuanqu-6450','王月英元夜留鞋记・鹊踏枝','无名氏','元','元曲','yuanqu','','[]','我为他蹙娥眉，减腰围，但得个寄信传音，也省的人废寝忘食。',49,'元曲/yuanqu.json','["我为他蹙娥眉，减腰围，但得个寄信传音，也省的人废寝忘食。", "若能勾相会在星前月底，早医可了这染病耽疾。"]'),
('yuanqu-6451','王月英元夜留鞋记・寄生草','无名氏','元','元曲','yuanqu','','[]','他可有浑身俏，我偷将冷眼窥，端的个眉清目秀多伶俐。',67,'元曲/yuanqu.json','["他可有浑身俏，我偷将冷眼窥，端的个眉清目秀多伶俐。", "他把娇胭腻粉频交易，与我言来语去相调戏。", "现如今紫鸾箫断彩云空，几时得流苏帐暖春风细。"]'),
('yuanqu-6452','王月英元夜留鞋记・金盏儿','无名氏','元','元曲','yuanqu','','[]','咱两个最相知，说真实。',167,'元曲/yuanqu.json','["咱两个最相知，说真实。", "梅香也，你休要等闲泄漏春消息，我忙赔笑脸厮央及。", "<带云)你若去时呵，(唱)我索与你金环儿重改造，鹤袖儿做新的。", "(梅香云)姐姐，我说便也说了，则没个媒人，怎生是好？(正旦唱)何须寻月老，则你是良媒。", "(做写诗科，云)我亲笔写下一首诗在此，你与我送与那生去咱。", "(梅香云)姐姐，我去便去，则是把甚么做定礼那？(正旦唱)。"]'),
('yuanqu-6453','王月英元夜留鞋记・后庭花','无名氏','元','元曲','yuanqu','','[]','你将这锦纹笺为定礼，(梅香云)也要鼓笛送去才好。',217,'元曲/yuanqu.json','["你将这锦纹笺为定礼，(梅香云)也要鼓笛送去才好。", "(正旦唱)你将这紫霜毫做鼓笛。", "(梅香云)谁是保亲的？(正旦唱)保亲的是鸳鸯字，(梅香云)谁是主婚的？(正旦唱)主婚的是锦绣题。", "(梅香云)母亲知道呵，可怎了也？(正旦唱)休怕我母亲知，抵多少姻缘相会。", "卓文君驾香车归故里，汉相如到他乡发志气。", "薛琼琼有宿缘仙世期，崔怀宝花园中成匹配。", "韩彩云芙蓉亭遇故知，崔伯英两团圆直到底。", "(梅香云)常言道得好，佳人有意郎君俏，可知姐姐看上他来。", "(正旦唱)。"]'),
('yuanqu-6454','王月英元夜留鞋记・柳叶儿','无名氏','元','元曲','yuanqu','','[]','这的是佳人有意，都做了年少的夫妻，那会真诗就是我傍州例。',54,'元曲/yuanqu.json','["这的是佳人有意，都做了年少的夫妻，那会真诗就是我傍州例。", "便犯出风流罪，暗约下雨云期，常言道，风情事那怕人知。"]'),
('yuanqu-6455','王月英元夜留鞋记・赚煞尾','无名氏','元','元曲','yuanqu','','[]','只几句断肠词，写不尽中心意，全靠你梅香说知。',119,'元曲/yuanqu.json','["只几句断肠词，写不尽中心意，全靠你梅香说知。", "我比待月莺莺不姓崔，休教咱罗帏中魂梦先飞。", "莫延迟，你与我疾去忙归，(梅香云)姐姐，也还要选个好日期才是。", "(正旦唱)拣甚么良辰并吉日。", "则愿他停眠少睡，早早的成双作对，趁着那梅梢月转画楼西。", "(下)。"]'),
('yuanqu-6456','王月英元夜留鞋记・正宫/端正好','无名氏','元','元曲','yuanqu','','[]','车马践尘埃，罗绮笼烟霭，灯球儿月下高抬。',35,'元曲/yuanqu.json','["车马践尘埃，罗绮笼烟霭，灯球儿月下高抬。", "这回偿了鸳鸯债，则愿的今朝赛。"]'),
('yuanqu-6457','王月英元夜留鞋记・滚绣球','无名氏','元','元曲','yuanqu','','[]','天澄澄恰二更，人纷纷闹九垓，(云)不知今夜怎生这等耳热眼跳也。',141,'元曲/yuanqu.json','["天澄澄恰二更，人纷纷闹九垓，(云)不知今夜怎生这等耳热眼跳也。", "(唱)敢是母亲行有些嗔责，(梅香云)奶奶着俺们看罢灯早回去哩。", "(正旦唱)则教我看灯罢早早回来。", "你看那月轮呵光满天。", "灯轮呵红满街，沸春风管弦一派，趁游人拥出蓬莱。", "莫不是六鳌海上扶山了？莫不是双凤云中驾辇来？直恁的人马相挨。"]'),
('yuanqu-6458','王月英元夜留鞋记・倘秀才','无名氏','元','元曲','yuanqu','','[]','看一望琼瑶月色，似万盏琉璃世界，则见那于朵金莲五夜开。',45,'元曲/yuanqu.json','["看一望琼瑶月色，似万盏琉璃世界，则见那于朵金莲五夜开。", "笙歌门院落，灯火映楼台，把梳妆再改。"]'),
('yuanqu-6459','王月英元夜留鞋记・滚绣球','无名氏','元','元曲','yuanqu','','[]','浅浅的匀粉腮，淡淡的扫眉黛，不梳妆又则怕母亲疑怪，没奈何云鬓上斜插金钗。',99,'元曲/yuanqu.json','["浅浅的匀粉腮，淡淡的扫眉黛，不梳妆又则怕母亲疑怪，没奈何云鬓上斜插金钗。", "风飘飘吹缕衣，露冷冷湿绣鞋，多情月送我在三条九陌，又不曾泛桃花流下天台。", "则因这武陵仙子春心荡，却被那尘世刘郎引出来，今仅和谐。"]'),
('yuanqu-6460','王月英元夜留鞋记・叨叨令','无名氏','元','元曲','yuanqu','','[]','背着这闹火火亲身自向莲台拜，只见他静悄悄月明千里人何在？(做见科，唱)元来个困腾腾和衣倒在窗儿外，(云)哦，我猜着他了。',161,'元曲/yuanqu.json','["背着这闹火火亲身自向莲台拜，只见他静悄悄月明千里人何在？(做见科，唱)元来个困腾腾和衣倒在窗儿外，(云)哦，我猜着他了。", "(唱)莫不为步迟迟更深等的无聊赖？早些儿觉来也波哥，早些儿觉来也波哥，我只索向前去推整他头巾带。", "(梅香云)这厮敢睡着了，待我叫他。", "(做叫不醒科，云)这等好睡！姐姐，待我推醒他。", "(做推不醒科)(正旦唱)。"]'),
('yuanqu-6461','王月英元夜留鞋记・滚绣球','无名氏','元','元曲','yuanqu','','[]','且饶过王月英，待唤声郭秀才，又则怕有人在画檐之外，我靠香肩将玉体轻挨。',109,'元曲/yuanqu.json','["且饶过王月英，待唤声郭秀才，又则怕有人在画檐之外，我靠香肩将玉体轻挨。", "觑着时眼不开，问着时头不抬，扶起来试看他容颜面色，(做见郭醉科，唱)哎，却原来醉醺醺东倒西歪。", "我这里一双柳叶眉儿皱，他那里两朵桃花上脸来，说甚乖乖。"]'),
('yuanqu-6462','王月英元夜留鞋记・呆骨朵','无名氏','元','元曲','yuanqu','','[]','说甚么金尊倒处千愁解，好教人感叹伤怀。',88,'元曲/yuanqu.json','["说甚么金尊倒处千愁解，好教人感叹伤怀。", "你只恋北海春醪，偏不待西厢月色。", "我道是看书人多志诚，你如今倒把我厮禁害。", "(带云)哎，秀才，秀才。", "(唱)那里也色胆天来大，却原来酒肠宽似海。"]'),
('yuanqu-6463','王月英元夜留鞋记・煞尾','无名氏','元','元曲','yuanqu','','[]','本待要秦楼夜访金钗客，倒教我楚馆尘昏五镜台。',660,'元曲/yuanqu.json','["本待要秦楼夜访金钗客，倒教我楚馆尘昏五镜台。", "则被伊家厮定害，醉眼蒙胧唤不开，一枕南柯懒觉来。", "遗下香罗和绣鞋，再约佳期又一载。", "月转西楼怎停待，角奏梅花不宁奈，空抱愁怀归去来。", "(带云)哎，秀才，秀才。", "(唱)你若要人月团圆鸾凤谐，那其间还把那三万贯胭脂再来买。", "(同梅香下)(郭华醒，云)不觉的睡着了也。", "(做闻科，云)怎生一阵麝兰香，是那里吹来的？呀！我这怀中是甚么东西？(做见手帕、鞋儿科，云)原来是一个香罗帕，包着一只绣鞋儿。", "嗨！这鞋儿正是小娘子穿的！他必定到此处来，见我醉了睡着了，他害羞不肯叫我，故留绣鞋为记。", "小娘子，你有如此下顾小生之心，我倒有怠慢姐姐之意。", "这多是小生缘薄分浅，不能成其美事，岂不恨杀我也！(做看鞋科，云)我看了这一只绣鞋儿，端端正正，窄窄弓弓；这个香罗帕儿香香喷喷，细细腻腻的。", "物在人何在？天阿！我费了多少心情，才能勾今夜小娘子来此寺中，相约一会。", "谁想小生贪了几杯儿酒，睡着了！正是好事多磨，要我这性命何用？我就将这香罗帕儿咽入腹中，便死了也表小生为小娘子这点微情。", "(诗云)苦为烧香断了头，姻缘到手却干休。", "拚向牡丹花下死，纵教做鬼也风流。", "(做咽汗巾噎倒科)(净扮和尚上，诗云)我做和尚年幼，生来不断酒肉。", "施主请我看经，单把女娘一溜。", "小僧是这相国寺殿主。", "时遇元宵节令，大开山门，游人玩赏。", "这早晚更深夜静，长老分付着载巡视殿宇两廊灯烛香火，来到这观音殿内。", "(做绊倒科，云)呀，怎生有个人睡在地下？我试看咱。", "(做举灯看科，云)原来是个秀才。", "秀才起来，天色将明了，你起来家去罢。", "呀，可怎生唤不醒也？我再看咱。"]'),
('yuanqu-6464','王月英元夜留鞋记・中吕/粉蝶儿','无名氏','元','元曲','yuanqu','','[]','云鬓堆鸦，敛双眉不堪妆画，有甚事愁绪交加？我这里昼忘餐，夜废寝，把咱牵挂。',242,'元曲/yuanqu.json','["云鬓堆鸦，敛双眉不堪妆画，有甚事愁绪交加？我这里昼忘餐，夜废寝，把咱牵挂。", "想昨宵短命冤家，引的人放心不下。", "(梅香云)姐姐，想那秀才好没福也。", "姐姐为他费了多少心，干走了我们这半夜哩。", "(正旦云)怎么这一会儿有些心绪不宁？梅香，待我少将息咱。", "(张千上，云)自家张千的便是。", "适才拿得王婆婆到官去，如今又着我勾他女孩儿王月英，只索再走一遭。", "王月英在家么？(梅香云)姐姐，门首有人唤你哩。", "(正旦云)梅香，你看去，这是甚么人？(梅香云)是那开封府的公人，好生凶狠哩。", "(正旦云)这事可怎了也。", "(唱)。"]'),
('yuanqu-6465','王月英元夜留鞋记・迎仙客','无名氏','元','元曲','yuanqu','','[]','我须是王月英，又不是泼烟花，又不是风尘卖酒家。',228,'元曲/yuanqu.json','["我须是王月英，又不是泼烟花，又不是风尘卖酒家。", "有甚么败了风化，有甚么差了礼法。", "公然便把人勾拿？哥哥也，你休将这女孩儿相惊唬。", "(张千云)王月英，快跟我去来。", "(正旦云)哎呀，可着谁救我也！(同张千下)(包待制上，云)着张千勾王月英去了，这早晚怎生还不见来？(张千拿正旦入，跪科，云)禀爷，这就是不见了绣鞋儿的王月英。", "(包待制云)你便是王月英么？(正旦云)妾身是王月英。", "(包待制云)你多大年纪？曾有婚配来么？(正旦云)告爷爷可怜见，试听我王月英说一遍咱。", "(唱)。"]'),
('yuanqu-6466','王月英元夜留鞋记・红绣鞋','无名氏','元','元曲','yuanqu','','[]','俺年纪小未曾招嫁，(包待制云)你在那里住坐？(正旦唱)从小里长在京华，(包待制云)你家做甚营生买卖？(正旦唱)祖辈儿卖脂粉作生涯。',196,'元曲/yuanqu.json','["俺年纪小未曾招嫁，(包待制云)你在那里住坐？(正旦唱)从小里长在京华，(包待制云)你家做甚营生买卖？(正旦唱)祖辈儿卖脂粉作生涯。", "(包待制云)你有兄弟也无？(正旦唱)叹只身无兄弟，(包待制云)你有父亲么？(正旦唱)更老亲早亡化，(包待制云)你是何门户？(正旦唱)本是个守农庄百姓家。", "(包待制云)你既是个女子，怎生不守闺门之训，这绣鞋儿却揣在郭华怀中？有何理论，从实招来，休讨打吃。", "(正旦唱)。"]'),
('yuanqu-6467','王月英元夜留鞋记・石榴花','无名氏','元','元曲','yuanqu','','[]','相公你怀揣着明镜掌刑罚，断王事不曾差。',174,'元曲/yuanqu.json','["相公你怀揣着明镜掌刑罚，断王事不曾差。", "我本是深宅大院好人家，说甚郭华？(包待制云)胡说！你道不认的郭华，这绣鞋儿是飞在他怀里的？(正旦做慌科，唱)郭华因咱，唬的我兢兢战战寒毛乍。", "(包待制云)眼见得这绣鞋是与他做表记了。", "(正旦唱)见相公语话儿兜搭，(包待制云)你还不招，只这绣鞋儿便是真赃正犯了。", "(正旦唱)你道是真赃正犯难干罢，平白地揣与我个祸根芽。"]'),
('yuanqu-6468','王月英元夜留鞋记・斗鹌鹑','无名氏','元','元曲','yuanqu','','[]','又不曾锦被里情浓，原来是绣鞋儿事发。',167,'元曲/yuanqu.json','["又不曾锦被里情浓，原来是绣鞋儿事发。", "(包待制云)可知是你的鞋儿。", "张千，唤他母亲出来对证。", "(张千云)王婆婆，老爷呼唤。", "(卜儿上，见正旦哭科，云)孩儿，此一件事你做下了也。", "(正旦唱)见母亲哭哭啼啼，却教我羞羞答答。", "(卜儿云)孩儿，这绣鞋因甚在那秀才怀里来？(正旦唱)则管里将那缘由审问咱，我则索无言指落花。", "本待要寄信传情，却做了违条犯法。"]'),
('yuanqu-6469','王月英元夜留鞋记・上小楼','无名氏','元','元曲','yuanqu','','[]','我金莲步狭，常只在罗裙底下。',54,'元曲/yuanqu.json','["我金莲步狭，常只在罗裙底下。", "为贪着一轮皓月，万盏花灯，九街车马。", "更漏深，田地滑，游人稠杂，鳌山畔把他来撇下。"]'),
('yuanqu-6470','王月英元夜留鞋记・十二月','无名氏','元','元曲','yuanqu','','[]','尚不见留情手帕，却教我受罪南衙。',118,'元曲/yuanqu.json','["尚不见留情手帕，却教我受罪南衙。", "(包待制云)哦，元来还有个香罗帕儿。", "你是未嫁的闺女，可也不该做这等勾当。", "(正旦唱)本待望同衾共枕，倒做了带锁披枷。", "这一场风流话靶，也是个欢喜冤家。", "(包待制云)这两件东西，却也不该就害了他性命。", "(正旦唱)。"]'),
('yuanqu-6471','王月英元夜留鞋记・尧民歌','无名氏','元','元曲','yuanqu','','[]','呀，都只为武陵仙子泛桃花，可教我一灵儿身死野人家。',64,'元曲/yuanqu.json','["呀，都只为武陵仙子泛桃花，可教我一灵儿身死野人家。", "只落的潇潇洒洒伴残霞，杳杳冥冥卧黄沙。", "差也波差，当初怨恨咱，常言道色胆天来大。"]'),
('yuanqu-6472','王月英元夜留鞋记・煞尾','无名氏','元','元曲','yuanqu','','[]','娘呵你年纪过五旬，抬举的孩儿青春恰二八。',51,'元曲/yuanqu.json','["娘呵你年纪过五旬，抬举的孩儿青春恰二八。", "不争葫芦提斩首在云阳下，把我这养育的娘亲痛哭杀。", "(同张千下)。"]'),
('yuanqu-6473','王月英元夜留鞋记・双调/新水令','无名氏','元','元曲','yuanqu','','[]','痛伤情望的我眼睛穿，咱两个得成双死而无怨。',83,'元曲/yuanqu.json','["痛伤情望的我眼睛穿，咱两个得成双死而无怨。", "虽然是相期灯月底，又不曾取乐枕屏边。", "如今你命掩黄泉，这阴司下怎分辩？(张千云)这是你自做的差了，还要分辩甚么那！(正旦唱)。"]'),
('yuanqu-6474','王月英元夜留鞋记・驻马听','无名氏','元','元曲','yuanqu','','[]','有口难言，月里嫦娥爱少年。',63,'元曲/yuanqu.json','["有口难言，月里嫦娥爱少年。", "恩多成怨，你莫是酒中得道遇神仙？抵多少笙歌引至画堂前，鸳鸯深锁黄金殿。", "空教我恨绵绵，当初悔不休相见。"]'),
('yuanqu-6475','王月英元夜留鞋记・太平令','无名氏','元','元曲','yuanqu','','[]','唬的我手脚儿惊惊战战，鬼魂灵怎敢胡缠。',101,'元曲/yuanqu.json','["唬的我手脚儿惊惊战战，鬼魂灵怎敢胡缠。", "(郭华做见旦科，云)小娘子，我和你相见，知道是睡里梦里？(做起身搂，正旦摔开科，唱)断不了轻狂寒贱，还只待痴迷留恋。", "我这里跃然，向前，谢天，呀！险些的在云阳推转！。"]'),
('yuanqu-6476','王月英元夜留鞋记・川拨棹','无名氏','元','元曲','yuanqu','','[]','你怀揣着似轩辕、似轩辕明镜，他如今诉说根源。',50,'元曲/yuanqu.json','["你怀揣着似轩辕、似轩辕明镜，他如今诉说根源。", "两下当年，都则为一点情牵。", "我王月英有甚言，任恩官怎发遣。"]'),
('yuanqu-6477','王月英元夜留鞋记・七弟兄','无名氏','元','元曲','yuanqu','','[]','则他这解元，使钱，早使过了偌多千。',72,'元曲/yuanqu.json','["则他这解元，使钱，早使过了偌多千。", "(包待制云)他是个读书人，买你胭脂做甚么？(正旦唱)奈胭脂不上书生面，都将来撒在洛河边，恰便似天台流出桃花片。"]'),
('yuanqu-6478','王月英元夜留鞋记・梅花酒','无名氏','元','元曲','yuanqu','','[]','呀！俺娘亲敢自专，俺娘亲敢自专。',75,'元曲/yuanqu.json','["呀！俺娘亲敢自专，俺娘亲敢自专。", "待择取英贤，匹配婵娟，断送他的衰年。", "问甚么鸾胶续断弦，巴不得顺水便推船。", "呀！谢恩官肯见怜，休拗折并头莲，莫掐杀双飞燕。"]'),
('yuanqu-6479','王月英元夜留鞋记・收江南','无名氏','元','元曲','yuanqu','','[]','呀！也不枉了一春常费买花钱，谁承望包龙图到与我递丝鞭，赢的个洛阳儿女笑喧阗。',57,'元曲/yuanqu.json','["呀！也不枉了一春常费买花钱，谁承望包龙图到与我递丝鞭，赢的个洛阳儿女笑喧阗。", "都道这风情不浅，准备着今生重结再生缘。"]'),
('yuanqu-6480','鲁智深喜赏黄花峪・仙吕/点绛唇','无名氏','元','元曲','yuanqu','','[]','九月重阳，暮秋霜降，闲云住。',25,'元曲/yuanqu.json','["九月重阳，暮秋霜降，闲云住。", "满目山光，对景堪游赏。"]'),
('yuanqu-6481','鲁智深喜赏黄花峪・混江龙','无名氏','元','元曲','yuanqu','','[]','猛然观望，见宾鸿摆列两三行。',73,'元曲/yuanqu.json','["猛然观望，见宾鸿摆列两三行。", "枯茶减翠，衰柳添黄。", "我则红叶满目滴溜溜枝上舞，可这黄菊可都喷鼻香。", "端的是堪写在围屏上，看了这秋天景致，怎不教宋玉悲伤。"]'),
('yuanqu-6482','鲁智深喜赏黄花峪・油葫芦','无名氏','元','元曲','yuanqu','','[]','是这涧水潺潺波浪响，我这里便听了半晌，元来是这水声山色趁秋光，则听啾啾唧唧聒耳山禽唱，唬的那呆呆邓邓的麋鹿赤留出律的撞。',119,'元曲/yuanqu.json','["是这涧水潺潺波浪响，我这里便听了半晌，元来是这水声山色趁秋光，则听啾啾唧唧聒耳山禽唱，唬的那呆呆邓邓的麋鹿赤留出律的撞。", "见人呵急张张屈屈的走，更那堪惊惊颤颤的慌。", "我这里手分开芦苇吸溜疏刺的挡，(云)惊起一件好物也，(唱)惊起那沙暖宿鸳鸯。"]'),
('yuanqu-6483','鲁智深喜赏黄花峪・天下乐','无名氏','元','元曲','yuanqu','','[]','见一座摧塌了山神古庙堂，我这里思也波量，端的着谁上香？你看那拖拖沓沓乔供养。',78,'元曲/yuanqu.json','["见一座摧塌了山神古庙堂，我这里思也波量，端的着谁上香？你看那拖拖沓沓乔供养。", "(云)贪看山神庙，误了我行路也。", "(唱)我这里登峻岭，蓦浅岗，见一道放牛羊小径荒。"]'),
('yuanqu-6484','鲁智深喜赏黄花峪・醉中天','无名氏','元','元曲','yuanqu','','[]','我见一个小店儿凄凉象，野犬吠汪汪。',587,'元曲/yuanqu.json','["我见一个小店儿凄凉象，野犬吠汪汪。", "破芦席搭在旧水床，将一张无尾的题头放。", "醉仙几尊画在石灰壁上，草禾享滴溜溜斜挑在墙头上。", "(云)行说着话。", "可早来到也。", "(做入店见科，云)小二哥，有干净阁子末？(店小二云)官人请坐。", "(正末云)打二百文长钱酒来，我不这般干吃你的。", "来、来，我与你些碎金银做本钱。", "(店小二做揣入怀里科，云)不要也罢。", "(正末云)这厮口道不要，可揣在怀里。", "将酒来。", "(店小二与酒科)(正末吃酒科，云)小二哥，时遇九月九节令，家家正好欢喜饮酒，那里这般啼哭？(店小二云)官人，那厢两口儿吃酒。", "这厢个官人，要那秀才的浑家，替他递三杯酒，因他不肯，将那秀才吊着打，因此上那秀才啼哭。", "(正末云)你不好劝他一劝。", "(店小二云)我劝他来，连我打的不着忙。", "他是个权豪势要的人，我不敢劝他。", "(正末云)我将这酒寄在这里，等我劝他去。", "(店小二云)哥，你休去。", "(正末做采店小二跌科，云)不干你事，我劝去。", "(做采蔡净科)(蔡净瞅店小二科)(正末做解刘庆甫科)(做扳蔡净三科了，云)喏，客官。", "(蔡净云)走到土地庙里来了，怎主喏喏？(正末云)官人，我是个过路的，这个人是你的伴当？那侵你使数的？你为何吊着他打？拐带了你多少银两？你若说的是呵，我与你行究。", "(蔡净云)一个好聪明人也。", "我说起这厮的罪过来，大似狗蚤。", "这厮和他浑家唱着吃酒，我着卖酒的与他说去，着他浑家替我递三杯酒，叫我三声义男儿，我便上马回去。"]'),
('yuanqu-6485','鲁智深喜赏黄花峪・醉扶归','无名氏','元','元曲','yuanqu','','[]','你这厮无道理荒淫相，你怎生迤逗人家女红妆。',123,'元曲/yuanqu.json','["你这厮无道理荒淫相，你怎生迤逗人家女红妆。", "他别人行路夫妻在旅店上，你是个大胆的行凶党。", "(云)兀那厮，我和你有小比喻。", "(蔡净云)喻将何比？(正末唱)假若是你媳妇者波我止将来挨、挨枪，(云)你若不见呵，万事都休，你若见了呵。", "(唱)你恨不的一跳三千丈。"]'),
('yuanqu-6486','鲁智深喜赏黄花峪・尾声','无名氏','元','元曲','yuanqu','','[]','你告俺哥哥宋公明，(庆甫云)他是哥哥的谁？(正末唱)他是我亲兄长，(庆甫云)哥哥姓甚名谁？(正末唱)则我是病关索一身姓杨。',568,'元曲/yuanqu.json','["你告俺哥哥宋公明，(庆甫云)他是哥哥的谁？(正末唱)他是我亲兄长，(庆甫云)哥哥姓甚名谁？(正末唱)则我是病关索一身姓杨。", "(庆甫云)你生牢记者。", "(正末唱)着我心中自暗想，(庆甫云)若不是哥哥呵，那的那性命来。", "(正末唱)俺端的志气昂昂，(庆甫云)多谢了哥哥。", "(正末唱)我从来本高强。", "不是我说短论长，他若欺负你来梁山告俺宋江。", "(庆甫云)则怕又撞见他怎了也？(正末唱)那厮更十分不良，将平人屈漾，(庆甫云)则怕宋江哥哥不肯与我作主末？(正末云)投到你去呵。", "(唱)我与你待先说话衷肠。", "(庆甫云)大嫂，俺休往大路上去，咱往小路上去，则怕撞见蔡衙内，怎了？(旦云)你也说的是。", "则怕撞见那贼汉，强夺的我去了，不能与你相见。", "我这里有个枣木梳儿，与你做信物，久以后见了这梳儿，便和见我一般。", "(庆甫云)我收了这梳儿，久以后见了这梳儿，便是信物。", "俺休离了。", "大嫂，俺走、走、走。", "(下)(店小二云)走将这几个人来，酒也卖不成，整嚷了这一日。", "收了铺儿，往钟鼓司学行金斗去来。", "(下)(刘庆甫同旦做慌上，云)走、走、走。", "(蔡做冲上，栏住科)好也，那里去？打的我好也。", "我将他浑家驼在马上，我拐他去十八层水南寨里去也。", "走、走、走。", "(下)(庆甫云)天也，谁想正撞着蔡衙内，将我浑家夺在马上去了。", "我别处告，近不的他，直往梁山上告宋江哥哥走一遭去。", "大嫂，则被你疼杀我也。", "(下)。"]'),
('yuanqu-6487','鲁智深喜赏黄花峪・南吕/一枝花','无名氏','元','元曲','yuanqu','','[]','俺哥哥传将令三四番，可怎生无一个承头的？这一个燕青将面劈，那一个杨志头低。',99,'元曲/yuanqu.json','["俺哥哥传将令三四番，可怎生无一个承头的？这一个燕青将面劈，那一个杨志头低。", "那里也大胆姜维，问着呵一个个缄口无人言对，你可便怕相持对垒。", "(云)似恁的呵。", "(唱)你可便枉住在梁山，兀的不辱没杀俺哥哥保义。"]'),
('yuanqu-6488','鲁智深喜赏黄花峪・哭皇天','无名氏','元','元曲','yuanqu','','[]','莫不是再生下张车骑？(宋江云)张车骑是张飞，这个人义利害似他。',386,'元曲/yuanqu.json','["莫不是再生下张车骑？(宋江云)张车骑是张飞，这个人义利害似他。", "(正末唱)莫不是重生下胡敬德？(宋江云)尉迟敬德也不如他。", "(正末云)哥也，张飞比他如何？(宋江云)张飞不如他。", "(正末云)敬德比他如何？(宋江云)也不如他。", "(正末云)哥，您兄弟比他如何？(宋江云)你也不如他。", "(正末唱)阿，恼的我磕叉叉斧砍人，(宋江云)俺这里敲牛宰马，做个庆喜的筵席。", "(正末唱)你则待稳拍做筵席。", "(宋江云)山儿，你怎生强嘴也那？(正末唱)不是李山儿便强嘴，(云)哥也，您兄弟有功劳来也。", "(宋江云)你有甚么功劳？(正末唱)小可如我郓州东平府带着枷披着锁，我跳三层家那死囚牢，比那时节更省我些气力。", "(宋江云)你三日不杀人呵呢？(正末云)我三日不杀人呵。", "(唱)我浑身上下拘系，(宋江云)三日不放火呢？(正末云)我三日不放火呵。", "(唱)倚着那石墙下呵盹睡。", "(宋江云)我哄他者。", "山儿，我着你杀人。", "(正末唱)。"]'),
('yuanqu-6489','鲁智深喜赏黄花峪・絮蛤蟆','无名氏','元','元曲','yuanqu','','[]','我打扮做个货郎儿，担着些零碎去寻那个艳质，他来买我些东西。',147,'元曲/yuanqu.json','["我打扮做个货郎儿，担着些零碎去寻那个艳质，他来买我些东西。", "(宋江云)可是甚么物件那？(正末唱)也有挑线领戏，也有钗环头篦。", "他若问我是谁，我索将他支对。", "那厮将我骂毁，我不邓邓火起。", "我见揪住头梢，挽住衣袂，滴溜扑摔下那厮阶基。", "拳捶心窝里，使靴尖踢，打这厮无道理，无见识，羊披着虎皮，打这厮狐假虎威。"]'),
('yuanqu-6490','鲁智深喜赏黄花峪・尾声','无名氏','元','元曲','yuanqu','','[]','我与你沿村转疃亲寻觅，四大神州捉逆贼。',75,'元曲/yuanqu.json','["我与你沿村转疃亲寻觅，四大神州捉逆贼。", "我若还撞着你，揪住头梢，扌昝住领戏，我将那厮滴溜扑摔下那厮阶基。", "我将那厮死羊儿般，到拖将来俺这个山寨里。", "(下)。"]'),
('yuanqu-6491','鲁智深喜赏黄花峪・正宫/端正好','无名氏','元','元曲','yuanqu','','[]','绕村坊，寻门户，一径的打探个实虚。',41,'元曲/yuanqu.json','["绕村坊，寻门户，一径的打探个实虚。", "恰便似竹林寺有影无寻处，我问那蔡衙内在何方住？。"]'),
('yuanqu-6492','鲁智深喜赏黄花峪・滚绣球','无名氏','元','元曲','yuanqu','','[]','希壤忽浓泥义滑，失流疏刺水渲的渠，赤留出律惊起些野鸭鸥鹭，我这里急煎煎整顿了衣服。',72,'元曲/yuanqu.json','["希壤忽浓泥义滑，失流疏刺水渲的渠，赤留出律惊起些野鸭鸥鹭，我这里急煎煎整顿了衣服。", "急周各支荡散了枪竿篓，急彪各邦踏折了剑菖蒲，见一道小路儿荒疏。"]'),
('yuanqu-6493','鲁智深喜赏黄花峪・倘秀才','无名氏','元','元曲','yuanqu','','[]','我则见水围着人家一簇，中间里叠成一道旱路，则听，则听的狗儿咬各邦捣碓处。',54,'元曲/yuanqu.json','["我则见水围着人家一簇，中间里叠成一道旱路，则听，则听的狗儿咬各邦捣碓处。", "我这里担着零碎，践程途，我与你觅去。"]'),
('yuanqu-6494','鲁智深喜赏黄花峪・倘秀才','无名氏','元','元曲','yuanqu','','[]','我这里见姐姐忙道好处，(云)好人家，好家法，恶人家，恶举动，他也不慌不忙。',122,'元曲/yuanqu.json','["我这里见姐姐忙道好处，(云)好人家，好家法，恶人家，恶举动，他也不慌不忙。", "(唱)他那里掩着袂，货郎儿万福。", "他那里荒唤个万福，我这里问姐姐商量你可也买甚么物。", "(旦云)你卖的是那几件儿物件？你数与我听。", "(正末唱)我这里一一说，从头初，听货郎儿细数。"]'),
('yuanqu-6495','鲁智深喜赏黄花峪・倘秀才','无名氏','元','元曲','yuanqu','','[]','那秀才济州人氏，姓刘，名甚么庆甫？(旦云)他媳妇是谁？(正末唱)他媳妇姓李，(旦云)哥哥，是李甚么？(正末云)我把来忘了，我试想者。',173,'元曲/yuanqu.json','["那秀才济州人氏，姓刘，名甚么庆甫？(旦云)他媳妇是谁？(正末唱)他媳妇姓李，(旦云)哥哥，是李甚么？(正末云)我把来忘了，我试想者。", "(唱)小名唤做甚么幼奴？(旦云)他正是我的丈夫。", "(正末云)你好爱便宜，赶着货郎叫丈夫。", "(旦云)那秀才是我的丈夫。", "(正末唱)兀那秀才原来是你的丈夫，(旦云)阿，好烦恼人也呵！(正末唱)你可道莫烦恼莫啼哭，我与你做主。"]'),
('yuanqu-6496','鲁智深喜赏黄花峪・尾声','无名氏','元','元曲','yuanqu','','[]','我今日寻着你个李幼奴，分付与你刘庆甫。',48,'元曲/yuanqu.json','["我今日寻着你个李幼奴，分付与你刘庆甫。", "你两口儿欢喜重圆聚，我直要拿住无徒报了您那苦。", "(同旦下)。"]'),
('yuanqu-6497','鲁智深喜赏黄花峪・黄钟/醉花阴','无名氏','元','元曲','yuanqu','','[]','酒不醒贫僧怕见走，云岩寺权为宿头。',53,'元曲/yuanqu.json','["酒不醒贫僧怕见走，云岩寺权为宿头。", "且时住，暂停留，混践您些儿改日为友。", "常言道措大谒儒流，自古道客僧投寺宿。"]'),
('yuanqu-6498','鲁智深喜赏黄花峪・刮地风','无名氏','元','元曲','yuanqu','','[]','你性命当风秉蜡烛，俺似水上浮沤。',125,'元曲/yuanqu.json','["你性命当风秉蜡烛，俺似水上浮沤。", "病羊儿落在屠家手，咱两个怎肯平休？这厮更胡寻歹斗，故来承头。", "(蔡净云)打杀我也！寺里和尚，都来救我。", "(正末唱)怕有那寺院中埋伏着，您都来答救。", "我着这莽拳头，向这厮嘴缝上丢。", "泼水难收，则一拳打你个翻筋斗，来叫爹爹的呵休。"]'),
('yuanqu-6499','鲁智深喜赏黄花峪・四门子','无名氏','元','元曲','yuanqu','','[]','黑旋风与我先说透，(蔡净云)干你甚么事？(正末唱)你是个强夺人家女艳羞。',71,'元曲/yuanqu.json','["黑旋风与我先说透，(蔡净云)干你甚么事？(正末唱)你是个强夺人家女艳羞。", "不索你忧，不索你愁，泼贱货性命不过九。", "不索忧，不索愁，打这厮将没作有。"]'),
('yuanqu-6500','鲁智深喜赏黄花峪・古水仙子','无名氏','元','元曲','yuanqu','','[]','那那女艳羞，你拆散了他鸾交和凤友。',73,'元曲/yuanqu.json','["那那女艳羞，你拆散了他鸾交和凤友。", "待飞来难飞，待走来怎走？身躯似不缆舟，炎腾腾水上浇油。", "一只手便把衣领揪，一只手捂住衣和袖，滴溜扑摔翻一个肉春牛。"]'),
('yuanqu-6501','鲁智深喜赏黄花峪・尾声','无名氏','元','元曲','yuanqu','','[]','叵奈无徒歹禽兽，摘心肝扭下这驴头，与俺那梁山泊宋公明为案酒。',30,'元曲/yuanqu.json','["叵奈无徒歹禽兽，摘心肝扭下这驴头，与俺那梁山泊宋公明为案酒。"]'),
('yuanqu-6502','刘千病打独角牛・那吒令','无名氏','元','元曲','yuanqu','','[]','说着他这种田呵，我三衙家抹丢；道着他这放牛呵，我十分的便抖擞；提着道是拽拳呵，美也我精神儿便有。',72,'元曲/yuanqu.json','["说着他这种田呵，我三衙家抹丢；道着他这放牛呵，我十分的便抖擞；提着道是拽拳呵，美也我精神儿便有。", "我可便打熬成，我敢则是温习就，凭着我这武艺滑熟。"]'),
('yuanqu-6503','刘千病打独角牛・寄生草','无名氏','元','元曲','yuanqu','','[]','这一个吐架子先缠住手，(带云)这一个展不的也。',97,'元曲/yuanqu.json','["这一个吐架子先缠住手，(带云)这一个展不的也。", "(唱)怕扣落紧刺了头。", "这一个撞入去往上可便鼻凹里扣，这一个着昏拳厮打住胡厮纽，你与我中间里解开分前后。", "麦场上禾豆您亲收，你若到兀那泰安州银碗难能勾。"]'),
('yuanqu-6504','刘千病打独角牛・越调/梅花引','无名氏','元','元曲','yuanqu','','[]','将我个年老的尊堂恁厮拍，年纪小的妻儿迤逗来。',55,'元曲/yuanqu.json','["将我个年老的尊堂恁厮拍，年纪小的妻儿迤逗来。", "好着我忿怒夯胸怀，我今日践尘埃，这厮好情理切害，不报了冤仇和姓改。"]'),
('yuanqu-6505','刘千病打独角牛・紫花儿序','无名氏','元','元曲','yuanqu','','[]','休道是刘、刘、刘千的这和尚，便是那释迦如来，被这厮恼下莲台。',206,'元曲/yuanqu.json','["休道是刘、刘、刘千的这和尚，便是那释迦如来，被这厮恼下莲台。", "(折拆驴云)孩儿也，你身子不停当哩，将息你那证候咱。", "(正末唱)将我这神眉剔竖，把我这病眼来睁开。", "我好怨恨那个乔才，一会儿气的我浑身上津津的汗出来。", "(折拆驴云)孩儿也，倒是些儿好汗。", "(正末唱)美也觉我这身子儿轻快。", "(折拆驴云)孩儿也，你这般面黄肌瘦，眼嵌缩腮。", "两条腿恰似麻秸，十个指头有如灯草，你且将息几日去。", "(正末唱)你笑我脸似刀条，腿、腿、腿似麻秸。"]'),
('yuanqu-6506','刘千病打独角牛・耍三台','无名氏','元','元曲','yuanqu','','[]','常言道我虎瘦呵雄心在，你可便休笑我眼嵌缩腮。',93,'元曲/yuanqu.json','["常言道我虎瘦呵雄心在，你可便休笑我眼嵌缩腮。", "你道他偌来肥胖，你道我恁来大小身材。", "不是我自说口、自庄主、自邀买，我是那那吒社里横祸来的非灾。", "则今番破题儿和他相搏，他可敢寄着一场天来大利害。"]'),
('yuanqu-6507','刘千病打独角牛・络丝娘','无名氏','元','元曲','yuanqu','','[]','若是独角牛今番撇台，着那厮浅水鱼儿摸来。',42,'元曲/yuanqu.json','["若是独角牛今番撇台，着那厮浅水鱼儿摸来。", "山海也似冤仇我和他劈甚么排，不是我舌尖口快。"]'),
('yuanqu-6508','刘千病打独角牛・紫花儿序','无名氏','元','元曲','yuanqu','','[]','我怎肯主着面拳厮扑，和他两个厮捱，你看我倒蹬儿智厮瞒由咱摆划。',292,'元曲/yuanqu.json','["我怎肯主着面拳厮扑，和他两个厮捱，你看我倒蹬儿智厮瞒由咱摆划。", "俺两个硬厮并暗厮算，浓闹里休着那布束解。", "直打的这壁破那壁伤，碜可可嘴塌鼻歪。", "(折拆驴云)孩儿也，你上的那路台去，一个在左边，一个在右边，中间里部署扯了那藤棒，擂家汉要智的擒，打的擒，肚有智，瞒过人，一狠二毒三短命，便是擂的旧家风。", "你怎生遮截架解，你试说一遍，我试听咱。", "(正末唱)看那厮拽大拳可这般出、出、出的赶来，你看我跌过脚轻轻的倒台。", "吐架子扒下来，嘴缝上飕飕的着我扣落拍，直打的摇着头跌着脚道好、好、好擂可这般失惊打怪。", "(折拆驴云)孩儿也，你使的是上三路，下三路，中三路，可是那一路拳？你一发对我说一遍咱。", "(正末唱)。"]'),
('yuanqu-6509','刘千病打独角牛・正宫/端正好','无名氏','元','元曲','yuanqu','','[]','我来到这泰安州，我可便不住您兀那招商店，那厮便紧和我钉钉胶粘。',83,'元曲/yuanqu.json','["我来到这泰安州，我可便不住您兀那招商店，那厮便紧和我钉钉胶粘。", "把一池绿水可也浑都占，可怎生不放俺这傍人僭？(独角牛云)那一个好汉，敢出来与我独角牛擂三台？(正末唱)。"]'),
('yuanqu-6510','刘千病打独角牛・滚绣球','无名氏','元','元曲','yuanqu','','[]','他将那名姓呼，志气来口店，他在那露台上光闪，果然是名不虚传。',91,'元曲/yuanqu.json','["他将那名姓呼，志气来口店，他在那露台上光闪，果然是名不虚传。", "他可也忒自专，说大言，自夸轻健，可是他空说在骏马之前。", "我打这厮东头不说可在这西头说，我打这厮上口不口店下口口店，无耻无廉。"]'),
('yuanqu-6511','刘千病打独角牛・白鹤子','无名氏','元','元曲','yuanqu','','[]','谁不道你威凛凛，谁不道我瘦恹恹。',32,'元曲/yuanqu.json','["谁不道你威凛凛，谁不道我瘦恹恹。", "谁不道你有能奇，谁不道我无扎垫。"]'),
('yuanqu-6512','刘千病打独角牛・倘秀才','无名氏','元','元曲','yuanqu','','[]','我恰才吐架子左闪来右闪，我踢了个提过脚里臁也那外臁。',54,'元曲/yuanqu.json','["我恰才吐架子左闪来右闪，我踢了个提过脚里臁也那外臁。", "嘴缝上直拳并塌那厮脸，着这厮头完擂，早着拳，打这厮自专。"]'),
('yuanqu-6513','刘千病打独角牛・双调/新水令','无名氏','元','元曲','yuanqu','','[]','独角牛无对整三年，则今番赛还了他那口愿。',52,'元曲/yuanqu.json','["独角牛无对整三年，则今番赛还了他那口愿。", "说刘千一个展，值看官满怀钱。", "端的是名不虚传，看了那几合擂不曾见。"]'),
('yuanqu-6514','刘千病打独角牛・夜行船','无名氏','元','元曲','yuanqu','','[]','独角牛肥膜相搏呵，吁，他则落的一声喘，可是他空说在骏马之前。',56,'元曲/yuanqu.json','["独角牛肥膜相搏呵，吁，他则落的一声喘，可是他空说在骏马之前。", "他则待举意儿赢，他其心儿不善，可是他捉住鼓自开一遍。"]'),
('yuanqu-6515','刘千病打独角牛・川拨棹','无名氏','元','元曲','yuanqu','','[]','独角牛气冲天，他向那露台上说大言。',89,'元曲/yuanqu.json','["独角牛气冲天，他向那露台上说大言。", "卖弄他能拽直拳，快使横拳，你比俺刘千绝后光前。", "去也郑州出曹门较远，都部署将藤棒传。", "(孛老儿云)怎生擂鼓筛锣？呐喊摇旗？你试说一遍咱。", "(正末唱)。"]'),
('yuanqu-6516','刘千病打独角牛・七弟兄','无名氏','元','元曲','yuanqu','','[]','鼓儿着撒边、撒边，(云)手停手稳看相搏。',99,'元曲/yuanqu.json','["鼓儿着撒边、撒边，(云)手停手稳看相搏。", "(唱)你可便看，咱拳合手停，各自寻机变。", "一个拳沉脚重谨当先，俺哥哥身轻体健能挪展。", "(孛老儿云)俺刘千与独角牛怎生劈排定对？你试再说一遍，我试听咱。", "(正末唱)。"]'),
('yuanqu-6517','刘千病打独角牛・梅花酒','无名氏','元','元曲','yuanqu','','[]','呀！独角牛拽大拳，刘千见拳，来到跟前，火似放过条蚕椽，出虚影到他胸前。',76,'元曲/yuanqu.json','["呀！独角牛拽大拳，刘千见拳，来到跟前，火似放过条蚕椽，出虚影到他胸前。", "刘千使脚去手腕上剪，他敢迤逗的到露台边，接住脚往上掀。", "胖身躯怎回转，膂力的是刘千。"]'),
('yuanqu-6518','刘千病打独角牛・喜江南','无名氏','元','元曲','yuanqu','','[]','滴溜扑人丛里腾的脚稍天，俺哥哥他将那浑锦袄子急忙穿，早笙歌引至庙门前。',53,'元曲/yuanqu.json','["滴溜扑人丛里腾的脚稍天，俺哥哥他将那浑锦袄子急忙穿，早笙歌引至庙门前。", "独角牛自专，则他那输了的脸儿可怜见。"]'),
('yuanqu-6519','洞庭湖柳毅传书・仙吕/端正好','尚仲贤','元','元曲','yuanqu','','[]','我则为空负了雨云期，却离了沧波会，这一场抵多少水尽鹅飞。',50,'元曲/yuanqu.json','["我则为空负了雨云期，却离了沧波会，这一场抵多少水尽鹅飞。", "早是我受不过狠毒的儿夫气，更那堪不可公婆意。"]'),
('yuanqu-6520','洞庭湖柳毅传书・幺篇','尚仲贤','元','元曲','yuanqu','','[]','因此上拨下这牧羊差，妆出这捞龙汁。',88,'元曲/yuanqu.json','["因此上拨下这牧羊差，妆出这捞龙汁。", "想他每无恩义本性难移，养我向野川衰草残红世。", "离凤阁，近渔矶，蓬蝉鬓，蹙蛾眉，愁荏苒，泪淋漓。", "想父母，共亲戚。", "哎，天那知他何日得重完备。", "(下)。"]'),
('yuanqu-6521','洞庭湖柳毅传书・仙吕/点绛唇','尚仲贤','元','元曲','yuanqu','','[]','魂断频哭，梦回不睹，逢春暮，甚日归湖，备把这离愁诉。',26,'元曲/yuanqu.json','["魂断频哭，梦回不睹，逢春暮，甚日归湖，备把这离愁诉。"]'),
('yuanqu-6522','洞庭湖柳毅传书・油葫芦','尚仲贤','元','元曲','yuanqu','','[]','则我这头上风沙，脸上土，洗面皮惟泪雨，鬓蓬松除是冷风梳。',113,'元曲/yuanqu.json','["则我这头上风沙，脸上土，洗面皮惟泪雨，鬓蓬松除是冷风梳。", "他不去那巫山庙里寻神女，可教我在泾河岸上学苏武。", "这些时坐又不安，行又不舒，猛回头凝望着家何处，只落的一度一嗟吁。", "(云)我修的一封家书在此，怎得个便人寄去，可也好。", "(唱)。"]'),
('yuanqu-6523','洞庭湖柳毅传书・天下乐','尚仲贤','元','元曲','yuanqu','','[]','俺家在南天水国居。',52,'元曲/yuanqu.json','["俺家在南天水国居。", "就儿里非无尺素书，奈衡阳不传鸿雁羽，黄犬又筋力疲，锦鳞义，性格愚。", "儿遍家待相通常间阻。"]'),
('yuanqu-6524','洞庭湖柳毅传书・那吒令','尚仲贤','元','元曲','yuanqu','','[]','为一言半语，受千辛万苦。',66,'元曲/yuanqu.json','["为一言半语，受千辛万苦。", "受千辛万苦，想十亲九故。", "想十亲九故，在三江五湖。", "可怜我差迟了这夫妇情，错配了这姻缘簿，都则为俺那水性的儿夫。"]'),
('yuanqu-6525','洞庭湖柳毅传书・幺篇','尚仲贤','元','元曲','yuanqu','','[]','则俺那卫近沙浦有庙宇，到庙前将定金钗股，香案边击响金橙树，觑水中闪出金沙路，走将那巡海的夜叉来，敢背将你个寄信的先生去。',121,'元曲/yuanqu.json','["则俺那卫近沙浦有庙宇，到庙前将定金钗股，香案边击响金橙树，觑水中闪出金沙路，走将那巡海的夜叉来，敢背将你个寄信的先生去。", "(柳毅云)既如此，我与你做个传书使者。", "但你异日归于洞庭，是必休避我也。", "(正旦云)岂但不避，大恩人便是我亲戚一般哩。", "(唱)。"]'),
('yuanqu-6526','洞庭湖柳毅传书・赚煞','尚仲贤','元','元曲','yuanqu','','[]','俺为县么懒上凤凰台，羞对鸳鸯浦？则为那霹雳火无情的丈夫。',178,'元曲/yuanqu.json','["俺为县么懒上凤凰台，羞对鸳鸯浦？则为那霹雳火无情的丈夫。", "是则是海藏龙宫曾共逐，世不曾似水如鱼，谩踌躇。", "影只形孤。", "只我这泪点儿多如那落花雨，多谢你有心肠的足，可着我便乘龙归去。", "(做拜科)(唱)全在这寄双亲和泪一封书。", "(下)(柳毅云)知他是神是鬼，且将这书直至洞庭湖庙前走一遭去。", "(诗云)泾河岸偶遇三娘，诉离愁雨泪行行。", "如今去洞庭湖上．将此书寄与龙王。", "(下)。"]'),
('yuanqu-6527','洞庭湖柳毅传书・越调/斗鹌鹑','尚仲贤','元','元曲','yuanqu','','[]','他两个天北天南，海西海东，云闭云开，水淹水冲，烟罩烟飞，水烧火烘。',67,'元曲/yuanqu.json','["他两个天北天南，海西海东，云闭云开，水淹水冲，烟罩烟飞，水烧火烘。", "卒律律电影重，古突突雾气浓。", "起几个骨碌碌的轰雷，更一阵扑簌簌的怪风。"]'),
('yuanqu-6528','洞庭湖柳毅传书・紫花儿序','尚仲贤','元','元曲','yuanqu','','[]','险惊杀了负薪的樵子，慌杀了采药的仙童，吓杀了撒网的渔翁。',97,'元曲/yuanqu.json','["险惊杀了负薪的樵子，慌杀了采药的仙童，吓杀了撒网的渔翁。", "全不见红莲映日，翠盖迎风，遮笼，都是那鬼卒神兵四下攻。", "则俺这两只脚争些儿踏空，可擦擦堕落红尘。", "(带云)报报报喏。", "(唱)兀的不跌破了我青铜。"]'),
('yuanqu-6529','洞庭湖柳毅传书・紫花儿序','尚仲贤','元','元曲','yuanqu','','[]','忽的呵阴云伏地，淹的呵洪水滔天，腾的呵烈火飞空。',93,'元曲/yuanqu.json','["忽的呵阴云伏地，淹的呵洪水滔天，腾的呵烈火飞空。", "泾河龙逃归碧落，钱塘龙赶上亡苍穹。", "两条龙的威风，怕不唬杀了鳖大夫，龟将军，龟相公。", "这其间各赌神通，早翻过那海岛十洲，只待要拔倒了华岳三峰。"]'),
('yuanqu-6530','洞庭湖柳毅传书・鬼三台','尚仲贤','元','元曲','yuanqu','','[]','两条龙身躯纵，震的那乾坤动。',71,'元曲/yuanqu.json','["两条龙身躯纵，震的那乾坤动。", "恶哏哏健勇，赤焰焰满天红。", "一撞一冲，则教你心如铁石也怕恐，便有那铜山铁壁都没用。", "钱塘龙逆水忙截，泾河龙淤泥里便穴。"]'),
('yuanqu-6531','洞庭湖柳毅传书・秃厮儿','尚仲贤','元','元曲','yuanqu','','[]','恰是这三娘命通，更和那柳毅两下相逢。',40,'元曲/yuanqu.json','["恰是这三娘命通，更和那柳毅两下相逢。", "可是他从头至尾言始终，寄书到洞庭中也么龙宫。"]'),
('yuanqu-6532','洞庭湖柳毅传书・拙鲁速','尚仲贤','元','元曲','yuanqu','','[]','则咱这水卒有两三重，鬼兵有数百种，并没那半星儿放松，一谜里便冲。',63,'元曲/yuanqu.json','["则咱这水卒有两三重，鬼兵有数百种，并没那半星儿放松，一谜里便冲。", "无非是鱼鳖鼋鼍共随从，紧拦纵，阵面上交攻，将他来苦淹淹厮葬送。"]'),
('yuanqu-6533','洞庭湖柳毅传书・收尾','尚仲贤','元','元曲','yuanqu','','[]','则他走金蛇电影内将神威弄。',54,'元曲/yuanqu.json','["则他走金蛇电影内将神威弄。", "你觑那霸桥北泾河岸东，俺只见淹淹的血水泻做江湖，和着这滚滚的尸骸炼做丘冢。", "(下)。"]'),
('yuanqu-6534','洞庭湖柳毅传书・商调/集贤宾','尚仲贤','元','元曲','yuanqu','','[]','则俺那寄书来的秀才错立了身，怎能勾平步上青云。',110,'元曲/yuanqu.json','["则俺那寄书来的秀才错立了身，怎能勾平步上青云。", "则为他长安市不登虎榜，救的我泾河岸脱离羊群。", "他本望至公楼独占鳌头，今日向洞庭湖跳过了龙门。", "则我这重叠叠的眷姻可也堪自哂，若不成就燕尔新婚，我则待收拾些珍宝物，报答您的大恩人。"]'),
('yuanqu-6535','洞庭湖柳毅传书・金菊香','尚仲贤','元','元曲','yuanqu','','[]','则我这凌波袜小上阶痕，手提着沥水湘裙与你入殿门。',77,'元曲/yuanqu.json','["则我这凌波袜小上阶痕，手提着沥水湘裙与你入殿门。", "在这浑金椅前(做见二亲科，唱)参了二亲，那一场电走雷奔，(做见钱塘君科)(唱)驾风云的叔父你可也索是劳神。"]'),
('yuanqu-6536','洞庭湖柳毅传书・梧叶儿','尚仲贤','元','元曲','yuanqu','','[]','我这些掩着袂忙趋进，改愁颜做喜欣，(做拜谢科)(唱)施礼罢叙寒温。',66,'元曲/yuanqu.json','["我这些掩着袂忙趋进，改愁颜做喜欣，(做拜谢科)(唱)施礼罢叙寒温。", "你水路上风波恶，旱路上程限紧。", "似这等受辛勤，你索是远路风尘的故人。"]'),
('yuanqu-6537','洞庭湖柳毅传书・柳叶儿','尚仲贤','元','元曲','yuanqu','','[]','秀才也敢教你有家难奔，是是是熬不出寡宿孤辰。',56,'元曲/yuanqu.json','["秀才也敢教你有家难奔，是是是熬不出寡宿孤辰。", "谁着你自揽下四海三江闷，你端的心儿顺，意儿真，秀才也便休愁暮雨朝云。"]'),
('yuanqu-6538','洞庭湖柳毅传书・金菊香','尚仲贤','元','元曲','yuanqu','','[]','这的是钱塘破阵乐纷纷，半入湖风半入云，能得筵前几度闻。',75,'元曲/yuanqu.json','["这的是钱塘破阵乐纷纷，半入湖风半入云，能得筵前几度闻。", "(钱塘君云)秀才，你便就了这桩亲事，也不辱没了你。", "(正旦唱)还卖弄剑舌枪唇，兀的不羞杀你大媒人。"]'),
('yuanqu-6539','洞庭湖柳毅传书・浪里来煞','尚仲贤','元','元曲','yuanqu','','[]','这薄礼呵请先生休见阻，送行者宁无赆。',65,'元曲/yuanqu.json','["这薄礼呵请先生休见阻，送行者宁无赆。", "则为你假乖张不就我这门亲，害的来两下里憔悴损。", "我则索向龙宫纳闷，怎禁他水村山馆自黄昏。", "(下)。"]'),
('yuanqu-6540','洞庭湖柳毅传书・双调/新水令','尚仲贤','元','元曲','yuanqu','','[]','谁想并头莲情断藕丝长，搬调的俺趁波逐浪。',89,'元曲/yuanqu.json','["谁想并头莲情断藕丝长，搬调的俺趁波逐浪。", "正是相逢没话说。", "不见却思量。", "全不肯惜玉怜香，则他那占忄敞性尚然强。", "(内吹打科)(正旦云)这是甚么响。", "(媒云)这是成亲的鼓乐哩。", "(正旦唱)。"]'),
('yuanqu-6541','洞庭湖柳毅传书・驻马听','尚仲贤','元','元曲','yuanqu','','[]','高点起画烛荧煌，我则道为雨为云会洞房。',99,'元曲/yuanqu.json','["高点起画烛荧煌，我则道为雨为云会洞房。", "细听的仙音嘹亮，我几番的和愁和闷到华堂。", "离了那平胡十里芰荷香，谁想他禹门三月桃花浪。", "(带云)柳毅也，我想你怎生认的我来？(唱)情惨伤，则教你热心肠看不破这勾当。"]'),
('yuanqu-6542','洞庭湖柳毅传书・夜行舡','尚仲贤','元','元曲','yuanqu','','[]','他那里絮叨叨则管问行藏，咱两个相见在泾阳。',56,'元曲/yuanqu.json','["他那里絮叨叨则管问行藏，咱两个相见在泾阳。", "欲待对官人说个明降，又恐怕肉身人道我荒唐。", "不俊眼的襄王对面儿犹疑梦想。"]'),
('yuanqu-6543','洞庭湖柳毅传书・沽美酒','尚仲贤','元','元曲','yuanqu','','[]','我也曾做人奴去牧羊，多谢你寄音书与俺老爷娘，救的我避难逃灾还故乡。',49,'元曲/yuanqu.json','["我也曾做人奴去牧羊，多谢你寄音书与俺老爷娘，救的我避难逃灾还故乡。", "每日家眠思坐想，无明夜受忄西惶。"]'),
('yuanqu-6544','洞庭湖柳毅传书・太平令','尚仲贤','元','元曲','yuanqu','','[]','你怎不记泾河堤傍，(柳毅云)则你是谁？(正旦唱)我便是龙女三娘。',69,'元曲/yuanqu.json','["你怎不记泾河堤傍，(柳毅云)则你是谁？(正旦唱)我便是龙女三娘。", "不道我愁容苦相，也伴你牙床锦帐。", "今日个吉祥乐康，受享，呀，同归那龙宫海藏。"]'),
('yuanqu-6545','洞庭湖柳毅传书・雁儿落','尚仲贤','元','元曲','yuanqu','','[]','则为你恩人不敢忘，幸得我贱妾犹无恙，因此上冒卢家住范阳，特故的嫁柳氏来淮上。',38,'元曲/yuanqu.json','["则为你恩人不敢忘，幸得我贱妾犹无恙，因此上冒卢家住范阳，特故的嫁柳氏来淮上。"]'),
('yuanqu-6546','洞庭湖柳毅传书・得胜令','尚仲贤','元','元曲','yuanqu','','[]','呀，管教你共醉紫霞觞，并绾紫游缰。',131,'元曲/yuanqu.json','["呀，管教你共醉紫霞觞，并绾紫游缰。", "(柳毅云)你如今既到人间，怎生还去得你处？(正旦指天云)疾，柳官人你觑者。", "(唱)岂不见天际秋虹起，(带云)婆婆，请就登桥。", "(唱)少甚么蓝桥饮玉浆，(做扶母科)(唱)扶着你萱堂，但觉的两耳畔波涛响，早过了扶桑，猛闻的洞庭湖橘柚香。"]'),
('yuanqu-6547','洞庭湖柳毅传书・鸳鸯尾煞','尚仲贤','元','元曲','yuanqu','','[]','我向洞庭湖躲过愁风浪，才能勾绮罗从遇着呆张敞。',92,'元曲/yuanqu.json','["我向洞庭湖躲过愁风浪，才能勾绮罗从遇着呆张敞。", "则落的浪蘸蛟绡，云锁霓裳。", "昨日呵亏你那有信行的先生，今日呵稳做了无反覆的新郎。", "向画阁兰堂，描写在流苏帐。", "说不尽星斗文章，都裁做风流话儿讲。"]'),
('yuanqu-6548','黄钟・醉花阴北闺情','荆干臣','元','元曲','yuanqu','','[]','鸳鸯浦莲开并蒂长，桃源洞春光艳阳。',51,'元曲/yuanqu.json','["鸳鸯浦莲开并蒂长，桃源洞春光艳阳。", "花解语玉生香，月户云窗，忽被风飘荡。", "分莺燕，拆鸾凰，总是离人苦断肠。"]'),
('yuanqu-6549','画眉序南・虚度了好时光，枕剩衾余怎不凄凉！肠拴万结，泪滴千行。愁','荆干臣','元','元曲','yuanqu','','[]','戚戚恨在眉尖，意悬悬人来心上。',31,'元曲/yuanqu.json','["戚戚恨在眉尖，意悬悬人来心上。", "暗伤，何日同鸳帐，难捱地久天长。"]'),
('yuanqu-6550','喜迁莺北・自别来模样，瘦恹恹病在膏肓。难当，越添惆怅，恰便似柳絮','荆干臣','元','元曲','yuanqu','','[]','随风上下狂。',27,'元曲/yuanqu.json','["随风上下狂。", "心劳意攘，一会家情牵恨惹，一会家腹热肠荒。"]'),
('yuanqu-6551','画眉序南・欲待要不思量，若不思量都是谎！要相逢，除是梦里成双。冰','荆干臣','元','元曲','yuanqu','','[]','上人不许欢娱，月下老难为主张。',31,'元曲/yuanqu.json','["上人不许欢娱，月下老难为主张。", "暗伤，何日同鸳帐，难捱地久天长。"]'),
('yuanqu-6552','出队子北・心怀悒怏，无一时不盼望。尘蒙了锦瑟助凄凉，香尽了金炉空','荆干臣','元','元曲','yuanqu','','[]','念想，弦断了瑶琴魂荡羡。',12,'元曲/yuanqu.json','["念想，弦断了瑶琴魂荡羡。"]'),
('yuanqu-6553','神杖儿南・人离画堂，人离画堂；枕剩鸳鸯，钗分凤凰。想当初樽前席上','荆干臣','元','元曲','yuanqu','','[]','共双双，偎红倚翠，浅斟低唱。',28,'元曲/yuanqu.json','["共双双，偎红倚翠，浅斟低唱。", "歌金缕韵悠扬，依腔调按宫商。"]'),
('yuanqu-6554','刮地风北・当初啜赚我的言词都是谎，害的人倒枕垂床。鸾台上尘锁无心','荆干臣','元','元曲','yuanqu','','[]','傍，有似风狂。',69,'元曲/yuanqu.json','["傍，有似风狂。", "寂寞了绿窗朱幌，空闲了绣榻兰房。", "行时思坐时想甚时撇漾？你比那题桥的少一行，闪的我独自孤孀。", "望禹门三汲桃花浪，你为功名纸半张。"]'),
('yuanqu-6555','耍鲍老南・手抵着牙儿自思想，意踌踌魂荡漾，玉减香消怎不悲伤？几番','荆干臣','元','元曲','yuanqu','','[]','欲待不思量，医相思无药方。',13,'元曲/yuanqu.json','["欲待不思量，医相思无药方。"]'),
('yuanqu-6556','四门子北・玉容寂寞娇模样，饭不拈，茶不汤。一会家思，一会家想：你','荆干臣','元','元曲','yuanqu','','[]','莫不流落在帝京旅店上？一会家思，一会家想：你莫不名标在虎榜？。',31,'元曲/yuanqu.json','["莫不流落在帝京旅店上？一会家思，一会家想：你莫不名标在虎榜？。"]'),
('yuanqu-6557','闹樊楼南・锦被堆堆空闲了半床，怎揉我心上痒？越越添惆怅！共谁人相','荆干臣','元','元曲','yuanqu','','[]','傍？最难捱苦夜长。',9,'元曲/yuanqu.json','["傍？最难捱苦夜长。"]'),
('yuanqu-6559','中吕・醉春风','荆干臣','元','元曲','yuanqu','','[]','红袖霞飘彩，翠裙香散霭。',41,'元曲/yuanqu.json','["红袖霞飘彩，翠裙香散霭。", "都将窃玉偷香心，改、改、改。", "半夜星前，五更月下，九霄云外。"]'),
('yuanqu-6560','幺篇・旖旎金钗客，相莲花阵侧。难娱一笑拚千金，买、买、买。珊枕浓','荆干臣','元','元曲','yuanqu','','[]','欢，绮窗幽梦，锦堂深爱。',12,'元曲/yuanqu.json','["欢，绮窗幽梦，锦堂深爱。"]'),
('yuanqu-6561','喜春来・玉鞭杨柳春风陌，绣毂梨花夜月街，楚云湘雨梦阳台。休分处，','荆干臣','元','元曲','yuanqu','','[]','花柳暗尘埃。',6,'元曲/yuanqu.json','["花柳暗尘埃。"]'),
('yuanqu-6562','双鸳鸯・玉箫哀，立闲阶，彩凤人归更不来。隐隐遥山行云碍，萋萋芳草','荆干臣','元','元曲','yuanqu','','[]','远烟埋。',4,'元曲/yuanqu.json','["远烟埋。"]'),
('yuanqu-6563','喜春来・茶不茶饭不饭恹恹害，死不死活不活强强捱，相思何日得明白。','荆干臣','元','元曲','yuanqu','','[]','愁似海，烦恼早安排。',10,'元曲/yuanqu.json','["愁似海，烦恼早安排。"]'),
('yuanqu-6564','卖花声煞・俺疑他指不过走智儿猜，他只俺除将罢字儿揣，厮等待心肠各','荆干臣','元','元曲','yuanqu','','[]','宁奈。',19,'元曲/yuanqu.json','["宁奈。", "女貌郎才怎难摘？志诚心看谁去败。"]'),
('yuanqu-6565','双调・折桂令席上偶谈蜀汉事，因赋短柱体','虞集','元','元曲','yuanqu','','[]','鸾舆三顾茅庐，汉祚难扶，日暮桑榆。',66,'元曲/yuanqu.json','["鸾舆三顾茅庐，汉祚难扶，日暮桑榆。", "深渡南泸，长驱西蜀，力拒东吴。", "美乎周瑜妙术，悲夫关羽云殂。", "天数盈虚，造物乘除。", "问汝何如，早赋归欤。"]'),
('yuanqu-6566','西华山陈抟高卧・混江龙','马致远','元','元曲','yuanqu','','[]','开坛讲命，六爻搜尽鬼神惊。',91,'元曲/yuanqu.json','["开坛讲命，六爻搜尽鬼神惊。", "传圣人清高道业，指君子暗昧前程。", "袍袖拂开八卦图，掌中躔度一天星。", "也不论冠婚宅葬，也不论出入经营，但有那辨荣枯问吉凶，买卦的心尊敬，我也则全凭圣典，不顺人情。"]'),
('yuanqu-6567','西华山陈抟高卧・油葫芦','马致远','元','元曲','yuanqu','','[]','古圣传留周易经，有几人能穷究的精？诵读如坐井，不能明。',160,'元曲/yuanqu.json','["古圣传留周易经，有几人能穷究的精？诵读如坐井，不能明。", "(带云)这易呵，(唱)伏羲以上无人定，仲尼之下无人省。", "俺下的数又真，传的课又灵。", "待要避凶趋吉知天命，试来帘下问君平。", "(赵云)兄弟，好个先生也！(郑恩云)哥哥怎见的？(赵云)中消数言之间，包罗古今上下，参透阴阳表里。", "(郑恩云)是好先生也！咱再听他说一会者。", "(正末唱)。"]'),
('yuanqu-6568','西华山陈抟高卧・天下乐','马致远','元','元曲','yuanqu','','[]','凭着八字从头断一生，叮咛、不教差半星。',52,'元曲/yuanqu.json','["凭着八字从头断一生，叮咛、不教差半星。", "论旺气，相死囚，凭五行。", "似这般暗夺鬼神机，豫知天地情，堪教高士听。"]'),
('yuanqu-6569','西华山陈抟高卧・后庭花','马致远','元','元曲','yuanqu','','[]','这命干是丙丁戊己庚，乾元亨利贞。',85,'元曲/yuanqu.json','["这命干是丙丁戊己庚，乾元亨利贞。", "正是一字连珠格，三重坐禄星。", "你休道俺不着情，不应后我敢罚银十锭，未酬劳先早陪了几瓶。", "(赵云)先生向后推一推，看我流年大运如何？(正末唱)。"]'),
('yuanqu-6570','西华山陈抟高卧・金盏儿','马致远','元','元曲','yuanqu','','[]','到这戌字上呵，水形成火长生，避垂龙大小运今年并：后交的丙辰一运大峥嵘。',67,'元曲/yuanqu.json','["到这戌字上呵，水形成火长生，避垂龙大小运今年并：后交的丙辰一运大峥嵘。", "日犯空亡为将相，时逢禄马作公卿。", "你是南方赤帝子，上应北极紫微星。"]'),
('yuanqu-6571','西华山陈抟高卧・金盏儿','马致远','元','元曲','yuanqu','','[]','左关陕，右徐青，背怀孟，附襄荆；用兵的形势连着唐、邓，太行天险壮神京。',67,'元曲/yuanqu.json','["左关陕，右徐青，背怀孟，附襄荆；用兵的形势连着唐、邓，太行天险壮神京。", "江山埋旺气，草木助威灵。", "欲寻那四百年兴龙地，除是这八十里卧牛城。"]'),
('yuanqu-6572','西华山陈抟高卧・醉中天','马致远','元','元曲','yuanqu','','[]','你是五霸诸侯命，一品大臣名，干打哄胡厮哝过了半生。',90,'元曲/yuanqu.json','["你是五霸诸侯命，一品大臣名，干打哄胡厮哝过了半生。", "(郑恩云)你说我是个五霸诸侯，我如何瞎了一目？(正末唱)注定你不带破多残病，命中有、愁甚眼睛？兀那明郎群星虽盛，怎如的孤月偏明！。"]'),
('yuanqu-6573','西华山陈抟高卧・金盏儿','马致远','元','元曲','yuanqu','','[]','投至我石枕上梦魂清，布袍底白云生。',78,'元曲/yuanqu.json','["投至我石枕上梦魂清，布袍底白云生。", "但睡呵，一年半载没干净，则看您朝台暮省干功名。", "我睡呵，黑甜甜倒身如酒醉，忽喽喽酣睡似雷鸣；谁理会的五更朝马动，三唱晓鸡声。"]'),
('yuanqu-6574','西华山陈抟高卧・赚煞','马致远','元','元曲','yuanqu','','[]','治世圣人生，指日乾坤定。',142,'元曲/yuanqu.json','["治世圣人生，指日乾坤定。", "(赵云)天下果有平定之时，那时节拜请先生下山，共享太平之福。", "(正末唱)何须把山野陈抟拜请。", "(指郑科，唱)若久后休忘了这青眼相看旧弟兄，不索重酬劳卖卦先生。", "从今后罢刀兵，四海澄清，且放闲人看太平。", "我又不似出师的孔明、休官的陶令，则待学那钓鱼台下老严陵。", "(并下)。"]'),
('yuanqu-6575','西华山陈抟高卧・南吕/一枝花','马致远','元','元曲','yuanqu','','[]','我往常读书求进身，学剑随时混；文能匡社稷，武可定乾坤。',62,'元曲/yuanqu.json','["我往常读书求进身，学剑随时混；文能匡社稷，武可定乾坤。", "豪气凌云，似莘野商伊尹，佐成汤救万民；扫荡了海内烽尘，早扶策沟中愁困。"]'),
('yuanqu-6576','西华山陈抟高卧・梁州第七','马致远','元','元曲','yuanqu','','[]','从逢着那买卦的潜龙帝王，饶了个算命的开国功臣，便即时拂袖归山隐。',158,'元曲/yuanqu.json','["从逢着那买卦的潜龙帝王，饶了个算命的开国功臣，便即时拂袖归山隐。", "全不管人间甲子，单则守洞里庚申。", "降伏尽婴儿姹女，将炼成丹汞黄银。", "思飘飘出世离群，乐陶陶礼圣参真。", "想他那乱扰扰红尘内争利的愚人，更和那闹攘攘黄阁上为官的贵人，争如这闲摇摇华山中得道的仙人。", "一身驾云，九垓八表神游尽，觑浮世暗中哂。", "坐看蟠桃几度春，岁月常新。"]'),
('yuanqu-6577','西华山陈抟高卧・隔尾','马致远','元','元曲','yuanqu','','[]','则与这高山流水同风韵，抵多少野草闲花作近邻，满地白云扫不尽。',55,'元曲/yuanqu.json','["则与这高山流水同风韵，抵多少野草闲花作近邻，满地白云扫不尽。", "你与我紧关上洞门，休放个客人，我待静倚蒲团自在盹。"]'),
('yuanqu-6578','西华山陈抟高卧・牧羊关','马致远','元','元曲','yuanqu','','[]','我恰才游仙阙，谒帝阍，惊的我跨黄鹤飞下天门。',70,'元曲/yuanqu.json','["我恰才游仙阙，谒帝阍，惊的我跨黄鹤飞下天门。", "为甚的玉节忙持，金钟煞紧？又不是红窗明觉晓，布被暖和春。", "惊的那梦庄周蝶飞去，尚古自炊黄粱锅未滚。"]'),
('yuanqu-6579','西华山陈抟高卧・菩萨梁州','马致远','元','元曲','yuanqu','','[]','特遣天臣，把贤良访问；当今至尊，重酬劳卖卦山人。',77,'元曲/yuanqu.json','["特遣天臣，把贤良访问；当今至尊，重酬劳卖卦山人。", "虽然是前言不忘是君恩，争奈我烟霞不忆风雷信，琴鹤自有林泉分。", "想名利有时尽，乞的田园自在身，我怎肯再入红尘。"]'),
('yuanqu-6580','西华山陈抟高卧・隔尾','马致远','元','元曲','yuanqu','','[]','俺只待下棋白日闲消困，高枕清风睡杀人。',46,'元曲/yuanqu.json','["俺只待下棋白日闲消困，高枕清风睡杀人。", "世事无由恼方寸，则除你个继恩使臣，方便向君王行奏得准。"]'),
('yuanqu-6581','西华山陈抟高卧・牧羊关','马致远','元','元曲','yuanqu','','[]','既然海岳归明主，敢放巢由作外臣，怎望您吊千年高冢麒麟。',69,'元曲/yuanqu.json','["既然海岳归明主，敢放巢由作外臣，怎望您吊千年高冢麒麟。", "谁待要老去攀龙，则不如闲来卧云。", "试看蓬莱寻药客，商岭采芝人；天下已归汉，山中犹避秦。"]'),
('yuanqu-6582','西华山陈抟高卧・贺新郎','马致远','元','元曲','yuanqu','','[]','我往常鸡鸣舞剑学刘琨，看三卷天书，演八门五遁。',100,'元曲/yuanqu.json','["我往常鸡鸣舞剑学刘琨，看三卷天书，演八门五遁。", "我也曾遍游诸国占时运，则为卖卦处逢着圣君，以此的入山来专意修真。", "看猿鹤知导引，观山水爽精神，大都来性于远、习于近。", "则这黄冠野服一道士，伴着清风明月两闲人。"]'),
('yuanqu-6583','西华山陈抟高卧・牧羊关','马致远','元','元曲','yuanqu','','[]','则你这一身拜将悬金印，万里封侯守玉门；现如今际明良千载风云，怎学的河上仙翁、关门令尹？可不道朝中随圣主，却甚的林下访闲人。',80,'元曲/yuanqu.json','["则你这一身拜将悬金印，万里封侯守玉门；现如今际明良千载风云，怎学的河上仙翁、关门令尹？可不道朝中随圣主，却甚的林下访闲人。", "既受了雨露九天恩，怎还想云霞三市隐？。"]'),
('yuanqu-6584','西华山陈抟高卧・哭皇天','马致远','元','元曲','yuanqu','','[]','酒醉汉难朝觐，睡魔王怎做的宰臣？穿着这紫罗袍似酒布袋，执着这白象笏似睡馄饨。',76,'元曲/yuanqu.json','["酒醉汉难朝觐，睡魔王怎做的宰臣？穿着这紫罗袍似酒布袋，执着这白象笏似睡馄饨。", "若做官后每日价行眠立盹，休休休枉笑杀凌烟阁上人。", "有这般疏庸愚钝，孤陋寡闻？。"]'),
('yuanqu-6585','西华山陈抟高卧・乌夜啼','马致远','元','元曲','yuanqu','','[]','幸然法正天心顺，索甚我横枝儿治国安民？我则有住山缘，那里有为官分。',97,'元曲/yuanqu.json','["幸然法正天心顺，索甚我横枝儿治国安民？我则有住山缘，那里有为官分。", "乐道安贫，谁羡画戟朱门？丹砂好炼养闲身，黄金不铸封侯印。", "我其实戴不的幞头紧，穿不的朝衣坌。", "倒不如我这拂黄尘的布袍，洒浑酒的纶巾。"]'),
('yuanqu-6586','西华山陈抟高卧・正宫/端正好','马致远','元','元曲','yuanqu','','[]','下云台，来朝会，不听的华山里鹤唳猿啼。',36,'元曲/yuanqu.json','["下云台，来朝会，不听的华山里鹤唳猿啼。", "道人非为苍生起，只是报圣主招贤意。"]'),
('yuanqu-6587','西华山陈抟高卧・滚绣球','马致远','元','元曲','yuanqu','','[]','俺便是那闲云自在飞，心情与世违。',120,'元曲/yuanqu.json','["俺便是那闲云自在飞，心情与世违。", "可又不贪名利，怎生来教天子闻知？是未发迹，卦铺里，那时节相识，曾算是他南面登基。", "(使臣上，云)陈先生恭喜，官里赐来衣冠道号，望阙谢恩。", "(正末拜谢科，唱)因此上将龙庭御宝皇宣诏，赐与我鹤氅金冠碧玉圭，道号希夷。"]'),
('yuanqu-6588','西华山陈抟高卧・倘秀才','马致远','元','元曲','yuanqu','','[]','俺那里草舍花栏药畦，石洞松窗竹几；您这里玉殿朱楼未为贵。',53,'元曲/yuanqu.json','["俺那里草舍花栏药畦，石洞松窗竹几；您这里玉殿朱楼未为贵。", "您那人间千古事，俺只松下一盘棋，把富贵做浮云可比。"]'),
('yuanqu-6589','西华山陈抟高卧・倘秀才','马致远','元','元曲','yuanqu','','[]','无那舞蹈扬尘体例，只打个稽首权充拜礼。',89,'元曲/yuanqu.json','["无那舞蹈扬尘体例，只打个稽首权充拜礼。", "(驾云)故人别来无恙？今蒙不弃，喜慰平生，就在殿廷赐坐，好叙闲阔。", "(正末唱)愿陛下圣寿齐天万万岁。", "如今黄阁功臣少，白发故人稀，见贫道且自喜。"]'),
('yuanqu-6590','西华山陈抟高卧・叨叨令','马致远','元','元曲','yuanqu','','[]','向那华山中已觅终焉计，怎生都堂内才看旁州例。',72,'元曲/yuanqu.json','["向那华山中已觅终焉计，怎生都堂内才看旁州例。", "议公事枉损了元阳气，理朝纲怕搅了安眠睡。", "贫道做不的官也么哥，做不的官也么哥！不要紫罗袍，只乞黄绸被。"]'),
('yuanqu-6591','西华山陈抟高卧・倘秀才','马致远','元','元曲','yuanqu','','[]','我但睡呵，十万根更筹转刻，七八瓮铜壶漏水，恨不的生扭死窗前报晓鸡。',54,'元曲/yuanqu.json','["我但睡呵，十万根更筹转刻，七八瓮铜壶漏水，恨不的生扭死窗前报晓鸡。", "休想我惜花春早起，爱月夜眠迟，这般的道理。"]'),
('yuanqu-6592','西华山陈抟高卧・倘秀才','马致远','元','元曲','yuanqu','','[]','陛下道君子周而不比，贫道呵小人穷斯滥矣。',108,'元曲/yuanqu.json','["陛下道君子周而不比，贫道呵小人穷斯滥矣。", "俺须索志于道、依于仁、据于德，本待用贤退不肖，怎倒做举枉错诸直，更是不宜。", "(驾云)先生休要推辞。", "似这朝中为官，却不强如山中学道也？(正末云)这为官的好处，贫道也尽知了。", "(唱)。"]'),
('yuanqu-6593','西华山陈抟高卧・倘秀才','马致远','元','元曲','yuanqu','','[]','道有个治家治国，索分个为人为己，不患人之不己知。',42,'元曲/yuanqu.json','["道有个治家治国，索分个为人为己，不患人之不己知。", "石床绵被暖，瓦钵菜羹肥，是山人乐矣。"]'),
('yuanqu-6594','西华山陈抟高卧・三煞','马致远','元','元曲','yuanqu','','[]','身安静宇蝉初蜕，梦绕南华蝶正飞。',73,'元曲/yuanqu.json','["身安静宇蝉初蜕，梦绕南华蝶正飞。", "卧一榻清风，看一轮明月，盖一片白云，枕一块顽石。", "直睡的陵迁谷变，石烂松枯，斗转星移。", "长则是抱元守一，穷妙理造玄机。"]'),
('yuanqu-6595','西华山陈抟高卧・煞尾','马致远','元','元曲','yuanqu','','[]','俺那里云间太华烟霞细，鼎内还丹日月迟；山上高眠梦寐稀，殿下朝元剑佩齐；玉阙仙阶我曾履，王母蟠桃我曾吃，欲醉不醉酒数杯，上天下天鹤一只；有客相逢问浮世，无事登临叹',200,'元曲/yuanqu.json','["俺那里云间太华烟霞细，鼎内还丹日月迟；山上高眠梦寐稀，殿下朝元剑佩齐；玉阙仙阶我曾履，王母蟠桃我曾吃，欲醉不醉酒数杯，上天下天鹤一只；有客相逢问浮世，无事登临叹落辉；危坐谈玄讲《道德》，静室焚香诵《秋水》；滴露研朱点《周易》，散诞逍遥不拘系。", "赴召离山到朝里，央及陈抟受宣敕。", "送上都堂入八位，掌管台衡总百揆。", "御史台纲索省会，六部当该各详细；攘攘垓垓不伶俐，是是非非无尽期。", "好教我战战兢兢睡不美。", "(下)。"]'),
('yuanqu-6596','西华山陈抟高卧・双调/新水令','马致远','元','元曲','yuanqu','','[]','半生不识晓来霜，把五更寒打在老夫头上。',91,'元曲/yuanqu.json','["半生不识晓来霜，把五更寒打在老夫头上。", "笑他满朝朱紫贵，怎知我一枕黑甜乡。", "揭起那翠巍巍太华山光，这一幅绣帏帐。", "(色旦上，待直，云)妾等官里送来，与先生作传奉，愿奉枕席之欢。", "(正末唱)。"]'),
('yuanqu-6597','西华山陈抟高卧・驻马听','马致远','元','元曲','yuanqu','','[]','白酒樽旁，闲慰眼金钗十二行；误了我清风岭上，不翻身恶睡一千场。',69,'元曲/yuanqu.json','["白酒樽旁，闲慰眼金钗十二行；误了我清风岭上，不翻身恶睡一千场。", "您则待泛桃花到处觅刘郎，我委实画蛾眉不会学张敞。", "没好酌量，出家儿怎受闲魔障。"]'),
('yuanqu-6598','西华山陈抟高卧・步步娇','马致远','元','元曲','yuanqu','','[]','遮莫胡厮缠到晨钟撞，休想我一点狂心荡。',79,'元曲/yuanqu.json','["遮莫胡厮缠到晨钟撞，休想我一点狂心荡。", "(色旦云)你来，我与你有句话说。", "(正末唱)唤陈抟有甚勾当？命不快遭烽着这火醉婆娘，干误了我晚夕参圣一炉香，半夜里观乾象。"]'),
('yuanqu-6599','西华山陈抟高卧・沉醉东风','马致远','元','元曲','yuanqu','','[]','这茶呵采的是一旗半枪，来从五岭三湘。',117,'元曲/yuanqu.json','["这茶呵采的是一旗半枪，来从五岭三湘。", "泛一瓯瑞雪香，生两腋松风响，润不得七碗枯肠。", "辜负一醉无忧老杜康，谁信您卢仝健忘。", "(云)您每各自安置，我待睡也。", "(做睡，色旦扯末科，云)俺每都陪先生，怎敢舍的先生孤孤忄西忄西、凄凄冷冷的。", "(正末唱)。"]'),
('yuanqu-6600','西华山陈抟高卧・搅筝琵','马致远','元','元曲','yuanqu','','[]','你好是轻薄相，我又不寂寞恨更长。',69,'元曲/yuanqu.json','["你好是轻薄相，我又不寂寞恨更长。", "干把那蝶梦惊回，多管葫芦提害痒。", "早则是卧破月昏黄，直睡到日出扶桑。", "慌忙，猛听得净鞭三下响，又待要颠倒衣裳。"]'),
('yuanqu-6601','西华山陈抟高卧・川拨棹','马致远','元','元曲','yuanqu','','[]','恰离高唐，躲巫娥一壁厢。',52,'元曲/yuanqu.json','["恰离高唐，躲巫娥一壁厢。", "客舍凄凉，仙梦悠扬；只想着邯郸道上，原来在佳人锦瑟旁。", "(色旦劝酒科)(正末唱)。"]'),
('yuanqu-6602','西华山陈抟高卧・七兄弟','马致远','元','元曲','yuanqu','','[]','这场厮央，不相当。',41,'元曲/yuanqu.json','["这场厮央，不相当。", "你便有粉白黛绿装宫样，茜裙罗袜缕金裳，则我这铁卧单有甚风流况？。"]'),
('yuanqu-6603','西华山陈抟高卧・梅茶酒','马致远','元','元曲','yuanqu','','[]','你可也忒莽撞，则道你燮理阴阳，却惜玉怜香。',52,'元曲/yuanqu.json','["你可也忒莽撞，则道你燮理阴阳，却惜玉怜香。", "撮合山错了眼光，就儿里我也仓皇。", "你休使着这智量，俺乐处是天堂。"]'),
('yuanqu-6604','西华山陈抟高卧・收江南','马致远','元','元曲','yuanqu','','[]','呀，你敢硬将咱送上云雨场，则待高烧银烛照红妆。',54,'元曲/yuanqu.json','["呀，你敢硬将咱送上云雨场，则待高烧银烛照红妆。", "出家儿心地本清凉，怎禁得直恁般闹攘！便是一千年不见，也不思量。"]'),
('yuanqu-6605','西华山陈抟高卧・水仙子','马致远','元','元曲','yuanqu','','[]','我恰才神游八表放金光，礼拜三清朝玉皇。',78,'元曲/yuanqu.json','["我恰才神游八表放金光，礼拜三清朝玉皇。", "不争你拽双环呀的门关上，缠杀我也瞎大王，惊的那下三山鹤梦翱翔。", "俺只待丹鼎内降龙虎，谁教咱锦巢边宿凤凰，枉羞杀金殿鸳鸯。"]'),
('yuanqu-6606','西华山陈抟高卧・太平令','马致远','元','元曲','yuanqu','','[]','现如今山鬼只打显象，野猿抢笔题墙。',56,'元曲/yuanqu.json','["现如今山鬼只打显象，野猿抢笔题墙。", "怕腐烂了芒鞋竹杖，尘没了蒲团纸帐。", "纵有那女娘、艳妆、洞房，早盹睡了都堂里宰相。"]'),
('yuanqu-6607','西华山陈抟高卧・离亭宴带歇指煞','马致远','元','元曲','yuanqu','','[]','把投林高鸟西风里放，也强如衔茶野兔深宫里养。',143,'元曲/yuanqu.json','["把投林高鸟西风里放，也强如衔茶野兔深宫里养。", "你待要加官赐赏，教俺头顶紫金冠，手执碧玉简，身着白鹤氅。", "昔年旧草庵，今日新方丈。", "贫道呵，除睡外别无伎俩。", "本不是贪名利世间人，则一个乐琴书林下客，绝宠辱山中相。", "推开名利关，摘脱英雄网，高打起南山吊窗。", "常则是烟雨外种莲花，云台上看仙掌。", "(并下)。"]'),
('yuanqu-6608','折桂令・问苏卿','王晔','元','元曲','yuanqu','','[]','俏排场惯战曾经，自古惺惺，爱惜惺惺。',136,'元曲/yuanqu.json','["俏排场惯战曾经，自古惺惺，爱惜惺惺。", "燕友莺朋，花阴柳影，海誓山盟。", "哪一个坚心志诚？哪一个薄幸杂情？则问苏卿，是爱冯魁，是爱双生？答平生恨落风尘，虚度年化，减尽精神。", "月枕云窗，锦衾绣褥，柳户花门。", "一个将百十引江茶问肯，一个将数十联诗句求亲。", "心事纷纭：待嫁了茶商，怕误了诗人。"]'),
('yuanqu-6609','水仙子・','王晔','元','元曲','yuanqu','','[]','驳明明的退佃丽春园，暗暗的开除了双解元。',127,'元曲/yuanqu.json','["驳明明的退佃丽春园，暗暗的开除了双解元。", "惨可可说下神仙愿，却原来都是骗。", "再谁听甜句儿留连。", "同他行坐，和他过遣，怎做的误走上茶船。", "招书生俊俏却无钱，茶客村虔倒有缘。", "孔方兄教得俺心窑变，胡芦提过遣，如今是走上茶船。", "拜辞了呆黄肇，上复那双解元，休怪俺不赴临川。"]'),
('yuanqu-6610','折桂令・问双渐','王晔','元','元曲','yuanqu','','[]','小苏卿窑变了心肠，改抹了姻缘，倒换排场。',67,'元曲/yuanqu.json','["小苏卿窑变了心肠，改抹了姻缘，倒换排场。", "强拆鸳鸯，轻分莺燕，失配鸾凰。", "实丕丕兜笼富商，虚飘飘蹬脱了才郎。", "你试思量，不害相思，也受凄凉。"]'),
('yuanqu-6611','水仙子・答','王晔','元','元曲','yuanqu','','[]','阳台云雨暂教晴，金斗风波且慢行。',63,'元曲/yuanqu.json','["阳台云雨暂教晴，金斗风波且慢行。", "小苏卿是接了冯魁定，俏书生便噤声。", "没来由闲战闲争，非干是咱薄幸。", "既然是他浅情，我著甚干害心疼。"]'),
('yuanqu-6612','水仙子・答','王晔','元','元曲','yuanqu','','[]','风流双渐惯轮铡，澜浪苏卿能跳塔。',63,'元曲/yuanqu.json','["风流双渐惯轮铡，澜浪苏卿能跳塔。", "小机关背地里商量下，把俺做皮灯笼看待咱，从来道水性难拿。", "从他走过，由他演撒，终只是个路柳墙花。"]'),
('yuanqu-6613','折桂令・问苏妈妈','王晔','元','元曲','yuanqu','','[]','苏婆婆常只是熬煎，临逼得孩儿，一谜地胡扇。',67,'元曲/yuanqu.json','["苏婆婆常只是熬煎，临逼得孩儿，一谜地胡扇。", "使会虚脾，著些甜唾，引起顽涎。", "用力的从教气喘，著昏的一任头旋。", "只为贪钱，将个婵娟，卖上茶船。"]'),
('yuanqu-6614','双调・新水令闺情','王晔','元','元曲','yuanqu','','[]','梨花夜雨未开门，日迟迟绿窗人困。',40,'元曲/yuanqu.json','["梨花夜雨未开门，日迟迟绿窗人困。", "镜缄鸾未起，香尽鸭犹温。", "半晌抬身，舒玉笋整婵鬓。"]'),
('yuanqu-6615','驻马听・春意犹昏，杨柳青牵绵正滚；香腮微印，海棠横界线留痕。目前','王晔','元','元曲','yuanqu','','[]','春暖物华新，意中人远天涯近。',26,'元曲/yuanqu.json','["春暖物华新，意中人远天涯近。", "怨未伸，枝头春色三色褪。"]'),
('yuanqu-6617','雁儿落・齐臻臻光消宝髻云，宽绰绰瘦掩罗衫衤肯。碧幽幽天高少雁书，','王晔','元','元曲','yuanqu','','[]','绿湛湛水阔无鱼信。',9,'元曲/yuanqu.json','["绿湛湛水阔无鱼信。"]'),
('yuanqu-6618','得胜令・愁戚戚萧索对清晨，情默默冷落坐黄昏。悄促促翠掩合欢帐，湿','王晔','元','元曲','yuanqu','','[]','津津红绡拭泪巾。',38,'元曲/yuanqu.json','["津津红绡拭泪巾。", "清黯黯销魂，烟淡淡草际遥天尽。", "昏惨惨伤神，夜迢迢花残过雨频。"]'),
('yuanqu-6619','沽美酒・江分平绿草茵，门半掩翠苔痕。悄悄闲庭不见人，无语自晒，空','王晔','元','元曲','yuanqu','','[]','目断定楚台云。',7,'元曲/yuanqu.json','["目断定楚台云。"]'),
('yuanqu-6620','太平令・怪则怪鸾凰生分，恼则恼莺燕争春。恨则恨心中有刃，悔则悔言','王晔','元','元曲','yuanqu','','[]','而无信。',21,'元曲/yuanqu.json','["而无信。", "想这厮背恩，负恩，说着后一言难尽。"]'),
('yuanqu-6621','水仙子・气吁鸾影宝奁昏，愁蹙蛾眉翠黛颦。情随雁足青霄近，倚朱扉欲','王晔','元','元曲','yuanqu','','[]','断魂。',35,'元曲/yuanqu.json','["断魂。", "能消得几个青春？恰透风光一阵。", "春来度尽花容数本，春先去人瘦三分。"]'),
('yuanqu-6622','折桂令・春先去人瘦三分。妆减了半面风流，衣松了一捻精神。步红尘愁','王晔','元','元曲','yuanqu','','[]','践红芳，上绣榻怕拈绣贴，倚朱扉愁盼朱轮。',56,'元曲/yuanqu.json','["践红芳，上绣榻怕拈绣贴，倚朱扉愁盼朱轮。", "海棠困琴闲玉轸，石榴皱睡损罗裙。", "愁思昏昏，人事纷纷；眼底卿卿，心上人人。"]'),
('yuanqu-6623','尾声・来明跪膝儿在床前问，将那厮谎舌头裙刀儿碎刎。先将他抛闪去的','王晔','元','元曲','yuanqu','','[]','罪名儿一件件招，后把受用过凄凉一星星证了本。',22,'元曲/yuanqu.json','["罪名儿一件件招，后把受用过凄凉一星星证了本。"]'),
('yuanqu-6624','萧淑兰情寄菩萨蛮・混江龙','贾仲明','元','元曲','yuanqu','','[]','晓来情厌，收拾心事上眉尖。',58,'元曲/yuanqu.json','["晓来情厌，收拾心事上眉尖。", "把金钱暗卜，龟卦时占。", "杏脸胭消娇淡淡，柳腰香褪弱纤纤。", "料应也是前生欠，因无兄嫂，有失拘钤。"]'),
('yuanqu-6625','萧淑兰情寄菩萨蛮・鹊踏枝','贾仲明','元','元曲','yuanqu','','[]','则见他气炎炎，那里也笑掀髯。',43,'元曲/yuanqu.json','["则见他气炎炎，那里也笑掀髯。", "显出些外貌威严，内性清廉。", "他避我遮遮掩掩，抵多少等等潜潜。"]'),
('yuanqu-6626','萧淑兰情寄菩萨蛮・后庭花','贾仲明','元','元曲','yuanqu','','[]','你道女孩儿家休弄险，你读书人不会谄。',104,'元曲/yuanqu.json','["你道女孩儿家休弄险，你读书人不会谄。", "为非事无行上，见家兄有甚脸。", "不索你话儿口店。", "你须恶厌，不由我腮斗儿上添笑靥。", "(张世英云)休道是兄嫂知道，则那奶母梅香知呵，早晚说与令兄，如何臆得？可不你我何安？(正旦唱)。"]'),
('yuanqu-6627','萧淑兰情寄菩萨蛮・赚煞','贾仲明','元','元曲','yuanqu','','[]','秀才每难托志诚心，好吃开荒剑，一条担两下里脱尖。',104,'元曲/yuanqu.json','["秀才每难托志诚心，好吃开荒剑，一条担两下里脱尖。", "有多少胡讲歪谈信口口店，乔文物拘耻拘廉。", "我看你瘦恹恹眼札眉苫，多敢是家菜不甜野菜甜。", "你也消不得俺娇滴滴桃腮杏脸，香馥馥玉温花艳，则好去破窑中风雪断齑盐。", "(下)。"]'),
('yuanqu-6628','萧淑兰情寄菩萨蛮・越调/耍三台','贾仲明','元','元曲','yuanqu','','[]','姐姐命亲分付，为张秀才丁宁使俺。',70,'元曲/yuanqu.json','["姐姐命亲分付，为张秀才丁宁使俺。", "您稳放着个先忧后喜，我空怀着个有苦无甘。", "烦恼这场非是揽，恶风声委实心惨。", "则为他粉悴胭憔，端的是香消也那玉减。"]'),
('yuanqu-6629','萧淑兰情寄菩萨蛮・紫花儿序','贾仲明','元','元曲','yuanqu','','[]','姐姐怕不心劳意攘，哥哥又不性躁情乖，嫂嫂可要坐守行监。',67,'元曲/yuanqu.json','["姐姐怕不心劳意攘，哥哥又不性躁情乖，嫂嫂可要坐守行监。", "他如今看看衣褪，渐渐裙搀，春衫双袖漫漫将泪揞。", "不明不暗，几时配上金钗，接上琼簪。"]'),
('yuanqu-6630','萧淑兰情寄菩萨蛮・小桃红','贾仲明','元','元曲','yuanqu','','[]','你九经三史煞曾谙，习典故观《通鉴》。',187,'元曲/yuanqu.json','["你九经三史煞曾谙，习典故观《通鉴》。", "课赋吟涛有风范，更非凡，临帖写字知个浓淡。", "把今古博览，将前人比勘，那一事不详参？(云)先生九经皆通，无书不读，岂不晓三纲五常之理？圣人言：\"男子三十而娶。", "\"又云：\"不孝有三，无后为大。", "\"何不求一门亲事，老身当为月老，聘结良姻。", "先生尊意如何？(张世英云)嬷嬷言之甚善。", "但小生在此处馆，惟知守严父之训，读圣人之书，岂有求亲之念哉？(嬷嬷唱)。"]'),
('yuanqu-6631','萧淑兰情寄菩萨蛮・鬼三台','贾仲明','元','元曲','yuanqu','','[]','我着些言语来探，将他来赚，他那里急截舌紧搀。',271,'元曲/yuanqu.json','["我着些言语来探，将他来赚，他那里急截舌紧搀。", "秀才每自古眼睛馋，不似这生忒铜心铁胆。", "哎，你个颜叔子秉烛真个堪，柳下惠开怀没店三。", "酸溜溜《鲁论》《齐论》，醋滴滴《周南》《召南》。", "(背云)将这词与他，这生必然动念也。", "(做递词科，云)小姐有词一章，望先生改削。", "(张世英接着读科，云)君心情远迷蓬岛，妾心命薄连芳草。", "芳草正凄凄，君心知不知？妾身轻似叶，君意坚如铁。", "妾意为君多，君心弃妾何。", "右词寄〔菩萨蛮〕，不才妾淑兰谨奉文郎云杰吟几电览是幸，就请回音。", "再拜。", "(张世英云)嬷嬷，你乃萧公管家老者，萧公共汝一家无外，怎生持此淫词戏我？是何道理？(嬷嬷唱)。"]'),
('yuanqu-6632','萧淑兰情寄菩萨蛮・调笑令','贾仲明','元','元曲','yuanqu','','[]','说的我面惨，转羞惭，你因甚，相通这书一缄？莫怪我等闲特故来摇撼，赤紧的张横渠不肯贪婪。',112,'元曲/yuanqu.json','["说的我面惨，转羞惭，你因甚，相通这书一缄？莫怪我等闲特故来摇撼，赤紧的张横渠不肯贪婪。", "只待要坐取公侯伯子男，气昂昂阔论高谈。", "(张世英云)昨朝行之，今日如此，似此小生当告辞，有何面目立于萧公之门，耻见天下士大夫也！(嬷嬷唱)。"]'),
('yuanqu-6633','萧淑兰情寄菩萨蛮・秃厮儿','贾仲明','元','元曲','yuanqu','','[]','俺那崔氏女正红愁绿惨，你个张君瑞待面北眉南，着我老红娘将两下里做一担扭。',48,'元曲/yuanqu.json','["俺那崔氏女正红愁绿惨，你个张君瑞待面北眉南，着我老红娘将两下里做一担扭。", "请先生，省言鬼朱，喃喃。"]'),
('yuanqu-6634','萧淑兰情寄菩萨蛮・圣药王','贾仲明','元','元曲','yuanqu','','[]','一迷里口似泼钐怎扑掊，那里肯周而不比且包含。',53,'元曲/yuanqu.json','["一迷里口似泼钐怎扑掊，那里肯周而不比且包含。", "本待成就您，颠倒连累咱。", "唬的我手忙脚乱似痴憨，似寻虎窟觅龙潭。"]'),
('yuanqu-6635','萧淑兰情寄菩萨蛮・络丝娘','贾仲明','元','元曲','yuanqu','','[]','将韩王殿忽然火虫分，蓝桥驿平空水淹。',75,'元曲/yuanqu.json','["将韩王殿忽然火虫分，蓝桥驿平空水淹。", "(云)你道既读孔圣之书，必达周公之礼，可知可知。", "(唱)人前面古怪刚直假撇欠，(做冷笑科，唱)只怕您背地坦荒淫愚滥。"]'),
('yuanqu-6636','萧淑兰情寄菩萨蛮・雪里梅','贾仲明','元','元曲','yuanqu','','[]','空着我功退似游蚕，早则罢暮四与朝三。',42,'元曲/yuanqu.json','["空着我功退似游蚕，早则罢暮四与朝三。", "这生性狠情毒，老身惊心战胆，姐姐也你敢愁添病感。"]'),
('yuanqu-6637','萧淑兰情寄菩萨蛮・收尾','贾仲明','元','元曲','yuanqu','','[]','请学士忍耐权时暂，何必恁高声怒喊。',377,'元曲/yuanqu.json','["请学士忍耐权时暂，何必恁高声怒喊。", "自待教兄嫂逼临了他，着主人公葬送了俺。", "(下)(张世英云)谁想有此事，小生必当退步。", "恐萧公知此，难以分辩。", "只除如此，且往西兴朋友家住数日。", "在此壁间留诗一首，使萧公知之，好往西兴来接我也。", "(做写科)(诗云)感公清盼寄余生，三载交游两月情。", "别去难言心下事，月明酒醒在西兴。", "琴书衣衾，我皆不动，只是单身去咱。", "(下)(萧公让上，云)今日无甚事，书房中望云杰闲话片时。", "(做到科，云)怎生不见云杰？必是望朋友去了。", "(做见壁诗科，惊云)此诗必有缘故，莫非俺家孩儿每侍奉不周，故使如此？琴剑铺陈，皆不曾动。", "他往西兴去，准在朋友家停住，可也容易，我修一简帖，遣一仆到西兴去请他。", "若不如此，云杰平日与人寡合，怎肯自回？(做写书科，云)书已写就了也，便令人早接去。", "(诗云)与云杰交情非薄，详诗意有何不乐？遣使者直至西兴，请回来便知下落。", "(下)。"]'),
('yuanqu-6638','萧淑兰情寄菩萨蛮・双调/五供养','贾仲明','元','元曲','yuanqu','','[]','肌削玉，钏松金，陡恁的闷广愁深。',68,'元曲/yuanqu.json','["肌削玉，钏松金，陡恁的闷广愁深。", "空着我干忍耻，枉留心。", "都是我忒轻浮，欠检束，正好教他撒沁，则索咬定牙儿暗。", "这文君待驾车，谁承望司马抛琴。"]'),
('yuanqu-6639','萧淑兰情寄菩萨蛮・落梅风','贾仲明','元','元曲','yuanqu','','[]','离魂魄，似失心，思昏沉闷围愁浸。',33,'元曲/yuanqu.json','["离魂魄，似失心，思昏沉闷围愁浸。", "白日里忘餐夜废寝，自寻思不知因甚。"]'),
('yuanqu-6640','萧淑兰情寄菩萨蛮・乔牌儿','贾仲明','元','元曲','yuanqu','','[]','嫂嫂待将咱病审，我无语似害淋。',67,'元曲/yuanqu.json','["嫂嫂待将咱病审，我无语似害淋。", "是前日打秋千斗草处无拘禁，脱衣时敢被风侵。", "(老旦云)虽是感冒，怎生这等沉重，茶饭也不思进些？(正旦唱)。"]'),
('yuanqu-6641','萧淑兰情寄菩萨蛮・折桂令','贾仲明','元','元曲','yuanqu','','[]','至如今茶不茶饭不饭心内阴阴，有时节透顶炎炎，有时节彻骨森森，头眩旋旋，眼昏暗暗，身倦沉沉。',99,'元曲/yuanqu.json','["至如今茶不茶饭不饭心内阴阴，有时节透顶炎炎，有时节彻骨森森，头眩旋旋，眼昏暗暗，身倦沉沉。", "一会家发增寒脾神凛凛，一会家添潮热冷汗淋淋。", "病来时难灸难针，心疼时难忍难禁，人问时难诉难分，茶饭上不想不寻。"]'),
('yuanqu-6642','萧淑兰情寄菩萨蛮・庆宣和','贾仲明','元','元曲','yuanqu','','[]','信步谩将花径临，掩映着柳影花阴。',66,'元曲/yuanqu.json','["信步谩将花径临，掩映着柳影花阴。", "害的我瘦骨岩岩死临侵，端的是为您，为您。", "(张世英推旦科，云)您休推睡里梦里。", "(下，正旦惊醒科，唱)。"]'),
('yuanqu-6643','萧淑兰情寄菩萨蛮・殿前欢','贾仲明','元','元曲','yuanqu','','[]','这生好不知音，虚度了春宵一刻价千金，空闲了琐窗朱户鸳鸯枕，翡翠罗衾。',77,'元曲/yuanqu.json','["这生好不知音，虚度了春宵一刻价千金，空闲了琐窗朱户鸳鸯枕，翡翠罗衾。", "早则么韩吏部李翰林，一任教他恁。", "谁想你睡梦里也将人冷侵，待古里掂折了玉簪，摔碎了瑶琴。"]'),
('yuanqu-6644','萧淑兰情寄菩萨蛮・雁儿落','贾仲明','元','元曲','yuanqu','','[]','把西兴路黄犬寻，南浦道青驾任。',33,'元曲/yuanqu.json','["把西兴路黄犬寻，南浦道青驾任。", "信手的联成肠断词，抵多少织就回文锦。"]'),
('yuanqu-6645','萧淑兰情寄菩萨蛮・得胜令','贾仲明','元','元曲','yuanqu','','[]','早难道诗对会家吟，他全没些惜花心。',56,'元曲/yuanqu.json','["早难道诗对会家吟，他全没些惜花心。", "点勾般圈红问，描朱似刷画儿临。", "表数句佳音，字字胭脂渗，书两字泥金，行行血泪浸。"]'),
('yuanqu-6646','萧淑兰情寄菩萨蛮・出队子','贾仲明','元','元曲','yuanqu','','[]','这都是姻缘前判，幸今生得聚完。',87,'元曲/yuanqu.json','["这都是姻缘前判，幸今生得聚完。", "玉肩同并赴云端，素手相携跨采鸾，清韵双吹鸣凤管。", "(张世英云)我张世英若非令兄相待之厚，不负卿之初心，岂敢玷污名教，致有今日？(正旦冷笑科，唱)。"]'),
('yuanqu-6647','萧淑兰情寄菩萨蛮・水仙子','贾仲明','元','元曲','yuanqu','','[]','酒斟着鹦鹉杯，光映着玛瑙盘。',117,'元曲/yuanqu.json','["酒斟着鹦鹉杯，光映着玛瑙盘。", "茶烹着丹凤髓，香浮着碧玉碗。", "开银屏金孔雀绿嫩红娇，隐锦褥绣芙蓉枝繁叶乱。", "嵌玲珑香球挂金缕，团梅红罗鲛绡帐舞凤飞鸾。", "是、是、是，东邻女曾窥宋玉垣，喜、喜、喜，果相逢翡翠银花幔，早、早、早，同心带扣双挽结交欢。"]'),
('yuanqu-6648','萧淑兰情寄菩萨蛮・古寨儿令','贾仲明','元','元曲','yuanqu','','[]','我这里偷看，不由人心欢，没褒弹，忒丰韵，表正形端。',50,'元曲/yuanqu.json','["我这里偷看，不由人心欢，没褒弹，忒丰韵，表正形端。", "趁着这风和月圆春夜暖，逢天喜值红鸾，配宿缘成仙伴。"]'),
('yuanqu-6649','萧淑兰情寄菩萨蛮・神仗儿','贾仲明','元','元曲','yuanqu','','[]','荔枝浆乳酪蜜团，甘蔗汁酥油糖拌。',95,'元曲/yuanqu.json','["荔枝浆乳酪蜜团，甘蔗汁酥油糖拌。", "蔷薇露秋菊春兰，紫苏盐姜醋荐款，碧芥芽葱针寸段。", "(云)梅香，你看这生在书院相见之时，许多道学身分，今都到那里去了？(唱)细端详俊沈娇潘，可不道尊瞻视，正衣冠。"]'),
('yuanqu-6650','萧淑兰情寄菩萨蛮・尾声','贾仲明','元','元曲','yuanqu','','[]','锦片前程今美满，舞菱花一对青鸾，早不入凤台闲玉管。',25,'元曲/yuanqu.json','["锦片前程今美满，舞菱花一对青鸾，早不入凤台闲玉管。"]'),
('yuanqu-6651','正官・醉太平题情','乔吉','元','元曲','yuanqu','','[]','离情厮禁，旧约难寻。',200,'元曲/yuanqu.json','["离情厮禁，旧约难寻。", "落红堆径雨沉沉，锁梨花院深。", "瘦来裙掩鸳鸯锦，愁多梦冷芙蓉枕，髻松钗落凤凰金，险掂折玉簪。", "乐闲链秋霞汞鼎，煮晴雪茶铛。", "落花流水护茅亭，似春风武陵。", "唤樵青、椰瓢倾、云浅松醪剩，倚围屏、洞仙酣、露冷石床净，挂枯藤、野猿啼、月淡纸窗明，老先生睡醒。", "渔樵闲话柳穿鱼旋煮，柴换酒新沽。", "斗牛儿乘兴老樵渔，论闲言伥语。", "燥头颅束云担雪耽辛苦，坐蒲团攀风咏月穷活路，按葫芦谈天说地醉模糊。", "入江山画图。"]'),
('yuanqu-6652','正官・绿幺遍自述','乔吉','元','元曲','yuanqu','','[]','不占龙头选，不入名贤传。',51,'元曲/yuanqu.json','["不占龙头选，不入名贤传。", "时时酒圣，处处诗禅，烟霞状元，江湖醉仙，笑谈便是编修院。", "留连，批风抹月四十年。"]'),
('yuanqu-6653','南吕・阅全经闺情','乔吉','元','元曲','yuanqu','','[]','玉减梅花瘦，翠颦妆镜羞，雨念云思何日休？休，休登江上楼。',76,'元曲/yuanqu.json','["玉减梅花瘦，翠颦妆镜羞，雨念云思何日休？休，休登江上楼。", "红弯袖，泪痕都是愁。", "砑金红鸾纸，染香丹凤词，情系人心狄藉丝。", "思，掷梭双泪时。", "回文字，织成肠断诗。"]'),
('yuanqu-6654','中吕・红绣鞋竹衫儿','乔吉','元','元曲','yuanqu','','[]','并刀剪龙须为寸，玉丝穿龟背成文，襟袖清凉不沾尘。',182,'元曲/yuanqu.json','["并刀剪龙须为寸，玉丝穿龟背成文，襟袖清凉不沾尘。", "汗香晴带雨，肩瘦冷搜云，是玲珑剔透人。", "浃背全无暑汗，曲肱时印新瘢，衬荷花落魄壮怀宽。", "挹风香双袖细，披野色一襟团，满身儿窥豹管。", "书所见脸儿嫩难藏酒晕，扇儿薄不隔歌尘，佯整金钗暗窥人。", "凉风醒醉眼，明月破诗魂，料今宵怎睡得稳。", "泊皋亭山下石骨瘦金珠窟嵌，树身驰璎珞褴衤参，秋影秋声绕蓬龛。", "青山黄鹤楼，白水黑龙潭，野猿啼碎胆。"]'),
('yuanqu-6655','中吕・喜春秋秋望','乔吉','元','元曲','yuanqu','','[]','千山落叶岩岩瘦，百尺危阑寸寸愁，有人独倚晚妆楼。',34,'元曲/yuanqu.json','["千山落叶岩岩瘦，百尺危阑寸寸愁，有人独倚晚妆楼。", "楼外柳，眉暗不禁秋。"]'),
('yuanqu-6656','商调・梧叶儿出金陵','乔吉','元','元曲','yuanqu','','[]','尘暗埋金地，云寒树玉宫，归去也老仙翁。',46,'元曲/yuanqu.json','["尘暗埋金地，云寒树玉宫，归去也老仙翁。", "东北朝宗水，西南解愠风，船急似飞龙，到铁瓮城边喜落篷。"]'),
('yuanqu-6657','越调・天净沙即事','乔吉','元','元曲','yuanqu','','[]','笔尖扫尽痴云，歌声唤醒芳春，花担安排酒樽。',133,'元曲/yuanqu.json','["笔尖扫尽痴云，歌声唤醒芳春，花担安排酒樽。", "海棠风信，明朝陌上吹尘。", "一从鞍马西东，几番衾枕朦胧，薄幸虽来梦中。", "争如无梦，那时真个相逢。", "隔窗谁爱听琴？倚帘人是知音，一句话当时至今。", "今番推甚，酬劳凤枕鸳衾。", "莺莺燕燕春春，花花柳柳真真，事事风风韵韵。", "娇娇嫩嫩，停停当当人人。"]'),
('yuanqu-6658','越调・酒旗儿陪雅斋万户游仙都洞天','乔吉','元','元曲','yuanqu','','[]','千古藏真洞，一柱立晴空，石笋参差似太华峰，醉入天台梦。',46,'元曲/yuanqu.json','["千古藏真洞，一柱立晴空，石笋参差似太华峰，醉入天台梦。", "绿树溪边晚风，碧云不动，粉香只下芙蓉。"]'),
('yuanqu-6659','越调・凭栏人香篆','乔吉','元','元曲','yuanqu','','[]','一点雕盘萤度秋，半缕宫奁云弄愁。',177,'元曲/yuanqu.json','["一点雕盘萤度秋，半缕宫奁云弄愁。", "情缘不到头，寸心灰未休。", "金陵道中瘦马驮诗天一涯，倦鸟呼愁村数家。", "扑头飞柳花，与人添鬓华。", "春思淡月梨花曲槛傍，清露苍苔罗袜凉。", "恨他愁断肠，为他烧夜香。", "小姬手捻红牙花满头，爱唱春词不解愁。", "一声出画楼，晓莺无奈羞。", "香暖蜕龙团香骨尘，细袅云衣古篆文。", "宝奁余烬温，小池明月昏。", "心火蟠烧九曲肠，鼻观薰修三昧香。", "劫灰书几场，犹存延寸光。"]'),
('yuanqu-6660','双调・庆东原青田九楼山舟中作','乔吉','元','元曲','yuanqu','','[]','渺渺山头路，鳞鳞山上田，绕篷窗六曲屏风面。',51,'元曲/yuanqu.json','["渺渺山头路，鳞鳞山上田，绕篷窗六曲屏风面。", "似丹青辋川，是神仙洞天，隔云树人烟，试看玉溪边，恐有桃花片。"]'),
('yuanqu-6661','双调・钱丝泫','乔吉','元','元曲','yuanqu','','[]','避豪杰，隐岩穴，煮茶香扫梅梢雪。',37,'元曲/yuanqu.json','["避豪杰，隐岩穴，煮茶香扫梅梢雪。", "中酒酣迷纸帐蝶，枕书睡足松窗月，一灯蜗舍。"]'),
('yuanqu-6662','双调・春闺怨','乔吉','元','元曲','yuanqu','','[]','雪月风花收拾够也，用心用力这时节，担儿上一担担风月。',155,'元曲/yuanqu.json','["雪月风花收拾够也，用心用力这时节，担儿上一担担风月。", "途路赊，步步些些。", "不系雕鞍门前柳，玉容寂寞见花羞，冷风儿吹雨黄昏后。", "帘控钩，掩上珠楼，风雨替花愁。", "黑海春愁浑无处躲，嫩香腻玉渐消磨，瘦呵也不似今春个。", "无奈何，自画双蛾，添得越愁多。", "薄命儿心肠较软，道声去也泪涟涟，这些时攒下春闺怨。", "离恨天，几度前，羞见月儿圆。"]'),
('yuanqu-6663','双调・殿前欢里西瑛号懒云窝自叙有作奉和','乔吉','元','元曲','yuanqu','','[]','懒云窝，石床苔翠暖相和。',357,'元曲/yuanqu.json','["懒云窝，石床苔翠暖相和。", "不施霖雨为良佐，遁迹岩阿。", "林泉梦引台，风月诗分破，富贵沾讠宛。", "歌残楚些，闲损巫娥。", "懒云窝，云边日月尽如梭。", "槐根梦觉兴亡破，依旧南柯。", "休听宁戚歌，学会陈抟卧，不管伯夷饿。", "无何浩饮，浩饮无何。", "懒云窝，静看松影挂长萝。", "半间僧舍平分破，尘虑消磨。", "听不厌隐士歌，梦不喜高轩过，聘不起东山卧。", "疏慵在我，奔竞从他。", "懒云窝，懒云窝里避风波。", "无荣无辱无灾祸，尽我婆娑。", "闲讴乐道歌，打会清闲坐，放浪形骸卧。", "人多笑我，我笑人多。", "懒云窝，云窝客至欲如何？懒云窝里和云卧，打会磨跎。", "想人生待怎么，贵比我争些大，富比我争些个。", "呵呵笑我，我笑呵呵。", "懒神仙，懒窝中打坐几多年。", "梦魂不到青云殿，酒兴诗颠。", "轻便如宰相权，冷淡如名贤传，自在如彭泽县。", "苍天负我，我负苍天。", "登凤凰台凤凰台，金龙玉虎帝王宅，猿鹤只欠山人债，千古兴怀。"]'),
('yuanqu-6664','双调・卖花声悟世','乔吉','元','元曲','yuanqu','','[]','肝肠百炼炉间铁，富贵三更枕上蝶，功名两字酒中蛇。',177,'元曲/yuanqu.json','["肝肠百炼炉间铁，富贵三更枕上蝶，功名两字酒中蛇。", "尖风薄雪，残杯冷炙，掩清灯竹篱茅舍。", "太平吴氏楼会集桃花扇底窥春笑，杨柳帘前按舞娇，海棠梦里醉魂销。", "香团娇小，歌头水调，断肠也五陵年少。", "香云帘幕风流燕，花月楼台富贵仙，新调骏马紫藤鞭。", "能歌小妾，轻罗团扇，醉归来牡丹亭院。", "香茶细研片脑梅花粉，新剥珍珠豆蔻仁，依方修合凤团春。", "醉魂清爽，舌尖香嫩，这孩儿那些风韵。"]'),
('yuanqu-6665','仙吕・赏花时风情','乔吉','元','元曲','yuanqu','','[]','春透天台醉碧桃，月满云窗听紫箫。',34,'元曲/yuanqu.json','["春透天台醉碧桃，月满云窗听紫箫。", "莺燕友凤鸾交，幽期密约，不许外人瞧。"]'),
('yuanqu-6666','幺・打不觉头毒如睡马杓，粘随风絮沾如肉膘胶。藤缠葛数千遭，把丽春','乔吉','元','元曲','yuanqu','','[]','园缠倒，吓的那贩茶客五魂消。',14,'元曲/yuanqu.json','["园缠倒，吓的那贩茶客五魂消。"]'),
('yuanqu-6667','赚煞・我是个锻炼成的铁连环，不比您捻合就的泥圈套。挣么快的锋芒怎','乔吉','元','元曲','yuanqu','','[]','敢犯着，小厮扑如何敢和我换交？伏唇枪舌剑吹毛，不是我骋粗豪。',111,'元曲/yuanqu.json','["敢犯着，小厮扑如何敢和我换交？伏唇枪舌剑吹毛，不是我骋粗豪。", "强霸着月夜花朝，围你在垓心里怎地逃？若不纳降旗受缚，肯舒心伏弱，敢教点钢锹劈碎纸糊锹。", "睡鞋儿双凤衔花宫样弯，窄玉圈金三寸悭。", "绿窗静翠帘闲，似锦鸳日晚，并宿向雕阑。"]'),
('yuanqu-6668','南吕・一枝花合筝','乔吉','元','元曲','yuanqu','','[]','酒酣春色浓，帘卷花阴静。',60,'元曲/yuanqu.json','["酒酣春色浓，帘卷花阴静。", "佳人娇和曲，豪客醉弹筝。", "心与手调停，敛袂待弦初定，雁行斜江月影。", "挡银甲指拨轻清，按金缕歌喉数声。"]'),
('yuanqu-6669','尾・煞强如泣琵琶泪湿青衫上冷，仿佛似鹦鹉声讹锦罩内听，洗得平生耳','乔吉','元','元曲','yuanqu','','[]','根净。',91,'元曲/yuanqu.json','["根净。", "风流这生，乞戏可憎，我便有陶学士的鼻凹也下不得饼。", "私情云髻金雀翘，山隐青鸾鉴，藕丝轻织粉，湘水细揉蓝。", "性子儿岩嵌，小可底难摇撼，起初儿着莫咱，假撇清面北眉南，实怕亻替红愁绿惨。"]'),
('yuanqu-6670','尾・从今将凤凰巢鸳鸯殿遮笼教暗，将金缝锁玉连环对勘的严，锦片也似','乔吉','元','元曲','yuanqu','','[]','前程做的来不愚滥。',103,'元曲/yuanqu.json','["前程做的来不愚滥。", "非是咱不甘，不是你不堪，只被这受惊怕的恩情都吓破我胆。", "杂情粉云香脸试搽，翠烟腻眉学画，红酥润冰笋手，乌金渍玉粳牙，鬓拢宫鸦。", "改样儿新鞋袜，挑粉垢修指甲。", "收拾得所事儿温柔，妆点得诸余里颗恰。"]'),
('yuanqu-6671','骂玉郎・但些儿头疼眼热我早心惊呀，着疼热只除咱，寻方里药占龟卦。','乔吉','元','元曲','yuanqu','','[]','直到吃得粥食，离了卧榻，恰撇得心儿下。',19,'元曲/yuanqu.json','["直到吃得粥食，离了卧榻，恰撇得心儿下。"]'),
('yuanqu-6672','感皇恩・看承似美玉无瑕，谁敢帮野草闲花。曹大家卖杏虎，裴小蛮学撒','乔吉','元','元曲','yuanqu','','[]','撇，温太真索妆虾。',36,'元曲/yuanqu.json','["撇，温太真索妆虾。", "丽春园扎撒，鸣珂巷南衙，现而今如嚼蜡，似咬瓦，若抟沙。"]'),
('yuanqu-6673','采茶歌・喜时节脸烘霞，笑时节眼生花，一霎时一天风雪冷鼻凹。本待做','乔吉','元','元曲','yuanqu','','[]','曲吕木头车儿随性打，原来是滑出律水晶球子怎生拿。',24,'元曲/yuanqu.json','["曲吕木头车儿随性打，原来是滑出律水晶球子怎生拿。"]'),
('yuanqu-6674','一枝花・忙拈鹊画弓，急取雕翎箭，端直了燕尾钅比，搭上虎筋弦，秋月','乔吉','元','元曲','yuanqu','','[]','弓圆，箭发如飞电，觑高低无侧偏，正中宾鸿，落在蒹葭不见。',28,'元曲/yuanqu.json','["弓圆，箭发如飞电，觑高低无侧偏，正中宾鸿，落在蒹葭不见。"]'),
('yuanqu-6675','商调・集贤宾咏柳忆别','乔吉','元','元曲','yuanqu','','[]','恨青青画桥东畔柳，曾祖送少年游。',77,'元曲/yuanqu.json','["恨青青画桥东畔柳，曾祖送少年游。", "散睛雪杨花清昼，又一场心事悠悠。", "翠丝长不系雕鞍，碧云寒空掩朱楼。", "揎罗袖试将纤玉手，绾东风摇损轻柔，同心方胜结，缨络绣文球。"]'),
('yuanqu-6676','逍遥乐・绾不成鸳鸯双叩，空惊散梢头，一双锦鸠。何处忘忧？听枝上数','乔吉','元','元曲','yuanqu','','[]','声黄栗留，怕不弄春娇巧转歌喉。',30,'元曲/yuanqu.json','["声黄栗留，怕不弄春娇巧转歌喉。", "惊回好梦，题起离情，唤醒闲愁。"]'),
('yuanqu-6677','越调・斗鹌鹑歌姬','乔吉','元','元曲','yuanqu','','[]','教坊驰名，梨园上班，院本诙谐，宫妆样范。',52,'元曲/yuanqu.json','["教坊驰名，梨园上班，院本诙谐，宫妆样范。", "肤若凝脂，颜如渥丹，香肩凭玉楼，湘云拥翠鬓。", "罗帕分香，春纤换盏。"]'),
('yuanqu-6678','天净沙・眉儿初月弯弯，鞋儿瘦玉悭悭，脸儿孜孜耐看。琵琶弦慢，青衫','乔吉','元','元曲','yuanqu','','[]','泪点才干。',5,'元曲/yuanqu.json','["泪点才干。"]'),
('yuanqu-6679','尾・丽春园门外是浔阳岸，最险是茶船上跳板。一句话悔时难，两般儿爱','乔吉','元','元曲','yuanqu','','[]','处拣。',3,'元曲/yuanqu.json','["处拣。"]'),
('yuanqu-6680','双调・新水令闺丽','乔吉','元','元曲','yuanqu','','[]','绣闺深培养出牡丹芽，控银钩绣帘不挂。',42,'元曲/yuanqu.json','["绣闺深培养出牡丹芽，控银钩绣帘不挂。", "莺燕游上苑，蝶梦绕东华。", "富贵人家，花阴内柳阴下。"]'),
('yuanqu-6681','乔木查・忽地迎头见咱，娇小心儿里怕，厌地回身拢鬓鸦，傍阑干行又羞，','乔吉','元','元曲','yuanqu','','[]','双脸烘霞。',5,'元曲/yuanqu.json','["双脸烘霞。"]'),
('yuanqu-6682','搅筝琶・我凝眸罢，心内顽麻。可知曲江头三次遗鞭，我粉墙外几乎坠马。','乔吉','元','元曲','yuanqu','','[]','人说观自在活菩萨，堪夸。',29,'元曲/yuanqu.json','["人说观自在活菩萨，堪夸。", "普院山几时曾到他，更隔着海角天涯。"]'),
('yuanqu-6683','甜水令・他秋水回波，春山摇翠，芳心迎迓，彼此各承答。诗句传情，琴','乔吉','元','元曲','yuanqu','','[]','声写恨，衷肠牵挂，许多时不得欢洽。',17,'元曲/yuanqu.json','["声写恨，衷肠牵挂，许多时不得欢洽。"]'),
('yuanqu-6684','雁儿落・斗的满街里闲嗑牙，待罢呵如何罢？空揣着题诗玉版笺，织绵香','乔吉','元','元曲','yuanqu','','[]','罗帕。',3,'元曲/yuanqu.json','["罗帕。"]'),
('yuanqu-6685','得胜令・我是个为客秀才家，你是个未嫁女娇娃，不是将海鹤儿相埋怨，','乔吉','元','元曲','yuanqu','','[]','休把这纸鹞儿厮调发。',35,'元曲/yuanqu.json','["休把这纸鹞儿厮调发。", "若是真么，回与我句实成的话。", "天那，送了人呵不是耍。"]'),
('yuanqu-6686','双调・乔牌儿别情','乔吉','元','元曲','yuanqu','','[]','凤求凰琴慢弹，莺求友曲休咀，楚阳台更隔着连云栈，桃源洞在蜀道难。',32,'元曲/yuanqu.json','["凤求凰琴慢弹，莺求友曲休咀，楚阳台更隔着连云栈，桃源洞在蜀道难。"]'),
('yuanqu-6687','搅筝琶・无边岸，黑海也似那煎烦。愁万结柔肠，泪双垂业眼。泪眼与愁','乔吉','元','元曲','yuanqu','','[]','肠，直熬得烛灭香残。',30,'元曲/yuanqu.json','["肠，直熬得烛灭香残。", "更阑，望情人必然来梦间，争奈这枕冷衾寒。"]'),
('yuanqu-6688','沉醉东风・风铃响猛猜做佩环，柳烟颦只疑是眉攒。想犀梳似新月牙，忆','乔吉','元','元曲','yuanqu','','[]','宫额似芙蓉瓣，见桃花呵似见他容颜，觑得越女吴姬匹似闲，厌听那银筝象板。',35,'元曲/yuanqu.json','["宫额似芙蓉瓣，见桃花呵似见他容颜，觑得越女吴姬匹似闲，厌听那银筝象板。"]'),
('yuanqu-6690','双调・行香子题情','乔吉','元','元曲','yuanqu','','[]','燕亻愁莺亻孱，凤只鸾单，无多时春事阑珊。',43,'元曲/yuanqu.json','["燕亻愁莺亻孱，凤只鸾单，无多时春事阑珊。", "东阳瘦体，潘岳苍颜，我怕春归，愁日永，睚更阑。"]'),
('yuanqu-6692','锦上花・酒社诗坛，不茶不饭，夜雨愁肠，东风泪眼。海誓山盟，白玉连','乔吉','元','元曲','yuanqu','','[]','环，月约星期，泥金小简。',12,'元曲/yuanqu.json','["环，月约星期，泥金小简。"]'),
('yuanqu-6693','小阳关・次第明月食，容易彩云散，咫尺巫山，顷刻阳关。地窄天宽，十','乔吉','元','元曲','yuanqu','','[]','番九番；雨涩云怪，千难万难。',14,'元曲/yuanqu.json','["番九番；雨涩云怪，千难万难。"]'),
('yuanqu-6694','江儿水・西楼倚遍十二阑，望断处空长叹。不由人脚儿勤，更怕咱心儿惮，','乔吉','元','元曲','yuanqu','','[]','得空便对着他实掉讠兄。',11,'元曲/yuanqu.json','["得空便对着他实掉讠兄。"]'),
('yuanqu-6695','包待制智赚灰栏记・仙吕/赏花时','李行甫','元','元曲','yuanqu','','[]','凭着我皓首苍颜老母亲，待着我尽世今生不嫁人。',133,'元曲/yuanqu.json','["凭着我皓首苍颜老母亲，待着我尽世今生不嫁人。", "(云)员外，我可也不爱你别的。", "(马员外云)姐姐，你爱我些甚的来？(正旦唱)我只爱你性儿软意儿真，我今日寻的个前程定准。", "(带云)我着那一班姊妹道，张海棠嫁了马员外，可也不枉了。", "(唱)从此后不教人笑我做辱家门。", "(同马员外下)。"]'),
('yuanqu-6696','包待制智赚灰栏记・仙吕/点绛唇','李行甫','元','元曲','yuanqu','','[]','月户云窗，绣帏罗帐。',30,'元曲/yuanqu.json','["月户云窗，绣帏罗帐。", "谁承望，我如今弃贱从良，拜辞了这鸣珂巷。"]'),
('yuanqu-6697','包待制智赚灰栏记・混江龙','李行甫','元','元曲','yuanqu','','[]','毕罢了浅斟低唱，撇下了数行莺燕占排场。',158,'元曲/yuanqu.json','["毕罢了浅斟低唱，撇下了数行莺燕占排场。", "不是我攀高接贵，由他每说短论长。", "再不去卖笑追欢风月馆，再不去迎新送旧翠红乡。", "我可也再不怕官司勾唤，再不要门户承当，再不放宾朋出入，再不见邻里推抢，再不愁家私营运，再不管世事商量。", "每日价喜孜孜一双情意两相投，直睡到暖溶溶三竿日影在纱窗上。", "伴着个有疼热的夫主，更送着个会板障的亲娘。"]'),
('yuanqu-6698','包待制智赚灰栏记・油葫芦','李行甫','元','元曲','yuanqu','','[]','自丧了亲爷撇下个娘，偏你敢不姓张，怎教咱辱门败户的妹子去支当！(张林云)妹子，不必敲打我了，我也知道，多多的亏了你也！(正旦唱)到今日你便安排着这句甜话儿来寻访',250,'元曲/yuanqu.json','["自丧了亲爷撇下个娘，偏你敢不姓张，怎教咱辱门败户的妹子去支当！(张林云)妹子，不必敲打我了，我也知道，多多的亏了你也！(正旦唱)到今日你便安排着这句甜话儿来寻访。", "(张林云)妹子，我今日特来投托，你怎做下这一个冷脸儿那！(正旦唱)也不是俺便做下的这一个冷脸儿难亲傍，想当日你怒烘烘的挺一身，急煎煎的走四方。", "(张林云)妹子，这旧话也休提了。", "(正旦唱)我则道你怎生发迹身荣旺，怎还穿着这蓝蓝缕缕的这样旧衣裳？(张林云)妹子，我和你是一父母生的兄妹，你哥哥便有甚的不是，你也将就些儿，不要记怨了。", "(正旦唱)。"]'),
('yuanqu-6699','包待制智赚灰栏记・天下乐','李行甫','元','元曲','yuanqu','','[]','哥哥也，你便有甚脸今朝到我行，听说罢这衷也波肠！(张林云)妹子也，我也是出于无奈，特特投奔你来。',829,'元曲/yuanqu.json','["哥哥也，你便有甚脸今朝到我行，听说罢这衷也波肠！(张林云)妹子也，我也是出于无奈，特特投奔你来。", "没奈何，不论多少，赍发些盘缠使用，等我好去。", "(正旦唱)口声声道是无奈何，哥哥也，你既无钱呵怎生走汴梁？(张林云)妹子，你也不必多说了，你不赍发我，教那个赍发我？(正旦唱)你今日投奔我个小妹子，只要我赍发你个大兄长，(带云)你不道来，(唱)可不道是男儿当自强！(张林云)妹子，你不曾忘了一句儿也。", "打落的我勾了，你则是赍发我去者。", "(正旦云)哥哥不知，俺这衣服头面，都是马员外与姐姐的，我怎做的主好与人，除这些有甚的盘缠好赍发的你？哥哥，你则回去了罢，休来这门首也。", "(做不礼、入门科)(张林云)妹子，你好狠也。", "你是我同胞亲妹子，我特投奔着你，一文盘缠也不与我，倒花白了我这许多。", "我如今也不回去，只在这门首等着，待他马员外来，或者有些面情，也不见得。", "(搽旦上，云)我是马员外的大浑家，领着孩儿烧香，我先回来了。", "呀！怎么我家解典库门首，立着个教化头？你在此有甚么勾当？(张林云)姐姐休骂，小人是张海棠的哥哥，来寻我妹子的。", "(搽旦云)原来你是张海棠的哥哥，这等是舅舅了。", "你可认的我么？(张林云)小人不认的那壁姐姐。", "(搽旦云)则我便是马员外的大浑家。", "(张林云)我小人眼拙不认得，大娘子是必休怪。", "(做揖科)(搽旦云)舅舅，你要寻你妹子怎么？(张林云)说也惶恐。", "因为贫难，无以度日，要寻我妹子，讨些盘缠使用。", "(搽旦云)他与你多少？(张林云)他道家私里外，都是大娘子掌把着哩，自做不得主，一些没有。", "(搽旦云)舅舅不知，自从你妹子到我家来，添了一个孩儿，如今也五岁了，这是你的外甥。", "现今我家大小家私，都着他掌把，我是没儿子的！(做敲胸科，云)一些也没分了！你是张海棠的哥哥，便是我亲哥哥一般。", "我如今过去，问他讨些盘缠与你。", "若有呵，你也休欢喜；若无呵，你也休烦恼，只看你的造化。", "你且在门首待者。", "(张林云)小人知道。", "好一个贤慧的妇人也！(正旦见搽旦科，云)姐姐，你先回来了！劳动着姐姐哩。"]'),
('yuanqu-6700','包待制智赚灰栏记・那吒令','李行甫','元','元曲','yuanqu','','[]','我当初自伤，别无甚忖量；别无甚忖量，将他来不防，将他来不防；可送咱这场。',64,'元曲/yuanqu.json','["我当初自伤，别无甚忖量；别无甚忖量，将他来不防，将他来不防；可送咱这场。", "俺越打得手脚儿慌，他越逞着言词儿谤，端的个狠毒世上无双。"]'),
('yuanqu-6701','包待制智赚灰栏记・寄生草','李行甫','元','元曲','yuanqu','','[]','便是那狠毒的桑新妇，也不似你这个七世的娘，倒说我实心儿主意瞒家长。',112,'元曲/yuanqu.json','["便是那狠毒的桑新妇，也不似你这个七世的娘，倒说我实心儿主意瞒家长。", "(搽旦云)谁着你背地里养着奸夫，还强嘴那！(正旦唱)他道我共奸大背地常来往，他道我会支吾对面舌头强。", "不争将滥名儿揣在我跟前，姐姐也，便是将个屎盆儿套在他头上。"]'),
('yuanqu-6702','包待制智赚灰栏记・后庭花','李行甫','元','元曲','yuanqu','','[]','恰才我脊梁上挨了棍棒，又索去厨房中煎碗热汤，一任他男子汉多心硬，大刚来则是俺这婆娘每不气长。',333,'元曲/yuanqu.json','["恰才我脊梁上挨了棍棒，又索去厨房中煎碗热汤，一任他男子汉多心硬，大刚来则是俺这婆娘每不气长。", "(做下、捧汤上科，云)姐姐，兀的不是汤。", "(搽旦云)拿汤来，我试尝咱。", "(做尝科，云)还少些盐酱，快去取来。", "(正旦应，下)(搽旦云)前日这一服毒药，待我取来，倾在这汤儿里。", "(做倾药科，云)海棠，快来。", "(正旦上，唱)怎这般忒慌张，连催盐酱？(云)姐姐，兀的不是盐酱。", "(搽旦做调汤科，云)海棠，你将去。", "(正旦云)姐姐，你将去波，怕员外见了我越气也。", "(搽旦云)你不去，员外又道你恼着他哩。", "(下)(正旦云)理会得。", "员外，你吃口汤儿波。", "(员外做接吃科)(正旦唱)则见他闷沉沉等半晌，苦恹恹口内尝。", "(员外做死科)(正旦惊，云)员外，你放精细者！(唱)为甚的黄甘甘改了面上，白邓邓丢了眼光？。"]'),
('yuanqu-6703','包待制智赚灰栏记・青哥儿','李行甫','元','元曲','yuanqu','','[]','呀！唬得我胆飞魂丧，不由不两泪千行。',78,'元曲/yuanqu.json','["呀！唬得我胆飞魂丧，不由不两泪千行。", "眼见的四体难收一命亡，撇下多少房廊，几处田庄，两个婆娘，五岁儿郎。", "从今后无挨无靠，母子每守孤孀，孩儿也，你将个谁依仗？。"]'),
('yuanqu-6704','包待制智赚灰栏记・赚煞','李行甫','元','元曲','yuanqu','','[]','且休问你真实，休问咱虚谎，现放着剃胎头收生的老娘，则问他谁是亲娘，谁是继养？(搽旦云)我是孩儿的亲亲的亲娘，这孩儿是我的的亲亲的亲儿，是娘的心肝，娘的肚子，娘的',246,'元曲/yuanqu.json','["且休问你真实，休问咱虚谎，现放着剃胎头收生的老娘，则问他谁是亲娘，谁是继养？(搽旦云)我是孩儿的亲亲的亲娘，这孩儿是我的的亲亲的亲儿，是娘的心肝，娘的肚子，娘的脚后跟，那一个不知道的！(正旦唱)怎瞒得过看生见长的街坊。", "(搽旦云)你合毒药，谋死员外，也是我脏埋你的？(正旦云)这毒药呵，(唱)你平日里预收藏，暗暗的倾下羹汤。", "(搽旦云)明明是你下这毒药在汤儿里，怎赖得我？怕你不去偿命！(正旦唱)这的是谁药死亲夫呵要将性命偿。", "你畅好是不良，送的人来冤枉。", "则普天厂大浑家那里有你这片歹心肠！(下)。"]'),
('yuanqu-6705','包待制智赚灰栏记・商调/集贤宾','李行甫','元','元曲','yuanqu','','[]','火匝匝把衣服紧攥着，(搽旦云)你药死亲夫，该死罪的，我放了你，倒等你逃走去了？(正旦唱)你道我该死罪怎生逃？(带云)张海棠也，(唱)我则道嫁良人十成九稳，今日个',185,'元曲/yuanqu.json','["火匝匝把衣服紧攥着，(搽旦云)你药死亲夫，该死罪的，我放了你，倒等你逃走去了？(正旦唱)你道我该死罪怎生逃？(带云)张海棠也，(唱)我则道嫁良人十成九稳，今日个越不见末尾三梢。", "则我这负屈的有口难言，赤紧的原告人见肚生苗，这一场没揣的罪名除非天地表！(搽旦云)可知道你药死了亲夫，自有个天理神明鉴察。", "(正旦唱)我将这虚空中神灵来祷告，便做道男儿无显迹，可难道天理不昭昭？。"]'),
('yuanqu-6706','包待制智赚灰栏记・逍遥乐','李行甫','元','元曲','yuanqu','','[]','你道是经官发落，怎的支吾这场棒拷。',72,'元曲/yuanqu.json','["你道是经官发落，怎的支吾这场棒拷。", "我则道人命事须要个归着，怎肯把药死亲夫罪屈招，平白地落人圈套！拚守着七贞九烈，怕甚么六问三推，一任地万打千敲。"]'),
('yuanqu-6707','包待制智赚灰栏记・梧叶儿','李行甫','元','元曲','yuanqu','','[]','厅阶下，膝跪着，听贱妾说根苗。',99,'元曲/yuanqu.json','["厅阶下，膝跪着，听贱妾说根苗。", "(赵令史云)你说，你说。", "(正旦唱)狼虎般排着祗从，神鬼般设着六曹。", "(赵令史云)你药杀亲夫，这是十恶大罪哩。", "(正旦唱)若妾身犯下分毫，相公也，我情愿吃那杀丈夫的绷扒吊拷。"]'),
('yuanqu-6708','包待制智赚灰栏记・山坡羊','李行甫','元','元曲','yuanqu','','[]','念妾身求食卖笑，本也是旧家风调。',69,'元曲/yuanqu.json','["念妾身求食卖笑，本也是旧家风调。", "则为俺穷滴滴子母每无依靠，挨今宵，到明朝。", "谢的个马均卿一见投他好，下钱财将妾身娶做小。", "他莺燕交，咱成就了。"]'),
('yuanqu-6709','包待制智赚灰栏记・金菊香','李行甫','元','元曲','yuanqu','','[]','我与他生男长女受劬劳。',231,'元曲/yuanqu.json','["我与他生男长女受劬劳。", "(赵令史云)你家里有甚么人，也还往来么？(正旦唱)俺哥哥因为少吃无穿来投托，曾被我赶离门恰和他两个厮撞着。", "(赵令史云)是你的哥哥，便和他厮见，也不妨事。", "(正旦云)俺姐姐道：海棠，既是你哥哥来投奔你时，你便没银子，何不解下这衣服头面，与他做盘缠使用去。", "(赵令史云)这般说也是他好意。", "(正旦云)我信了他，将这些衣服头面与哥哥去了。", "等的员外回来，问道海棠的衣服头面，为何不见，他便道，瞒着员外，都与奸夫了也。", "(唱)岂知他有两面三刀，向夫主厮搬调。"]'),
('yuanqu-6710','包待制智赚灰栏记・醋葫芦','李行甫','元','元曲','yuanqu','','[]','俺男儿气中子，丕地倒，醒来时俺姐姐自扶着。',648,'元曲/yuanqu.json','["俺男儿气中子，丕地倒，醒来时俺姐姐自扶着。", "(带云)他道，海棠，员外要汤吃，你去煎来。", "(唱)煎的一碗热汤来又道是盐酱少，(带云)他赚的我取盐酱去呵，(唱)谁承望暗倾着毒药。", "(带云)员外才把这汤吃下不的一两口，就死了也。", "相公，你试寻思波。", "(唱)怎便登时间火焚了尸首，葬在荒郊？(赵令史云)这毒药明明是你的了。", "你怎么又要强夺他孩儿，混赖他家私，有何理说？(正旦云)这孩儿原是我养的。", "相公，你只唤那收生的刘四婶，剃胎头的张大嫂，并邻里街坊问时，便有分晓。", "(赵令史云)这个也说的是。", "左右，快去拘唤那老娘街坊来者。", "(孤做票臂科)(祗从出，唤云)老娘街坊人等，衙门中唤你哩。", "(二净扮街坊、二丑扮老娘上，净云)常言道，得人钱财，与人消灾。", "如今马员外的大娘子，告下来了，唤我们做证见哩。", "这孩子本不是大娘子养的，我们得过他银子，则说是他养的。", "你们不要怕打，说的不明白。", "(净、丑等云)这个知道。", "(做随祗从入跪科，祗从云)当面。", "(赵令史云)你是街坊么？这孩儿是谁养的？(二净云)那马员外是个财主，小的每平日也不往来。", "五年前因他大娘子养了个儿子，小的们街坊邻里，各人三分银子与他贺喜，那员外也请小的每吃满月酒，看见倒生的一个好娃娃。", "以后每年儿子生日，那员外同着大娘子，领了儿子到各寺院烧香去，这是一城人都看见的，也不只是小的们这几个。", "(赵令史云)这等明明是他大娘子养的了。", "(正旦云)相公，这街坊都是他用钱买转了的，听不得他说话。", "(二净云)我每买不转的，都是倾心吐胆说真实的话，若有半句说谎，你嘴上害碗大的疔疮。", "(正旦唱)。"]'),
('yuanqu-6711','包待制智赚灰栏记・幺篇','李行甫','元','元曲','yuanqu','','[]','现放着收生的刘四婶，剃胎头的张大嫂，俺孩儿未经满月早问道我十数遭。',72,'元曲/yuanqu.json','["现放着收生的刘四婶，剃胎头的张大嫂，俺孩儿未经满月早问道我十数遭。", "今日个浪包娄到公庭混赖着您，街坊每常好是不合天道，得这些口含钱直恁般使的坚牢。"]'),
('yuanqu-6712','包待制智赚灰栏记・幺篇','李行甫','元','元曲','yuanqu','','[]','哎，儿也，则你那心儿里自想度，自暗约，见您娘苦恹恹皮肉上挨着荆条。',68,'元曲/yuanqu.json','["哎，儿也，则你那心儿里自想度，自暗约，见您娘苦恹恹皮肉上挨着荆条。", "则你那出胞胎便将人事晓，须汜的您娘亲三年乳抱，怎禁这桑新妇当面闹抄抄。"]'),
('yuanqu-6713','包待制智赚灰栏记・后庭花','李行甫','元','元曲','yuanqu','','[]','我则见飕飕的棍棒拷，烘烘的脊背上着，扑扑的精神乱，悠悠的魂魄消，他们紧攥住我头梢。',146,'元曲/yuanqu.json','["我则见飕飕的棍棒拷，烘烘的脊背上着，扑扑的精神乱，悠悠的魂魄消，他们紧攥住我头梢。", "(祗从云)口退！快招了者，不强似这等受苦！(正旦唱)则听的耳边厢大呼小叫，似这般恶令史肯恕饶，狠公人显燥暴。", "(赵令史云)你招，那奸夫是谁？(孤云)他又不肯招，待我权认了罢。", "(正旦唱)被官司强逼着，指奸大要下落。"]'),
('yuanqu-6714','包待制智赚灰栏记・双雁儿','李行甫','元','元曲','yuanqu','','[]','我向那鬼门关寻觅到两三遭，您这般顺人情有甚好？则我这浓血临身要还报。',49,'元曲/yuanqu.json','["我向那鬼门关寻觅到两三遭，您这般顺人情有甚好？则我这浓血临身要还报。", "有钱的容易了，无钱的怎打煞！。"]'),
('yuanqu-6715','包待制智赚灰栏记・浪里来煞','李行甫','元','元曲','yuanqu','','[]','则您那官吏每忒狠毒，将我这百姓忒凌虐，葫芦提点纸将我罪名招。',127,'元曲/yuanqu.json','["则您那官吏每忒狠毒，将我这百姓忒凌虐，葫芦提点纸将我罪名招。", "我这里哭啼啼告天天又高，几时节盼的个清官来到？(赵令史云)掌嘴。", "我这衙门问事，真个官清法正，件件依条律的，还有那个清官清如我老爷的？(正旦哭科，唱)则我这泼残生，怎熬出这个死囚牢？(同祗从下)。"]'),
('yuanqu-6716','包待制智赚灰栏记・黄钟/醉花阴','李行甫','元','元曲','yuanqu','','[]','头上雪何曾住半霎？摧林木狂风乱刮。',101,'元曲/yuanqu.json','["头上雪何曾住半霎？摧林木狂风乱刮。", "我这更耽烦恼受嗟呀，走的来力尽筋乏，又加上些脓撼撼的棒疮发。", "(薛净云)着我们当这等苦差，还不走哩。", "(做打科)(正旦唱)怎当这嗔忿忿吖吖，但走的慢行的迟，他可便舍命的打。"]'),
('yuanqu-6717','包待制智赚灰栏记・喜迁莺','李行甫','元','元曲','yuanqu','','[]','遭这场无情的官法，方信道漫漫黄沙。',63,'元曲/yuanqu.json','["遭这场无情的官法，方信道漫漫黄沙。", "怎当的他家将咱苦打，逼勒得将招伏文状押。", "到今日有谁来怜见咱？似这等衔冤负屈，空吃尽吊拷绷扒。"]'),
('yuanqu-6718','包待制智赚灰栏记・刮地风','李行甫','元','元曲','yuanqu','','[]','绰见了容颜敢是他，莫不我泪眼昏花？再凝睛仔细观瞻罢，却原来正是无差。',233,'元曲/yuanqu.json','["绰见了容颜敢是他，莫不我泪眼昏花？再凝睛仔细观瞻罢，却原来正是无差。", "我这里挺一挺耸着肩胛，摆一摆摩着腰胯，紧待赶更那堪带锁披枷。", "(张林做看见科，云)这一个带锁披枷的妇人，是那里解将来的？(正旦叫云)哥哥。", "(唱)哥哥也，且住咱，将妹子怎生提拔？(叫云)哥哥。", "(唱)你是个洛伽山观世的活菩萨，这里不显出救人心待怎么？(叫云)哥哥，救你妹子咱。", "(张林云)你是谁？(正旦云)我是你妹子海棠。", "(张林做打推科，云)这泼娼根，那一日谢你好赍发我也。", "(做走科)(正旦做哭赶科，唱)。"]'),
('yuanqu-6719','包待制智赚灰栏记・四门子','李行甫','元','元曲','yuanqu','','[]','我道他为甚的声声把我娼根骂，似这等无明火难按纳。',92,'元曲/yuanqu.json','["我道他为甚的声声把我娼根骂，似这等无明火难按纳。", "却原来正是他，见了咱，思量起有前仇恨杀；正是他，见了咱，不邓邓嗔生怒发。", "(张走，正旦赶上做扯衣服，张林做摔科，正旦叫云)哥哥也！(唱)。"]'),
('yuanqu-6720','包待制智赚灰栏记・古寨儿令','李行甫','元','元曲','yuanqu','','[]','那婆娘面子花花，你则道所事贤达，搬调的男儿问咱家。',42,'元曲/yuanqu.json','["那婆娘面子花花，你则道所事贤达，搬调的男儿问咱家。", "他便逞俐齿，弄伶牙，对面说三般话。"]'),
('yuanqu-6721','包待制智赚灰栏记・古神仗儿','李行甫','元','元曲','yuanqu','','[]','他道我将男儿药杀，又道我将家私来尽把，又道我要混赖他孩儿，拖我去州衙中告发。',333,'元曲/yuanqu.json','["他道我将男儿药杀，又道我将家私来尽把，又道我要混赖他孩儿，拖我去州衙中告发。", "也不管难挨难熬，只一味屈敲屈打，活断送在剑头刀下。", "这的是谁做就死冤家？哎，都是那搅蛆扒。", "(云)哥哥，你在这里，我要见风去也。", "(下)(赵令史同搽旦上，云)自家赵令史的便是。", "如今将张海棠解上开封府去，我想那海棠，又无甚么亲人讨命，不若到路上结果了他，何等干净！因此特特拣两个能事的公人董超、薛霸解去。", "起身时节，每人与了五两银子，教他不必远去，只在僻静处所，便好下手。", "怎么不见来回话？事有可疑，只得和大嫂亲自打听一遭去来。", "(搽旦云)这等雪天，走了这一会，好生寒冷。", "我们且到酒店中买碗酒吃，暖暖寒再走。", "(赵令史云)大嫂说的是。", "(做进店，正旦见科，云)好也。", "他同奸夫赶到这里，待我对哥哥说来。", "(唱)。"]'),
('yuanqu-6722','包待制智赚灰栏记・节节高','李行甫','元','元曲','yuanqu','','[]','这婆娘好生心狠，好生胆大，相赶到这里，要干罢，如何干罢！(云)哥哥，奸夫奸妇都在这店里，咱和你拿他去来。',103,'元曲/yuanqu.json','["这婆娘好生心狠，好生胆大，相赶到这里，要干罢，如何干罢！(云)哥哥，奸夫奸妇都在这店里，咱和你拿他去来。", "(张林云)兄弟，你撮哺着我，拿那奸夫奸妇去也。", "(正旦唱)忙出去，休惊散，快捉拿，这的是谁风情谁当罪法。"]'),
('yuanqu-6723','包待制智赚灰栏记・挂金索','李行甫','元','元曲','yuanqu','','[]','我这里攥住衣服，则被她撇撒我阶直下，因此上走了婆娘，空做一场话。',63,'元曲/yuanqu.json','["我这里攥住衣服，则被她撇撒我阶直下，因此上走了婆娘，空做一场话。", "枉着我哥哥，气力有天来大，只恨那摆手的公人，倒说道放了奸大罢。"]'),
('yuanqu-6724','包待制智赚灰栏记・尾声','李行甫','元','元曲','yuanqu','','[]','他是奉命官差将我紧监押，不争你途路上两下争差，(张林揪董净发科)(董净揪正旦发科)(正旦唱)把我个病恹恹的罪囚没乱杀。',59,'元曲/yuanqu.json','["他是奉命官差将我紧监押，不争你途路上两下争差，(张林揪董净发科)(董净揪正旦发科)(正旦唱)把我个病恹恹的罪囚没乱杀。"]'),
('yuanqu-6725','包待制智赚灰栏记・双调/新水令','李行甫','元','元曲','yuanqu','','[]','则我这腹中冤枉有谁知？刚除的哭啼啼两行情泪。',51,'元曲/yuanqu.json','["则我这腹中冤枉有谁知？刚除的哭啼啼两行情泪。", "恨当初见不早，到今日悔何迟！他将我后拥前推，何曾道暂歇气。"]'),
('yuanqu-6726','包待制智赚灰栏记・步步娇','李行甫','元','元曲','yuanqu','','[]','你道他是高悬明镜南衙内，拚的个诉根由直把冤情洗。',67,'元曲/yuanqu.json','["你道他是高悬明镜南衙内，拚的个诉根由直把冤情洗。", "我可也怕甚的？则为带锁披枷有话难支对。", "万一个达不着大人机，哥哥也，你须是搭救你亲生妹。"]'),
('yuanqu-6727','包待制智赚灰栏记・乔牌儿','李行甫','元','元曲','yuanqu','','[]','妾身在厅阶下忙跪膝，传台旨问详细。',44,'元曲/yuanqu.json','["妾身在厅阶下忙跪膝，传台旨问详细。", "怎当这虎狼般恶狠狠排公吏，爷爷也，你听我一星星说就里。"]'),
('yuanqu-6728','包待制智赚灰栏记・甜水令','李行甫','元','元曲','yuanqu','','[]','妾身是柳陌花街，送旧迎新，舞姬歌妓。',271,'元曲/yuanqu.json','["妾身是柳陌花街，送旧迎新，舞姬歌妓。", "(包待制云)哦，你是个妓女。", "那马均卿也待的你好么？(正旦唱)与马均卿心厮爱，做夫妻。", "(包待制云)这张林说是你的哥哥，是么？(张林云)张海棠是小的妹子。", "(正旦唱)俺哥哥只为一载之前，少吃无穿，向我求觅。", "(包待制云)这等你可与他些甚的盘缠么？(正旦唱)是、是、是，他将去了我这头面衣袂。", "(张林叩头，云)小的买窝银子，就是这头面衣服倒换的。", "(包待制云)难道你丈夫不问你这头面衣服，到那里去了？(正旦云)爷爷，俺员外曾问来，就是这大浑家撺掇我与了哥哥将的去，却又对员外说我背地送了奸夫，教员外怎的不气死也！(唱)。"]'),
('yuanqu-6729','包待制智赚灰栏记・折桂令','李行甫','元','元曲','yuanqu','','[]','气的个亲男儿唱叫扬疾，(包待制云)既是他气杀丈夫，怎生又告官来？(正旦唱)没揣的告府经官，吃了些六问三推。',260,'元曲/yuanqu.json','["气的个亲男儿唱叫扬疾，(包待制云)既是他气杀丈夫，怎生又告官来？(正旦唱)没揣的告府经官，吃了些六问三推。", "(包待制云)你夫主死了，那强夺孩儿，又怎么说？(正旦唱)一壁厢夫主身亡，更待教生各札子母分离。", "(包制待云)这孩儿说是那妇人养的哩。", "(正旦唱)信着他歹心肠千般妒嫉，(包待制云)那街坊、老娘，都说是他的。", "(正旦唱)他买下了众街坊，听事儿依随。", "(包待制云)难道官吏每更不问个虚实？(正旦唱)官吏每再不问一个谁是谁非，谁信谁欺。", "(包待制云)你既是这等，也不该便招认了。", "(正旦唱)妾身本不待点纸招承，也则是吃不过这棍棒临逼。"]'),
('yuanqu-6730','包待制智赚灰栏记・雁儿落','李行甫','元','元曲','yuanqu','','[]','怎当他官不威牙爪威，也不问谁有罪谁无罪。',41,'元曲/yuanqu.json','["怎当他官不威牙爪威，也不问谁有罪谁无罪。", "早则是公堂上有对头，更夹着这祗候人无巴壁。"]'),
('yuanqu-6731','包待制智赚灰栏记・得胜令','李行甫','元','元曲','yuanqu','','[]','呀！厅阶下一声叫似一声雷，我脊梁上一杖子起一层皮。',77,'元曲/yuanqu.json','["呀！厅阶下一声叫似一声雷，我脊梁上一杖子起一层皮。", "这壁厢吃打的难挨痛，那壁厢使钱的可也不受亏。", "打的我昏迷，一下下骨节都敲碎。", "行杖的心齐，一个个腕头有气力。"]'),
('yuanqu-6732','包待制智赚灰栏记・水仙子','李行甫','元','元曲','yuanqu','','[]','街坊也却不道您吐胆倾心说真实，老娘也却不道您久年深记不得，孔目也却不道您官清法正依条例，姐姐也却不道您是第一个贤慧的，今日就开封府审问出因依。',106,'元曲/yuanqu.json','["街坊也却不道您吐胆倾心说真实，老娘也却不道您久年深记不得，孔目也却不道您官清法正依条例，姐姐也却不道您是第一个贤慧的，今日就开封府审问出因依。", "这几个流窜在边荒地，这两个受刑在闹市里，爷爷也这灰栏记传扬得四海皆知。"]'),
('yuanqu-6733','看钱奴买冤家债主・仙吕/赏花时','郑延玉','元','元曲','yuanqu','','[]','积善存仁为第一，暗室亏心天地和。',47,'元曲/yuanqu.json','["积善存仁为第一，暗室亏心天地和。", "则俺这家豪富是祖先积，只为他施仁布德，也则要博一个孝子和贤妻。"]'),
('yuanqu-6734','看钱奴买冤家债主・幺篇','郑延玉','元','元曲','yuanqu','','[]','可不道湛湛青天不可欺，举意之前悔后迟。',60,'元曲/yuanqu.json','["可不道湛湛青天不可欺，举意之前悔后迟。", "空内有神祗，(带云)俺父亲呵！(唱)不合兴心儿拆毁，今日个客路里怨他谁！(同下)。"]'),
('yuanqu-6735','看钱奴买冤家债主・仙吕/点绛唇','郑延玉','元','元曲','yuanqu','','[]','这等人轻视贫乏，不恤鳏寡。',29,'元曲/yuanqu.json','["这等人轻视贫乏，不恤鳏寡。", "天生下、一种奸滑，将神鬼都瞒唬。"]'),
('yuanqu-6736','看钱奴买冤家债主・混江龙','郑延玉','元','元曲','yuanqu','','[]','你休要虚贪声介，但存的那心田一寸是根芽。',137,'元曲/yuanqu.json','["你休要虚贪声介，但存的那心田一寸是根芽。", "不肯道甘贫守分，都则待侥幸成家。", "自拿着杀子杀孙笑里刀，怎留的好儿好女眼前花。", "你则看那阳间之事，正和俺阴府无差，明明折挫，暗暗消乏。", "这等人动则是忘人恩、背人义、昧人心，管甚么败风俗、杀风景、伤风化！怎能够长享着肥羊法酒，异锦的这轻纱？。"]'),
('yuanqu-6737','看钱奴买冤家债主・油葫芦','郑延玉','元','元曲','yuanqu','','[]','那一个红脸儿的阎王不是耍，捏胎儿依正法，则他注生的分数几曾差？这等人向官员财主里难安插，好去那驴骡狗马里刚投下。',102,'元曲/yuanqu.json','["那一个红脸儿的阎王不是耍，捏胎儿依正法，则他注生的分数几曾差？这等人向官员财主里难安插，好去那驴骡狗马里刚投下。", "又不曾将他去油锅里炸，又不曾将他去剑树上杀。", "据着那阿鼻地狱天来大，但得个人身体便可也不亏他。"]'),
('yuanqu-6738','看钱奴买冤家债主・天下乐','郑延玉','元','元曲','yuanqu','','[]','这等人何足人间挂齿牙，他前世里奢华，那一片贪财心没乱煞，则他油锅内见钱也去挝。',65,'元曲/yuanqu.json','["这等人何足人间挂齿牙，他前世里奢华，那一片贪财心没乱煞，则他油锅内见钱也去挝。", "富了他这一辈人，穷了他那数百家，今世里受贫穷还报他。"]'),
('yuanqu-6739','看钱奴买冤家债主・那吒令','郑延玉','元','元曲','yuanqu','','[]','你前世里造下，今世里折罚；前世里狡猾，今世里叫华；前世里抛撒，今世里饿杀。',150,'元曲/yuanqu.json','["你前世里造下，今世里折罚；前世里狡猾，今世里叫华；前世里抛撒，今世里饿杀。", "(贾仁云)我平昔间也是个敬天地，尊法度，和弟兄，睦六亲，信佛法，礼三光，孝父母，不偷盗。", "我是个心慈好善的人，现如今吃长斋哩！上圣，但与我些小富贵，我做本分营生买卖去也。", "(正末唱)你使的是造恶心，但说的是亏心话，不肯做本分生涯。"]'),
('yuanqu-6740','看钱奴买冤家债主・鹊踏枝','郑延玉','元','元曲','yuanqu','','[]','亏心也尽由他，造恶也怎瞒咱，上面有湛湛青天，下面有漫漫黄沙。',52,'元曲/yuanqu.json','["亏心也尽由他，造恶也怎瞒咱，上面有湛湛青天，下面有漫漫黄沙。", "请上圣鉴察，枉将他救拔，俺可管他甚贫富穷达。"]'),
('yuanqu-6741','看钱奴买冤家债主・六幺序','郑延玉','元','元曲','yuanqu','','[]','这人没钱时无些话，才的有便说夸，打扮似大户豪家。',90,'元曲/yuanqu.json','["这人没钱时无些话，才的有便说夸，打扮似大户豪家。", "你看他耸起肩胛，迸定鼻凹，没半点和气谦洽。", "每日在长街市上把青骢跨，只待要弄柳拈花，马儿上扭捏着身子儿诈。", "做出那般般样势，种种村沙！。"]'),
('yuanqu-6742','看钱奴买冤家债主・赚煞','郑延玉','元','元曲','yuanqu','','[]','则你这成家子未安身，那个破家鬼先生下。',299,'元曲/yuanqu.json','["则你这成家子未安身，那个破家鬼先生下。", "(贾仁云)我若做了财主呵，穿一架子好衣服，骑着一匹好马，去那三山骨上赠他一鞭，那马不剌剌。", "(正末云)做甚么？(贾仁云)没，我则这般道。", "(正末做笑科，唱)我则是借与你那钱龙儿入家，有限次的光阴你权掌把，(贾仁云)上圣可怜见，不知借与我几十年？(正末唱)我则是借与你二十年仍旧还他。", "(贾仁云)上圣，怎么可怜见，则借得小人二十年？左右是一个小字儿，高处再添上一画，借的我三十年，可也好也？(正末云)噤声！这厮还不足哩！(唱)你还待告增加，怎知这祸福无差，贫和富都是前缘非浪假。", "为甚么桃花向三月奋发，菊花向九秋开罢？(带云)你道为甚么那？(唱)也则为这天公不放一时花。"]'),
('yuanqu-6743','看钱奴买冤家债主・正宫/瑞正好','郑延玉','元','元曲','yuanqu','','[]','赤紧的路难通，俺可也家何在？休道是乾坤老山也头白。',48,'元曲/yuanqu.json','["赤紧的路难通，俺可也家何在？休道是乾坤老山也头白。", "四野冻云垂，万里冰花盖，肯分的俺三口儿离乡外。"]'),
('yuanqu-6744','看钱奴买冤家债主・滚绣球','郑延玉','元','元曲','yuanqu','','[]','是谁人碾琼瑶往下筛？是谁人剪冰花迷眼界？恰便似玉琢成六街承三陌，恰便似粉妆就展阁楼台。',167,'元曲/yuanqu.json','["是谁人碾琼瑶往下筛？是谁人剪冰花迷眼界？恰便似玉琢成六街承三陌，恰便似粉妆就展阁楼台。", "(带云)似这雪呵，(唱)便有那韩退之蓝关前冷怎当？便有那孟浩然驴背上也跌下来，(带云)似这雪呵，(唱)便有那剡溪中禁回他子猷访戴，则俺这三口儿兀的不冻倒尘埃？(做寒战科，带云)勿、勿、勿！(唱)眼见的一家受尽千般苦，可甚么十谒朱门九不开，委实难捱。"]'),
('yuanqu-6745','看钱奴买冤家债主・倘秀才','郑延玉','元','元曲','yuanqu','','[]','饿的我肚里饥失魂丧魄，冻的我身上冷无颜落色。',70,'元曲/yuanqu.json','["饿的我肚里饥失魂丧魄，冻的我身上冷无颜落色。", "这雪呵，偏向俺穷汉身边乱洒来。", "(带云)大嫂(唱)你看雪深埋脚面，风紧透人怀，我忙将这孩儿的手揣。"]'),
('yuanqu-6746','看钱奴买冤家债主・滚绣球','郑延玉','元','元曲','yuanqu','','[]','见哥哥酒斟着磁盏台，香浓也胜琥珀，哥哥也你莫不道小人现钱多卖，问甚么新醉茅柴。',156,'元曲/yuanqu.json','["见哥哥酒斟着磁盏台，香浓也胜琥珀，哥哥也你莫不道小人现钱多卖，问甚么新醉茅柴。", "(带云)这酒呵，(唱)赛中山宿酝开，笑兰陵高价抬，不枉了唤做那凤城春色，(带云)我饮一杯呵，(唱)恰便似重添上一件锦胎。", "(带云)这雪呵，(唱)似千团柳絮随风舞，(带云)我恰才咽下这杯酒去呵，(唱)可又早两朵桃花上脸来，便觉的和气开怀。"]'),
('yuanqu-6747','看钱奴买冤家债主・倘秀才','郑延玉','元','元曲','yuanqu','','[]','卖与个有儿女的是孩儿命衰，卖与个无子嗣的是孩儿大采，撞着个有道理的爹娘是孩儿修福来。',77,'元曲/yuanqu.json','["卖与个有儿女的是孩儿命衰，卖与个无子嗣的是孩儿大采，撞着个有道理的爹娘是孩儿修福来。", "(带云)哥哥，(唱)你救孩儿一身苦，强似把万僧斋，越显的你个哥哥敬客。"]'),
('yuanqu-6748','看钱奴买冤家债主・倘秀才','郑延玉','元','元曲','yuanqu','','[]','俺儿也差着一个字千般的见责，(云)那员外好狠也！(唱)那员外伸着五个指十分的便掴，打的他连耳通红半壁腮。',77,'元曲/yuanqu.json','["俺儿也差着一个字千般的见责，(云)那员外好狠也！(唱)那员外伸着五个指十分的便掴，打的他连耳通红半壁腮。", "说又不敢高声语，哭又不敢放声来，他则是偷将那泪揩。"]'),
('yuanqu-6749','看钱奴买冤家债主・滚绣球','郑延玉','元','元曲','yuanqu','','[]','也曾有三年乳十月胎，似珍珠掌上抬；甚工夫养得他偌大，须不是半路里拾的婴孩。',141,'元曲/yuanqu.json','["也曾有三年乳十月胎，似珍珠掌上抬；甚工夫养得他偌大，须不是半路里拾的婴孩。", "(做叹科，唱)我虽是穷秀才，他觑人忒小哉！那些个公平买卖，量这一贯钞值甚钱财！(带云)员外，你的意思我也猜着你了。", "(陈德甫云)你猜着甚的？(正末唱)他道我贪他香饵终吞钓，我则道留下青山怕没柴，拚的个搠笔巡街。"]'),
('yuanqu-6750','看钱奴买冤家债主・随煞','郑延玉','元','元曲','yuanqu','','[]','别人家便当的一周年下架容赎解，(带云)这员外呵，(唱)他巴到那五个月还钱本利该。',257,'元曲/yuanqu.json','["别人家便当的一周年下架容赎解，(带云)这员外呵，(唱)他巴到那五个月还钱本利该。", "纳了利从头儿再取索，还了钱文书上厮混赖。", "似这等无仁义愚浊的却有财，偏着俺的德行聪明的嚼齑菜。", "这八个字穷通怎的排，则除非天打算日头儿轮到来。", "发背疔疮是你这富汉的灾，禁口伤寒着你这有钱的害。", "有一日贼打劫火烧了您院宅，有一日人连累抄没了旧钱债。", "恁时节合着锅无钱买米些，忍饥饿街头做乞丐，这才是你家破人亡见天败。", "(贾仁云)你这穷弟子孩儿，还不走哩。", "(正末云)员外，(唱)你还这等苦克瞒心骂我来，直待要犯了法遭了刑你可便恁时节改。", "(同旦儿下)。"]'),
('yuanqu-6751','看钱奴买冤家债主・商调/集贤宾','郑延玉','元','元曲','yuanqu','','[]','我可便区区的步行离了汴梁，(带云)这途路好远也！(唱)过了些山隐隐更和这水茫茫。',150,'元曲/yuanqu.json','["我可便区区的步行离了汴梁，(带云)这途路好远也！(唱)过了些山隐隐更和这水茫茫。", "盼了些州城县镇，经了些店道村坊。", "遥望那东岱岳万丈巅峰，怎不见泰安州四面儿墙匡？(云)婆婆，这前面不是东岳爷爷的庙哩？(唱)这不是仁安殿盖造的接上苍，掩映着紫气红光。", "正值他春和三月天，(带云)婆婆，(唱)早来到仙阙五云乡。"]'),
('yuanqu-6752','看钱奴买冤家债主・逍遥乐','郑延玉','元','元曲','yuanqu','','[]','这的是人间天上，烧是的御赐名香，盖的是那敕修的这庙堂。',88,'元曲/yuanqu.json','["这的是人间天上，烧是的御赐名香，盖的是那敕修的这庙堂。", "我则见不断头客旅经商，还口愿百二十行。", "听的道是儿愿爹爹寿命长，又见那校椅上顶戴着亲娘。", "我这里千般感叹，万种凄惶，百样思量。"]'),
('yuanqu-6753','看钱奴买冤家债主・金菊香','郑延玉','元','元曲','yuanqu','','[]','这的是雕梁画栋圣祠堂，又不是锦帐罗帏你的卧房，怎这般厮推厮抢赶我在半壁厢？(兴儿云)你这老弟子孩儿，口里唠唠叨叨的，还说甚么哩？(正末唱)你、你、你，全不顾我这',130,'元曲/yuanqu.json','["这的是雕梁画栋圣祠堂，又不是锦帐罗帏你的卧房，怎这般厮推厮抢赶我在半壁厢？(兴儿云)你这老弟子孩儿，口里唠唠叨叨的，还说甚么哩？(正末唱)你、你、你，全不顾我这鬓雪鬟霜，(云)你这厮还要打谁？婆婆，你向前着，我不信。", "(唱)你可敢便打、打、打这个八十岁病婆娘？。"]'),
('yuanqu-6754','看钱奴买冤家债主・醋葫芦','郑延玉','元','元曲','yuanqu','','[]','你道是没钱的好受亏，有钱的好使强。',150,'元曲/yuanqu.json','["你道是没钱的好受亏，有钱的好使强。", "你和俺须同村共疃近邻庄，(兴儿云)你这叫化的不强嘴哩。", "(正末唱)俺也是钱里生来钱里长。", "怎便打的俺一个不知方向！你须不是泰安州官府到此压坛场。", "(兴儿云)官便不是官，叫做钱舍。", "(正末云)俺这无钱的好不气长也。", "(旦儿云)老的，你与他争甚么，俺每将就在那边歇罢。", "(正末唱)。"]'),
('yuanqu-6755','看钱奴买冤家债主・后庭花','郑延玉','元','元曲','yuanqu','','[]','你不肯冬三月开暖堂，你不肯夏三月舍义浆。',121,'元曲/yuanqu.json','["你不肯冬三月开暖堂，你不肯夏三月舍义浆。", "则你那情狠身中病，则你那心平便是海上方。", "您爷呵，休想道是安康，稳情取无人埋葬。", "泪汪汪甚人来守孝堂，急慌慌为亲爷来献香。", "我痛杀杀身躯儿无倚仗，他絮叨叨还口愿都是谎。", "我骨胀胀傍人谁尽让，他气昂昂不做好勾当。"]'),
('yuanqu-6756','看钱奴买冤家债主・高过浪来里煞','郑延玉','元','元曲','yuanqu','','[]','但得见亲生儿俺可也不似这凄惶，他、他、他，明欺负俺无人侍养。',168,'元曲/yuanqu.json','["但得见亲生儿俺可也不似这凄惶，他、他、他，明欺负俺无人侍养。", "(做哭科，云)俺那长寿儿也。", "(唱)想着俺长寿儿来，也和他都一般家血气方刚。", "(带云)婆婆，(唱)则俺这受苦的糟糠，卖儿呵也合将咱拦当。", "俺可甚么养小防备老，栽树要阴凉。", "想着俺那忤逆的儿郎，便成人也不认爷娘。", "有一日激恼了穹他，要整顿着纲常，你可不怕那五六月的雷声骨碌碌只在半空里响。"]'),
('yuanqu-6757','看钱奴买冤家债主・尾声','郑延玉','元','元曲','yuanqu','','[]','为一家父母昌，生下辈子孙旦。',68,'元曲/yuanqu.json','["为一家父母昌，生下辈子孙旦。", "灵椿一株老，丹桂五枝芳。", "古贤人教子有义方，您家里出不的个伯俞泣杖，量你个看钱奴也学不的窦十郎。", "(同旦儿下)。"]'),
('yuanqu-6758','看钱奴买冤家债主・越调/半鹌鹑','郑延玉','元','元曲','yuanqu','','[]','赛五岳灵神，为一人圣慈。',56,'元曲/yuanqu.json','["赛五岳灵神，为一人圣慈。", "总四海神州，受千年祭祀。", "护百二山河，掌七十四司。", "献香钱，火醮纸。", "积善的长生，造恶的便死。"]'),
('yuanqu-6759','看钱奴买冤家债主・紫花儿序','郑延玉','元','元曲','yuanqu','','[]','一个那颜回短命，一个那盗跖延年，一个那伯道无儿。',626,'元曲/yuanqu.json','["一个那颜回短命，一个那盗跖延年，一个那伯道无儿。", "人都道威灵有验，正直无私，劝化的人心慈。", "现如今神祠东岱岳新添一个速报司，大刚来祸无虚至。", "只要你恶事休行，择其这善者从之。", "(旦儿做心疼科，正末云)婆婆，你做甚么？(旦儿云)老的也，我一阵急心疼，你那里讨一杯儿酒来我吃。", "(正末云)你害急心疼，我去那酒店里讨一蛊酒去咱。", "哥哥，俺这婆婆害急心疼呵，对门那一家儿有这急心疼的药，施舍与人，你问他讨一服去。", "(正末云)是真个？俺去对门讨一服儿急心疼药去来。", "(同旦儿下)(店小二云)大清早起，利市也不曾发，这两个老的就来教化酒吃，被我支他对门讨药去了。", "便心疼杀他，也不干我事。", "我自前后执料去也。", "(下)(陈德甫上，云)自家陈德甫的便是。", "过日月好疾也，自从贾老员外买了那个小的，今经可早二十年光景了。", "老员外一生悭吝苦克，今亡逝已过。", "那小的长立成人，比他父亲在日，家私越增添了。", "他父亲在日，人都叫他做钱舍，如今那小的仗义疏财，比老员外甚的不同，人都叫他做小员外。", "老夫一向在他家上些帐目，这几年间精神老惫，只得辞了馆，开着一个小小药铺，施舍些急心疼的药。", "虽则普济贫人，然也有病好的，酬谢我些药钱，我老夫也不敢辞，好将来做药本。", "今日铺里闲坐，看有甚么人来。", "(正末同旦儿上，见科，云)先生可怜见，我那婆婆害急心疼，说先生施的好药，好汉不揣，求一服儿咱。", "(做揖科，陈德甫云)老人家免礼。", "有、有、有，我这一服药与你那婆婆吃了，登时间就好。", "则要你与我传名，我叫做陈德甫。", "(正末云)多谢了。"]'),
('yuanqu-6760','看钱奴买冤家债主・小桃红','郑延玉','元','元曲','yuanqu','','[]','你这般雪盔白发鬓如丝，(陈德甫云)你说的是几时的话？(正末唱)我说的是二十年前事。',319,'元曲/yuanqu.json','["你这般雪盔白发鬓如丝，(陈德甫云)你说的是几时的话？(正末唱)我说的是二十年前事。", "(陈德甫云)兀那老的，你那里人氏？姓甚名谁？(正末唱)你问我姓甚名谁那里人氏？(陈德甫云)你因何认得老夫来？(正夫唱)说起来痛嗟咨。", "常言道：闻钟始觉山藏寺，这搭儿里曾卖了一个小厮。", "(陈德甫云)你莫不是卖儿子的周秀才么？(正末唱)我常记的你个恩人名字，(陈德甫云)你还记得我赍发你那两贯钱么？(正末唱)我怎敢便忘了你那周急济贫时？(陈德甫云)秀才，你欢喜咱。", "你那孩儿贾长寿，如今长立成人了也。", "(正末云)贾老员外好么？(陈德甫云)老员外亡化过了也。", "(正末云)死的好，死的好！打俺孩儿的那妇人有么？(陈德甫云)那婆婆早些死了也。", "(正末云)死的好，死的好。", "(唱)。"]'),
('yuanqu-6761','看钱奴买冤家债主・鬼三台','郑延玉','元','元曲','yuanqu','','[]','则他这庞居士，世做的亏心事，恨不把穷民勒死。',544,'元曲/yuanqu.json','["则他这庞居士，世做的亏心事，恨不把穷民勒死。", "满口假悲慈，可曾有半文儿布施？(带云)想他两贯钞强买俺孩儿时节，还要与俺算饭钱哩。", "(唱)空掌着精金响钞百万资，偏没个寸男尺女为继嗣。", "俺倒不如郭巨埋儿，也强似明达卖子。", "(云)陈先生，俺那长寿孩儿好么？(陈德甫云)贾员外的万贯家财，都是你的孩儿贾长寿掌把着，人皆叫他做小员外哩。", "(正末云)陈先生可怜见，着俺那孩儿来厮见一面，可也好也？(陈德甫云)你要见他，待我寻他去。", "(小末上，云)自家贾长寿的便是。", "自从泰安山烧香回来，父亲亡逝过了，如今营葬已毕，无甚么事，去望陈德甫叔叔走一遭。", "(做撞见科，云)叔叔，我一径来望你也。", "(陈德甫云)小员外，你欢喜咱。", "(小末云)俺喜从何来？(陈德甫云)我老实的说与你知。", "你当初原不是贾老员外的儿子。", "你父亲是周秀才，偶在打员外家经过，我是保见人，将你卖与那员外为儿。", "你今日长立成人，现有你的一双父母在这里，要与你相见。", "我说兀的做甚，二十年来把你瞒，老夫说着尚心酸。", "可怜你生身父母饥寒死，直与陌路傍人做一般。", "(做见科，云)则这两个，便是你的父亲母亲，你拜他咱。", "(小末做认科，云)这是我父亲母亲？住、住、住，泰安神州，我打的不是你来？(正末云)婆婆，泰安神州打俺的，不是这厮么？(旦儿云)俺认的，他正叫做钱舍哩。", "(正末唱)。"]'),
('yuanqu-6762','看钱奴买冤家债主・幺篇','郑延玉','元','元曲','yuanqu','','[]','猛觑了这字，是俺正明师，想祖上留传到此时。',82,'元曲/yuanqu.json','["猛觑了这字，是俺正明师，想祖上留传到此时。", "是儿孙合着俺儿孙使，若不沙，怎题着公公名氏！(带云)贾员外，贾员外，(唱)亏了他二十年用心把钥匙，也则是看守俺祖上的金赀。"]'),
('yuanqu-6763','看钱奴买冤家债主・天净纱','郑延玉','元','元曲','yuanqu','','[]','若不是陈先生肯把恩施，俺周荣祖争些和雪里停尸。',54,'元曲/yuanqu.json','["若不是陈先生肯把恩施，俺周荣祖争些和雪里停尸。", "则这两贯钞俺念兹在兹，常恐怕报不得你故人之赐，又何须苦苦推辞。"]'),
('yuanqu-6764','看钱奴买冤家债主・秃厮儿','郑延玉','元','元曲','yuanqu','','[]','论你个小本钱茶坊酒肆，有甚么大度量仗义轻施，你也则可怜俺饥寒穷路不自支。',130,'元曲/yuanqu.json','["论你个小本钱茶坊酒肆，有甚么大度量仗义轻施，你也则可怜俺饥寒穷路不自支。", "如今这银一个，酬谢你酒三卮，也见俺的情私。", "(店小二云)这等，小子收了，多谢老员外。", "(正末云)孩儿，这多余的银子，你与我都散与那贫难无倚的。", "可是为何？这二十年来俺骂的那财主每多了也。", "(唱)。"]'),
('yuanqu-6765','看钱奴买冤家债主・圣药王','郑延玉','元','元曲','yuanqu','','[]','为甚么骂这厮，骂那厮，他道俺贫儿到底做贫儿。',48,'元曲/yuanqu.json','["为甚么骂这厮，骂那厮，他道俺贫儿到底做贫儿。", "又谁知彼一时，此一时，这家私原是俺家私，相对喜孜孜。"]'),
('yuanqu-6766','看钱奴买冤家债主・收尾','郑延玉','元','元曲','yuanqu','','[]','这的是贫穷富贵皆轮至，(做笑科)(陈德甫云)老员外，你笑甚来？(正末云)俺不笑别的，(唱)笑则笑贾员外一文不使。',78,'元曲/yuanqu.json','["这的是贫穷富贵皆轮至，(做笑科)(陈德甫云)老员外，你笑甚来？(正末云)俺不笑别的，(唱)笑则笑贾员外一文不使。", "单为这口衔垫背几文钱，险送了拽布拖麻孝顺子。"]'),
('yuanqu-6767','吕洞宾度铁拐李岳・仙吕/点绛唇','岳伯川','元','元曲','yuanqu','','[]','名分轻薄，俸钱些小，家私暴。',31,'元曲/yuanqu.json','["名分轻薄，俸钱些小，家私暴。", "又不会耕种锄刨，倚仗着笞杖徒流绞。"]'),
('yuanqu-6768','吕洞宾度铁拐李岳・混江龙','岳伯川','元','元曲','yuanqu','','[]','想前日解来强盗，都只为昧心钱买转了这管紫霜毫。',429,'元曲/yuanqu.json','["想前日解来强盗，都只为昧心钱买转了这管紫霜毫。", "减一笔教当刑的责断，添一笔教为从的该敲。", "这-管扭曲作宜取状笔，更狠似图财致命杀人刀。", "出来的都关来节去，私多公少，町曾有一件儿合天道？他每都指出卖磨，将百姓画地为牢。", "(吕洞宾做笑科，去)岳寿，你今年今月今日今时，你死也。", "(张千做看见科，云)哥哥，有一个风魔先生，哭三声，笑三声，在咱门首闹哩。", "(正末怒，云)这先生好无礼也。", "他是盆儿，我是罐儿，他敢不知道岳孔目的名儿？我试看咱。", "(做见科，云)兀那先生，为甚在我门首，哭三声，笑三声？这是怎说？(吕洞宾云)岳寿，你是个没头鬼，你死也。", "(正末云)呸！你看我悔气。", "连日接新官不着，来家吃饭，又被这泼先生骂我是没头鬼。", "(旦上，云)孔目你不知，孩儿下学来吃饭，被这先生骂孩儿是没爷业种，又骂我是寡妇，好无礼也。", "(正末云)大嫂，你家里去，等我问他。", "兀那先生，我那孩儿恼着你甚么来？你骂他。", "(吕洞宾云)岳寿，没头鬼，你死也，这孩儿就是无爷业种。", "(正末云)这泼先生好无礼也，(唱)。"]'),
('yuanqu-6769','吕洞宾度铁拐李岳・油葫芦','岳伯川','元','元曲','yuanqu','','[]','你欺负俺孩儿年纪小，出家人厮扇摇，吃的来滴滴邓邓醉陶陶。',120,'元曲/yuanqu.json','["你欺负俺孩儿年纪小，出家人厮扇摇，吃的来滴滴邓邓醉陶陶。", "门前哭罢门前笑，街头指定街头闹。", "孩儿他娘引着，你骂他爷死了。", "(吕洞宾云)我是个出家人，你怎生近的我？(正末唱)也不索宫中插状衙中告，(带云)我要禁持你至容易，(唱)只消得二指阔纸提条。"]'),
('yuanqu-6770','吕洞宾度铁拐李岳・天下乐','岳伯川','元','元曲','yuanqu','','[]','敢把你拖到官司便下牢，我先教你，省会了你和那打家贼并排压定脚。',71,'元曲/yuanqu.json','["敢把你拖到官司便下牢，我先教你，省会了你和那打家贼并排压定脚。", "祗从人解了你绦，首领每剥了你袍，(带云)休道是先生，(唱)我着你似生驴般吃顿拷。"]'),
('yuanqu-6771','吕洞宾度铁拐李岳・金盏儿','岳伯川','元','元曲','yuanqu','','[]','你道是新官正决难逃，俺这旧吏富易通交。',70,'元曲/yuanqu.json','["你道是新官正决难逃，俺这旧吏富易通交。", "眼见得一官二吏三年了，家私休想落分毫。", "他这新官倚俸禄，俺这旧吏靠窠巢。", "他这官清司吏瘦，俺这家富小儿娇。"]'),
('yuanqu-6772','吕洞宾度铁拐李岳・醉扶归','岳伯川','元','元曲','yuanqu','','[]','你问他在村镇居城郭？(张千云)兀那老子，俺哥哥问你城里住？村里住？(韩魏公云)哥哥，老汉村里也有庄儿，城里也有宅儿。',508,'元曲/yuanqu.json','["你问他在村镇居城郭？(张千云)兀那老子，俺哥哥问你城里住？村里住？(韩魏公云)哥哥，老汉村里也有庄儿，城里也有宅儿。", "(张千云)这老头子，硬头硬脑的，正是躲避差徭游食户。", "村里寻往城里去。", "城里寻往村里去。", "你则在这里，我回俺哥哥话去。", "(做见正末，云)哥哥，那村老子说：城里也有宅儿，村里也有庄儿。", "(正末云)这老子好无礼也，他回我这等话。", "张千，你敢问的差了也，你则依着我再问他去。", "(唱)你问他当军役纳差徭。", "(张千云)兀那老子，俺哥哥着我问你当差是军身？是民户？(韩魏公云)老汉军差也当，民差也当。", "因老汉有几文钱，又当站户哩。", "(张千云)你军差也当，民差也当，因有钱又当站户？(韩魏公云)是。", "(张千云)他是埋头财主。", "我回哥哥话去。", "(做见正末，云)哥哥，他说军差也当，民差也当，因有钱又当站户哩。", "(正末云)噤声！这厮好不干事，跟我这几年了，着这庄家老子使的两头回来走的，你则依着我再问去。", "(唱)你问他开铺席为经商可也做甚手作？(张千云)兀那老子，你可开铺席，做经商的，是什么手作？(正末云)张千你再问他。", "(唱)你与我审个住处查个名号。", "(张千云)他是个庄家老子，只管要问他住处怎的？(正末唱)我多待不的三日五朝，将他那左解的冤仇报。"]'),
('yuanqu-6773','吕洞宾度铁拐李岳・金盏儿','岳伯川','元','元曲','yuanqu','','[]','他或是使斗秤拿个大小等个低高，(云)我禁的他么？(张千云)他不卖粮食，开个段子铺儿，你怎生禁他？(正末云)更好奈何他哩。',387,'元曲/yuanqu.json','["他或是使斗秤拿个大小等个低高，(云)我禁的他么？(张千云)他不卖粮食，开个段子铺儿，你怎生禁他？(正末云)更好奈何他哩。", "(唱)或是他卖段匹拣个宽窄觑个纰薄。", "(云)我奈何的他么？(张千云)他也不做买卖，每日闭着门，只在家里坐，你怎生奈何他？(正末云)我越好奈何他哩。", "(唱)或是他粉壁迟水瓮小拖出来我则就这当街拷。", "(张千云)他城里也不住，搬在乡里住，你怎生奈何他？(正末云)我正好奈何他。", "(唱)便是他避城中居乡下，我则着司房中勾一遭。", "(带云)他来的疾便罢，来的迟呵，加上个顽慢二字。", "(唱)我着他便有祸，(带云)他依着我便罢，若不依我呵，我下上个欺官枉吏四个字。", "(唱)我着他便违条。", "(带云)这老子是下户，我添做中户，是中户我添做上户的差徭。", "(唱)我着那挑河夫当一当直穷断那厮筋，(带云)我更狠一狠呵，(唱)我着那打家贼指一指，(带云)轻便是寄脏，重便是知情。", "(唱)我直拷折那厮腰。"]'),
('yuanqu-6774','吕洞宾度铁拐李岳・后庭花','岳伯川','元','元曲','yuanqu','','[]','怕不初来时妆会幺，看他间深里探会爪。',50,'元曲/yuanqu.json','["怕不初来时妆会幺，看他间深里探会爪。", "我见先他见后，他临行我放刁，笑里暗藏刀。", "代官来到，不道咱轻放了。"]'),
('yuanqu-6775','吕洞宾度铁拐李岳・金盏儿','岳伯川','元','元曲','yuanqu','','[]','有了状但去呵决私逃，停了俸但住呵怎轻饶。',79,'元曲/yuanqu.json','["有了状但去呵决私逃，停了俸但住呵怎轻饶。", "离了官房没了倚靠，绝了左右没了牙爪。", "我直着他典了衣卖了马，方见俺心似铁笔如刀。", "饶他便会钻天能入地，怎当俺拿住脚放头稍。"]'),
('yuanqu-6776','吕洞宾度铁拐李岳・赚煞尾','岳伯川','元','元曲','yuanqu','','[]','赤紧的官长又廉，曹司又拗，我便是好令史怎禁他三遍家取招。',133,'元曲/yuanqu.json','["赤紧的官长又廉，曹司又拗，我便是好令史怎禁他三遍家取招。", "我今日为头便把交，争奈在前事乱似牛毛。", "有人若是但论着，休想道肯担饶。", "早停了俸追了钱断罢了。", "不是我千错万错，大刚来一还一报。", "(带云)他道我是大鹏金翅雕。", "哎哟！(唱)谁想那百姓每的口也是祸之门，舌是斩身刀。", "(下)。"]'),
('yuanqu-6777','吕洞宾度铁拐李岳・正宫/端正好','岳伯川','元','元曲','yuanqu','','[]','你装裹我二十重，或是三十件。',62,'元曲/yuanqu.json','["你装裹我二十重，或是三十件。", "(旦云)你置下的合该你穿。", "(正末唱)你道是我置下我死合穿，知他土坑中埋我多深浅，装裹杀也无人见。"]'),
('yuanqu-6778','吕洞宾度铁拐李岳・滚绣球','岳伯川','元','元曲','yuanqu','','[]','妻也空费你心，你也索听我言。',118,'元曲/yuanqu.json','["妻也空费你心，你也索听我言。", "这衣服呵且休算万针千线，也不论旧絮新绵。", "你如今值着业冤，使着死钱。", "这衣服但存几件，(旦云)你命也不保留着他做甚么？(正末唱)怕你子母每受穷时典卖盘缠。", "比如包尸裹骨棺函内烂，把似遇节迎寒您子母每穿，省可里熬煎。"]'),
('yuanqu-6779','吕洞宾度铁拐李岳・倘秀才','岳伯川','元','元曲','yuanqu','','[]','也不索嘱付你千言万言，想着咱同衙府十年五年。',111,'元曲/yuanqu.json','["也不索嘱付你千言万言，想着咱同衙府十年五年。", "(带云)倘我死之后。", "(唱)你是必打听着山妻，照顾着豚犬。", "他一头亡了夫主，废了家缘，(带云)您嫂嫂是个年少妇人家，(唱)他从来腼腆。", "(孙福云)哥哥放心，便怎生有这等事？(正末唱)。"]'),
('yuanqu-6780','吕洞宾度铁拐李岳・叨叨令','岳伯川','元','元曲','yuanqu','','[]','怕有那无廉耻谎汉子胡来缠，(孙福云)嫂嫂不比其他的人。',196,'元曲/yuanqu.json','["怕有那无廉耻谎汉子胡来缠，(孙福云)嫂嫂不比其他的人。", "(正末云)兄弟也，我死之后，有那等谎厮上门来。", "(唱)则你那无主意拙嫂嫂从来善，则要你无私曲好兄弟频来见，(带云)你见你那嫂子有不中处，你说不出来呵。", "(唱)着你那无面目的婶子儿便将他劝。", "(孙福云)着媳妇子劝些甚么？(正末云)着婶子劝道：姆姆，俺伯伯是人面上的人，你要爱惜行止。", "(唱)着言语劝他也么哥，着语劝他也么哥，岂不闻临危好与人方便？。"]'),
('yuanqu-6781','吕洞宾度铁拐李岳・倘秀才','岳伯川','元','元曲','yuanqu','','[]','或是祭先祖逢冬遇年，(云)到那冬年时节，月一十五，孩儿又小，上坟呵，大嫂，你可出去见人么？(旦云)我不去，着张千引着孩儿坟上烧纸便了。',217,'元曲/yuanqu.json','["或是祭先祖逢冬遇年，(云)到那冬年时节，月一十五，孩儿又小，上坟呵，大嫂，你可出去见人么？(旦云)我不去，着张千引着孩儿坟上烧纸便了。", "(正末云)这个且罢。", "(唱)或是待亲戚排筵坐筵，(云)福童孩儿娶媳妇，六亲相识每吃筵席，你不出去支待，着谁支待？(旦云)若有女客来，我便支待，若有男客来，着张千支待罢。", "(正末云)大嫂，若有呵。", "(唱)非五服内男儿不曾教见一见？则为你有人材多娇态，不老相正中年，(带云)我死之后。", "(唱)你休忘了大人家体面。"]'),
('yuanqu-6782','吕洞宾度铁拐李岳・滚绣球','岳伯川','元','元曲','yuanqu','','[]','你必索迎门儿接纸钱，(旦云)孔目也，你直恁般多心。',406,'元曲/yuanqu.json','["你必索迎门儿接纸钱，(旦云)孔目也，你直恁般多心。", "我着张千领着孩儿出去迎接，我只不见人便了。", "(正末云)可早一桩儿也，这个也罢。", "我死之后，停到一七者波，便停到二七者波，想着咱二十年儿女夫妇，你没的不送我到郊外。", "(唱)又索随灵车哭少年，(云)有那等年纪小的后生便道：岳孔目有个好浑家。", "三门四户不出，无人能勾得见，今日出来送岳也目的殡，咱看去来。", "(唱)那其间任谁都见，(带云)见了你这个中注模样，(唱)有那等厮图谋的贼汉心专。", "(云)有那谎汉每便道：这个是岳孔目的浑家。", "我久已后，好歹要娶了他。", "(唱)俺亲眷行除孝服，你爷娘行使会钱，(带云)俺的亲眷，你的爷娘，都肯了，只你不肯。", "(唱)他与你些打眼目的衣服头面，(云)你见了好衣服，好头面，那里还想我哩。", "(旦云)孔目也，我坚心守志，怎生肯嫁别人？(正末唱)你便守熬呵刚捱到服满三年。", "你嫁个知心可意新家长，(带云)哎哟，福童儿也，(唱)那里发付那有母无爷小业冤，就儿里难言。"]'),
('yuanqu-6783','吕洞宾度铁拐李岳・脱布衫','岳伯川','元','元曲','yuanqu','','[]','我和你十七八共枕闷眠，二十载儿女姻缘。',46,'元曲/yuanqu.json','["我和你十七八共枕闷眠，二十载儿女姻缘。", "一脚地停尸在眼前，(带云)妻阿！(唱)则落的酒茶浇奠。"]'),
('yuanqu-6784','吕洞宾度铁拐李岳・小梁州','岳伯川','元','元曲','yuanqu','','[]','怕不的痛哭灵堂守志坚，两泪涟涟。',54,'元曲/yuanqu.json','["怕不的痛哭灵堂守志坚，两泪涟涟。", "有那等赢奸卖俏俊官员，早聘下金钗钏，(带云)你见了呵，(唱)还守的几多年？。"]'),
('yuanqu-6785','吕洞宾度铁拐李岳・幺篇','岳伯川','元','元曲','yuanqu','','[]','那里想夫妻往日心厮恋，也是前世前缘。',69,'元曲/yuanqu.json','["那里想夫妻往日心厮恋，也是前世前缘。", "嘱付你小业冤，听爷劝。", "您娘别寻了缱绻，(带云)若有人与你金银钱物呵，(唱)你是必休、是必休接受买服钱。"]'),
('yuanqu-6786','吕洞宾度铁拐李岳・倘秀才','岳伯川','元','元曲','yuanqu','','[]','笑里刀一千声抱怨，(带云)我见新宫到呵。',73,'元曲/yuanqu.json','["笑里刀一千声抱怨，(带云)我见新宫到呵。", "(唱)马前剑有三千个利便。", "旧官行揩勒些东西，新官行过度些钱。", "见起由难似产，听得到照会紧如烟，做多少家罪谴。"]'),
('yuanqu-6787','吕洞宾度铁拐李岳・滚绣球','岳伯川','元','元曲','yuanqu','','[]','新官若清得意虔，旧官若米得自然。',164,'元曲/yuanqu.json','["新官若清得意虔，旧官若米得自然。", "(云)新官到任，衙门中事，必须问俺，我从头说一遍，再访之于旧官相同，所谓旧令尹之政，必以告新令尹。", "(唱)若是新官和旧官相见，旧尹政新尹合传。", "问衙事那个虚那个实，那个愚那个贤，议论咱六房中吏人-遍。", "咱那前程事，则消得旧官去新官行附耳低言。", "把那奸猾刁刺的州县里剖，将那清干忠直的向省部内迁，平地升仙。"]'),
('yuanqu-6788','吕洞宾度铁拐李岳・倘秀才','岳伯川','元','元曲','yuanqu','','[]','他那擎天柱官人每得权，俺拖地胆曹司又爱钱。',73,'元曲/yuanqu.json','["他那擎天柱官人每得权，俺拖地胆曹司又爱钱。", "(带云)兄弟也。", "(唱)你须知我六案间，峥嵘了这几年。", "也曾在饥喉中夺饭吃，冻尸上剥衣穿。", "便早死呵不敢怨天。"]'),
('yuanqu-6789','吕洞宾度铁拐李岳・滚绣球','岳伯川','元','元曲','yuanqu','','[]','儿呵！你学使牛学种田，你自养蚕自摘茧。',96,'元曲/yuanqu.json','["儿呵！你学使牛学种田，你自养蚕自摘茧。", "农庄家这衣饭稳善，便刷卷呵我也只自安然。", "当军呵你自当，做夫呵快向前。", "剩纳些税粮丝绢，只守着本等家缘，你若不辞白屋农桑苦，免似你爷请受公门俸禄钱，无罪无愆。"]'),
('yuanqu-6790','吕洞宾度铁拐李岳・三煞','岳伯川','元','元曲','yuanqu','','[]','妻呵！你将这干家私使心力二十年夫主相随见，把你这忒娇养正愚顽十一岁免家嘶可怜。',126,'元曲/yuanqu.json','["妻呵！你将这干家私使心力二十年夫主相随见，把你这忒娇养正愚顽十一岁免家嘶可怜。", "教孩儿镇守亲娘，休遭继父，专记临终，莫忘遗言。", "若孩儿不官呵，教听些有理的公事，为民呵，教做些有理的营生，为吏呵，教取些有理的入钱。", "休教我这白骨头上作贱，我便死也口眼闭在黄泉。"]'),
('yuanqu-6791','吕洞宾度铁拐李岳・二煞','岳伯川','元','元曲','yuanqu','','[]','你为夫上呵似孟光般举案非为谄，你为孩儿呵似陈母般埋金恰是贤。',94,'元曲/yuanqu.json','["你为夫上呵似孟光般举案非为谄，你为孩儿呵似陈母般埋金恰是贤。", "常则是户静门清，上和下睦，立计成家，众口流传。", "那时节保香名到省内，除杂役在官中，立绰楔在门前。", "教满城人钦羡，强如哭一万遍少年天。"]'),
('yuanqu-6792','吕洞宾度铁拐李岳・煞尾','岳伯川','元','元曲','yuanqu','','[]','你学那守三贞赵真女罗裙包土将坟茔建，休学那犯十恶桑新妇彩扇题诗则将那墓顶扇。',123,'元曲/yuanqu.json','["你学那守三贞赵真女罗裙包土将坟茔建，休学那犯十恶桑新妇彩扇题诗则将那墓顶扇。", "黑娄娄潮上涎，铁屑屑手腕软，直挺挺腿怎拳。", "铜斗儿家私不能勾擅，血点儿相识不能勾面，花朵般浑家不能勾恋，魔合罗孩儿不能勾见。", "半世团圆分福浅，则俺这三口儿相逢路儿远。", "(下)。"]'),
('yuanqu-6793','吕洞宾度铁拐李岳・仙吕/赏花时','岳伯川','元','元曲','yuanqu','','[]','火炕里消息我敢踏，油镬内钱财我敢拿，则为我能跳塔快轮铡。',67,'元曲/yuanqu.json','["火炕里消息我敢踏，油镬内钱财我敢拿，则为我能跳塔快轮铡。", "今日向阴司折罚，(牛头云)我一叉跳下油镬去。", "(正末慌科，唱)望着番滚滚热油叉。"]'),
('yuanqu-6794','吕洞宾度铁拐李岳・幺篇','岳伯川','元','元曲','yuanqu','','[]','我手扯住环绦礼拜他，(吕洞宾云)岳寿，你晓得人有生死么？(正末云)师父救徒弟咱。',583,'元曲/yuanqu.json','["我手扯住环绦礼拜他，(吕洞宾云)岳寿，你晓得人有生死么？(正末云)师父救徒弟咱。", "(吕洞宾云)油锅虽热，全真不傍，苦海无边，回头是岸。", "岳寿你省也么？(正末云)徒弟省了也。", "(吕洞宾云)跟我出家去来。", "(正末云)情愿跟师父出家。", "(吕洞宾云)鬼力，且留下，等我见阎君去。", "(吕做见阎王科，阎王云)早知上仙到来，只合远接，接待不周，勿令见罪。", "(吕洞宾云)岳寿所犯何罪，叉入九鼎油锅？(阎王云)因他在阳间做六案都孔目，造罪极多，又触犯上仙，因此又入油镬。", "(吕洞宾云)上帝好生之德。", "阎君看贫道面上，免岳寿油镬之罪，化与贫道做个徒弟，放他回阳间去罢。", "(阎王云)待我看咱。", "(做望科，云)可怜也，岳寿的妻，将他尸骸焚化，还魂不的了也。", "(吕洞宾云)却怎了？阎君你再与我看一看去。", "(阎王云)待小圣再看去。", "(做看科，云)上仙，有今郑州奉宁郡东关里青眼老李屠的儿子小李屠死了三日，热气末断，着岳寿借尸还魂去？上仙可是如何？(吕洞宾云)好、好、好！岳寿，谁想你浑家将你尸骸烧化了，我如今着你借尸还魂，尸骸是小李屠，魂灵是岳寿，休迷了本来面目。", "若到人间，休恋着酒色财气，人我是非，贪嗔痴爱。", "你听者，前姓休移后姓莫改，双名李岳，道号铁拐。", "迷离阴府者。", "(正末云)大嫂你好狠也，把我多留几日，怕做甚么那？(唱)听的道烧了我尸骸，将我来没乱煞。", "俺妻子知他是怎生么？若放我回家儿半霎，只当似枯树上再开花。", "(下)。"]'),
('yuanqu-6795','吕洞宾度铁拐李岳・双调/新水令','岳伯川','元','元曲','yuanqu','','[]','只俺个把官猾吏堕阿鼻，多谢得吕先生化为徒弟。',50,'元曲/yuanqu.json','["只俺个把官猾吏堕阿鼻，多谢得吕先生化为徒弟。", "家里啼哭杀娇养子，没乱杀脚头妻。", "生死轮回，一去了早三日。"]'),
('yuanqu-6796','吕洞宾度铁拐李岳・沽美酒','岳伯川','元','元曲','yuanqu','','[]','知道他准是谁？我将你记一记，委实、委实不认的。',101,'元曲/yuanqu.json','["知道他准是谁？我将你记一记，委实、委实不认的。", "(旦儿云)李屠，你不认的我么？我是你浑家。", "(孛老云)孩儿，你怎生说这等话？孩儿，我是你父亲，你魂迷了，忘记了也。", "(正末唱)却怎生一发的闹起，知他是甚亲戚？。"]'),
('yuanqu-6797','吕洞宾度铁拐李岳・太平令','岳伯川','元','元曲','yuanqu','','[]','依旧有青天白日，则不见幼子娇妻。',573,'元曲/yuanqu.json','["依旧有青天白日，则不见幼子娇妻。", "我才离了三朝五日，儿也这其间哭的你一丝两气。", "我如今在这里，不知他在那里，几时得父子夫妻完备？(云)张千，你与我拿将下去。", "(孛老云)孩儿，怎生说这话？我是你爹爹。", "(正末云)我倒是你公公哩。", "(孛老云)你听我说，你是我儿子小李屠，今日死了三日也，心头有些热，不曾送出去。", "今日你还魂来了，怎生不认的我了？(旦儿云)李屠，我是你浑家，怎生不认的？(正末云)休要大惊小怪的，等我寻思咱。", "(做沉吟科，背云)我是岳寿，骂了韩魏公，得了这一惊，唬死了。", "我死至阴府，阎君将我叉入九鼎油镬。", "是吕先生救了，着我还魂。", "谁想岳大嫂烧了我的尸骸，着我借尸还魂。", "尸骸是李屠的，魂灵是岳寿的。", "这里敢是李屠家里，我待看岳大嫂和福童孩儿，怎生得去？只除是这般。", "(向众云)我虽是还魂回来，我这三魂不全，一魂还在城隍庙里，我自家取去。", "(孛老云)媳妇儿，快收拾香纸，咱替孩儿取魂去。", "(旦儿云)爷！休教他去。", "(正末云)我自家取去，您是生人，惊散了我的魂灵，我又是死的了。", "你休来，我自己取去。", "(正末起身，跌倒科，云)哎哟！跌杀我也。", "(孛老云)孩儿，你一条腿瘸，你走不动。", "(旦儿云)你一了瘸。", "(正末云)怎生腿瘸？师父也，把似你与我个完全尸首，怕做甚么呢？(孛老云)你有一条拐，我拿将来你拄着，你便行的动。", "(正末云)将来，将来。", "(做柱拐起身行科，旦儿云)我扶将你去。"]'),
('yuanqu-6798','吕洞宾度铁拐李岳・雁儿落','岳伯川','元','元曲','yuanqu','','[]','则我那一管笔扭曲直，一片心瞒天地。',31,'元曲/yuanqu.json','["则我那一管笔扭曲直，一片心瞒天地。", "一家儿享富贵，一辈儿无差役。"]'),
('yuanqu-6799','吕洞宾度铁拐李岳・得胜令','岳伯川','元','元曲','yuanqu','','[]','俺只道一世里吃不尽那东西，谁承望半路里脚残疾。',98,'元曲/yuanqu.json','["俺只道一世里吃不尽那东西，谁承望半路里脚残疾。", "为甚么尸首儿登途慢，则为我魂灵儿探爪迟。", "则为当日，骂韩魏公一场怕一场气，至如今日，(带云)若有人说：脑背后韩魏公来也。", "(唱)哎哟！唬的我一脚高一脚低。"]'),
('yuanqu-6800','吕洞宾度铁拐李岳・庆东原','岳伯川','元','元曲','yuanqu','','[]','为甚我今日身不正，则为我往常心不直，和那鬼魂灵不能勾两脚踏实地。',78,'元曲/yuanqu.json','["为甚我今日身不正，则为我往常心不直，和那鬼魂灵不能勾两脚踏实地。", "至如省里部里，台里院里，咱只说府里州驻。", "他官人每一个个要为国不为家，怎知道也似我说的行不的。"]'),
('yuanqu-6801','吕洞宾度铁拐李岳・川拨棹','岳伯川','元','元曲','yuanqu','','[]','俺自从做夫妻二十年几曾离了半日，早起去衙里便是分离。',92,'元曲/yuanqu.json','["俺自从做夫妻二十年几曾离了半日，早起去衙里便是分离。", "晚夕来到家里，那场欢喜。", "满门贤惠，一划精细，要一供十，举案齐眉，那些夫妻道理。", "听的当远差教休出去，早教我推病疾，今日受烦恼有甚尽期。"]'),
('yuanqu-6802','吕洞宾度铁拐李岳・七弟兄','岳伯川','元','元曲','yuanqu','','[]','那一七，二七，哭啼啼，尽七少似头七泪。',35,'元曲/yuanqu.json','["那一七，二七，哭啼啼，尽七少似头七泪。", "亲人约束外人欺，独自坐地独自睡。"]'),
('yuanqu-6803','吕洞宾度铁拐李岳・梅花酒','岳伯川','元','元曲','yuanqu','','[]','看看的过百日，官事又萦羁，衣食又催逼，儿女又央及。',119,'元曲/yuanqu.json','["看看的过百日，官事又萦羁，衣食又催逼，儿女又央及。", "那婆娘人材迭七八分，年纪勾四十岁。", "不争我去的迟，被那家使心力，使心力厮搬递，厮搬递卖东西，卖东西到家里，到家里看珠翠，看珠翠寄钗篦，寄钗篦定成计，定成计使良媒，使良媒怎支持，怎支持谎人贼。"]'),
('yuanqu-6804','吕洞宾度铁拐李岳・收江南','岳伯川','元','元曲','yuanqu','','[]','我只怕谎人贼营勾了我那脚头妻，脚头妻害怕便依随，依随了一遍怎相离？我如今在这里，(云)适才李屠的浑家，也有些颜色。',127,'元曲/yuanqu.json','["我只怕谎人贼营勾了我那脚头妻，脚头妻害怕便依随，依随了一遍怎相离？我如今在这里，(云)适才李屠的浑家，也有些颜色。", "着我就这里不中。", "(唱)我这里得便宜，俺浑家敢那里落便宜。", "(带云)我想这做屠户的，虽是杀生害命，还强似俺做吏人的瞒心昧己，欺天害人也。", "(唱)。"]'),
('yuanqu-6805','吕洞宾度铁拐李岳・太清歌','岳伯川','元','元曲','yuanqu','','[]','他退猪汤不热如俺浓研的墨，他杀狗刀不快如俺完成笔。',102,'元曲/yuanqu.json','["他退猪汤不热如俺浓研的墨，他杀狗刀不快如俺完成笔。", "他虽是杀生害命为家计，这恶业休提。", "俺请受了人几文钱改是成非，似这般所为，碜可可的活取民心髓，抵多少猪肝猪蹄。", "也则是秤大小为生过日，不强似俺着人脓血换人衣。"]'),
('yuanqu-6806','吕洞宾度铁拐李岳・川拨棹','岳伯川','元','元曲','yuanqu','','[]','想当初去衙里，马儿上稳坐地。',51,'元曲/yuanqu.json','["想当初去衙里，马儿上稳坐地。", "挺着腰肋，捻着髭须。", "引着亲随，傲着相知。", "似那省官气势，到如今折罚来直恁的。"]'),
('yuanqu-6807','吕洞宾度铁拐李岳・中吕/粉蝶儿','岳伯川','元','元曲','yuanqu','','[]','大院深宅，闲杂人赶离门外，与亡灵累七修斋。',62,'元曲/yuanqu.json','["大院深宅，闲杂人赶离门外，与亡灵累七修斋。", "则俺那守服的妻，带孝的子，争知我在也不在。", "若听的岳孔目回来，孩儿每那一场大惊小怪。"]'),
('yuanqu-6808','吕洞宾度铁拐李岳・醉春风','岳伯川','元','元曲','yuanqu','','[]','则俺情意重如山，那里也侯门深似海。',118,'元曲/yuanqu.json','["则俺情意重如山，那里也侯门深似海。", "(做叫门，云)岳大嫂开门来。", "(岳旦开门，云)一个鏖槽叫化头，出去！(做推倒末科)(正末唱)出门来推了个脚梢天，这婆娘不将我睬，睬！(带云)大嫂，你不睬也罢。", "(唱)怎将我擘面拳敦，涌身推抢，那里降阶接待。"]'),
('yuanqu-6809','吕洞宾度铁拐李岳・十二月','岳伯川','元','元曲','yuanqu','','[]','唬的我忘魂丧魄，谢吕洞宾免难除灾。',54,'元曲/yuanqu.json','["唬的我忘魂丧魄，谢吕洞宾免难除灾。", "阎罗王饶过我性命，你把岳孔目烧毁了尸骸。", "一灵儿无处百刂划，空教人雨泪盈腮。"]'),
('yuanqu-6810','吕洞宾度铁拐李岳・尧民歌','岳伯川','元','元曲','yuanqu','','[]','我一灵儿先到望乡台，将这李屠尸首借回来。',90,'元曲/yuanqu.json','["我一灵儿先到望乡台，将这李屠尸首借回来。", "为孤儿寡妇动情怀，因此上瘸足兼跛足践尘埃。", "哀也波哉，特地望你来，怎下的推我出宅门外。", "(岳旦云)原来是也目借尸还魂，这等你且进来。", "(正未唱)。"]'),
('yuanqu-6811','吕洞宾度铁拐李岳・红绣鞋','岳伯川','元','元曲','yuanqu','','[]','贤达妇将咱休怪，这奸猾心把你胡猜。',81,'元曲/yuanqu.json','["贤达妇将咱休怪，这奸猾心把你胡猜。", "盖世间那个不是水性女裙钗，把亲夫殡抬出去，不曾把后老子招将来？我比你倒拄着一半拐。", "(岳旦云)孔目，你怎生这等模样了？(正末唱)。"]'),
('yuanqu-6812','吕洞宾度铁拐李岳・喜春来','岳伯川','元','元曲','yuanqu','','[]','我往常见那有钱无理的慌分解，见有理无钱的即便拍，瞒心昧己觅钱财。',51,'元曲/yuanqu.json','["我往常见那有钱无理的慌分解，见有理无钱的即便拍，瞒心昧己觅钱财。", "为甚我两个脚一个歪，也是我前世不修来。"]'),
('yuanqu-6813','吕洞宾度铁拐李岳・迎仙客','岳伯川','元','元曲','yuanqu','','[]','一个家嗔忿忿，一个家闹咳咳，改不了司房里欺人恶性格。',366,'元曲/yuanqu.json','["一个家嗔忿忿，一个家闹咳咳，改不了司房里欺人恶性格。", "孙福咱相识二十年，张千你随我六七载。", "哎，没上下村材，怎不把岳孔目哥哥拜？(岳旦云)这人不是叫化的，是你哥哥岳孔目。", "(张千云)呸！俺哥哥怎生这般嘴脸？(正末云)孙福、张千，我是你哥哥岳寿。", "(张千云)你道是岳孔目，你怎生死了来？(正末云)我借李屠尸首还魂回来，你怎生不认我？(孙福、张千做悲科，云)原来是孔目哥哥借尸还魂了也。", "(孛老同旦儿上，云)我远远的跟着，孩儿往这一家里去了也，只得跟进去。", "(做见科，云)孩儿，你在这里做甚么？咱回家去来。", "(正末云)这是俺家里。", "(岳旦云)这是我的夫主。", "(李旦云)他是我的丈夫。", "(众争认科)(张千夺拐打孛老科)(正末做劝，跌倒科，云)张千，我须有些瘸。", "(张千发科，云)你可不早说与我。", "(孛老云)我家的儿子认了别人，更待干罢。", "俺去告官去来。", "(众同下)。"]'),
('yuanqu-6814','吕洞宾度铁拐李岳・快活三','岳伯川','元','元曲','yuanqu','','[]','恁的官法严把牛马宰，你见行市紧早母猪灾。',40,'元曲/yuanqu.json','["恁的官法严把牛马宰，你见行市紧早母猪灾。", "悬羊头卖狗肉赖人财，倚仗着秤儿小刀儿快。"]'),
('yuanqu-6815','吕洞宾度铁拐李岳・鲍老催','岳伯川','元','元曲','yuanqu','','[]','你正是拾的孩儿落的摔，待将我细切薄批卖。',101,'元曲/yuanqu.json','["你正是拾的孩儿落的摔，待将我细切薄批卖。", "(韩魏公云)这桩事，着老夫怎生下断？(吕洞宾冲上科，云)韩魏公，休错断了事也。", "(正末唱)有德行的吾师恰到来，我这里掂脚舒腰拜。", "好着我慌慌乱乱，劳劳嚷嚷，怨怨哀哀。"]'),
('yuanqu-6816','吕洞宾度铁拐李岳・上小楼','岳伯川','元','元曲','yuanqu','','[]','我如今把玉锁顿开，金枷不带。',52,'元曲/yuanqu.json','["我如今把玉锁顿开，金枷不带。", "撇了酒色，辞了财气，跳出墙来。", "上的街，化了斋，别无妨碍，只望完全了乞儿皮袋。"]'),
('yuanqu-6817','吕洞宾度铁拐李岳・幺篇','岳伯川','元','元曲','yuanqu','','[]','抹了钵盂，装在布袋。',53,'元曲/yuanqu.json','["抹了钵盂，装在布袋。", "褴褴缕缕，悲悲邓邓，往往来来。", "拄着拐，穿草鞋，麻袍宽袂。", "但得个无烦恼，恰胜似紫袍金带。"]'),
('yuanqu-6818','吕洞宾度铁拐李岳・耍孩儿','岳伯川','元','元曲','yuanqu','','[]','从今日填还了妻子冤家债，我心上别无挂碍。',70,'元曲/yuanqu.json','["从今日填还了妻子冤家债，我心上别无挂碍。", "拜辞了人我是非乡，拂绰了满面尘埃。", "名缰利锁都教剖，意马心猿尽放开。", "也只怕尊师怪，远离尘世，近访天台。"]'),
('yuanqu-6819','吕洞宾度铁拐李岳・二煞','岳伯川','元','元曲','yuanqu','','[]','汉钟离有正一心，吕洞宾有贯世才，张四郎曹国舅神通大，蓝采和拍板云端里响，韩湘子仙花腊月里开，张果老驴儿快。',68,'元曲/yuanqu.json','["汉钟离有正一心，吕洞宾有贯世才，张四郎曹国舅神通大，蓝采和拍板云端里响，韩湘子仙花腊月里开，张果老驴儿快。", "我访七真游海岛，随八仙赴蓬莱。"]'),
('yuanqu-6820','吕洞宾度铁拐李岳・煞尾','岳伯川','元','元曲','yuanqu','','[]','你着我侧着身云雾里行，瘸着腿波面上踹。',41,'元曲/yuanqu.json','["你着我侧着身云雾里行，瘸着腿波面上踹。", "屠户家脚起全凭着拐，则俺这令史每心平过的海。"]'),
('yuanqu-6821','仙吕・后庭花破子','孙梁','元','元曲','yuanqu','','[]','柳叶黛眉秋，菱花妆镜羞。',39,'元曲/yuanqu.json','["柳叶黛眉秋，菱花妆镜羞。", "夜夜长门月，天寒独上楼。", "水东流，新诗谁寄，相思红叶秋。"]'),
('yuanqu-6822','双调・蟾宫曲','刘秉忠','元','元曲','yuanqu','','[]','盼和风春雨如膏，花发南枝，北岸冰销。',545,'元曲/yuanqu.json','["盼和风春雨如膏，花发南枝，北岸冰销。", "夭桃似火，杨柳如烟，穰穰桑条。", "初出谷黄莺弄巧，乍衔泥燕子寻巢。", "宴赏东郊，杜甫游春，散诞逍遥。", "炎天地热如烧，散发披襟，纨扇轻摇。", "积雪敲冰，沉李浮瓜，不用百尺楼高。", "避暑凉亭静扫，树阴稠绿波池沼。", "流水溪桥，右军观鹅，散诞逍遥。", "梧桐一叶初凋，菊绽东篱，佳节登高。", "金风飒飒，寒雁呀呀，促织叨叨。", "满目黄花衰草，一川红叶飘飘。", "秋景萧萧，赏菊陶潜，散诞逍遥。", "朔风瑞雪飘飘，暖阁红炉，酒泛羊羔。", "如飞柳絮，似舞胡蝶，乱剪鹅毛。", "银砌就楼台殿阁，粉妆成野外荒郊。", "冬景寂寥，浩然踏雪，散诞逍遥。", "中国诗歌库中华诗库中国诗典中国诗人中国诗坛首页,{Connection=[close],Content-Type=[text/html;charset=gb2312],Last-Modified=[Thu,12Apr201807:09:17GMT],Accept-Ranges=[bytes],Vary=[Accept-Encoding],Date=[Sun,29Sep201904:38:49GMT],Server=[LiteSpeed],Alt-Svc=[quic=\":443\";ma=2592000;v=\"39,43,46\",h3-22=\":443\";ma=2592000]}>。"]'),
('yuanqu-6823','中吕・十二月过尧民歌别情','王德信','元','元曲','yuanqu','','[]','自别后遥山隐隐，更那堪远水粼粼。',100,'元曲/yuanqu.json','["自别后遥山隐隐，更那堪远水粼粼。", "见杨柳飞绵滚滚，对桃花醉脸醺醺。", "透内阁香风阵阵，掩重门暮雨纷纷。", "怕黄昏忽地又黄昏，不销魂怎地不销魂。", "新啼痕压旧啼痕，断肠人忆断肠人。", "今春，香肌瘦几分，搂带宽三寸。", "套数。"]'),
('yuanqu-6824','商调・集贤宾退隐','王德信','元','元曲','yuanqu','','[]','捻苍髯笑擎冬夜酒，人事远老怀幽。',80,'元曲/yuanqu.json','["捻苍髯笑擎冬夜酒，人事远老怀幽。", "志难酬知机的王粲，梦无凭见景的庄周。", "抱孙孙儿成愿足，引甥甥女嫁心休。", "百年期六分甘到手，数支干周遍又从头。", "笑频因酒醉，烛换为诗留。"]'),
('yuanqu-6825','逍遥乐・江梅并瘦，槛竹同清，岩松共久，无愿何求！笑时人鹤背扬州，','王德信','元','元曲','yuanqu','','[]','明月清风老致优，对绿水青山依旧。',31,'元曲/yuanqu.json','["明月清风老致优，对绿水青山依旧。", "曲肱北牖，舒啸东皋，放眼西楼。"]'),
('yuanqu-6826','金菊香・想着那红尘黄阁昔年羞，到如今白发青衫此地游。乐桑榆酬诗共','王德信','元','元曲','yuanqu','','[]','酒，酒侣诗俦，诗潦倒酒风流。',14,'元曲/yuanqu.json','["酒，酒侣诗俦，诗潦倒酒风流。"]'),
('yuanqu-6827','醋葫芦・到春来日迟迟庭馆春，暖溶溶红绿稠，闹春光莺燕语啾啾。自焚','王德信','元','元曲','yuanqu','','[]','香下帘清坐久，闲把那丝桐一奏，涤尘襟消尽了古今愁。',25,'元曲/yuanqu.json','["香下帘清坐久，闲把那丝桐一奏，涤尘襟消尽了古今愁。"]'),
('yuanqu-6828','幺・到夏来锁松阴竹坞亭，载荷香柳岸舟。有鲜鱼鲜藕客堪留，放白鹤远','王德信','元','元曲','yuanqu','','[]','邀云外叟。',22,'元曲/yuanqu.json','["邀云外叟。", "展楸枰消磨长昼，较亏成一笑两奁收。"]'),
('yuanqu-6829','幺・到秋来醉丹霞树饱霜，绽金钱篱菊秋，半山残照挂城头，老菱香蟹肥','王德信','元','元曲','yuanqu','','[]','堪佐酒。',21,'元曲/yuanqu.json','["堪佐酒。", "正值着登高时候，染霜毫乘醉赋归休。"]'),
('yuanqu-6830','幺・到冬来搅清酣鸡语繁，漾茅檐日影稠，压梅梢晴雪带花留。倚蒲团唤','王德信','元','元曲','yuanqu','','[]','童重荡酒，看万里冰绡染就，有王维妙手总难酬。',22,'元曲/yuanqu.json','["童重荡酒，看万里冰绡染就，有王维妙手总难酬。"]'),
('yuanqu-6831','梧叶儿・退一步乾坤大，饶一着万虑休，怕狼虎恶图谋。遇事休开口，逢','王德信','元','元曲','yuanqu','','[]','人只点头。',20,'元曲/yuanqu.json','["人只点头。", "见香饵莫吞钩，高抄起经纶大手。"]'),
('yuanqu-6832','青哥儿・呀，闲处叹蜂喧蜂喧蚁斗，静中笑蝶讪蝶讪莺羞，你便有快马难','王德信','元','元曲','yuanqu','','[]','熬我这钝炕头。',48,'元曲/yuanqu.json','["熬我这钝炕头。", "见如今蔬果初熟，浊酒新ド，豆粥香浮，大叫高讴，睁着眼张着口尽胡诌，这快活谁能够！。"]'),
('yuanqu-6833','尾声・醉时节盘陀石上眠，饱时节婆娑松下走，困时节布衲里睡<鼻勾>','王德信','元','元曲','yuanqu','','[]','<鼻勾>。',35,'元曲/yuanqu.json','["<鼻勾>。", "偶乘闲细将玄奥剖，把至理一星星参透，却原来括乾坤物我总浮沤。"]'),
('yuanqu-6834','南吕・四块玉北','王德信','元','元曲','yuanqu','','[]','信物存，情词在，想着他美貌端庄，锦绣文才，好教我病恹恹愁冗冗看看害。',55,'元曲/yuanqu.json','["信物存，情词在，想着他美貌端庄，锦绣文才，好教我病恹恹愁冗冗看看害。", "害的我头懒抬，头懒抬眼倦开，锦繁花无心戴。"]'),
('yuanqu-6835','金索挂梧桐南・繁花满目开，锦被空闲在，劣性冤家误得人忒毒害，前生','王德信','元','元曲','yuanqu','','[]','少欠他今世里相思债。',31,'元曲/yuanqu.json','["少欠他今世里相思债。", "失寐忘餐，倚定着这门儿待，房栊静悄如何捱。"]'),
('yuanqu-6836','骂玉郎北・冷清清房栊静悄如何捱，独自把围屏倚，知他是甚情怀。想当','王德信','元','元曲','yuanqu','','[]','初同行同坐同欢爱，到如今孤另另怎百刂划，愁戚戚酒倦酾，羞惨惨花慵戴。',34,'元曲/yuanqu.json','["初同行同坐同欢爱，到如今孤另另怎百刂划，愁戚戚酒倦酾，羞惨惨花慵戴。"]'),
('yuanqu-6837','东瓯令南・花慵戴，酒慵酾，如今燕约莺期不见来，多应他在那里那里贪','王德信','元','元曲','yuanqu','','[]','欢爱。',24,'元曲/yuanqu.json','["欢爱。", "物在人何在？空劳魂梦到阳台，则落得泪盈腮。"]'),
('yuanqu-6838','感皇恩北・呀，则落得雨泪盈腮，多应是命里合该。莫不是你缘薄，咱分','王德信','元','元曲','yuanqu','','[]','浅，都一般运拙时乖。',46,'元曲/yuanqu.json','["浅，都一般运拙时乖。", "怎禁那搅闲人是非，施巧计栽排，撕ㄎ碎合欢带，硬分开鸾凤钗，水淹塌楚阳台。"]'),
('yuanqu-6839','针线箱南・把一床弦索尘埋，两眉峰不展开，香肌瘦损愁无奈。懒刺绣，','王德信','元','元曲','yuanqu','','[]','傍妆台，旧恨新愁教我如何捱？我则怕蝶使蜂媒不再来，临鸾镜也问道朱颜未改，他早先改。',41,'元曲/yuanqu.json','["傍妆台，旧恨新愁教我如何捱？我则怕蝶使蜂媒不再来，临鸾镜也问道朱颜未改，他早先改。"]'),
('yuanqu-6840','采茶歌北・改朱颜瘦了形骸，冷清清怎生捱？我则怕梁山伯不恋我这祝英','王德信','元','元曲','yuanqu','','[]','他若是背义忘恩寻罪责，我将这盟山誓海说的明白。',23,'元曲/yuanqu.json','["他若是背义忘恩寻罪责，我将这盟山誓海说的明白。"]'),
('yuanqu-6841','解三酲南・顿忘了誓山盟海，顿忘了音书不寄来，顿忘了枕边许多恩和爱，','王德信','元','元曲','yuanqu','','[]','顿忘了素体相挨，顿忘了神前设下千千拜，顿忘了表记香罗红绣鞋，说将起傍人见了珠泪盈腮。',42,'元曲/yuanqu.json','["顿忘了素体相挨，顿忘了神前设下千千拜，顿忘了表记香罗红绣鞋，说将起傍人见了珠泪盈腮。"]'),
('yuanqu-6842','乌夜啼北・俺如今相离了三月如隔数载，要相逢甚日何年再？则我这瘦伶','王德信','元','元曲','yuanqu','','[]','仃形体如柴，甚时节还彻了相思债。',74,'元曲/yuanqu.json','["仃形体如柴，甚时节还彻了相思债。", "又不见青鸟书来，黄犬音乖。", "每日家病恹恹懒去傍妆台，得团圆便把神羊赛。", "意厮投，心相爱，早成了鸾交凤友，省的着蝶笑蜂猜。"]'),
('yuanqu-6844','金水桥陈琳抱妆盒・仙吕/端正好','无名氏','元','元曲','yuanqu','','[]','奉皇宣，传君命，为春光堪写围屏。',39,'元曲/yuanqu.json','["奉皇宣，传君命，为春光堪写围屏。", "端的个御园中锦绣似花开盛，因此上打动这巡游兴。"]'),
('yuanqu-6845','金水桥陈琳抱妆盒・幺篇','无名氏','元','元曲','yuanqu','','[]','传示那六宫人知严令，(带云)这金弹呵，(唱)弹落处各办虔城，分头儿自去穿芳径。',82,'元曲/yuanqu.json','["传示那六宫人知严令，(带云)这金弹呵，(唱)弹落处各办虔城，分头儿自去穿芳径。", "寻仔细，认分明，捧金弹，献彤庭，当寝夕，应前星，那其间可也永团圆万万载同欢庆。", "(下)。"]'),
('yuanqu-6846','金水桥陈琳抱妆盒・仙吕/点绛唇','无名氏','元','元曲','yuanqu','','[]','往日个文武登筵，帝王设宴，在金銮殿。',33,'元曲/yuanqu.json','["往日个文武登筵，帝王设宴，在金銮殿。", "就着这御赐樽前，动弦管仙音院。"]'),
('yuanqu-6847','金水桥陈琳抱妆盒・混江龙','无名氏','元','元曲','yuanqu','','[]','尚兀白嫌他拘倦，向御园中别是一壶天。',191,'元曲/yuanqu.json','["尚兀白嫌他拘倦，向御园中别是一壶天。", "争些儿寂寞了梨花院宇，冷落了杨柳亭轩。", "想昨宵暮雨梨花娇不语，今日早春风杨柳乱飞绵。", "则待要驾銮舆尽日不知还，拚的个满园林到处都游遍。", "(做跪送弹弓科，云)这八角亭子上，正是东南方，好打金弹。", "(唱)弹去似晓星乍落，弓开似秋月初圆。", "(驾云)寡人拿这弹弓在手，那诸禽百鸟看见，只道要打他，都也惊怕哩。", "(殿头官云)圣上，便好道蠢动含灵，皆有佛性。", "(正末唱)。"]'),
('yuanqu-6848','金水桥陈琳抱妆盒・天下乐','无名氏','元','元曲','yuanqu','','[]','则见一个喜鹊儿喳喳的噪过御前，俺想这灵也波禽，常好是识空便，也为甚的撇下个闹花丛不将春顾恋。',73,'元曲/yuanqu.json','["则见一个喜鹊儿喳喳的噪过御前，俺想这灵也波禽，常好是识空便，也为甚的撇下个闹花丛不将春顾恋。", "背莺声花萼楼，隔燕语锦树园，他怎肯孤负了这艳阳三月天。"]'),
('yuanqu-6849','金水桥陈琳抱妆盒・鹊踏枝','无名氏','元','元曲','yuanqu','','[]','俺如今行过这海棠轩，荡散了这绿杨烟，细细的拂开了这满径苍苔，和那遍地榆钱。',164,'元曲/yuanqu.json','["俺如今行过这海棠轩，荡散了这绿杨烟，细细的拂开了这满径苍苔，和那遍地榆钱。", "俺这里行一步堪图一个扇面，有丹青巧笔难传。", "(云)这茫茫荡荡，一片御园中，那丸金弹知道落于何处也。", "(李美人云)妾身李美人，立在御园东首，不期这金丸正打到妾身边，被妾拾着。", "如今不敢隐藏，只得亲到御前进献去来。", "(正末见美人科，云)兀的不是李美人来了也。", "(唱)。"]'),
('yuanqu-6850','金水桥陈琳抱妆盒・寄生草','无名氏','元','元曲','yuanqu','','[]','则见他娇滴滴颜如玉，薄松松鬓似蝉。',77,'元曲/yuanqu.json','["则见他娇滴滴颜如玉，薄松松鬓似蝉。", "眼儿呵绿澄澄溜出秋波转，眉儿呵曲弯弯画出双蛾浅，脸儿呵汗津津显出桃花片。", "若不是昭阳宫粉黛美人图，争认做落伽山水月观音现。"]'),
('yuanqu-6851','金水桥陈琳抱妆盒・金盏儿','无名氏','元','元曲','yuanqu','','[]','这是你忒心坚，金弹也恰多缘。',70,'元曲/yuanqu.json','["这是你忒心坚，金弹也恰多缘。", "想天公好与人方便，因此上着李美人和圣上永团圆。", "这的是在地成连理树，入水长并头莲。", "早则不惊开比翼鸟，不打散锦纹鸳。"]'),
('yuanqu-6852','金水桥陈琳抱妆盒・赚煞','无名氏','元','元曲','yuanqu','','[]','从今后则想凤楼期，休把羊车羡，今日个谢圣恩可怜。',124,'元曲/yuanqu.json','["从今后则想凤楼期，休把羊车羡，今日个谢圣恩可怜。", "阻隔的那刘氏娘娘欢爱远，那里也独宿孤眠。", "似这等美缠绵，直似神仙，再不索倚定宫门听过辇。", "李美人相逢在上苑，宋真宗别登了寝殿。", "本是一对儿好姻缘，(带云)若刘娘娘知道呵，(唱)他可敢生扭做了恶姻缘！(下)。"]'),
('yuanqu-6853','金水桥陈琳抱妆盒・南吕/一枝花','无名氏','元','元曲','yuanqu','','[]','虽不比三台中玉佩臣，现掌些六院里金钗客。',85,'元曲/yuanqu.json','["虽不比三台中玉佩臣，现掌些六院里金钗客。", "常则待鸡鸣宫禁启，簇捧着龙绕圣颜开。", "那里也将相之才，无过是随步辇君王爱，听传宣妃后差。", "管领他美孜孜八百胭娇，守定这艳亭亭三千粉黛。"]'),
('yuanqu-6854','金水桥陈琳抱妆盒・牧羊关','无名氏','元','元曲','yuanqu','','[]','则索向盒中放，又不敢怀内揣，我正是杀人处钻出头来。',88,'元曲/yuanqu.json','["则索向盒中放，又不敢怀内揣，我正是杀人处钻出头来。", "刘娘娘你结下海样阔冤仇，陈琳也担着天来大利害。", "太子也你曲着腰难回转，拳着腿怎舒开．则我这救主的空生受，太子也你可是成人不自在。"]'),
('yuanqu-6855','金水桥陈琳抱妆盒・隔尾','无名氏','元','元曲','yuanqu','','[]','太子也你比着那双龙紫阙争低矮，比着那五凤丹楼较匾窄，比着那一合乾坤少宽大。',65,'元曲/yuanqu.json','["太子也你比着那双龙紫阙争低矮，比着那五凤丹楼较匾窄，比着那一合乾坤少宽大。", "这的是潜龙世界，关系着皇朝后代，只愿的保护了江山万万载。"]'),
('yuanqu-6856','金水桥陈琳抱妆盒・牧羊关','无名氏','元','元曲','yuanqu','','[]','我抱定这妆盒子，便是揣着个愁布袋，我未到宫门早忧的我这头白。',102,'元曲/yuanqu.json','["我抱定这妆盒子，便是揣着个愁布袋，我未到宫门早忧的我这头白。", "盒子里藏的是储君，我肚皮里怀的是鬼胎。", "虽不见公庭上遭横祸。", "赤紧的盒子里隐飞灾。", "承御也你办着个喜溶溶笑脸儿回还去，却教我将着个碜磕磕恶头儿掇过来。"]'),
('yuanqu-6857','金水桥陈琳抱妆盒・隔尾','无名氏','元','元曲','yuanqu','','[]','我若是无妨碍，你可也无妨碍；我若是有患害，你可也有患害。',358,'元曲/yuanqu.json','["我若是无妨碍，你可也无妨碍；我若是有患害，你可也有患害。", "只要得我命活，便留得你身在。", "(带云)那刘娘娘呵，(唱)偷觑他眼色，斟量了性格，太子也但得个尸首儿完全是大古里彩。", "(做放盒见科)(刘皇后云)陈琳，你那里去？(正末云)奴婢往后花园采办时新果品来。", "(刘皇后云)别无甚公事么？(正末云)别无甚公事。", "(刘皇后云)这等，你去罢。", "(正末做捧盒，急走科)(刘皇后云)你且转来。", "(正末回，放盒跪科，云)娘娘有甚分付？(刘皇后云)这厮，我放你去，就如弩箭离弦，脚步儿可走的快，我叫你转来，就如毯上拖毛，脚步儿可这等慢，必定有些蹊跷。", "陈琳，我问你，东果园西果园南果园北果园都有果品，你可是那一个园里采的？那果品是何名降？你对我从实说来。", "说的是，万事罢论；说的不是，我不道的饶了你哩！(正末云)娘娘停嗔息怒，听奴婢细说一遍咱。", "(唱)。"]'),
('yuanqu-6858','金水桥陈琳抱妆盒・红芍药','无名氏','元','元曲','yuanqu','','[]','御园中百卉斗争开，另巍巍将根脚儿培栽。',138,'元曲/yuanqu.json','["御园中百卉斗争开，另巍巍将根脚儿培栽。", "则为这东君惜爱降甘泽，因此上结子成胎。", "(刘皇后云)你在那里摘将来的？(正末唱)恰便似娘肠肚摘将下来。", "(刘皇后云)甚么颜色？(正末唱)天生的颜色儿红白。", "(刘皇后云)为何要放在这个盒儿里？(正末唱)则为他不堪日炙与风筛，特赐这黄封盒内好藏埋。"]'),
('yuanqu-6859','金水桥陈琳抱妆盒・菩萨梁州','无名氏','元','元曲','yuanqu','','[]','石榴长在金阶，(刘皇后云)莫不是核桃？(正末唱)合逃出您宫外。',245,'元曲/yuanqu.json','["石榴长在金阶，(刘皇后云)莫不是核桃？(正末唱)合逃出您宫外。", "(刘皇后云)莫不是梨儿？(正末唱)今宵离子后宰，(刘皇后云)莫不是李子？(正末唱)这玉皇李子苦尽甘来。", "也是他天然异种出群材，开时节不许游蜂采，摘时节则愿的君王戴。", "(刘皇后云)李子有甚好处，万岁爷倒喜着他，待我把这树都砍坏了者。", "(正末唱)娘娘也偏生你意儿歹，怎忍见片片残红点碧苔，陪伴他这古木崩崖。", "(刘皇后云)陈琳，那里听的你这巧言令色，则待我揭开盒儿，看个明白。", "果然没有夹带，我才放你出去。", "(正末云)这妆盒儿有甚夹带来。", "(唱)。"]'),
('yuanqu-6860','金水桥陈琳抱妆盒・骂玉郎','无名氏','元','元曲','yuanqu','','[]','我便是苏秦般嘴巧舌头快，我这里越分说他那里越疑猜，常言道脱空到底终须败。',201,'元曲/yuanqu.json','["我便是苏秦般嘴巧舌头快，我这里越分说他那里越疑猜，常言道脱空到底终须败。", "(刘皇后云)取盒儿过来，待我揭开看波。", "(正末用手按盒科，云)娘娘，这盒盖开不的。", "上有黄封御笔，须和娘娘同到万岁爷根前面说过时，方才敢开这盒盖你看。", "(刘皇后云)我管甚么黄封御笔，则等我揭开看看。", "(正末按住科，唱)可著我怎百刂划，怎百刂划，要揭开，要揭开，妆盒盖！(刘皇后做怒科，云)陈琳，你不揭开盒儿我看，要我自动手么？(正末唱)。"]'),
('yuanqu-6861','金水桥陈琳抱妆盒・感皇恩','无名氏','元','元曲','yuanqu','','[]','呀，见娘娘走向前唉，可不我陈琳呵这死罪应该。',195,'元曲/yuanqu.json','["呀，见娘娘走向前唉，可不我陈琳呵这死罪应该。", "(刘皇后云)我只要辩个虚实，觑个真假，审个明白。", "(正末唱)他待要辩个虚实，觑个真假，审个明白。", "(寇承御慌上科，云)请娘娘回去。", "圣驾幸中宫，要排筵宴哩。", "(刘皇后云)陈琳，恰好了你。", "若不是驾幸中宫，我肯就放了你出去？待明日这等果品满满的装一盒儿，送到我宫里来。", "(并下)(正末云)知道。", "(唱)见承御慌传圣旨，请娘娘疾便回来。", "道銮舆，在寝殿，要把御筵排。"]'),
('yuanqu-6862','金水桥陈琳抱妆盒・采茶歌','无名氏','元','元曲','yuanqu','','[]','一来是鬼神差，二来是搭救这小婴孩，谁想道滴溜溜九天飞下一纸赦书来。',67,'元曲/yuanqu.json','["一来是鬼神差，二来是搭救这小婴孩，谁想道滴溜溜九天飞下一纸赦书来。", "陈琳呵，则我似刀刃上偷全得蝼蚁命，太子也，你便似钓竿头活脱了巨鳌腮。"]'),
('yuanqu-6863','金水桥陈琳抱妆盒・二煞','无名氏','元','元曲','yuanqu','','[]','小储君在盒子内多宽泰，则我这泼性命从针关里透出来。',103,'元曲/yuanqu.json','["小储君在盒子内多宽泰，则我这泼性命从针关里透出来。", "我这里忙趋疾走楚王宅，荡一缕尘埃。", "恨不得到这一座濯龙门侧，将两步为一蓦。", "(带云)我这一去见南清宫八大王呵，(唱)只要他做五颗神珠在掌上抬，我方才的放下心怀。"]'),
('yuanqu-6864','金水桥陈琳抱妆盒・黄钟尾','无名氏','元','元曲','yuanqu','','[]','从今后跳出了九重围子连环寨，脱离子十面埋伏大会垓。',113,'元曲/yuanqu.json','["从今后跳出了九重围子连环寨，脱离子十面埋伏大会垓。", "走蛟龙，投大海。", "纵彩凤，扬天外。", "小储君，好惊骇。", "刘皇后，肯耽待？便是蛇蝎心肠，不似般恁毒害！把一个太子提起来，望着那花斑石殿阶，哎！娘娘也你拾的个孩儿，敢可也落的价摔！(下)。"]'),
('yuanqu-6865','金水桥陈琳抱妆盒・仙吕/赏花时','无名氏','元','元曲','yuanqu','','[]','大王也，你须是一脉流传亲叔侄，怎不念万里江山托付谁？(带云)大王，你若不收呵，(唱)我则索抱太子撞街基。',282,'元曲/yuanqu.json','["大王也，你须是一脉流传亲叔侄，怎不念万里江山托付谁？(带云)大王，你若不收呵，(唱)我则索抱太子撞街基。", "(楚王云)陈琳，你快住者。", "我是玉叶金枝，怕那刘皇后怎的？恰才我斗你耍哩。", "你抱太子过来，与我看波。", "(做接太子在手科，云)你看他生的龙颜凤目，他日必为太平天子。", "谢天地，我宋家有福，得此一男一女，两个忠臣，救到我府中。", "校尉，快去分付宫人，只拣有乳食的，着他好生抚养太子。", "等他长大成人，接我宋家后代，休教辜负了这两个忠臣的一场好意。", "(官校抱太子下)(正末叩谢科)(唱)这一场先忧后喜，(带云)陈琳愿领这妆盒去，依旧采了果品来上寿也。", "(唱)也不枉了我这抱妆盒冒死出宫闱。"]'),
('yuanqu-6866','金水桥陈琳抱妆盒・双调/新水令','无名氏','元','元曲','yuanqu','','[]','则听得闭宫门推勘这女娇姿，多应是十年前那-场公事，赤紧的寇大人先胆寒，刘皇后你可也不心慈。',66,'元曲/yuanqu.json','["则听得闭宫门推勘这女娇姿，多应是十年前那-场公事，赤紧的寇大人先胆寒，刘皇后你可也不心慈。", "不弱似吕太后当时，恰便待鸩了如意彘了戚氏。"]'),
('yuanqu-6867','金水桥陈琳抱妆盒・驻马听','无名氏','元','元曲','yuanqu','','[]','他使着这嫉妒的心儿，只待要六宫人不生一个子。',356,'元曲/yuanqu.json','["他使着这嫉妒的心儿，只待要六宫人不生一个子。", "搜寻那李美人不是，大刚来一碗饭怎插两张匙？做妃嫔倒去暗通私，赏宫娥又不敢明宣赐。", "你道他怎为此，单则怕凤楼前引得羊车至。", "(做入见叩头科，云)娘娘唤陈琳，那厢使用？(刘皇后云)兀那陈琳，今有寇承御，十年前我曾使他到金水桥河边干一件事来。", "今日问他，抵死不肯招，你与我行杖者。", "(正末云)娘娘，我陈琳手无缚鸡捉鼠之力，行不的杖。", "(刘皇后做怒科，云)你敢违我的懿旨么？(正末做叩头科，云)小臣情愿行杖。", "(做打杖科)(刘皇后云)陈琳，你拣那大棒子打着，一下子打死了他，做的个死无对证哩。", "(正末云)待我拣那小棒子打波。", "(刘皇后云)陈琳，你把小棒打他，怕他打的疼呵，指攀你下来么？(正末云)大棒子又不是，小棒子又不是，则拣中样的打便了。", "(做打科，云)寇承御，你快招了者，招了者。", "(唱)。"]'),
('yuanqu-6868','金水桥陈琳抱妆盒・沽美酒','无名氏','元','元曲','yuanqu','','[]','打的你活不活死不死，(寇承御云)我委的丢在河里了也。',118,'元曲/yuanqu.json','["打的你活不活死不死，(寇承御云)我委的丢在河里了也。", "(正末唱)则要你一则一二则二，(做低说科，云)承御，你不道来。", "(唱)可不道保护潜龙掌命司。", "这句话入于咱耳，到今日自寻思。", "(刘皇后云)陈琳，你怎么不打？这事定要还我一个下落。", "(正末唱)。"]'),
('yuanqu-6869','金水桥陈琳抱妆盒・太平令','无名氏','元','元曲','yuanqu','','[]','非是我挑茶斡刺，则问你李美人生下的孩儿，要说个丁一卯二，不许你差三错四。',88,'元曲/yuanqu.json','["非是我挑茶斡刺，则问你李美人生下的孩儿，要说个丁一卯二，不许你差三错四。", "你则说淹死太子、这个口词，休连累陈琳两字。", "(刘皇后云)陈琳，你怎的这般打？敢怕他指攀你来那？(正末唱)。"]'),
('yuanqu-6870','金水桥陈琳抱妆盒・得胜令','无名氏','元','元曲','yuanqu','','[]','呀，你正是闭口抹胭脂，得推辞便推辞。',153,'元曲/yuanqu.json','["呀，你正是闭口抹胭脂，得推辞便推辞。", "(承御云)打了我这许多，不似这几下的能重。", "待我挣起来，看是那个。", "(正末唱)他眼瞪瞪瞅我有十余次，我怎敢实丕丕汤着他一棍儿。", "(刘皇后云)陈琳，你怎么不打呀！(正末唱)娘娘也孜孜，则见他不转睛将咱视。", "(承御云)打杀我也。", "(正末唱)寇承御你休得要雌也波雌，我打你个忠臣不怕死。"]'),
('yuanqu-6871','金水桥陈琳抱妆盒・川拨棹','无名氏','元','元曲','yuanqu','','[]','则见他倒在阶址，这嫩皮肤青间紫。',64,'元曲/yuanqu.json','["则见他倒在阶址，这嫩皮肤青间紫。", "则他这细袅袅的身子，瘦怯怯的腰肢，打得他慌张张把陈琳便指。", "你畅好是不三思，怎说道我根前信有之？。"]'),
('yuanqu-6872','金水桥陈琳抱妆盒・七弟兄','无名氏','元','元曲','yuanqu','','[]','咱两个对词，对词，恰便似打官司，你道是藏、藏、藏，怕绝了君乏嗣。',101,'元曲/yuanqu.json','["咱两个对词，对词，恰便似打官司，你道是藏、藏、藏，怕绝了君乏嗣。", "今日个指、指、指，道陈琳便是个证盟师，则你那狠、狠、狠寇承御，做了咱追魂使。", "(做打科)(承御云)陈琳，你一发打几下，打杀我罢。", "(正末唱)。"]'),
('yuanqu-6873','金水桥陈琳抱妆盒・梅花酒','无名氏','元','元曲','yuanqu','','[]','呀，雪消也见死尸，打的你气咽声丝，倒着我抹泪揉眵。',258,'元曲/yuanqu.json','["呀，雪消也见死尸，打的你气咽声丝，倒着我抹泪揉眵。", "(承御云)陈琳，你怕甚么哩？(正末唱)我则怕连累了玉叶金枝。", "你常好有上稍无下稍，也不索多议论少成事。", "(刘皇后云)这一日你见我来，你就躲在那金水桥边垂杨树下去，可不是这太子你曾看见那？(正末跪科，云)我陈琳并不曾看见甚么太子，待我问寇承御咱。", "(做问科，云)寇承御，你这一日可曾遇见我陈琳么？(承御云)我不曾遇见陈琳来。", "(正末云)娘娘，寇承御道不曾遇见我陈琳。", "(刘皇后云)这等，陈琳你再打着呀。", "(正末做打科)(唱)你那其间抱太子御沟边，见咱时杨柳岸，你亲自对咱家痛嗟咨。"]'),
('yuanqu-6874','金水桥陈琳抱妆盒・收江南','无名氏','元','元曲','yuanqu','','[]','呀，你则说金水桥扑通的丢下个半生半死小孩儿，(刘皇后云)陈琳，这尸首只在河里，与我打捞去来。',153,'元曲/yuanqu.json','["呀，你则说金水桥扑通的丢下个半生半死小孩儿，(刘皇后云)陈琳，这尸首只在河里，与我打捞去来。", "(正末云)娘娘，可是十年了也。", "(唱)这些时可不喂了那游来游去活鱼儿，(刘皇后云)我也不管，只要你与我问这桩事一个明白。", "(正末云)这事怎了也？(唱)兀的不是个难开难解闷弓儿。", "娘娘也甚意儿，怎揣与我这该敲该剐罪名儿？。"]'),
('yuanqu-6875','金水桥陈琳抱妆盒・鸳鸯尾煞','无名氏','元','元曲','yuanqu','','[]','刘娘娘不索把三尺青锋赐，寇夫人他自拣一搭金阶死。',83,'元曲/yuanqu.json','["刘娘娘不索把三尺青锋赐，寇夫人他自拣一搭金阶死。", "枉了也审问根由，折证言词，拷打千般，供招半纸。", "唱道女使丫鬟煞强似男儿志，端的个忠直无私，堪图写在香馥馥汗青史。", "(下)。"]'),
('yuanqu-6876','金水桥陈琳抱妆盒・中吕/粉蝶儿','无名氏','元','元曲','yuanqu','','[]','日月其除，草生合玉阶辇路，那些时一个个宫样妆梳。',59,'元曲/yuanqu.json','["日月其除，草生合玉阶辇路，那些时一个个宫样妆梳。", "端的是赛阳台，欺洛浦，生得来如花似玉。", "未知他福分何如，幸不幸总归天数。"]'),
('yuanqu-6877','金水桥陈琳抱妆盒・醉春风','无名氏','元','元曲','yuanqu','','[]','那一个刘娘娘占尽了寝殿百年欢，这一个李美人整受了冷宫中一世苦。',241,'元曲/yuanqu.json','["那一个刘娘娘占尽了寝殿百年欢，这一个李美人整受了冷宫中一世苦。", "他只道使心机断送了小潜龙，怎知道做了当朝的主，主。", "他不合意狠肠毒，则待要除根剪草，不肯着开花满树。", "(做入见叩头科，云)万岁，呼唤陈琳，有何差遣？(仁宗云)寡人宣你来，不为别事。", "我常见叔父与我说，是妆盒儿盛我送楚府中寄养的，又说宫娥寇承御、穿宫内使陈琳两个，甚是有功于我，教我不要忘了他。", "前日我查访寇承御所在，说已死过多年了。", "只有你还在，你可将上项的事，备细说与寡人听咱。", "(正末云)万岁爷不嫌絮烦，听奴婢试说一遍。", "(唱)。"]'),
('yuanqu-6878','金水桥陈琳抱妆盒・石榴花','无名氏','元','元曲','yuanqu','','[]','六宫中多少女娇姝，他可也每夜盼羊车。',86,'元曲/yuanqu.json','["六宫中多少女娇姝，他可也每夜盼羊车。", "都是那千妖百艳美人图，却元来都命犯着寡宿，注定孤独。", "到黄昏半掩迎风户，知他是几下里短叹长吁？这的是天教怨女伤情处，那一个不候到二更初？。"]'),
('yuanqu-6879','金水桥陈琳抱妆盒・普天乐','无名氏','元','元曲','yuanqu','','[]','想当日在御园中，先帝也可便闲行步，正遇着存风澹荡，春色荣敷。',128,'元曲/yuanqu.json','["想当日在御园中，先帝也可便闲行步，正遇着存风澹荡，春色荣敷。", "恰觑着锦鸠儿要中他，打的那金弹子无寻处。", "传示着众妃嫔向花丛里分头去，(带云)其时却是西宫李美人拾得这金弹来。", "(唱)偏是他李美人抬得在荒芜。", "多则是天生分福，又遇着姻缘对付，成就了《麟趾》、《关雎》。"]'),
('yuanqu-6880','金水桥陈琳抱妆盒・上小楼','无名氏','元','元曲','yuanqu','','[]','刘太后有十分狠毒，一时嫉妒。',141,'元曲/yuanqu.json','["刘太后有十分狠毒，一时嫉妒。", "全不想万载江山，只侍使千般恶计，百样亏图。", "将宫女，寇承御，暗行嘱咐，把太子碜可可着他死生别路。", "(仁宗云)这等说来，那太子正是寡人。", "可不多亏了你两个救驾之功。", "你还把向后的事，细说一遍。", "寡人试听者。", "(正末云)若不是万岁洪福齐天，怎能勾这等百灵咸助那。", "(唱)。"]'),
('yuanqu-6881','金水桥陈琳抱妆盒・十二月','无名氏','元','元曲','yuanqu','','[]','恰转过雕阑数曲，行不到百步其余。',58,'元曲/yuanqu.json','["恰转过雕阑数曲，行不到百步其余。", "俺陈琳便有张良般伎俩，怎当那刘太后有吕氏般机谋？可搭的把咽喉来当住，唬得咱魂魄全无。"]'),
('yuanqu-6882','金水桥陈琳抱妆盒・尧民歌','无名氏','元','元曲','yuanqu','','[]','小储君倒也女安稳稳守着妆盒做护身符。',106,'元曲/yuanqu.json','["小储君倒也女安稳稳守着妆盒做护身符。", "则是我陈琳兢兢战战抱着个天大闷葫芦。", "那刘人后嗔嗔忿忿这等左来右占忒粗疏，急的俺忐忐忑忑把花言巧语谩支吾。", "当初当也波初，俺也拚的厮挺触，(带云)则被刘太后呵，(唱)险揭开妆盒觑。"]'),
('yuanqu-6883','金水桥陈琳抱妆盒・仁宗云','无名氏','元','元曲','yuanqu','','[]','这等，你怎生送的我到楚王府里去那？(正末唱)。',23,'元曲/yuanqu.json','["这等，你怎生送的我到楚王府里去那？(正末唱)。"]'),
('yuanqu-6884','金水桥陈琳抱妆盒・耍孩儿','无名氏','元','元曲','yuanqu','','[]','俺则道这回定把机关露，敢陈琳也不知死所。',79,'元曲/yuanqu.json','["俺则道这回定把机关露，敢陈琳也不知死所。", "元来是圣明天子百灵扶，早则去迎接鸾舆。", "恰便似顿开金锁飞龙子，摔破雕笼放风雏，才出的这宫门去。", "因此上宗祧有托，民社无虞。"]'),
('yuanqu-6885','金水桥陈琳抱妆盒・二煞','无名氏','元','元曲','yuanqu','','[]','十年前曾入朝，刘太后见相貌殊，平空掇起心头怒。',66,'元曲/yuanqu.json','["十年前曾入朝，刘太后见相貌殊，平空掇起心头怒。", "要问他西宫阁下儿存否，金水沟边事有无。", "可怜受尽多冤楚，不能彀题名丹阙，只落得埋骨黄垆。"]'),
('yuanqu-6886','金水桥陈琳抱妆盒・尾煞','无名氏','元','元曲','yuanqu','','[]','死了的墓顶上加赠封，活在的殿阶前赐俸禄。',46,'元曲/yuanqu.json','["死了的墓顶上加赠封，活在的殿阶前赐俸禄。", "才表得到头善恶由人做，也则为救了这万万岁当今太平主。"]'),
('yuanqu-6887','郑孔目风雪酷寒亭・仙吕/赏花时','杨显之','元','元曲','yuanqu','','[]','若不是孔目哥哥救了宋彬，这其间吃剑餐刀作鬼魂。',48,'元曲/yuanqu.json','["若不是孔目哥哥救了宋彬，这其间吃剑餐刀作鬼魂。", "我待学晋灵辄古今闻，他为甚甘心赵盾，将臂膊代车轮。"]'),
('yuanqu-6888','郑孔目风雪酷寒亭・幺篇','杨显之','元','元曲','yuanqu','','[]','他则是报答桑间一饭恩，存得堂堂七尺身。',48,'元曲/yuanqu.json','["他则是报答桑间一饭恩，存得堂堂七尺身。", "也不敢望遂风云，报仇雪恨，则愿的积趱下金赠有恩人。", "(下)。"]'),
('yuanqu-6889','郑孔目风雪酷寒亭・仙吕/点绛唇','杨显之','元','元曲','yuanqu','','[]','俺嫂嫂连梦交杂，水米不下，将亡化。',31,'元曲/yuanqu.json','["俺嫂嫂连梦交杂，水米不下，将亡化。", "只等孔目来家，有几句遗留话。"]'),
('yuanqu-6890','郑孔目风雪酷寒亭・油葫芦','杨显之','元','元曲','yuanqu','','[]','道不的猿锁空房犹性耍，哥哥也咱须是官宦家，怎么好人家娶这等揽蛆扒？(搽旦向孔目云)你老婆若死了，我就嫁你。',115,'元曲/yuanqu.json','["道不的猿锁空房犹性耍，哥哥也咱须是官宦家，怎么好人家娶这等揽蛆扒？(搽旦向孔目云)你老婆若死了，我就嫁你。", "(正末唱)怕不待倾心吐胆商量嫁，都是些瞒神吓鬼求食话。", "哥哥，你休劝他，他敢和我便怒发。", "你看承似现世的活菩萨，则待恋定泼烟花。"]'),
('yuanqu-6891','郑孔目风雪酷寒亭・天下乐','杨显之','元','元曲','yuanqu','','[]','他不比寻常卖酒家，详也波察，怎便信杀。',52,'元曲/yuanqu.json','["他不比寻常卖酒家，详也波察，怎便信杀。", "有钱财似你恁作塌，不将那官事理，终日家偎恋他，久以后无根椽和片瓦。"]'),
('yuanqu-6892','郑孔目风雪酷寒亭・后庭花','杨显之','元','元曲','yuanqu','','[]','做下个束身白木匣，剪下些迎神雪柳花。',100,'元曲/yuanqu.json','["做下个束身白木匣，剪下些迎神雪柳花。", "人闹处休啼哭，我则怕当街里人笑活。", "(孔目哭入门、见旦科，云)好也他原来不曾死。", "兄弟，你这般说谎(正末唱)谁不知你这吏人猾，若不说妻儿亡化，你这令史每有三千番厮调发。"]'),
('yuanqu-6893','郑孔目风雪酷寒亭・金盏儿','杨显之','元','元曲','yuanqu','','[]','这婆娘忒奸猾，不贤达，走将来泪不住行儿下。',67,'元曲/yuanqu.json','["这婆娘忒奸猾，不贤达，走将来泪不住行儿下。", "则你这无端弟子，恰便似恶那吒。", "他夫妻每才厮守，子母每恰欢洽。", "你不脱了丧孝服，戴甚么纸麻花？。"]'),
('yuanqu-6894','郑孔目风雪酷寒亭・赚煞尾','杨显之','元','元曲','yuanqu','','[]','准备着送灵车，安排着装衣架，摆列些高驮细马，走去衙门自告咱。',90,'元曲/yuanqu.json','["准备着送灵车，安排着装衣架，摆列些高驮细马，走去衙门自告咱。", "问官人借对头踏，乱交加，奠酒浇茶。", "但见的都将你做话靶，满城人将你来怨煞。", "街坊都骂，骂你个不回头呆汉活气杀大浑家。", "(下)。"]'),
('yuanqu-6895','郑孔目风雪酷寒亭・越调/斗鹌鹑','杨显之','元','元曲','yuanqu','','[]','俺家里少东无西，可着我走南嘹北。',75,'元曲/yuanqu.json','["俺家里少东无西，可着我走南嘹北。", "俺哥哥才娶的偏房，新亡了正室。", "撇了个幼女娇男，可又没甚的远亲近戚。", "我这里仔细的寻思起：他则待卧柳眠花，怎知道迷妖着鬼。"]'),
('yuanqu-6896','郑孔目风雪酷寒亭・紫花儿序','杨显之','元','元曲','yuanqu','','[]','想着他亲娘在日，见这般打骂凌辱，不由的感叹伤悲。',129,'元曲/yuanqu.json','["想着他亲娘在日，见这般打骂凌辱，不由的感叹伤悲。", "我一心似箭两脚如飞，走的我气喘狼藉，恨不得一步奔来城市里。", "早行至哥哥门内，则听的大叫高呼。", "元来又打得他女哭儿啼。", "(搽旦云)如今酒又不醉，饭又不饱，我慢慢的打你这两个小弟子孩儿。", "(正末云)兀的不打孩儿哩。", "(唱)。"]'),
('yuanqu-6897','郑孔目风雪酷寒亭・天净沙','杨显之','元','元曲','yuanqu','','[]','我急忙忙取得文移，趱程途不敢耽迟。',42,'元曲/yuanqu.json','["我急忙忙取得文移，趱程途不敢耽迟。", "怎禁他这孩儿倒疾，紧拽住咱家衣袂，则待要步步追随。"]'),
('yuanqu-6898','郑孔目风雪酷寒亭・秃厮儿','杨显之','元','元曲','yuanqu','','[]','为甚么适才间吖天叫地，都一般汪汪的泪眼愁眉。',52,'元曲/yuanqu.json','["为甚么适才间吖天叫地，都一般汪汪的泪眼愁眉。", "他和你又没甚杀爷娘的仇共隙，怎这般苦死的，怕相依，也波堪悲。"]'),
('yuanqu-6899','郑孔目风雪酷寒亭・圣药王','杨显之','元','元曲','yuanqu','','[]','俺只见儿又啼，女又啼，哭的俺是铁人石意也酸嘶。',51,'元曲/yuanqu.json','["俺只见儿又啼，女又啼，哭的俺是铁人石意也酸嘶。", "他待要来也随，去也随，恰便似蚂蝗钉了鹭鸶屯，寸步不教离。"]'),
('yuanqu-6900','郑孔目风雪酷寒亭・寨儿令','杨显之','元','元曲','yuanqu','','[]','我骂你这歪刺骨，我骂你这泼东西。',48,'元曲/yuanqu.json','["我骂你这歪刺骨，我骂你这泼东西。", "你生的来兔儿头老鼠嘴，长则待吵是寻非，叫骂过日，怎做的好人妻？。"]'),
('yuanqu-6901','郑孔目风雪酷寒亭・幺篇','杨显之','元','元曲','yuanqu','','[]','这都是俺哥哥命运低微，带累你两个孩儿受尽禁持。',58,'元曲/yuanqu.json','["这都是俺哥哥命运低微，带累你两个孩儿受尽禁持。", "我本待好心肠苦劝你，你倒恶狠狠把咱推。", "来来来，我便死也拚得和你做头敌。"]'),
('yuanqu-6902','郑孔目风雪酷寒亭・收尾','杨显之','元','元曲','yuanqu','','[]','我如今一脱气直走向京都地，一句句向哥哥说知。',47,'元曲/yuanqu.json','["我如今一脱气直走向京都地，一句句向哥哥说知。", "有一日郑孔目到来时，不道肯轻轻的素放了你。", "(下)。"]'),
('yuanqu-6903','郑孔目风雪酷寒亭・梁州第七','杨显之','元','元曲','yuanqu','','[]','也强如提关列窖，也强如斡担挑箩。',146,'元曲/yuanqu.json','["也强如提关列窖，也强如斡担挑箩。", "满城中酒店有三十座，他将那醉仙高挂，酒器张罗。", "我则是茅庵草舍，瓦瓮瓷钵。", "老实酒不比其他，论清闲压尽鸣珂。", "又无那胖高丽去往来迎，又无那小扒头浓妆艳里，又无那大行首妙舞清歌。", "也不是我奖誉，太过，这黄汤强如醇醪糯，则为我酾酒浆水刺破，面米相停无添和，那说起玉液金波。"]'),
('yuanqu-6904','郑孔目风雪酷寒亭・贺新郎','杨显之','元','元曲','yuanqu','','[]','前家儿招了个后尧婆，小媳妇近日成亲，大浑家新来亡过。',180,'元曲/yuanqu.json','["前家儿招了个后尧婆，小媳妇近日成亲，大浑家新来亡过。", "题名儿骂了孜孜的唾，骂那无正事颓唆，则待折损杀业种活撮。", "(孔目云)那妇人折倒他一双儿女，他那街坊可骂郑孔目么。", "(正末唱)这厮掌刑法做令史，觅钱来养娇娥，送的他人离财散家缘破。", "那贱人也不是鲁义姑，这厮也不足汉萧何。", "(孔目云)我听的说：那小妇人不与他两个孩儿饭吃，那两个孩儿只在长街上讨吃。", "有这话么？(正末唱)。"]'),
('yuanqu-6905','郑孔目风雪酷寒亭・菩萨梁州','杨显之','元','元曲','yuanqu','','[]','汤水儿或少或多，干粮儿一个两个，米面儿一撮半撮，舍贫的姐姐哥哥。',89,'元曲/yuanqu.json','["汤水儿或少或多，干粮儿一个两个，米面儿一撮半撮，舍贫的姐姐哥哥。", "他娘在谁敢把气儿呵？糖堆里养的偌来大，如今风雪街忍着十分饿。", "他不爱惜倒折挫，常言道：灰不如火热。", "多敢怕我信口开合。"]'),
('yuanqu-6906','郑孔目风雪酷寒亭・感皇恩','杨显之','元','元曲','yuanqu','','[]','他将那门户关合。',69,'元曲/yuanqu.json','["他将那门户关合。", "怎生结磨？颤钦钦跪在阶基，可丕丕心惊惧，扑簌簌泪滂沱。", "当日个天时凛冽，怎能勾身上温和？孩儿每缩着脖项，拄着下颏，耸着肩窝。"]'),
('yuanqu-6907','郑孔目风雪酷寒亭・乌夜啼','杨显之','元','元曲','yuanqu','','[]','谢天地小人刚道的这淫邪货，并不曾道甚孔目哥哥。',140,'元曲/yuanqu.json','["谢天地小人刚道的这淫邪货，并不曾道甚孔目哥哥。", "(孔目云)你也骂的我勾了。", "你说他有奸夫，是那一个(正末唱)要奸夫略数与你三十个，尽都是把手为活，对酒当歌。", "郑州浪汉委实多。", "(云)那奸夫姓高，(孔目云)高甚么？(正末唱)高阳公子休空过。", "凭着我在口言是亡身祸，言多语少，小人有些九伯风魔。"]'),
('yuanqu-6908','郑孔目风雪酷寒亭・黄钟尾','杨显之','元','元曲','yuanqu','','[]','润纸窗把两个都瞧破，拽后门将三簧锁纳合。',80,'元曲/yuanqu.json','["润纸窗把两个都瞧破，拽后门将三簧锁纳合。", "捕巡军快拿捉，急开门走不脱。", "到官司问甚么？取了招带枷锁，建法场把市郭，上木驴着刀剁，万剐了尧婆。", "兀的不痛快杀我。", "(下)。"]'),
('yuanqu-6909','郑孔目风雪酷寒亭・双调/新水令','杨显之','元','元曲','yuanqu','','[]','我如今向槽房连瓮掇将来，偿还了我弟兄每口债。',50,'元曲/yuanqu.json','["我如今向槽房连瓮掇将来，偿还了我弟兄每口债。", "酒斟着醇糯醅，脍切着鲤鱼胎。", "今口开怀，直吃的沉醉出山寨。"]'),
('yuanqu-6910','郑孔目风雪酷寒亭・落梅风','杨显之','元','元曲','yuanqu','','[]','只管里贪恋着酒如泉，可顿忘了他恩似海。',53,'元曲/yuanqu.json','["只管里贪恋着酒如泉，可顿忘了他恩似海。", "万一个在中途被人谋害，可不乾着了当初救命来。", "则问你护桥龙宋彬安在？。"]'),
('yuanqu-6911','郑孔目风雪酷寒亭・川拨棹','杨显之','元','元曲','yuanqu','','[]','这两个小婴孩，引三军何处来？赤紧的云锁冰崖，风敛阴霾，雪洒尘埃。',71,'元曲/yuanqu.json','["这两个小婴孩，引三军何处来？赤紧的云锁冰崖，风敛阴霾，雪洒尘埃。", "则半合儿早粉画楼台，玉砌衢街。", "俺军中也做了银妆甲铠，俺哥哥在酷寒亭怕不活冻煞。"]'),
('yuanqu-6912','郑孔目风雪酷寒亭・七弟兄','杨显之','元','元曲','yuanqu','','[]','莫猜，快来，把枷锁疾忙开。',44,'元曲/yuanqu.json','["莫猜，快来，把枷锁疾忙开。", "将哥哥左右相扶策，在鬼门关夺转得这冻形骸，向酷寒亭展脚输腰拜。"]'),
('yuanqu-6913','郑孔目风雪酷寒亭・梅花酒','杨显之','元','元曲','yuanqu','','[]','咱两个自间隔，为杀了裙钗，揽下非灾，不得明白。',97,'元曲/yuanqu.json','["咱两个自间隔，为杀了裙钗，揽下非灾，不得明白。", "沙门岛程途怎地捱？酷寒亭风雪如何奈？从别离三二载，睡梦里记心怀，天对付巧安排。", "(孔目云)兄弟，是我当日救你命来，今日你却做我的大恩人也。", "(正末唱)。"]'),
('yuanqu-6914','郑孔目风雪酷寒亭・收江南','杨显之','元','元曲','yuanqu','','[]','呀！谁承望月明千里故人来，则被这泼烟花送了你犯由牌，狠公人又待活烧埋。',52,'元曲/yuanqu.json','["呀！谁承望月明千里故人来，则被这泼烟花送了你犯由牌，狠公人又待活烧埋。", "到今日救解，早收恰了那一点泪沾腮。"]'),
('yuanqu-6915','地藏王证东窗事犯・仙吕/端正好','孔文卿','元','元曲','yuanqu','','[]','见一日帝王宣十三次，多应挡回俺百万雄师。',46,'元曲/yuanqu.json','["见一日帝王宣十三次，多应挡回俺百万雄师。", "莫不朝廷中别有甚关机事，既不沙却怎竹节也似差天使？。"]'),
('yuanqu-6916','地藏王证东窗事犯・幺篇','孔文卿','元','元曲','yuanqu','','[]','多敢是圣明君犒赏待宣赐，怎肯信谗言节外生枝？只不过休兵罢战还朝呵是，我暗暗地自寻思。',108,'元曲/yuanqu.json','["多敢是圣明君犒赏待宣赐，怎肯信谗言节外生枝？只不过休兵罢战还朝呵是，我暗暗地自寻思。", "莫不是封官爵圣恩慈，明宣赐赏金资？添军校复还时，将三略展六韬施，收九府取京师，杀猛将血横尸。", "夺了四京九府，须要称了俺平生志！(下)。"]'),
('yuanqu-6917','地藏王证东窗事犯・仙吕/点绛唇','孔文卿','元','元曲','yuanqu','','[]','立国安邦，列着虎贲郎将。',30,'元曲/yuanqu.json','["立国安邦，列着虎贲郎将。", "沙场上，卧雪眠霜，争与恁百二山河掌。"]'),
('yuanqu-6918','地藏王证东窗事犯・油葫芦','孔文卿','元','元曲','yuanqu','','[]','想十三人舞袖登城临汴梁，向青城虏了上皇。',116,'元曲/yuanqu.json','["想十三人舞袖登城临汴梁，向青城虏了上皇。", "(带云)唬得禁军八百万丢盔卸甲。", "(唱)那其间，无一个匣中宝剑掣秋霜！杨戬是个帮闲攒懒元戎将，蔡京是个传书献简头厅相。", "一个治家亡了家，一个安邦的丧厂邦。", "虏得些金枝玉叶离了乡党，若不是泥马走康正。"]'),
('yuanqu-6919','地藏王证东窗事犯・天下乐','孔文卿','元','元曲','yuanqu','','[]','到如今宋室江山都属四国王，生并的国破城荒！那一场我与你重安口月定了四方。',83,'元曲/yuanqu.json','["到如今宋室江山都属四国王，生并的国破城荒！那一场我与你重安口月定了四方。", "战沙场几个死？破敌军几处伤？兀的是功名纸半张！(云)既是我谋反，哪里积草屯粮？谁见来？(唱)。"]'),
('yuanqu-6920','地藏王证东窗事犯・那吒令','孔文卿','元','元曲','yuanqu','','[]','恁寻思试想，向杀场战场；恁寻思试想，俺安邦定邦；恁寻思试想，立朝纲纪纲。',67,'元曲/yuanqu.json','["恁寻思试想，向杀场战场；恁寻思试想，俺安邦定邦；恁寻思试想，立朝纲纪纲。", "我不合扶持的帝业兴，我不合保护的山河壮，我不合整顿的地老天荒。"]'),
('yuanqu-6921','地藏王证东窗事犯・寄生草','孔文卿','元','元曲','yuanqu','','[]','仰面将高天问，英雄气怨上苍！问天公不曾天垂象，治居民不曾教居民荡，统三军不曾教三军丧。',65,'元曲/yuanqu.json','["仰面将高天问，英雄气怨上苍！问天公不曾天垂象，治居民不曾教居民荡，统三军不曾教三军丧。", "只落的满身枷锁跪厅前，却甚一轮皂盖飞头下！。"]'),
('yuanqu-6922','地藏王证东窗事犯・村里迓鼓','孔文卿','元','元曲','yuanqu','','[]','我不合扶立一人为帝，教万民失望；我不合于家为国，无明夜，将烟尘扫荡；我不合仗手策，凭英勇，占得山河雄壮。',77,'元曲/yuanqu.json','["我不合扶立一人为帝，教万民失望；我不合于家为国，无明夜，将烟尘扫荡；我不合仗手策，凭英勇，占得山河雄壮。", "镇得四海宁，帝业昌，民心良，则兀的是我请官受赏！。"]'),
('yuanqu-6923','地藏王证东窗事犯・元和令','孔文卿','元','元曲','yuanqu','','[]','消不得上马金下马银，也合教出朝将入朝相。',62,'元曲/yuanqu.json','["消不得上马金下马银，也合教出朝将入朝相。", "我与恁夺旗扯鼓统儿郎，不能够列金钗十二行。", "教这个牧童村叟蠢芒郎，到能够暮登天子堂！。"]'),
('yuanqu-6924','地藏王证东窗事犯・上马娇','孔文卿','元','元曲','yuanqu','','[]','不索你狠，更怕我慌。',52,'元曲/yuanqu.json','["不索你狠，更怕我慌。", "你道是先打后商量，做了个耕牛为主遭鞭杖。", "见外则慌，内则相隔着汉阳江，陛下久顾镇苏杭。"]'),
('yuanqu-6925','地藏王证东窗事犯・游四门','孔文卿','元','元曲','yuanqu','','[]','只怕不知祸起在萧墙！你待兴心乱朝纲，诈传宣赚离我边庭亡。',48,'元曲/yuanqu.json','["只怕不知祸起在萧墙！你待兴心乱朝纲，诈传宣赚离我边庭亡。", "原来恁没世界有官方，暗暗将刀斧列在阶旁。"]'),
('yuanqu-6926','地藏王证东窗事犯・胜葫芦','孔文卿','元','元曲','yuanqu','','[]','却甚烂醉佳人锦瑟旁，今日和天也顺时光。',54,'元曲/yuanqu.json','["却甚烂醉佳人锦瑟旁，今日和天也顺时光。", "则那逆天的天不教命亡，顺天的祸从天降；逆天的神灵不报，顺天的受灾殃！。"]'),
('yuanqu-6927','地藏王证东窗事犯・寄生草','孔文卿','元','元曲','yuanqu','','[]','你道我把朝廷乱，不合将社稷匡。',74,'元曲/yuanqu.json','["你道我把朝廷乱，不合将社稷匡。", "我不合降戚方揭寨施心亮，我不合捉李成贼到中军帐，我不合破金国扶立的高宗旺。", "待将我签头号令市曹中，却甚功劳写在凌烟上？。"]'),
('yuanqu-6928','地藏王证东窗事犯・赚煞','孔文卿','元','元曲','yuanqu','','[]','下我在十恶死囚牢，再不坐九鼎莲花帐，则我这谋反事如何肯当！我死呵，做个负屈衔冤忠孝鬼！见有侵境界小国偏邦，秦桧结勾起刀枪。',156,'元曲/yuanqu.json','["下我在十恶死囚牢，再不坐九鼎莲花帐，则我这谋反事如何肯当！我死呵，做个负屈衔冤忠孝鬼！见有侵境界小国偏邦，秦桧结勾起刀枪。", "陛下，则怕你坐不久龙床！俺死呵，落得个盖世界居民众众讲：岳飞子父每不合舍性命生并的南服北降，出气力西除东荡！(带云)杀了岳飞、岳云、张宪三人，(唱)陛下，你便似砍折条擎天架海紫金梁！(下)。"]'),
('yuanqu-6929','地藏王证东窗事犯・醉春风','孔文卿','元','元曲','yuanqu','','[]','又不曾礼经忏法堂中，俺则是打勤劳山寺里。',110,'元曲/yuanqu.json','["又不曾礼经忏法堂中，俺则是打勤劳山寺里。", "则为你上瞒天子下欺臣，(带云)你道我痴，我道你奸。", "\"缚虎则易，纵虎则难\"。", "(唱)太师，这言语单道着你！你休笑我秽，我干净如你！你问我缘由，我对你说破，看怎生支对？有甚不知你来意！。"]'),
('yuanqu-6930','地藏王证东窗事犯・迎仙客','孔文卿','元','元曲','yuanqu','','[]','你来意我理会得，你未说我先知。',74,'元曲/yuanqu.json','["你来意我理会得，你未说我先知。", "知你个怕心也你那梦境恶，故来动俺山寺里，祝神祗，礼忏会。", "休只管央及俺菩提，道不得念彼观音力。", "(等太师云了)(正末唱)。"]'),
('yuanqu-6931','地藏王证东窗事犯・石榴花','孔文卿','元','元曲','yuanqu','','[]','太师一一问真实，你听我说因依。',77,'元曲/yuanqu.json','["太师一一问真实，你听我说因依。", "当时不信大贤妻，他曾苦苦地劝你，你岂不自知？东窗下不解西来意，我葫芦提，你无支持。", "则为您奸猾狡佞将心昧，你但举意，我早先知。"]'),
('yuanqu-6932','地藏王证东窗事犯・斗鹤鹑','孔文卿','元','元曲','yuanqu','','[]','知你结勾他邦，可甚于家为国？咱人事要寻思，免劳后悔。',77,'元曲/yuanqu.json','["知你结勾他邦，可甚于家为国？咱人事要寻思，免劳后悔。", "岂不闻湛湛青天不可欺！据着你这所为，来这里唬鬼瞒神，做的个藏头露尾。", "(云)太师，你休笑这火筒。", "(唱)。"]'),
('yuanqu-6933','地藏王证东窗事犯・红绣鞋','孔文卿','元','元曲','yuanqu','','[]','他本是个君子人则待挟权倚势，吹一吹登时教人烟灭灰飞。',83,'元曲/yuanqu.json','["他本是个君子人则待挟权倚势，吹一吹登时教人烟灭灰飞。", "则为他节外生枝，教人落便宜。", "为甚不厨中放，常向我手中携？(带云)这其间不是我掌握着呵，(唱)敢起烟尘，倾了社稷！。"]'),
('yuanqu-6934','地藏王证东窗事犯・满庭芳','孔文卿','元','元曲','yuanqu','','[]','你则待亡家败国，你几曾夺旗扯鼓，厮杀相持？将别人边塞功番成罪，你只会改是为非。',79,'元曲/yuanqu.json','["你则待亡家败国，你几曾夺旗扯鼓，厮杀相持？将别人边塞功番成罪，你只会改是为非。", "有神方难除你病疾，无妙药将我难医。", "你将那英雄辈，都向钢刀下做鬼，云阳内血沾衣！。"]'),
('yuanqu-6935','地藏王证东窗事犯・快活三','孔文卿','元','元曲','yuanqu','','[]','则为你非来我这风越起，风过处日光辉。',46,'元曲/yuanqu.json','["则为你非来我这风越起，风过处日光辉。", "则为你拿了云握住雨不淋漓。", "便下雨呵，则是替岳飞天垂泪！。"]'),
('yuanqu-6936','地藏王证东窗事犯・鲍老儿','孔文卿','元','元曲','yuanqu','','[]','替头儿看看趱到你那里，怕犯法，没头罪。',56,'元曲/yuanqu.json','["替头儿看看趱到你那里，怕犯法，没头罪。", "我不念经强如人咒骂你，你仔细参详八句诗中意。", "你心我知，一言既出，驷马难追。"]'),
('yuanqu-6937','地藏王证东窗事犯・耍孩儿','孔文卿','元','元曲','yuanqu','','[]','这寺嵯峨秀丽山叠翠，这湖瀑布岚光水碧，这山千层万叠似屏帏，这玉湖清浩荡尽苏堤。',75,'元曲/yuanqu.json','["这寺嵯峨秀丽山叠翠，这湖瀑布岚光水碧，这山千层万叠似屏帏，这玉湖清浩荡尽苏堤。", "青山只会磨今古，绿水何曾洗是非？枉了你修福利，送的教人亡家破，瓦解星飞。"]'),
('yuanqu-6938','地藏王证东窗事犯・三煞','孔文卿','元','元曲','yuanqu','','[]','岳飞定家邦功已休，秦桧反朝廷事已知，你两家冤仇有似檐间水。',70,'元曲/yuanqu.json','["岳飞定家邦功已休，秦桧反朝廷事已知，你两家冤仇有似檐间水。", "则为奸谗宰相千般狠，送了慷慨将军八面威。", "你所事违天理，休言神明不报，只争来早来迟。"]'),
('yuanqu-6939','地藏王证东窗事犯・二煞','孔文卿','元','元曲','yuanqu','','[]','你看看业罐满，渐渐死限催，那三人等候在阴司内。',67,'元曲/yuanqu.json','["你看看业罐满，渐渐死限催，那三人等候在阴司内。", "这话是金风未动蝉先觉，暗送无常死不知。", "那时你归泉世，索受他十恶罪犯，休想打的出六道轮回。"]'),
('yuanqu-6940','地藏王证东窗事犯・收尾','孔文卿','元','元曲','yuanqu','','[]','便似哑迷般说与你猜，你索似闷弓儿心上疑。',49,'元曲/yuanqu.json','["便似哑迷般说与你猜，你索似闷弓儿心上疑。", "有一日东窗事犯知我来意，只怕你手搠着胸脯恁时节悔。", "(下)。"]'),
('yuanqu-6941','地藏王证东窗事犯・仙吕/赏花时','孔文卿','元','元曲','yuanqu','','[]','这六爻内特将祸福看，指引迷人八卦间。',104,'元曲/yuanqu.json','["这六爻内特将祸福看，指引迷人八卦间。", "(等牧童吹笛科)(做听住，唱)只听的笛声韵悠残，这其间天昏日晚，直引鬼门关。", "(闪下)(等地藏王上，云了)(正末做见了科，云)我哪里不寻你？却在这里。", "秦太师钧旨有勾！(唱)。"]'),
('yuanqu-6942','地藏王证东窗事犯・幺篇','孔文卿','元','元曲','yuanqu','','[]','兀底明写东南第一山，(等押秦太师带枷上，云了)(正末唱)则见鬼吏牛头惨雾间。',71,'元曲/yuanqu.json','["兀底明写东南第一山，(等押秦太师带枷上，云了)(正末唱)则见鬼吏牛头惨雾间。", "见太师搁着泪诉艰难，教传示夫人，只说道东窗事犯，大古是人马报平安。"]'),
('yuanqu-6943','地藏王证东窗事犯・越调/斗鹌鹑','孔文卿','元','元曲','yuanqu','','[]','但行处怨雾凄迷，悲风乱吼。',72,'元曲/yuanqu.json','["但行处怨雾凄迷，悲风乱吼。", "恰离枉死城中，早转到阴山背后。", "不能青史内标名，只落的钢刀下斩首。", "每日秦不管，魏不收。", "送的俺酩子里遭诛，更怕我葫芦罢手。"]'),
('yuanqu-6944','地藏王证东窗事犯・紫花儿序','孔文卿','元','元曲','yuanqu','','[]','三魂儿潇潇洒洒，七魄儿怨怨哀哀，一灵儿荡荡悠悠。',80,'元曲/yuanqu.json','["三魂儿潇潇洒洒，七魄儿怨怨哀哀，一灵儿荡荡悠悠。", "俺不是降灾邪祟，俺是出力公侯。", "你问缘由，我对圣主明言剐骨仇，俺说的并无虚谬。", "谢圣上将这屈死冤魂，放入这凤阁龙楼。"]'),
('yuanqu-6945','地藏王证东窗事犯・鬼三台','孔文卿','元','元曲','yuanqu','','[]','臣在生时多生受，驰甲胄，做先锋帅首，向沙塞拥貔貅。',74,'元曲/yuanqu.json','["臣在生时多生受，驰甲胄，做先锋帅首，向沙塞拥貔貅。", "臣说着呵自羞，想微臣挟人捉将一旦休，只落的披枷带锁遭重囚。", "臣想统三军永远长春，不想半路里拔着短筹。"]'),
('yuanqu-6946','地藏王证东窗事犯・紫花儿序','孔文卿','元','元曲','yuanqu','','[]','臣性命不若如花梢滴露，风里杨花，水上浮沤。',101,'元曲/yuanqu.json','["臣性命不若如花梢滴露，风里杨花，水上浮沤。", "臣统三军舍命，与四国王做敌头，将四京九府平收。", "不想臣扶侍君王不到头，提起来雨泪交流。", "想微臣盖世功名，到今日一笔都勾。", "(云)臣等三人每，曾与国家出气力来。", "(唱)。"]'),
('yuanqu-6947','地藏王证东窗事犯・秃厮儿','孔文卿','元','元曲','yuanqu','','[]','臣望写皇阁千年不朽，标青史万代名留。',43,'元曲/yuanqu.json','["臣望写皇阁千年不朽，标青史万代名留。", "臣做了个充饥画饼风内烛，这冤仇，这冤仇怎肯于休！。"]'),
('yuanqu-6948','地藏王证东窗事犯・圣药王','孔文卿','元','元曲','yuanqu','','[]','臣这方头，又不曾写犯由，也合三思然后再追求。',55,'元曲/yuanqu.json','["臣这方头，又不曾写犯由，也合三思然后再追求。", "臣海外收伏了四百州，将凌烟阁翻作抱官囚，久以后再谁想分破帝王忧！。"]'),
('yuanqu-6949','地藏王证东窗事犯・络丝娘','孔文卿','元','元曲','yuanqu','','[]','臣舍性命出气力请将边庭镇守，秦桧没功劳请俸干吃了堂食御酒。',51,'元曲/yuanqu.json','["臣舍性命出气力请将边庭镇守，秦桧没功劳请俸干吃了堂食御酒。", "他待将咱宋室江山一笔勾，好金帛和大金家结勾。"]'),
('yuanqu-6950','地藏王证东窗事犯・绵答絮','孔文卿','元','元曲','yuanqu','','[]','臣趁着悲风浙浙，怨气哀哀，天公不管，地府难收。',58,'元曲/yuanqu.json','["臣趁着悲风浙浙，怨气哀哀，天公不管，地府难收。", "相伴着野草闲花满地愁，不能够敕赐官封万户侯。", "想世事悠悠，叹英雄逐水流。"]'),
('yuanqu-6951','地藏王证东窗事犯・拙鲁速','孔文卿','元','元曲','yuanqu','','[]','臣将抽头不抽头，向杀人处便攒头。',44,'元曲/yuanqu.json','["臣将抽头不抽头，向杀人处便攒头。", "秦桧安排钓钩，正着他机彀，怎生收救？臣当初只见食不见钩。"]'),
('yuanqu-6952','地藏王证东窗事犯・幺篇','孔文卿','元','元曲','yuanqu','','[]','想微臣志未酬，除秦桧一命休。',58,'元曲/yuanqu.json','["想微臣志未酬，除秦桧一命休。", "陛下逼逐记在心头。", "将缘由苦苦遗留，明明说透。", "把那禽兽，剐割肌肉，号令签头，豁不尽心上忧。"]'),
('yuanqu-6953','地藏王证东窗事犯・收尾','孔文卿','元','元曲','yuanqu','','[]','忠臣难出贼臣彀，陛下宣的文武公卿讲究。',42,'元曲/yuanqu.json','["忠臣难出贼臣彀，陛下宣的文武公卿讲究。", "用刀斧将秦桧市曹中诛，唤俺这屈死冤魂奠盏酒！。"]'),
('yuanqu-6954','地藏王证东窗事犯・正宫/端正好','孔文卿','元','元曲','yuanqu','','[]','奉钧命陷在酆都，别妻子离了乡郡。',46,'元曲/yuanqu.json','["奉钧命陷在酆都，别妻子离了乡郡。", "则我便是个了事公人，鬼窟窿里衣饭也能寻趁，一去二十载无音信。"]'),
('yuanqu-6955','地藏王证东窗事犯・滚绣球','孔文卿','元','元曲','yuanqu','','[]','去时节未四旬，回来时经几春，不觉染秋霜两鬓，转回头高冢麒麟。',89,'元曲/yuanqu.json','["去时节未四旬，回来时经几春，不觉染秋霜两鬓，转回头高冢麒麟。", "改换的日月别，重安的社稷稳，每应旧功臣老尽，今日另巍巍别是个乾坤。", "果然道长江后浪催前浪，今日立起新君换旧君，岁月如奔。"]'),
('yuanqu-6956','地藏王证东窗事犯・呆古朵','孔文卿','元','元曲','yuanqu','','[]','玉阶前圣主将臣来问，听臣说太师原因。',68,'元曲/yuanqu.json','["玉阶前圣主将臣来问，听臣说太师原因。", "当日做好事回来，路逢着一人。", "施全心胆大将他坏，秦桧福气大难侵近。", "本向灵隐寺祭福星，不想到宅上惹祸根。"]'),
('yuanqu-6957','地藏王证东窗事犯・倘秀才','孔文卿','元','元曲','yuanqu','','[]','太师顿然省将诗句议论，道这个呆行者好言而有准，道那八个字自包天地自杀身！因此上差臣为公吏，勾唤那僧人，因此上事紧。',57,'元曲/yuanqu.json','["太师顿然省将诗句议论，道这个呆行者好言而有准，道那八个字自包天地自杀身！因此上差臣为公吏，勾唤那僧人，因此上事紧。"]'),
('yuanqu-6958','地藏王证东窗事犯・滚绣球','孔文卿','元','元曲','yuanqu','','[]','想着秦太师性情狠，不由何宗立去心紧，正行里起撼天关大风一阵，无片时间早刮的地惨天昏。',108,'元曲/yuanqu.json','["想着秦太师性情狠，不由何宗立去心紧，正行里起撼天关大风一阵，无片时间早刮的地惨天昏。", "那风出山卷怪尘，那风入山推败云，险刮的那太华山一时崩损，刮的昆仑山希力力难以影身。", "那风刮的六朝老树和根倒，万里长江恶浪奔，进退无门。"]'),
('yuanqu-6959','地藏王证东窗事犯・倘秀才','孔文卿','元','元曲','yuanqu','','[]','又无侵古道疏篱远村，见一个卦先儿深山中潜隐，他和那野草闲花作近邻。',51,'元曲/yuanqu.json','["又无侵古道疏篱远村，见一个卦先儿深山中潜隐，他和那野草闲花作近邻。", "要知山下路，须问往来人，□□□□□。"]'),
('yuanqu-6960','地藏王证东窗事犯・叨叨令','孔文卿','元','元曲','yuanqu','','[]','恰问罢早驾祥云瑞霭，乘着风信，见一个牧童牛背笛声韵。',75,'元曲/yuanqu.json','["恰问罢早驾祥云瑞霭，乘着风信，见一个牧童牛背笛声韵。", "我将那东南山去路将他问，他指一指隐灵寺行者分明近。", "他早去了也未哥，早去了也未哥，向前来扯住禅师问。"]'),
('yuanqu-6961','地藏王证东窗事犯・倘秀才','孔文卿','元','元曲','yuanqu','','[]','恰道罢见太师铁锁沉枷在身，并无那玉女金童接引，则有一簇牛头鬼吏跟。',49,'元曲/yuanqu.json','["恰道罢见太师铁锁沉枷在身，并无那玉女金童接引，则有一簇牛头鬼吏跟。", "教秦桧，见微臣，普碌碌推出狱门。"]'),
('yuanqu-6962','地藏王证东窗事犯・滚绣球','孔文卿','元','元曲','yuanqu','','[]','那阴司刑法别，比阳间官府狠，不想他苦恹恹痛遭危困，只因笑吟吟陷于人洗垢寻痕。',100,'元曲/yuanqu.json','["那阴司刑法别，比阳间官府狠，不想他苦恹恹痛遭危困，只因笑吟吟陷于人洗垢寻痕。", "参可可皮肉开，血力力骨肉分，痛杀杀怎挨那三推六问！监押都是恶鬼狞神。", "说太师于般凌虐苦，则除你一上青山便化身，显夫人九烈三贞。"]'),
('yuanqu-6963','地藏王证东窗事犯・二煞','孔文卿','元','元曲','yuanqu','','[]','岳飞道秦桧不肯学汉萧何追韩信，至潭溪赍发的交职挂三齐印。',101,'元曲/yuanqu.json','["岳飞道秦桧不肯学汉萧何追韩信，至潭溪赍发的交职挂三齐印。", "道陛下自离京兆泥马走，似高祖荥阳一跳身。", "枉了他子父每舍死忘生，苦征恶战，扯鼓夺旗，捉将挟人，漾人头厮滚，噙热血相喷。", "亏煞他枕盔腮印月，卧甲地生鳞。"]'),
('yuanqu-6964','地藏王证东窗事犯・尾','孔文卿','元','元曲','yuanqu','','[]','投至奏的九重禁阙君王准，教烧与掌恶酆都地藏神。',94,'元曲/yuanqu.json','["投至奏的九重禁阙君王准，教烧与掌恶酆都地藏神。", "屈杀了岳飞、岳云、张宪三人，已上升三个全身。", "将杀身秦桧贼臣不须论，想他诳上欺君，苦虐黎民。", "近有东岳灵文，交替了陈寿千年无字碑，古自证不的本！。"]'),
('yuanqu-6965','地藏王证东窗事犯・后庭花','孔文卿','元','元曲','yuanqu','','[]','见一日十三次金宇牌，差天臣将宣命开。',108,'元曲/yuanqu.json','["见一日十三次金宇牌，差天臣将宣命开。", "宣微臣火速临京阙，以此上无明夜离了寨栅，驰驿马践尘埃渡过长江一脉。", "臣到朝中怎挣揣？想秦桧无百刂划，送微臣大理寺问罪责，将反朝廷名字揣，屈英雄泪满腮。", "臣争战了十数载，将功劳翻作罪责。"]'),
('yuanqu-6966','地藏王证东窗事犯・柳叶儿','孔文卿','元','元曲','yuanqu','','[]','今日都撇在九霄云外，不能够位三公门转干阶。',76,'元曲/yuanqu.json','["今日都撇在九霄云外，不能够位三公门转干阶。", "将秦桧三宗九族家族坏，每家冤仇大。", "将秦桧剖棺椁坐刂尸骸，恁的呵，恩和仇报的明白。", "(等地藏王队子上)(断出了)。"]'),
('yuanqu-6967','越调・小桃红磕瓜','李伯瑜','元','元曲','yuanqu','','[]','木胎毡观要柔和，用最软的皮儿裹。',59,'元曲/yuanqu.json','["木胎毡观要柔和，用最软的皮儿裹。", "手内无他煞难过，得来呵，普天下好净也应难躲。", "兀的般砌末，守着个粉脸儿色末，诨广笑声多。"]'),
('yuanqu-6968','李素兰风月玉壶春・仙吕/点绛唇','贾仲明','元','元曲','yuanqu','','[]','映雪窗前，岂辞劳倦，攻经典。',25,'元曲/yuanqu.json','["映雪窗前，岂辞劳倦，攻经典。", "甲榜争先，独占文场选。"]'),
('yuanqu-6969','李素兰风月玉壶春・混江龙','贾仲明','元','元曲','yuanqu','','[]','赴琼林饮宴，不枉了青灯黄卷二十年。',153,'元曲/yuanqu.json','["赴琼林饮宴，不枉了青灯黄卷二十年。", "有郎官过盏，中使传宣。", "御酒淋漓袍袖湿，宫花蹀躞帽檐偏。", "列紫衫银带，听玉管冰弦。", "挑绛纱红烛，对皓月遥天。", "醉醺醺红妆扶策下瑶阶，气昂昂朱衣迎接离金殿。", "摆列着玉簪珠履，准备着宝马银鞭。", "(琴童云)相公，时遇春天清明节令，你看这郊外人稠物穰，都是赏心乐事。", "真个好热闹也。", "(正末唱)。"]'),
('yuanqu-6970','李素兰风月玉壶春・油葫芦','贾仲明','元','元曲','yuanqu','','[]','则见那仕女王孙游上苑，人人可便赏禁烟。',83,'元曲/yuanqu.json','["则见那仕女王孙游上苑，人人可便赏禁烟。", "则见那桃花散锦柳飞绵，语关关枝上流莺啭，舞翩翩波面鸳鸯恋。", "这壁厢罗绮丛，那壁厢鼓吹喧。", "抵多少笙歌闹入梨花院，可兀的就芳草设华筵。"]'),
('yuanqu-6971','李素兰风月玉壶春・天下乐','贾仲明','元','元曲','yuanqu','','[]','则待要闷向秦楼列管弦，青帘风外悬，嗔游人醉眠芳径软。',49,'元曲/yuanqu.json','["则待要闷向秦楼列管弦，青帘风外悬，嗔游人醉眠芳径软。", "绿阴中闻鹧鸪，红香中啼杜鹃，休辜负艳阳三月天。"]'),
('yuanqu-6972','李素兰风月玉壶春・鹊踏枝','贾仲明','元','元曲','yuanqu','','[]','一个个玉天仙，一双双关蝉娟。',46,'元曲/yuanqu.json','["一个个玉天仙，一双双关蝉娟。", "一层层锦坞花溪，一里里翠绕珠圈。", "一步步丹青扇面，一段段流水桃源。"]'),
('yuanqu-6973','李素兰风月玉壶春・六幺序','贾仲明','元','元曲','yuanqu','','[]','呀，猛见了心飘荡，魂灵儿飞在天，怎生来这搭儿遇着神仙？他那里眼送眉传，我这里腹热心煎，两下里都思惹情牵。',100,'元曲/yuanqu.json','["呀，猛见了心飘荡，魂灵儿飞在天，怎生来这搭儿遇着神仙？他那里眼送眉传，我这里腹热心煎，两下里都思惹情牵。", "他则管送春情不住相留恋，引的人意悬悬似热地蚰蜒。", "他生的身躯袅娜真堪羡。", "更那堪眉弯新月，步蹙金莲。"]'),
('yuanqu-6974','李素兰风月玉壶春・幺篇','贾仲明','元','元曲','yuanqu','','[]','好着俺俄延熬煎，眼晕头旋。',101,'元曲/yuanqu.json','["好着俺俄延熬煎，眼晕头旋。", "有口难言。", "兀的不送了我也这一搭儿平原。", "他那里褪后趋前，俺这里意马心猿。", "几时得共宿同眠。", "若天公肯与人方便，成就了一世姻缘。", "若是风亭月馆谐燕，但得他舌尖上甜唾，才止住这口角头顽涎。"]'),
('yuanqu-6975','李素兰风月玉壶春・后庭花','贾仲明','元','元曲','yuanqu','','[]','感谢你个曲江池李亚仙，肯颐恋这贬江州白乐天。',77,'元曲/yuanqu.json','["感谢你个曲江池李亚仙，肯颐恋这贬江州白乐天。", "愿你个李素兰常风韵，则这个玉壶生永结缘。", "双通叔敢开言，着你个苏卿心愿。", "我虽无那走江湖大本钱，也敢赔家私住几年。"]'),
('yuanqu-6976','李素兰风月玉壶春・赚煞','贾仲明','元','元曲','yuanqu','','[]','我得了这沉香串翠珠囊，你收取这玉螳螂白罗扇，四件儿是咱这玉洁冰清意坚。',150,'元曲/yuanqu.json','["我得了这沉香串翠珠囊，你收取这玉螳螂白罗扇，四件儿是咱这玉洁冰清意坚。", "(旦云)秀才，则是一件，争奈老母严恶，休得见责。", "(正末云)姐姐放心。", "(唱)料的这入马东西应个免，我着他拣口儿食，换套儿穿，任抓掀，不足我拨万论千，常拚着卖了城南金谷园。", "若你个李素兰意专，这玉壶生情愿，我情愿一春常费买花钱。", "(下)。"]'),
('yuanqu-6977','李素兰风月玉壶春・仙吕/端正好','贾仲明','元','元曲','yuanqu','','[]','赴皇都，趋天阙，现如今国家选用豪杰。',100,'元曲/yuanqu.json','["赴皇都，趋天阙，现如今国家选用豪杰。", "(陶伯常云)据贤弟文章，必得重用。", "(正末唱)凭着我三冬足用文章绝，挥翰墨，走龙蛇，穿宫锦，着朝靴，封官爵，享豪奢。", "那时分，恁时节，我可将仁兄结草的这衔环谢。", "(下)。"]'),
('yuanqu-6978','李素兰风月玉壶春・南吕/一枝花','贾仲明','元','元曲','yuanqu','','[]','每日家春风燕子楼，夜月鸣珂巷。',67,'元曲/yuanqu.json','["每日家春风燕子楼，夜月鸣珂巷。", "莺花脂粉社，诗酒绮罗乡。", "弄玉团香，助豪气三千丈，列金钗十二行。", "我是个翠红堆傅粉的何郎，花胡同画眉的张敞。"]'),
('yuanqu-6979','李素兰风月玉壶春・隔尾','贾仲明','元','元曲','yuanqu','','[]','看了这四时兰蕙十分旺，说甚么一架蔷薇满院香。',57,'元曲/yuanqu.json','["看了这四时兰蕙十分旺，说甚么一架蔷薇满院香。", "今日折向书斋玉壶中放。", "相近着绿窗，胜梨花淡妆。", "每日家净洗双眸乐心儿赏。"]'),
('yuanqu-6980','李素兰风月玉壶春・四块玉','贾仲明','元','元曲','yuanqu','','[]','这壶画的来玉润温，这兰画的来香飘荡。',64,'元曲/yuanqu.json','["这壶画的来玉润温，这兰画的来香飘荡。", "看了这玉软香娇不寻常，则这个玉生香花解语风流像。", "端的可便堪画图，画图来堪咏题，咏题来堪玩赏。"]'),
('yuanqu-6981','李素兰风月玉壶春・隔尾','贾仲明','元','元曲','yuanqu','','[]','那里是敲金击玉辞源响，则为这玉骨冰肌体段香。',70,'元曲/yuanqu.json','["那里是敲金击玉辞源响，则为这玉骨冰肌体段香。", "画的来素淡轻盈甚停当。", "从今后高卷起莫张，做一个绣袋儿谨藏。", "休着那等干咽唾，冷眼见的闲人把做话讲。"]'),
('yuanqu-6982','李素兰风月玉壶春・感皇恩','贾仲明','元','元曲','yuanqu','','[]','呀！眼见的打死鸳鸯，拆散鸾凰。',99,'元曲/yuanqu.json','["呀！眼见的打死鸳鸯，拆散鸾凰。", "则这个玉壶生，更和这素兰女，则索告你个柳青娘。", "(卜儿云)我将你卖与回回、达达、虏虏去。", "(旦悲科)(正末唱)从今后迎风北苑，早则不待月西厢。", "直惹的狂蝶觑，野蜂闹，喜蛛忙。"]'),
('yuanqu-6983','李素兰风月玉壶春・采茶歌','贾仲明','元','元曲','yuanqu','','[]','素兰呵，那里也翠珠囊，白忙里玉螳螂。',51,'元曲/yuanqu.json','["素兰呵，那里也翠珠囊，白忙里玉螳螂。", "决撒了高烧银烛照红妆，没指望月夜双歌玉壶腔，空压杀春风一曲杜韦娘。"]'),
('yuanqu-6984','李素兰风月玉壶春・牧羊关','贾仲明','元','元曲','yuanqu','','[]','多管是人遭遇，料应来天对当，走将来冻剥剥雪上加霜。',196,'元曲/yuanqu.json','["多管是人遭遇，料应来天对当，走将来冻剥剥雪上加霜。", "这厮待搠断了俺风月佳期，掀腾了花烛洞房。", "(卜儿云)李玉壶，你是个读书的人，好不聪明。", "你也知法度，你要娶俺女孩儿，你姓李，俺也姓李，同姓不可成亲，你晓的么？李婉儿为甚复落娼，皆因为李府尹的儿子也姓李的缘故。", "现放着断下一首〔南柯子〕词，便是个大证见。", "(正末唱)你又不是判宰府的南柯子，这的是玉壶生小词章。", "谁想花柳亭鸣珂巷，撞着你个嘴巴巴狠切的娘。"]'),
('yuanqu-6985','李素兰风月玉壶春・二煞','贾仲明','元','元曲','yuanqu','','[]','我为恋着春风兰芷娇容放，嗨，早忘了秋日槐花举子忙。',76,'元曲/yuanqu.json','["我为恋着春风兰芷娇容放，嗨，早忘了秋日槐花举子忙。", "玉壶生拜辞了素兰香，向着个客馆空床，独宿有梅花纸帐。", "那寂寞，那凄凉，那悲怆，雁杳鱼沉两渺茫，冷落吴江。"]'),
('yuanqu-6986','李素兰风月玉壶春・黄钟尾','贾仲明','元','元曲','yuanqu','','[]','再谁供养我那荔枝浆蔷薇露葡萄酿？再谁照顾我那应口饭依时茶醒酒汤？不是我冷气虚心厮数量，则要你玉骨冰肌自主张，傲雪欺霜映碧窗，不要你节外生枝有疏放。',146,'元曲/yuanqu.json','["再谁供养我那荔枝浆蔷薇露葡萄酿？再谁照顾我那应口饭依时茶醒酒汤？不是我冷气虚心厮数量，则要你玉骨冰肌自主张，傲雪欺霜映碧窗，不要你节外生枝有疏放。", "若别了巫山窈窕娘，忧愁杀章台走马郎。", "离了嘉禾旧朋党，断却苏州刺史肠，再要相逢莫承望。", "但提着俺那花前月下共双双，便是铁石的心肝我索慢慢的想。", "(下)。"]'),
('yuanqu-6987','李素兰风月玉壶春・中吕/粉蝶儿','贾仲明','元','元曲','yuanqu','','[]','则为我夜去明来，没来由惹一场大惊小怪。',68,'元曲/yuanqu.json','["则为我夜去明来，没来由惹一场大惊小怪。", "我不合占着柳陌花街，惹的那个主，这个语，教小生如何忍奈？我拜辞了后边榭歌台，赤紧的还不彻宿生冤债。"]'),
('yuanqu-6988','李素兰风月玉壶春・醉春风','贾仲明','元','元曲','yuanqu','','[]','俺情分重如山，相思深似海。',55,'元曲/yuanqu.json','["俺情分重如山，相思深似海。", "他心我意两相同，着小生如何便改、改？想着俺怀抱儿内恩情，枕头儿上恩意，被窝儿里恩爱。"]'),
('yuanqu-6989','李素兰风月玉壶春・迎仙客','贾仲明','元','元曲','yuanqu','','[]','谢姨姨，肯怜才，则你是洛伽山救苦的观自在。',52,'元曲/yuanqu.json','["谢姨姨，肯怜才，则你是洛伽山救苦的观自在。", "问甚么撞着丧门，管甚么逢着吊客。", "怕甚么月值年灾，拚死在莺花寨。"]'),
('yuanqu-6990','李素兰风月玉壶春・红绣鞋','贾仲明','元','元曲','yuanqu','','[]','若瞒过那老虔婆赚离了门外，便是将俺那望夫石唤下山来，哎，你一个忒聪明肯做美的姨姨，你白裁划。',79,'元曲/yuanqu.json','["若瞒过那老虔婆赚离了门外，便是将俺那望夫石唤下山来，哎，你一个忒聪明肯做美的姨姨，你白裁划。", "你道他风流刚二八，我俊雅未头门，姨姨则道波。", "我则怕兀那青春不再来。"]'),
('yuanqu-6991','李素兰风月玉壶春・满庭芳','贾仲明','元','元曲','yuanqu','','[]','端详了艳色，春生杏脸，笑入莲腮。',78,'元曲/yuanqu.json','["端详了艳色，春生杏脸，笑入莲腮。", "我本要秦楼夜访金钗客，我与你审问个明白。", "因甚上不插带犀梳凤钗，懒亲傍玉镜鸾台？为甚么云鬓松了金额，不由我转猜，端的为谁来？。"]'),
('yuanqu-6992','李素兰风月玉壶春・石榴花','贾仲明','元','元曲','yuanqu','','[]','你道是筝闲玉雁懒铺排，琴被暗中埋。',91,'元曲/yuanqu.json','["你道是筝闲玉雁懒铺排，琴被暗中埋。", "休道你那绿窗前针指不曾拈，便小生也土培了砚台，揪撇下诗才。", "你为我病恹恹搀过这裙儿带，我为你沈腰宽减尽了形骸。", "你怕咱问时休放解，告姨姨只借过那镜儿来。"]'),
('yuanqu-6993','李素兰风月玉壶春・斗鹤鹑','贾仲明','元','元曲','yuanqu','','[]','你便似淡描来的洛浦神仙，我胜似泥塑来的投江太白。',185,'元曲/yuanqu.json','["你便似淡描来的洛浦神仙，我胜似泥塑来的投江太白。", "你可便休疑我的心肠，莫寻咱罪责。", "(旦云)你则这般撇的下我，可怎生便不上门来那？(正末唱)赤紧的十谒朱门九不开，可着我怎百刂划？那老虔婆虎视着兰房，小生呵，怎能勾龙归大海？(贴旦云)姐姐，你休烦恼，少不的先忧后喜，苦尽甜来。", "烦恼他做甚么？(正末云)姨姨，休要大惊小怪的，则怕那虔婆听的。", "(贴旦云)你则这般怕他那？(正末唱)。"]'),
('yuanqu-6994','李素兰风月玉壶春・快活三','贾仲明','元','元曲','yuanqu','','[]','那虔婆恨不的竖起条金斗街，险化作楚阳台。',40,'元曲/yuanqu.json','["那虔婆恨不的竖起条金斗街，险化作楚阳台。", "将一朵并头莲生磕擦两分开，刀割断合欢带。"]'),
('yuanqu-6995','李素兰风月玉壶春・鲍老儿','贾仲明','元','元曲','yuanqu','','[]','硬鼻凹寒森森扫下雪来，冷脸似冬凌块。',72,'元曲/yuanqu.json','["硬鼻凹寒森森扫下雪来，冷脸似冬凌块。", "夕斗毛齐眼睛向下排，则是个敲人脑的活妖怪。", "动不动神头鬼脸。", "投河奔井，拽巷逻街，张舌骗口，花言巧语，指皂为白。"]'),
('yuanqu-6996','李素兰风月玉壶春・十二月','贾仲明','元','元曲','yuanqu','','[]','唬得他无颜落色，惊的他手脚难抬。',99,'元曲/yuanqu.json','["唬得他无颜落色，惊的他手脚难抬。", "姨姨也，那里是先忧后喜，再没些苦尽甘来。", "(旦云)玉壶生，你怎是好？那虔婆来了也。", "(正末唱)那里怕逻惹着囊揣的这秀才，兀良我则怕生唬杀软弱的裙钗。", "(带云)姨姨。", "(唱)。"]'),
('yuanqu-6997','李素兰风月玉壶春・尧民歌','贾仲明','元','元曲','yuanqu','','[]','俺可甚洛阳花酒一时来，也做场蒺莉沙上野花开。',73,'元曲/yuanqu.json','["俺可甚洛阳花酒一时来，也做场蒺莉沙上野花开。", "不能勾误随流水泛天台，则有分今宵无梦到阳台。", "哀哉，多应命里该，(带云)我怕怎么？(唱)便撞见何妨碍？。"]'),
('yuanqu-6998','李素兰风月玉壶春・幺篇','贾仲明','元','元曲','yuanqu','','[]','恕生面咱双秀才，告回避波县宰。',134,'元曲/yuanqu.json','["恕生面咱双秀才，告回避波县宰。", "你也索典田卖地，弃子休妻，送米供柴。", "(卜儿云)我则见有钱的便留他。", "(正末唱)则你那本性也难移，山河易改，雄心犹在，但来的一个个不赊，现钱便卖。", "(甚舍云)我这般模样，一表人物，我又有钱，你怎生比的我？(正末云)也怪不着那虔婆看上你。", "(唱)。"]'),
('yuanqu-6999','李素兰风月玉壶春・耍孩儿','贾仲明','元','元曲','yuanqu','','[]','这厮他村则村，到会做这等月音月是态。',109,'元曲/yuanqu.json','["这厮他村则村，到会做这等月音月是态。", "你向那兔窝儿里呈言献策，遮莫你羊绒绸段有数十车，待禁的几场儿日炙风筛。", "准备着一条脊骨捱那黄桑棒，安排着八片天灵撞翠崖，则你那本钱儿光州买了滑洲卖，但行处与村郎作伴，怎好共鸾凤和谐？。"]'),
('yuanqu-7000','李素兰风月玉壶春・四煞','贾仲明','元','元曲','yuanqu','','[]','则有分剔腾的泥球儿换了你眼睛，便休想欢喜的手帕儿兜着下颏。',162,'元曲/yuanqu.json','["则有分剔腾的泥球儿换了你眼睛，便休想欢喜的手帕儿兜着下颏。", "一弄儿打扮的实难赛，大信袋滴溜着三山骨，硬布衫拦截断十字街。", "(甚舍云)我是山西客人，甚黑子便是。", "看我打扮比你全别。", "(正末唱)细端详语音儿是个山西客，带着个高一尺和顶子齐眉的毡帽，穿一对连底儿重十斤壮乳的麻鞋。", "(甚舍云)你这等穷厮，我见有三十车羊绒潞绸哩。", "(正末唱)。"]'),
('yuanqu-7001','李素兰风月玉壶春・三煞','贾仲明','元','元曲','yuanqu','','[]','你虽有万贯财，争如俺七步才。',120,'元曲/yuanqu.json','["你虽有万贯财，争如俺七步才。", "两件儿那一件声名大？你那财常踏着那虎口去红尘中走，我这才但跳过龙门向金殿上排。", "你休要嘴儿尖舌儿快，这虔婆怕不口甜如蜜罐，他可敢心苦似黄蘖。", "(卜儿云)兀那李玉壶，你这等穷身泼命，俺女孩儿守着你做甚么那？(正末唱)。"]'),
('yuanqu-7002','李素兰风月玉壶春・双调/新水令','贾仲明','元','元曲','yuanqu','','[]','这厮他不明白硬撞入武陵溪，量你个野蜂儿怎调和蜂蜜？颓气了惜花春起早，拽塌了爱月夜眠迟。',64,'元曲/yuanqu.json','["这厮他不明白硬撞入武陵溪，量你个野蜂儿怎调和蜂蜜？颓气了惜花春起早，拽塌了爱月夜眠迟。", "强风情不晓事，呆厮，谁着你将钱去买憔悴？。"]'),
('yuanqu-7003','李素兰风月玉壶春・水仙子','贾仲明','元','元曲','yuanqu','','[]','俺只道玉壶春打灭再休题，险做了运退雷轰荐福碑。',156,'元曲/yuanqu.json','["俺只道玉壶春打灭再休题，险做了运退雷轰荐福碑。", "元来素兰香也有逢春日，沉香串依然共素手携，翠珠囊似合浦重回。", "玉螳螂飞绕在兰丛内，白罗扇长如明月辉，怎肯教杜韦娘嫁了王魁？(陶伯常云)兀那婆子，你听者：因他李玉壶献了万言长策，圣人就加他为本府同知。", "(甚舍云)我死也。", "(卜儿云)李玉壶，我道你不是个受穷的人。", "(正末唱)。"]'),
('yuanqu-7004','李素兰风月玉壶春・落梅风','贾仲明','元','元曲','yuanqu','','[]','从公道，依正理，怎做得倚官挟势？想李素兰剪断香云为甚的？也只是愿双双并谐比翼。',130,'元曲/yuanqu.json','["从公道，依正理，怎做得倚官挟势？想李素兰剪断香云为甚的？也只是愿双双并谐比翼。", "(陶伯常云)李素兰，我将你配与李玉壶为妻，你意下如何？(旦云)多谢相公，妾情愿从良改正。", "(陶伯常云)兄弟，小官将李素兰与你做夫人好么？(正末云)全仗仁兄主张，您兄弟不敢忘报。", "(唱)。"]'),
('yuanqu-7005','李素兰风月玉壶春・雁儿落','贾仲明','元','元曲','yuanqu','','[]','成就了碧桃间鸾凤栖，翠沼畔鸳鸯配。',34,'元曲/yuanqu.json','["成就了碧桃间鸾凤栖，翠沼畔鸳鸯配。", "一任他绿阴中莺燕喧，锦坞内蜂蝶戏。"]'),
('yuanqu-7006','李素兰风月玉壶春・得胜令','贾仲明','元','元曲','yuanqu','','[]','呀，这连理厚栽培，并蒂共葳蕤。',318,'元曲/yuanqu.json','["呀，这连理厚栽培，并蒂共葳蕤。", "今日个告别了烟花市，同归了锦绣闱。", "准备了佳期，合欢带常拴系；得遂了于飞，同心结莫摘离。", "(陶伯常云)既然从良改正，着礼案上除了名字，将素兰配与玉壶为夫人。", "(甚舍云)爷爷，这成不的。", "他也姓李，那也姓李，同姓不可为婚。", "(旦云)相公，妾身本姓张，自幼年过房与他做义女来。", "我如今要出姓改正，有何和可？(陶伯常云)是实么？(卜儿云)嗨，俺那忤逆种不认我了，教我怎好赖得？实是我过房的女孩儿，他本姓张。", "(陶伯常云)李玉壶兄弟，你将白银百两，给与这婆子做恩养礼钱。", "兀那甚黑子，倚仗财物，夺人妻妾，罪该不应。", "杖断四十，抢出衙门去。", "李玉壶今为本府同知，将五花官诰，与张素兰做夫人。", "你两个望阙谢了恩者。", "(末旦谢恩科)(正末唱)。"]'),
('yuanqu-7007','李素兰风月玉壶春・沽美酒','贾仲明','元','元曲','yuanqu','','[]','多谢你大恩人做主持，这本性不难移。',44,'元曲/yuanqu.json','["多谢你大恩人做主持，这本性不难移。", "也只为莺花寨声名非是美，情愿做从良正妻，结婚姻要成对。"]'),
('yuanqu-7008','李素兰风月玉壶春・太平令','贾仲明','元','元曲','yuanqu','','[]','请受了五花诰身荣显贵，七香车表汇容仪。',64,'元曲/yuanqu.json','["请受了五花诰身荣显贵，七香车表汇容仪。", "玉胡子元称国器，这素兰女堪为佳配。", "从今后足衣、足食、所事儿足意，呀！不枉了天地间人生一世。"]'),
('yuanqu-7009','杜牧之诗酒扬州梦・仙吕/赏花时','乔吉','元','元曲','yuanqu','','[]','唱一曲金缕悠扬云谩行，舞一回彩袖轻盈花弄影，今日个饯送在短长亭。',48,'元曲/yuanqu.json','["唱一曲金缕悠扬云谩行，舞一回彩袖轻盈花弄影，今日个饯送在短长亭。", "对着这江山胜景，慵斟酒，诉离情。"]'),
('yuanqu-7010','杜牧之诗酒扬州梦・幺篇','乔吉','元','元曲','yuanqu','','[]','怕听阳关第四声，回首家山千万程，博着个甚功名，教俺做浮萍浪梗？因此上意懒出豫章城。',47,'元曲/yuanqu.json','["怕听阳关第四声，回首家山千万程，博着个甚功名，教俺做浮萍浪梗？因此上意懒出豫章城。", "(同一下)。"]'),
('yuanqu-7011','杜牧之诗酒扬州梦・仙吕/点绛唇','乔吉','元','元曲','yuanqu','','[]','锦缆龙舟，可怜空有隋堤柳，千古闲愁，我则怕春光老，琼花瘦。',29,'元曲/yuanqu.json','["锦缆龙舟，可怜空有隋堤柳，千古闲愁，我则怕春光老，琼花瘦。"]'),
('yuanqu-7012','杜牧之诗酒扬州梦・油葫芦','乔吉','元','元曲','yuanqu','','[]','月底笼灯花下游，闲将佳兴酬，绮罗丛封我做醉乡侯，酌几杯锦橙浆说净谈天口，折一枝碧桃春占定拿云手。',122,'元曲/yuanqu.json','["月底笼灯花下游，闲将佳兴酬，绮罗丛封我做醉乡侯，酌几杯锦橙浆说净谈天口，折一枝碧桃春占定拿云手。", "(牛僧孺云)却不道文苑中古忄敞秀才家，多好此狂饮也。", "(正末唱)打迭起翰林中猛性子挺，拽扎起太学内体样儿亻刍。", "趁着这锦封未剖香先透，渴时节吸尽洞庭秋。"]'),
('yuanqu-7013','杜牧之诗酒扬州梦・天下乐','乔吉','元','元曲','yuanqu','','[]','端的是一醉能消万古愁，醒来时三杯，扶起头，我向那红裙队里夺下一筹。',261,'元曲/yuanqu.json','["端的是一醉能消万古愁，醒来时三杯，扶起头，我向那红裙队里夺下一筹。", "看花呵，致成症候，饮酒呵，灌的醉休，我则待胜簪花常带酒。", "(牛僧孺云)牧之在京师，日日有花酒之乐。", "老夫有一家乐女子，颇善歌舞，唤他出来伏事学士咱。", "好好那里？(旦上，云)妾身张好好是也，原是张尚之家女童。", "牛太守大人与张尚之为旧友，遂将妾身过房与牛太守为义女，经今三年矣。", "今日前厅上宴客，太守大人呼唤，须索见去。", "(见科)(正末云)此女是谁？(牛僧孺云)是老夫义女，小字好好，唤来歌舞一回，与学士奉一杯酒。", "(家童云)相公，好个标致的小姐！我那里曾见来。", "(正末唱)。"]'),
('yuanqu-7014','杜牧之诗酒扬州梦・那吒令','乔吉','元','元曲','yuanqu','','[]','倒金瓶凤头，捧琼浆玉瓯。',82,'元曲/yuanqu.json','["倒金瓶凤头，捧琼浆玉瓯。", "蹴金莲凤头，并凌波玉钩。", "蔡金钗风头，露春纤五手。", "天有情天亦老，春有意春须瘦，云无心云也生愁。", "(牛僧孺云)小家之女，有甚十分颜色？(正末唱)。"]'),
('yuanqu-7015','杜牧之诗酒扬州梦・鹊踏枝','乔吉','元','元曲','yuanqu','','[]','花比他不风流，玉比他不温柔，端的是莺也消魂，燕也含羞。',46,'元曲/yuanqu.json','["花比他不风流，玉比他不温柔，端的是莺也消魂，燕也含羞。", "蜂与蝶花间四友，呆打颏都歇在豆蔻梢头。"]'),
('yuanqu-7016','杜牧之诗酒扬州梦・寄生草','乔吉','元','元曲','yuanqu','','[]','我央了十个千岁，他刚咽下三个半口，险婉了内家妆束红鸳袖，越显的宫腰袅娜纤杨柳。',123,'元曲/yuanqu.json','["我央了十个千岁，他刚咽下三个半口，险婉了内家妆束红鸳袖，越显的宫腰袅娜纤杨柳。", "添上些芙蓉颜色娇皮肉；白处似梨花擎露粉酥凝，红处似海棠过雨胭脂透。", "(牛僧孺云)牧之，请饮酒。", "(正末云)且住，将文房四宝来，作诗一首相赠。", "(家童云)笔砚在此。", "(正末唱)。"]'),
('yuanqu-7017','杜牧之诗酒扬州梦・幺篇','乔吉','元','元曲','yuanqu','','[]','磨铁角乌犀冷，点霜毫玉兔秋。',135,'元曲/yuanqu.json','["磨铁角乌犀冷，点霜毫玉兔秋。", "对明窗沧海龙蛇走，蘸金星端砚云烟透。", "拂银笺湘水玻璃皱。", "(牛僧孺云)何劳学士这等费心。", "(正末唱)比及赏吴宫花草二十年，先索费翰林风月三千首。", "(云)你看这女子。", "(诗云)端的是仙人飞下紫云车，月阙才离蟾影孤。", "却向尊前擎玉盏，风流美貌世间无。", "(唱)。"]'),
('yuanqu-7018','杜牧之诗酒扬州梦・后庭花','乔吉','元','元曲','yuanqu','','[]','他那里应答的语话投，我这里笑谈的局面熟。',185,'元曲/yuanqu.json','["他那里应答的语话投，我这里笑谈的局面熟。", "准备着夜月携红袖，不觉的春风倒玉瓯。", "(旦云)我再斟的满者，与相公饮咱。", "(正末唱)怎生下我咽喉，劳你个田文生受？忘昂昂包古今赡宇宙，气腾腾吐虹霓贯斗牛；袖飘飘拂红云登凤楼，兴悠悠驾苍龙遍九州；娇滴滴赏琼花双玉头，风飕飕游广寒八月秋；乐陶陶倩春风散客愁，湿浸浸锦橙浆润紫裘；急煎煎想书娘不自由，虚飘飘恨彩云容易收，香馥馥斟一杯花露酒。"]'),
('yuanqu-7019','杜牧之诗酒扬州梦・赚煞尾','乔吉','元','元曲','yuanqu','','[]','比及客散锦堂中，准备人约黄昏后。',153,'元曲/yuanqu.json','["比及客散锦堂中，准备人约黄昏后。", "他不比寻常间墙花路柳。", "这公事怎肯甘心便索休，强风情酒病花愁。", "(牛僧孺云)无甚管待，承学士屈高就下也。", "(正末唱)这的是钓诗钩。", "我醉则醉常在心头，扫愁帚争如奉箕帚。", "(牛僧孺云)牧之，一番相见一番老也。", "(正末唱)遮莫你鬓角边霜华渐稠，衫袖上酒痕依旧，我正是风流到老也风流。", "(下)。"]'),
('yuanqu-7020','杜牧之诗酒扬州梦・正宫/端正好','乔吉','元','元曲','yuanqu','','[]','衫袖湿酒痕香，帽檐侧花枝重，似这等宾共主和气春风，一杯未尽笙歌送，就花前唤醒游仙梦。',42,'元曲/yuanqu.json','["衫袖湿酒痕香，帽檐侧花枝重，似这等宾共主和气春风，一杯未尽笙歌送，就花前唤醒游仙梦。"]'),
('yuanqu-7021','杜牧之诗酒扬州梦・滚绣球','乔吉','元','元曲','yuanqu','','[]','日高也花影重，风香时酒力涌，顺毛儿扑撤上翠鸾丹风，恣情的受用足玉暖香融。',124,'元曲/yuanqu.json','["日高也花影重，风香时酒力涌，顺毛儿扑撤上翠鸾丹风，恣情的受用足玉暖香融。", "这酒更压着玻璃钟琥珀酿，这楼正值着黄鹤仙白兔翁，这酒更胜似酿葡萄紫驼银瓮，这楼快活杀傲人间湖海元龙；这酒却便似泻金茎中天露擎仙掌，这楼恰便似香翠盘内霓裳到月宫，高卷起彩绣帘栊。"]'),
('yuanqu-7022','杜牧之诗酒扬州梦・倘秀才','乔吉','元','元曲','yuanqu','','[]','想当日宴私宅翰林应奉，倒做了使官府文章钜公，昨日今朝事不同。',52,'元曲/yuanqu.json','["想当日宴私宅翰林应奉，倒做了使官府文章钜公，昨日今朝事不同。", "暖溶溶脂粉队，香馥馥绮罗丛，端的是红遮翠拥。"]'),
('yuanqu-7023','杜牧之诗酒扬州梦・滚绣球','乔吉','元','元曲','yuanqu','','[]','尊中酒不空，筵前曲未终，你教他系垂杨五骢低鞋，准备着倩人，扶两袖春风。',102,'元曲/yuanqu.json','["尊中酒不空，筵前曲未终，你教他系垂杨五骢低鞋，准备着倩人，扶两袖春风。", "我这害酒的渴肚囊，看花的馋眼孔，结上的欢喜缘可着他厮重，我伴着些玉婵娟相守相从，也不索闲游柳陌寻歌妓。", "笑指前村问牧童，宜吃的月转梧桐。"]'),
('yuanqu-7024','杜牧之诗酒扬州梦・醉太平','乔吉','元','元曲','yuanqu','','[]','又不是痴呆懵懂，不辨个南北西东，恰才个彩云飞下广寒宫。',74,'元曲/yuanqu.json','["又不是痴呆懵懂，不辨个南北西东，恰才个彩云飞下广寒宫。", "醉蟠桃会中，一壁厢花间四友争陪奉，胜似那蓬莱八洞相随从，只落的华胥一枕梦初浓，都是这风流醉翁。"]'),
('yuanqu-7025','杜牧之诗酒扬州梦・脱布衫','乔吉','元','元曲','yuanqu','','[]','不觉的困腾腾醉眼朦胧，空对着明晃晃烛影摇红，这其间在何处残月晓风，知他是宿谁家枕鸳衾凤。',44,'元曲/yuanqu.json','["不觉的困腾腾醉眼朦胧，空对着明晃晃烛影摇红，这其间在何处残月晓风，知他是宿谁家枕鸳衾凤。"]'),
('yuanqu-7026','杜牧之诗酒扬州梦・小梁州','乔吉','元','元曲','yuanqu','','[]','这些时陡恁春寒绣被空，冷清清褥隐芙蓉。',43,'元曲/yuanqu.json','["这些时陡恁春寒绣被空，冷清清褥隐芙蓉。", "我则道阳台云雨去无踪，今夜个乘欢宠，山也有相逢。"]'),
('yuanqu-7027','杜牧之诗酒扬州梦・幺篇','乔吉','元','元曲','yuanqu','','[]','怎承望晓来误入桃源洞，又则怕公孙弘打凤牢龙。',51,'元曲/yuanqu.json','["怎承望晓来误入桃源洞，又则怕公孙弘打凤牢龙。", "手竹亡掐着疼，脚面上踏着痛，那里也情深意重，犹恐是梦魂中。"]'),
('yuanqu-7028','杜牧之诗酒扬州梦・一煞','乔吉','元','元曲','yuanqu','','[]','则愿的行云不返三山洞，好梦休惊五夜钟。',77,'元曲/yuanqu.json','["则愿的行云不返三山洞，好梦休惊五夜钟。", "我这里绣被香寒，五楼人去，锦树花飞，金谷阅空。", "飞腾了彩风，解放了红绒，摔碎下雕笼，若不是天公作用，险些儿风月两无功。"]'),
('yuanqu-7029','杜牧之诗酒扬州梦・煞尾','乔吉','元','元曲','yuanqu','','[]','从今后风云气概都做下阳台梦，花月恩情犹高似太华峰。',179,'元曲/yuanqu.json','["从今后风云气概都做下阳台梦，花月恩情犹高似太华峰。", "风送纱窗月影通，篆袅金炉香雾潆。", "银烛高烧锦帐融，罗帕重沾粉汗溶。", "高插鸾钗云髻耸，巧画蛾眉翠黛浓。", "柳坞花溪锦绣丛，烟户云窗闺阁中。", "可体样春衫亲手儿缝。", "有滋味珍馐拣口儿供。", "再不趁蝶使蜂媒厮断送，再不信怪友狂朋厮搬弄。", "但能勾鱼水相逢，琴瑟和同，(家童云)相公，咱回去来。", "(正末唱)早跳出这柳债花钱面糊桶。", "(同下)。"]'),
('yuanqu-7030','杜牧之诗酒扬州梦・南吕/一枝花','乔吉','元','元曲','yuanqu','','[]','温柔玉有香，旖旎春无价。',61,'元曲/yuanqu.json','["温柔玉有香，旖旎春无价。", "多情杨柳叶，解浯海棠花。", "压尽越女吴娃，从头髻至鞋袜，觅包弹无半掐，更那堪百事聪明，模样儿十分喜恰。"]'),
('yuanqu-7031','杜牧之诗酒扬州梦・隔尾','乔吉','元','元曲','yuanqu','','[]','锦机织就传情帕，翠沼裁成并蒂花。',42,'元曲/yuanqu.json','["锦机织就传情帕，翠沼裁成并蒂花。", "何日青弯得同跨？锦衾绣榻，弓鞋罗袜，玉软香温受用煞。"]'),
('yuanqu-7032','杜牧之诗酒扬州梦・骂玉郎','乔吉','元','元曲','yuanqu','','[]','这一双郎才女貌天生下，笋条儿游冶子，花朵儿俊娇娃，堪写入风流仕女丹青画。',88,'元曲/yuanqu.json','["这一双郎才女貌天生下，笋条儿游冶子，花朵儿俊娇娃，堪写入风流仕女丹青画。", "行一步百样娇，笑一声万种妖，歌一曲千金价。", "(白文礼云)小生也曾见来，果然生的风流，长的可喜。", "(正末唱)。"]'),
('yuanqu-7033','杜牧之诗酒扬州梦・感皇恩','乔吉','元','元曲','yuanqu','','[]','浓妆呵娇滴滴擎露山茶，淡妆呵颤巍巍带雨梨花。',110,'元曲/yuanqu.json','["浓妆呵娇滴滴擎露山茶，淡妆呵颤巍巍带雨梨花。", "齐臻臻齿排犀，曲湾湾眉扫黛，高耸耸髻堆鸦。", "香馥馥冰肌胜雪，喜孜孜醉脸烘霞。", "端详着庞儿俊，思量着口儿甜，怎肯教意儿差。", "(白文礼云)相公与此女有缘有分，所以如此留情也。", "(正末唱)。"]'),
('yuanqu-7034','杜牧之诗酒扬州梦・采茶歌','乔吉','元','元曲','yuanqu','','[]','非是我自矜夸，则为咱两情嘉，准备着天长地久享荣华。',77,'元曲/yuanqu.json','["非是我自矜夸，则为咱两情嘉，准备着天长地久享荣华。", "(白文礼云)相公放心，小生务要与相公成就了这桩事。", "(正末唱)既然你旨把赤绳来系足，久以后何须流水泛桃花。"]'),
('yuanqu-7035','杜牧之诗酒扬州梦・牧羊关','乔吉','元','元曲','yuanqu','','[]','则今日一言定，便休作两事家。',69,'元曲/yuanqu.json','["则今日一言定，便休作两事家。", "将你个撮合山慢慢酬答。", "成就了燕约莺期，收拾了心猿意马。", "合欢带同心结，连理树共根芽，知音吕琴中曲，好姻缘锦上花。"]'),
('yuanqu-7036','杜牧之诗酒扬州梦・一煞','乔吉','元','元曲','yuanqu','','[]','且陪伴西风摇落胭脂蜡，权宁耐夜月寒穿翡翠纱，闲愁不索拨琵琶。',154,'元曲/yuanqu.json','["且陪伴西风摇落胭脂蜡，权宁耐夜月寒穿翡翠纱，闲愁不索拨琵琶。", "(白文礼云)相公则为这小娘子留心那！(正末唱)我怎肯浪酒闲茶，再留意裙钗下。", "暂相别受些潇洒，隔云山天一涯，两地嗟呀。", "(白文礼云)相公再饮一杯。", "(正末云)酒勾了。", "小官就此告回。", "(白文礼云)相公慢慢而行，小生说成了，便有书呈奉，望赐回音咱。", "(正末唱)。"]'),
('yuanqu-7037','杜牧之诗酒扬州梦・黄钟尾','乔吉','元','元曲','yuanqu','','[]','你题情休写香罗帕，我寄恨须传鼓子花。',158,'元曲/yuanqu.json','["你题情休写香罗帕，我寄恨须传鼓子花。", "且宁心，度岁华，恐年过生计乏。", "(白文礼云)相公休别寻配偶，小生务要完成此事。", "(正末唱)纵有奢华豪富家，倒赔装奁许招嫁，休想我背却初盟去就他，把美满恩情却丢下，我直着诸人称扬众口夸，红粉佳人配与咱，玉肩相挨手相把，受用全别快活杀。", "做一对好夫妻出入京华，不强似门外绿杨闲系马。", "(下)。"]'),
('yuanqu-7038','杜牧之诗酒扬州梦・双调/新水令','乔吉','元','元曲','yuanqu','','[]','我向这酒葫芦着淹不曾醒，但说着花胡同我可早愿随鞭镫。',182,'元曲/yuanqu.json','["我向这酒葫芦着淹不曾醒，但说着花胡同我可早愿随鞭镫。", "今日个酒香金字馆，花重锦官城，不恋富贵峥嵘，则待谈笑平生。", "不望白马红缨，伴着象板银筝，似这淮南郡山水有名姓。", "(云)左右报复去，道杜牧之到了也。", "(随从报科，云)杜翰林来了也。", "(白文礼云)道有请。", "(正末做见科，云)量小官有何德能，着员外置酒张筵，何以克当！(白文礼云)蔬食薄味，不成管待，请相公欢饮几杯。", "(正末唱)。"]'),
('yuanqu-7039','杜牧之诗酒扬州梦・沉醉东风','乔吉','元','元曲','yuanqu','','[]','休想道惟吾独醒屈平，则待学众人皆醉刘伶。',286,'元曲/yuanqu.json','["休想道惟吾独醒屈平，则待学众人皆醉刘伶。", "浇消了湖海愁，洗涤下风云兴，怕孤负月朗风清，因此上落魄江湖载酒行，糊涂了黄粱梦境。", "(云)员外，今日席上，再有何人？(白文礼云)请牛太守去了，这早晚敢待来也。", "(牛太守上，云)老夫牛僧孺，今日白文礼在金字馆设席相请，左右报复去，道牛大守来了也。", "(随从报科，云)太守老爹来了也。", "(白文礼云)道有请。", "(牛太守做见科，与正末云)老夫相访数次，不蒙放参，只是某缘分浅薄也。", "(正末云)小官连日事冗，有失迎接，叔父勿罪。", "来日小官设席请罪，就屈员外同席，未知允否？(白文礼云)今日且饮过小生这一席，来日同赴盛宴，务要吹弹歌舞，开怀畅饮也。", "(正末唱)。"]'),
('yuanqu-7040','杜牧之诗酒扬州梦・水仙子','乔吉','元','元曲','yuanqu','','[]','喜的是楚腰纤细掌中擎，爱的是一派笙歌醉后听。',76,'元曲/yuanqu.json','["喜的是楚腰纤细掌中擎，爱的是一派笙歌醉后听。", "哎，你个孟尝君妒色独强性，靠损了春风软玉屏，戏金钗早吓掉了冠缨。", "杜牧之难折证，牛僧孺不志诚，都一般行浊言清。"]'),
('yuanqu-7041','杜牧之诗酒扬州梦・雁儿落','乔吉','元','元曲','yuanqu','','[]','我则道玉阶前花弄影，原来是金殴上传宣令。',41,'元曲/yuanqu.json','["我则道玉阶前花弄影，原来是金殴上传宣令。", "本为个牛僧孺门-下人，倒做了杜牧之心头病。"]'),
('yuanqu-7042','杜牧之诗酒扬州梦・得胜令','乔吉','元','元曲','yuanqu','','[]','则疑是天上许飞琼，原来是足下女娉婷。',92,'元曲/yuanqu.json','["则疑是天上许飞琼，原来是足下女娉婷。", "你栽下竹引丹山凤，笼着花藏金谷莺，都诉出实情。", "(白文礼云)学士，你不拜丈人，还等甚么？(正末唱)我做下强项令肩膀硬，今日个完成，将这个俊娇娥手内擎。"]'),
('yuanqu-7043','杜牧之诗酒扬州梦・甜水令','乔吉','元','元曲','yuanqu','','[]','我不合带酒簪花，沾红惹绿，疏狂情性，这几件罪我招承。',52,'元曲/yuanqu.json','["我不合带酒簪花，沾红惹绿，疏狂情性，这几件罪我招承。", "你不合打风牢龙，翻云覆雨，陷入坑阱，咱两个口说无凭。"]'),
('yuanqu-7044','杜牧之诗酒扬州梦・折桂令','乔吉','元','元曲','yuanqu','','[]','见放着御史台不顺人情，谁着你调罨子画阁兰堂，搠包儿锦阵花营。',95,'元曲/yuanqu.json','["见放着御史台不顺人情，谁着你调罨子画阁兰堂，搠包儿锦阵花营。", "既然是太守相容，俺朋友间有甚差争？摆着一对种花手似河阳县令，裹着一顶漉酒巾学五柳先生。", "既能勾鸾风和鸣，桃李春荣，赢得青楼薄幸之名。"]'),
('yuanqu-7045','杜牧之诗酒扬州梦・鸳鸯煞','乔吉','元','元曲','yuanqu','','[]','从今后立功名写入麒麟影，结牡萝配-亡菱花镜。',86,'元曲/yuanqu.json','["从今后立功名写入麒麟影，结牡萝配-亡菱花镜。", "准备着载月兰舟，煦夜花灯。", "畅道朋友同行，尚则怕衣衫不整。", "毕罢了雪月风花，医可了游荡疏扛病。", "今小个两眼惺惺，唤的个一枕南柯梦初醒。"]'),
('yuanqu-7046','中吕・粉蝶儿','王仲诚','元','元曲','yuanqu','','[]','昨宴东楼，玳筵开舞裙歌袖，一团儿玉软花柔。',47,'元曲/yuanqu.json','["昨宴东楼，玳筵开舞裙歌袖，一团儿玉软花柔。", "遏行云，回飞雪。", "玲珑剔透，交错觥筹，拈冰丸暗藏锦绣。"]'),
('yuanqu-7047','醉春风・娇滴滴香脸嫩如花，细松松纤腰轻似柳。有丹青巧笔写奇真，怎','王仲诚','元','元曲','yuanqu','','[]','的朽，朽？檀口能歌，莲舌轻调，柳眉频皱。',20,'元曲/yuanqu.json','["的朽，朽？檀口能歌，莲舌轻调，柳眉频皱。"]'),
('yuanqu-7048','迎仙客・露玉纤，捧金瓯，云鬓巧簪金凤头。荡缃裙，掩玉钩，百倍风流，','王仲诚','元','元曲','yuanqu','','[]','无福也难消受。',7,'元曲/yuanqu.json','["无福也难消受。"]'),
('yuanqu-7049','满庭芳・人间罕有，沉鱼落雁，月闭花羞。蕙兰性一点灵犀透，举止温柔。','王仲诚','元','元曲','yuanqu','','[]','成合了鸾交凤友，匹配了燕侣莺俦。',60,'元曲/yuanqu.json','["成合了鸾交凤友，匹配了燕侣莺俦。", "轻扌闰就，如弹玉纤粉汗流，佯呵欠袖儿里低声儿咒。", "一会家把人迤逗，撇不下漾秋波一对动情眸。"]'),
('yuanqu-7050','越调・半鹌鹑避纷','王仲诚','元','元曲','yuanqu','','[]','露冷霜寒，云低雾黯。',56,'元曲/yuanqu.json','["露冷霜寒，云低雾黯。", "洒洒潇潇，凄凄惨惨。", "眼底繁华，心头有感。", "名利绝，是非减。", "爱的是雪月风花，怕的是《官民要览》。"]'),
('yuanqu-7051','紫花儿・昨宵酩酊，今日模糊，来日醺酣。带一顶嵌肩幔笠，穿一领麻衫。','王仲诚','元','元曲','yuanqu','','[]','妆一座栽梅结草庵，谁能摇撼？跳出这蚁穴蜂衙，再不入虎窟龙潭。',30,'元曲/yuanqu.json','["妆一座栽梅结草庵，谁能摇撼？跳出这蚁穴蜂衙，再不入虎窟龙潭。"]'),
('yuanqu-7052','小桃红・刀名剑利大尴尬，唬碎闲人胆！白酒黄鸡捱时暂，就中甘，这般','王仲诚','元','元曲','yuanqu','','[]','滋味谁曾啖？谐音人即参，通经史亲探，世事要经谙。',24,'元曲/yuanqu.json','["滋味谁曾啖？谐音人即参，通经史亲探，世事要经谙。"]'),
('yuanqu-7054','骂玉郎北・娇娃俊雅天生就，腰似柳，袜如钩，湘裙微露金莲瘦。你看他','张氏','元','元曲','yuanqu','','[]','宝髻堆，玉笋长，露出春衫袖。',14,'元曲/yuanqu.json','["宝髻堆，玉笋长，露出春衫袖。"]'),
('yuanqu-7055','大迓鼓南・相逢莺燕友，四眸相顾，两意相投，此情难消受。风流自古，','张氏','元','元曲','yuanqu','','[]','偏惜风流，展转留情双凤眸。',13,'元曲/yuanqu.json','["偏惜风流，展转留情双凤眸。"]'),
('yuanqu-7056','感皇恩北・呀，指望待饱玩娇羞，谁承望各自分头。好教我恨天高，嫌地','张氏','元','元曲','yuanqu','','[]','窄，怨人稠。',37,'元曲/yuanqu.json','["窄，怨人稠。", "指望待相随皓首，谁承望鬼病因由。", "不由人魂缈缈，体飘飘，魄悠悠。"]'),
('yuanqu-7057','东瓯令南・添疾病，减风流，废寝忘餐相应候。前生作下今生受，今不遂','张氏','元','元曲','yuanqu','','[]','来生又。',19,'元曲/yuanqu.json','["来生又。", "魂劳梦穰感离愁，都则为女娇羞。"]'),
('yuanqu-7058','采茶歌北・都则为女娇羞，端的是忒风流，闪的人不茶不饭几时休。何日','张氏','元','元曲','yuanqu','','[]','相逢同配偶？甚时密约共绸缪？。',15,'元曲/yuanqu.json','["相逢同配偶？甚时密约共绸缪？。"]'),
('yuanqu-7060','乌夜啼北・闪的我看看疾重，实实病久。为多情镇日空亻孱亻愁。呀，一','张氏','元','元曲','yuanqu','','[]','会家近书斋想念无休，到黄昏愁云怨雨相拖逗。',81,'元曲/yuanqu.json','["会家近书斋想念无休，到黄昏愁云怨雨相拖逗。", "更阑也无限忧愁，夜深沉雨泪交流。", "想娇容直到五更头，我与你从头一一他行受。", "果然他心意坚，恩情厚，俺待要鸾交凤友，燕侣莺俦。"]'),
('yuanqu-7061','节节高南・喜孜孜暗讨求，语相投。今宵暗约同成就，灵犀透，共焚香，','张氏','元','元曲','yuanqu','','[]','齐言咒。',36,'元曲/yuanqu.json','["齐言咒。", "日坠月上初沉漏，星移斗转三更候。", "潜踪蹑足近庭闱，轻移那步临门候。"]'),
('yuanqu-7062','鹌鹑儿北・猛见了俊俏多情，我和他挨肩携手。悄悄的行入兰房，暗暗的','张氏','元','元曲','yuanqu','','[]','同眠共宿，娇滴滴语颤声低。',53,'元曲/yuanqu.json','["同眠共宿，娇滴滴语颤声低。", "情未休，情未休，锦被蒙头，燕侣莺俦，旖旎温柔。", "受过了无限凄凉，谁承望今宵配偶？。"]'),
('yuanqu-7064','双调・新水令武陵春','康进之','元','元曲','yuanqu','','[]','当年曾避虎狼秦，是仙家幻来风韵。',39,'元曲/yuanqu.json','["当年曾避虎狼秦，是仙家幻来风韵。", "景因人得誉，人为景摹真。", "佳趣平分，人景共评论。"]'),
('yuanqu-7065','驻马听・花片纷纷，过雨犹如弹泪粉。溪流滚滚，迎风还似皱湘裙。桃源','康进之','元','元曲','yuanqu','','[]','路近与楚台邻，丽春园未许渔舟问。',31,'元曲/yuanqu.json','["路近与楚台邻，丽春园未许渔舟问。", "两般儿情厮隐，浓妆淡抹包笼尽。"]'),
('yuanqu-7067','沉醉东风・瑶草细分明舞茵，翠鬟松仿佛溪云。蜂蝶莫浪猜，鱼雁难传信。','康进之','元','元曲','yuanqu','','[]','好风光自有东君，管领红霞万树春，说什么河阳县尹！。',25,'元曲/yuanqu.json','["好风光自有东君，管领红霞万树春，说什么河阳县尹！。"]'),
('yuanqu-7068','甜水令・难描难画，难题难咏，难亲难近，无意混嚣尘。若不是梦里相逢，','康进之','元','元曲','yuanqu','','[]','年时得见，生前有分，等闲间谁取温存！。',19,'元曲/yuanqu.json','["年时得见，生前有分，等闲间谁取温存！。"]'),
('yuanqu-7069','折桂令・美名儿比并清新，比不的他能舞能讴，宜喜宜嗔。惑不动他疏势','康进之','元','元曲','yuanqu','','[]','利的心肠，老不了他永长生的鬓发，瘦不的他无病患的腰身。',83,'元曲/yuanqu.json','["利的心肠，老不了他永长生的鬓发，瘦不的他无病患的腰身。", "另巍巍居世外天然异品，香馥馥产人间别样灵根。", "最喜骚人，寓意超群，把一段蓬莱境妆点入梁园，将半篇锦绣词互换出韩文。"]'),
('yuanqu-7070','随煞・说清高不比那寻常赚客的烟花阵，追访的须教自忖。先办下无差错','康进之','元','元曲','yuanqu','','[]','的意儿诚，后问的他许成合的话儿准。',17,'元曲/yuanqu.json','["的意儿诚，后问的他许成合的话儿准。"]'),
('yuanqu-7071','南吕・一枝花安庆湖雪夜','沙正卿','元','元曲','yuanqu','','[]','荒陂寒雁鸣，远树昏鸦噪。',57,'元曲/yuanqu.json','["荒陂寒雁鸣，远树昏鸦噪。", "断云淮甸阔，残照楚山高。", "古岸萧萧，败苇折芦罩，穿林荒径小。", "水村寒犬吠柴荆，梅岭冻猿啼树杪。"]'),
('yuanqu-7072','梁州・野烟暗迷合渡口，渔灯明照破江皋。溪边望罢归村路。野塘萧索，','沙正卿','元','元曲','yuanqu','','[]','暮景寂寥。',97,'元曲/yuanqu.json','["暮景寂寥。", "半间草厦，一榻橛床。", "冷清清伴我萧条，到黄昏恶限才交。", "ゐ惶运环海般相连，烦恼乡石城般围绕，离愁阵铁壁般坚牢。", "怎生，得逃？百千般无计把凄凉傲，愁恰去闷来到。", "愁和闷共凄凉厮缠缴，不离我周遭。"]'),
('yuanqu-7073','二煞・破窗鸣雨霰风犹恶，漏屋垂冰蚕冻未消，梦回酒醒越难熬。万籁皆','沙正卿','元','元曲','yuanqu','','[]','鸣，更一点残灯斜照。',32,'元曲/yuanqu.json','["鸣，更一点残灯斜照。", "供愁恨献烦恼，破思虑忧愁厮定害，暗消了年少。"]'),
('yuanqu-7074','尾・黄昏时春色生容貌，清镜晓秋霜点鬓毛。愁虽是多，恨也不少。衰了','沙正卿','元','元曲','yuanqu','','[]','潘容，瘦了沈腰。',37,'元曲/yuanqu.json','["潘容，瘦了沈腰。", "镜里端详，心下暗约。", "端详罢怎不教我心焦，则一夜剩添十岁老。"]'),
('yuanqu-7075','越调・斗鹌鹑闺情','沙正卿','元','元曲','yuanqu','','[]','挑绣也无心，茶饭不应口。',60,'元曲/yuanqu.json','["挑绣也无心，茶饭不应口。", "付能打揲起伤春，谁承望睚不过暮秋。", "暗想情怀，心儿里自羞。", "两件儿，出尽丑。", "脸淡似残花，腰纤如细柳。"]'),
('yuanqu-7076','幺・想杀我也枕头儿上恩爱，盼杀我也怀抱儿里多情，害杀我也被窝儿里','沙正卿','元','元曲','yuanqu','','[]','风流。',55,'元曲/yuanqu.json','["风流。", "浑身上四肢沉困，迅指间一命淹留。", "休、休，方信道相思是歹证喉，害的来不明不久。", "是做的沾粘，到如今泼水难收。"]'),
('yuanqu-7077','尾・实丕丕罪犯先招受，直到折倒了庞儿罢收。若不成就美满好姻缘，则','沙正卿','元','元曲','yuanqu','','[]','索学文君驾车走。',8,'元曲/yuanqu.json','["索学文君驾车走。"]'),
('yuanqu-7078','两军师隔江斗智・混江龙','无名氏','元','元曲','yuanqu','','[]','论你个梅香伏侍，那些儿寒温饥饱不宜时？(梅香云)小姐芙蓉面，杨柳腰，这般标致，谁人近得？(正旦唱)你道我这面呵还赛过芙蓉艳色，这腰呵不弱似杨柳柔枝。',175,'元曲/yuanqu.json','["论你个梅香伏侍，那些儿寒温饥饱不宜时？(梅香云)小姐芙蓉面，杨柳腰，这般标致，谁人近得？(正旦唱)你道我这面呵还赛过芙蓉艳色，这腰呵不弱似杨柳柔枝。", "有时节将彩线纂成新样谱，有时节向绿窗酬和古人诗。", "常则是嫔风作范，女诫为师。", "慵妆粉黛，净洗胭脂。", "兀那绣帘前几曾敢偷窥视？(梅香云)老夫人请哩，小姐行动些。", "(正旦唱)若不是堂前呼唤，我也怎轻出这厅上阶址？。"]'),
('yuanqu-7079','两军师隔江斗智・油葫芦','无名氏','元','元曲','yuanqu','','[]','母亲你无语低头甚意儿？唤我来何处使？(云)梅香，老夫人烦恼，可是为何？(梅香云)你也不知道，我那里省得？(正旦唱)敢是那一个泼无知恼犯俺尊慈？(夫人云)孩儿，你',259,'元曲/yuanqu.json','["母亲你无语低头甚意儿？唤我来何处使？(云)梅香，老夫人烦恼，可是为何？(梅香云)你也不知道，我那里省得？(正旦唱)敢是那一个泼无知恼犯俺尊慈？(夫人云)孩儿，你哥哥将你许了人家也。", "(梅香云)就与我也寻一门儿亲波。", "(正旦唱)你把俺成婚作配何人氏？也则要门当户对该如此。", "(云)哥哥许了甚的人家来？(孙权云)妹子，将你许了人便罢了，不必问他。", "(正旦唱)端的是谁保亲？在几时？(孙权云)则在这一二日内，就要成这亲事哩。", "(正旦唱)为甚么慌慌速速成亲事？(孙权云)我则为荆州九郡，才想这个念头。", "(正旦唱)元来你图取荆州地免兴师！。"]'),
('yuanqu-7080','两军师隔江斗智・天下乐','无名氏','元','元曲','yuanqu','','[]','您则待暗结春风连理枝，我这里寻也波思，好着我难动止。',98,'元曲/yuanqu.json','["您则待暗结春风连理枝，我这里寻也波思，好着我难动止。", "(孙权云)妹子，你休得推托。", "你那生时年月，我已写的去了也。", "(正旦唱)赤紧的老萱堂将我年月时，早送与新婿家，怎再辞？哎，也须拣一个无相犯的好日子。"]'),
('yuanqu-7081','两军师隔江斗智・鹊踏枝','无名氏','元','元曲','yuanqu','','[]','只见你喜孜孜，把计谋施，也不和我通个商量，匹配雄雌。',47,'元曲/yuanqu.json','["只见你喜孜孜，把计谋施，也不和我通个商量，匹配雄雌。", "只就着这送亲的将士，稳情取赚城门不待移时。"]'),
('yuanqu-7082','两军师隔江斗智・元和令','无名氏','元','元曲','yuanqu','','[]','我这里劝哥哥要三思，怕瞒不过诸葛亮那军师。',198,'元曲/yuanqu.json','["我这里劝哥哥要三思，怕瞒不过诸葛亮那军师。", "万一个被他识破有参差，可不把美人图干着使？(孙权做耳喑科)(云)妹子，若此计不成，又有一计。", "只等刘玄德拜罢堂，回到卧房里面，你平日待婢们都是佩着刀剑的。", "你觑个方便。", "将他刺死，不怕荆州不归我国，这就是你的功劳。", "我当替你别选高门。", "重婚俊杰，也不误你一世。", "(正旦唱)哎，我只道你甚机谋节外会生枝，元来只要我转关儿将他阴刺死。", "(云)哥哥，只怕此计不中么。", "(唱)。"]'),
('yuanqu-7083','两军师隔江斗智・后庭花','无名氏','元','元曲','yuanqu','','[]','我本待诵雎鸠淑女诗，怎着我仗龙泉行剑客的事？你只怕耽误了周元帅在三江口，哎，怎不想断送我孙夫人一世儿？(孙权云)妹子，你则依着我做，我若不取了荆州，不为丈夫！(',191,'元曲/yuanqu.json','["我本待诵雎鸠淑女诗，怎着我仗龙泉行剑客的事？你只怕耽误了周元帅在三江口，哎，怎不想断送我孙夫人一世儿？(孙权云)妹子，你则依着我做，我若不取了荆州，不为丈夫！(做怒科)(夫人云)孩儿，你哥哥恼了也，你只依着他罢。", "(正旦云)母亲，你孩儿知道，只凭哥哥自家做去便了。", "(唱)哥也你直恁的便怒嗤嗤，绰起了紫髯髭。", "我如今并不的推三阻四，任哥哥自主之，将母亲即拜辞，就佳期赴吉时，便新婚恰燕尔。"]'),
('yuanqu-7084','两军师隔江斗智・青哥儿','无名氏','元','元曲','yuanqu','','[]','哥也你道是明朝、明朝遣使，就问他讨个、讨个言词，不图他羊酒花红半缕丝。',95,'元曲/yuanqu.json','["哥也你道是明朝、明朝遣使，就问他讨个、讨个言词，不图他羊酒花红半缕丝。", "这壁是吴国娇姿，那壁是汉室亲支，情愿倒赔家私，送上门儿。", "香袅金狮，酒泛琼卮，抵多少笙歌引至画堂时，那其间才称了你平生志。"]'),
('yuanqu-7085','两军师隔江斗智・赚煞','无名氏','元','元曲','yuanqu','','[]','哥哥，哎，只怕你未解的腹中愁，早添上些心间事。',188,'元曲/yuanqu.json','["哥哥，哎，只怕你未解的腹中愁，早添上些心间事。", "从今后惹起干戈不止，怎靠得这不冠带的男儿某在斯。", "(梅香云)姐姐，常言道：姻缘姻缘，事非偶然。", "这桩儿亲事，也是天缘注定哩。", "(正旦唱)这姻缘甚些天赐，且因而勉强从之，免的道外向大家有怨词。", "(孙权云)妹子，只要你小心在意，休走漏了消息也。", "(正旦云)哥哥，你妹子知道。", "(唱)虽则你图为造次，我可也聪明无二，怎肯把军情泄漏了一些儿？(下)。"]'),
('yuanqu-7087','两军师隔江斗智・醉春风','无名氏','元','元曲','yuanqu','','[]','不索费叮咛，我从来识道理。',73,'元曲/yuanqu.json','["不索费叮咛，我从来识道理。", "见他时自有巧机关，我着他可也喜，喜。", "那一个掌亲的怎知道弄假成真？那一个说亲的早做了藏头露尾，那一个成亲的也自会拿粗挟细。"]'),
('yuanqu-7088','两军师隔江斗智・迎仙客','无名氏','元','元曲','yuanqu','','[]','你看桑麻映日稠，禾黍接天齐，(甘宁云)皆因荆州九郡，地广民富，俺主公以此不能弃舍。',88,'元曲/yuanqu.json','["你看桑麻映日稠，禾黍接天齐，(甘宁云)皆因荆州九郡，地广民富，俺主公以此不能弃舍。", "(正旦唱)这荆州我亲身、我亲身可便到这里。", "你看那地方宽，民富实，端的是锦绣城池，无福的难存济。"]'),
('yuanqu-7089','两军师隔江斗智・普天乐','无名氏','元','元曲','yuanqu','','[]','我则见玳筵前，摆列着英雄辈。',102,'元曲/yuanqu.json','["我则见玳筵前，摆列着英雄辈。", "一个个精神抖擞，一个个礼度委蛇。", "那军师有冠世才，堪可称龙德。", "觑他这道貌非常仙家气，稳称了星履霞衣。", "待道他是齐管仲多习些战策，待道他是周吕望大减些年纪，待道他是汉张良还广有神机。"]'),
('yuanqu-7090','两军师隔江斗智・十二月','无名氏','元','元曲','yuanqu','','[]','看了他形容动履，端的是虎将神威。',56,'元曲/yuanqu.json','["看了他形容动履，端的是虎将神威。", "想我那甘宁、凌统，比将来似鼠如狸。", "可知道刘玄德重兴汉室，却元来有这班儿文武扶持。"]'),
('yuanqu-7091','两军师隔江斗智・尧民歌','无名氏','元','元曲','yuanqu','','[]','呀，我见他曲躬躬双手捧金杯，喜孜孜一团儿和气蔼庭闱。',73,'元曲/yuanqu.json','["呀，我见他曲躬躬双手捧金杯，喜孜孜一团儿和气蔼庭闱。", "不由我不立钦钦奉命谨依随，拚的个醉醺醺满饮不辞推。", "我今日须也波知周瑜你好没见识，怎不的观时势。"]'),
('yuanqu-7092','两军师隔江斗智・耍孩儿','无名氏','元','元曲','yuanqu','','[]','从来不出闺门里，羞答答怎便将男儿细窥。',136,'元曲/yuanqu.json','["从来不出闺门里，羞答答怎便将男儿细窥。", "则我这三从四德幼闲习，既嫁鸡须逐他鸡。", "只见他目睛转盼能过耳，手臂垂来直至膝。", "赤帝子真苗裔，暂时间蛟龙蟠屈，少不得雷雨腾飞。", "(云)我只笑那周瑜好痴也，你自家没智识索取荆州，却将我送到这里，你须要做的功劳，我为甚来倒替你守寡一世？(唱)。"]'),
('yuanqu-7093','两军师隔江斗智・三煞','无名氏','元','元曲','yuanqu','','[]','不甫能射金屏中雀来，只索便上秦楼跨凤归，也是我妇人家自为终身计。',77,'元曲/yuanqu.json','["不甫能射金屏中雀来，只索便上秦楼跨凤归，也是我妇人家自为终身计。", "你只为一时功效犹难遂，却将我百岁姻缘竞不提，那个肯无番悔？你使着这般科段，敢可也枉用心机。"]'),
('yuanqu-7094','两军师隔江斗智・二煞','无名氏','元','元曲','yuanqu','','[]','想着我同胞的能有几，我大哥哥又不到底，提起来尚兀自肝肠碎。',73,'元曲/yuanqu.json','["想着我同胞的能有几，我大哥哥又不到底，提起来尚兀自肝肠碎。", "我母亲呵，可怜永日萱花晚，哥哥也没甚傍枝棠棣稀，怎不顾亲生妹？倒着我明为嫁送，暗夺城池。"]'),
('yuanqu-7095','两军师隔江斗智・煞尾','无名氏','元','元曲','yuanqu','','[]','怕只怕母兄上别了情，愁只愁夫妻上伤了美。',57,'元曲/yuanqu.json','["怕只怕母兄上别了情，愁只愁夫妻上伤了美。", "从今后做了个弄丸的宜僚，我只从中儿立直，着他两下干戈再不起。", "(同梅香下)。"]'),
('yuanqu-7096','两军师隔江斗智・逍遥乐','无名氏','元','元曲','yuanqu','','[]','想则想荆州消耗，与他那结义的人儿，这几日离多来会少。',142,'元曲/yuanqu.json','["想则想荆州消耗，与他那结义的人儿，这几日离多来会少。", "(梅香云)比及姐夫想他每兄弟呵，可着他回去了罢。", "(正旦唱)你说的来好没分晓，俺哥哥有妙计千条。", "则待取霸图王在这遭，(梅香云)既然主公不肯放姐夫去，着他悄悄的走了罢。", "(正旦唱)怕不要安排归棹。", "倘或的驱兵追赶，兀那一片长江，何处奔逃？。"]'),
('yuanqu-7097','两军师隔江斗智・梧叶儿','无名氏','元','元曲','yuanqu','','[]','哥哥当尊重，敢动劳，则见他金盏泛香醪。',118,'元曲/yuanqu.json','["哥哥当尊重，敢动劳，则见他金盏泛香醪。", "(孙权低云)妹子也，这一杯酒则要你见功者。", "(正旦唱)但饮酒只说酒中事，怎又伤我的心着我心下恼。", "(孙权云)妹子，你恼做甚么？饮了这杯酒者。", "(正旦背唱)我背地里将这酒儿浇天地，也只愿的俺两口儿夫妻到老。"]'),
('yuanqu-7098','两军师隔江斗智・金菊香','无名氏','元','元曲','yuanqu','','[]','哥哥你道我过门来事事有蹊跷，则你这两下里机关不甚巧。',323,'元曲/yuanqu.json','["哥哥你道我过门来事事有蹊跷，则你这两下里机关不甚巧。", "(孙权云)妹子，我当日与你计较的事，你几曾依我一些儿来？(正旦唱)若有那歹心儿天觑着，则愿你早放他还朝，也免的动枪刀。", "(孙权云)令人，着刘封过来，(卒子云)刘封，主公唤你哩。", "(刘封做见科，云)我刘封见父亲来的日子多了，天色寒冷，我为送暖衣过来。", "这桌面上吃不了的，也该散些我吃。", "(孙权云)哦，你原来为送暖衣。", "刘封，你父亲醉了也。", "(刘封云)哦，我还不曾唱喏哩。", "老奶奶唱喏，母亲唱喏。", "俺父亲醉了也。", "父亲，刘封送暖衣在此。", "(刘玄德做醉科，云)老夫人，刘备酒勾了也。", "(刘封云)母亲，我家老子怎么吃的这等醉了？你叫他一声。", "(正旦云)刘封，你且不要叫他，等我问你几句话咱。", "(刘封云)母亲问我甚么？(正旦唱)。"]'),
('yuanqu-7099','两军师隔江斗智・醋葫芦','无名氏','元','元曲','yuanqu','','[]','你那里群臣喜共忧？(刘封云)军师们都好好的没甚么忧。',139,'元曲/yuanqu.json','["你那里群臣喜共忧？(刘封云)军师们都好好的没甚么忧。", "(正旦唱)事情歹共好？(刘封云)我们荆州一个低钱买个大馍馍，这个便是事情。", "(正旦唱)则您那云长、翼德敢心焦？(刘封云)俺两个叔叔终日喝酒快据，则不心焦。", "(正旦唱)则怕他急煎煎盼着音信杳。", "为着个甚些担阁？我怕您无人处将我厮评跋。"]'),
('yuanqu-7100','两军师隔江斗智・幺篇','无名氏','元','元曲','yuanqu','','[]','他眼朦胧恰待开，对着人不敢瞧。',115,'元曲/yuanqu.json','["他眼朦胧恰待开，对着人不敢瞧。", "则他那巧机关在腹内暗藏着，(孙权云)小姐，你扶起刘玄德来，与他穿上暖衣，再饮几杯咱。", "(正旦唱)你教我扶将他起来把衣换了。", "他正是醉人难叫，(刘封云)父亲，你这一睡到几时也？(正旦唱)他直睡到明月上花梢。"]'),
('yuanqu-7101','两军师隔江斗智・幺篇','无名氏','元','元曲','yuanqu','','[]','他耳边厢悄悄的言，心儿里暗暗的晓。',74,'元曲/yuanqu.json','["他耳边厢悄悄的言，心儿里暗暗的晓。", "不争你把我厮瞒着，怎知我这些心地好。", "(刘封云)母亲，看俺父亲咱。", "(正旦唱)我怎肯将他来违拗，我须是忠臣门下女妖娆。"]'),
('yuanqu-7102','两军师隔江斗智・浪里来煞','无名氏','元','元曲','yuanqu','','[]','你那里担着愁，我这里倒含些笑，只待做了脱金钩东海冠山鳌。',94,'元曲/yuanqu.json','["你那里担着愁，我这里倒含些笑，只待做了脱金钩东海冠山鳌。", "(孙权云)妹子，你则今日就起身罢。", "(正旦唱)你还怕我有心留恋着，只望俺那荆州疾到。", "便排下那几千番筵席，你也休的再来邀。", "(同夫人下)。"]'),
('yuanqu-7103','两军师隔江斗智・仙吕/赏花时','无名氏','元','元曲','yuanqu','','[]','我着你换上青骢前路发，这早晚周瑜没乱杀。',50,'元曲/yuanqu.json','["我着你换上青骢前路发，这早晚周瑜没乱杀。", "再休来俺面上弄奸猾，凭着俺单枪也那只马，则着你都不得好还家。"]'),
('yuanqu-7104','两军师隔江斗智・双调/新水令','无名氏','元','元曲','yuanqu','','[]','听的个东君今日绮筵开，则俺这美前程世间无赛。',61,'元曲/yuanqu.json','["听的个东君今日绮筵开，则俺这美前程世间无赛。", "想当初要荆州通使去，舍了个亲妹子度江来。", "若不是巧计安排，怎能勾锦鸳鸯得宁耐？。"]'),
('yuanqu-7105','两军师隔江斗智・沉醉东风','无名氏','元','元曲','yuanqu','','[]','我只见众公卿欢容满腮，齐臻臻把果桌忙抬。',107,'元曲/yuanqu.json','["我只见众公卿欢容满腮，齐臻臻把果桌忙抬。", "画堂中音乐谐，宝鼎内香烟蔼。", "祝千秋磕头礼拜，不知道赤壁东风大会垓，可似这今朝奏凯？(诸葛又递酒科，云)夫人满饮此杯。", "(正旦云)军师先请。", "(诸葛亮云)不敢、夫人请。", "(正旦唱)。"]'),
('yuanqu-7106','两军师隔江斗智・沽美酒','无名氏','元','元曲','yuanqu','','[]','见军师送酒来，空折杀女裙钗。',41,'元曲/yuanqu.json','["见军师送酒来，空折杀女裙钗。", "多亏你决胜成功将相才，与妾身有何担带？敢劳动这酬待？。"]'),
('yuanqu-7107','两军师隔江斗智・太平令','无名氏','元','元曲','yuanqu','','[]','合谢你军师元帅，只这一封书促你回来。',130,'元曲/yuanqu.json','["合谢你军师元帅，只这一封书促你回来。", "识破了千般成败，杜绝了他十分毒害。", "这一场布摆，喝采，是谁的手策？呀，保护得荆州安泰。", "(刘玄德云)众将斟上酒，多要尽醉方归也。", "(众饮酒科)(关羽云)嫂嫂，想当初周公瑾怎生用计，要取索荆州？你是说一遍，与俺众将听咱。", "(正旦唱)。"]'),
('yuanqu-7108','两军师隔江斗智・锦上花','无名氏','元','元曲','yuanqu','','[]','要取荆州，人人无奈。',43,'元曲/yuanqu.json','["要取荆州，人人无奈。", "则有个周瑜，逞尽狂乖，定下机关，送亲过来。", "嘱付我的言词，扬扬不采。"]'),
('yuanqu-7109','两军师隔江斗智・碧玉箫','无名氏','元','元曲','yuanqu','','[]','这也是天数合该，姻缘线牵来。',298,'元曲/yuanqu.json','["这也是天数合该，姻缘线牵来。", "夫妻有情怀，永远得和谐。", "愿皇图万万载，保封疆弭祸灾。", "御酒酾，宫花戴，长似这筵前宴乐无妨碍。", "(诸葛亮云)您众将跪下者，听主公与你叙功赐赏。", "(词云)贫道本垅上遗民，遇明主三顾殷勤。", "在军中运筹决策，长则是羽扇纶巾。", "借荆州暂屯人马，奈东吴索取频频。", "屡设计皆为参透；故遣使议结姻亲。", "赚过江阴图谋害，锦囊至立送回轮。", "张翼德虽然粗鲁，翠鸾车假作夫人。", "将周瑜当场耻辱，箭疮裂一命难存。", "关云长雄略盖世，赵子龙大胆包身。", "便刘封不曾临阵，往来间亦有功勋。", "玄德公汉朝枝叶，孙小姐出自名门。", "正相应天缘匹配，排筵席庆贺长春。", "诸将佐加官赐赏，一齐的拜谢皇恩。", "(众谢科)(正旦云)俺玄德公呵。", "(唱)。"]'),
('yuanqu-7110','两军师隔江斗智・收尾','无名氏','元','元曲','yuanqu','','[]','他本是汉皇帝室亲支派，少不得将吴魏并做了刘家世界。',51,'元曲/yuanqu.json','["他本是汉皇帝室亲支派，少不得将吴魏并做了刘家世界。", "显得俺卧龙的诸葛十分能，笑杀那短命的周瑜刚则一时歹。"]'),
('yuanqu-7111','宋上皇御断金凤钗・仙吕/赏花时','郑延玉','元','元曲','yuanqu','','[]','守着这三尺萤窗十数春，便待要千丈龙门一跳身。',44,'元曲/yuanqu.json','["守着这三尺萤窗十数春，便待要千丈龙门一跳身。", "既生长在人伦，狗也有三升糠分，况道是我为人。"]'),
('yuanqu-7112','宋上皇御断金凤钗・仙吕/点绛唇','郑延玉','元','元曲','yuanqu','','[]','到冬来风雪柴扉，到春来破窗细雨，琴书湿。',37,'元曲/yuanqu.json','["到冬来风雪柴扉，到春来破窗细雨，琴书湿。", "似这般忍冷担饥，我子索长受妻儿气。"]'),
('yuanqu-7113','宋上皇御断金凤钗・混江龙','郑延玉','元','元曲','yuanqu','','[]','早则轮来到游街三日，不枉了寒窗十勒苦攻习。',79,'元曲/yuanqu.json','["早则轮来到游街三日，不枉了寒窗十勒苦攻习。", "头直上打一轮皂盖，马头上列两行朱衣。", "凭着我七步才为及第策，五言诗作上天梯，今日才得文章济。", "我如今脱白换绿，挂紫穿绯。"]'),
('yuanqu-7114','宋上皇御断金凤钗・油葫芦','郑延玉','元','元曲','yuanqu','','[]','他道我原是寒门一布衣，我怎生消受？投至的十年身到凤凰池，知他磨了几锭乌龙墨，知他坏了多少霜毫笔？不付能恰做官，没揣的罢了职。',108,'元曲/yuanqu.json','["他道我原是寒门一布衣，我怎生消受？投至的十年身到凤凰池，知他磨了几锭乌龙墨，知他坏了多少霜毫笔？不付能恰做官，没揣的罢了职。", "若是白衣回到俺家乡内，怎见我同学业，众相知！(云)教人道赵鹗得了官，可怎生又剥落了？(唱)。"]'),
('yuanqu-7115','宋上皇御断金凤钗・天下乐','郑延玉','元','元曲','yuanqu','','[]','我可甚金榜无名誓不归，争奈文齐福不齐。',197,'元曲/yuanqu.json','["我可甚金榜无名誓不归，争奈文齐福不齐。", "学了二十年，则得半霎儿享富贵。", "觑功名笋指般休，看荣华眨眼般疾，更疾如南柯一梦里。", "(殿云)兀那赵鹗，为你失仪落简，本当见罪。", "圣人见你文章，饶你死罪，原籍为民。", "你听者：文章冠世中高魁，争奈文齐福不齐。", "才蒙雨露剥官职，依旧中原一布衣。", "(下)(正末云)我出的这朝门来，怎教我不烦恼！哎，赵鹗也，你好命蹇福薄，付能得了官谢恩，又失仪落间，则是我命穷不合做官？(唱)。"]'),
('yuanqu-7116','宋上皇御断金凤钗・哪吒令','郑延玉','元','元曲','yuanqu','','[]','似这般发志气，如管宁割席；我看书，如匡衡凿壁；我受贫，如韩信乞食。',53,'元曲/yuanqu.json','["似这般发志气，如管宁割席；我看书，如匡衡凿壁；我受贫，如韩信乞食。", "我想这小人儒，儿曹辈，那一个肯见贤思齐。"]'),
('yuanqu-7117','宋上皇御断金凤钗・鹊踏枝','郑延玉','元','元曲','yuanqu','','[]','恰脱下紫罗衣，又穿上旧罗衣，远远而来，却不怏怏而归。',64,'元曲/yuanqu.json','["恰脱下紫罗衣，又穿上旧罗衣，远远而来，却不怏怏而归。", "好一似江淹梦笔，(云)我到家中，浑家问道：你得官也？(唱)我滴溜着一个休妻。"]'),
('yuanqu-7118','宋上皇御断金凤钗・寄生草','郑延玉','元','元曲','yuanqu','','[]','普天下习儒士，学业的。',68,'元曲/yuanqu.json','["普天下习儒士，学业的。", "七品八品，指望功名遂；千人万人，都想诗书济；十番九番，不得文章力。", "从盘古王没一个富书生，知他孔夫子，有多少穷徒弟。"]'),
('yuanqu-7119','宋上皇御断金凤钗・金盏儿','郑延玉','元','元曲','yuanqu','','[]','你道你典了满身衣，我搅了一身亏，想我那虚名枉上登科记。',116,'元曲/yuanqu.json','["你道你典了满身衣，我搅了一身亏，想我那虚名枉上登科记。", "(云)小二哥，你好乔，听的得了官，就买酒相贺；听的剥落了官职，就索要房钱。", "(唱)你却便攀高接贵，教我笑，店都知。", "我得官也，相庆相贺，剥落了也，不追随！正是世情看冷暖，人面逐高低。"]'),
('yuanqu-7120','宋上皇御断金凤钗・醉中天','郑延玉','元','元曲','yuanqu','','[]','你道我及第也不及第，我待支持怎支持？你可不观见容颜便得知，有什么不解其中意。',70,'元曲/yuanqu.json','["你道我及第也不及第，我待支持怎支持？你可不观见容颜便得知，有什么不解其中意。", "他觑了我穷身分，说个甚的；又没有金冠霞帔，则着怎支吾那一纸休离。"]'),
('yuanqu-7121','宋上皇御断金凤钗・后庭花','郑延玉','元','元曲','yuanqu','','[]','若是荣华后丑妇随，饥寒后亲子离。',86,'元曲/yuanqu.json','["若是荣华后丑妇随，饥寒后亲子离。", "我且不问嫌夫窘桑新妇，我则打这恨爹穷忤逆贼。", "则要各东西，不肯一家一计，水藉鱼，鱼藉水。", "(旦云)你不投托个人，讨些衣食，怎生度日！(正末唱)。"]'),
('yuanqu-7122','宋上皇御断金凤钗・金盏儿','郑延玉','元','元曲','yuanqu','','[]','如今等讨人衣，似剥了身上一张皮。',70,'元曲/yuanqu.json','["如今等讨人衣，似剥了身上一张皮。", "谁想四海之内皆兄弟，兼朝廷中举枉错诸直。", "指云中雁为膳馔，捞水中月觅衣食。", "如投吕先生访故友，似寻吴文政搠相知。"]'),
('yuanqu-7123','宋上皇御断金凤钗・赚煞','郑延玉','元','元曲','yuanqu','','[]','我卖得二文钱，籴得一升米，够养活孩儿共你。',93,'元曲/yuanqu.json','["我卖得二文钱，籴得一升米，够养活孩儿共你。", "凭着我端砚文章纸墨笔，吃的是淡饭黄齑。", "我挂招牌指万物为题，写着道吟诗寰中占了第一。", "更写着曾丹墀立地，在金门出入，教人道穷书生犹自说兵机。", "(下)。"]'),
('yuanqu-7124','宋上皇御断金凤钗・醉春风','郑延玉','元','元曲','yuanqu','','[]','投至二十载苦功名，却不想半霎剥落了。',54,'元曲/yuanqu.json','["投至二十载苦功名，却不想半霎剥落了。", "则那求官应举世间多，及第的少。", "似我这粪土之墙，斗筲之器，枉读了圣贤之道。"]'),
('yuanqu-7125','宋上皇御断金凤钗・红绣鞋','郑延玉','元','元曲','yuanqu','','[]','虽不达周公礼乐，虽不及子夏文学，寻思来惟有看书高。',52,'元曲/yuanqu.json','["虽不达周公礼乐，虽不及子夏文学，寻思来惟有看书高。", "放着花笺纸，端溪砚，乌龙墨，紫霜毫，穷不的卓儿出四宝。"]'),
('yuanqu-7126','宋上皇御断金凤钗・迎仙客','郑延玉','元','元曲','yuanqu','','[]','写染得无褒弹，吟咏的忒风骚，真真字儿不带草。',51,'元曲/yuanqu.json','["写染得无褒弹，吟咏的忒风骚，真真字儿不带草。", "又不曾倒了平仄，差了韵脚。", "又不似卖春豆秋糕，又索甚学歌叫。"]'),
('yuanqu-7127','宋上皇御断金凤钗・石榴花','郑延玉','元','元曲','yuanqu','','[]','则见压肩叠脊相簇一周遭，劝着的不睬半分毫。',258,'元曲/yuanqu.json','["则见压肩叠脊相簇一周遭，劝着的不睬半分毫。", "那厮憔憔忄敞忄敞，挥天霍地怒难消，(云)支揖哥哥，你休闹罢！(邦云)他少我二百钱，不还我，我和他跳河去！(正末唱)越见人劝着，越逞粗豪。", "(孤云)哥哥，你放了老汉，借些钱与哥哥便了。", "(做见正末科，云)支揖哥哥，多亏你相劝。", "老汉见你有二百长钱，怎生借与老汉，还了那人去，我一本一利交还。", "我撞着恶人也无奈何了。", "(邦云)你少我钱还胡赖！(正末唱)哎，你个孟尝君，自养着家中哨。", "(孤云)哥哥贵姓？(邦云)我是李虎。", "(正末唱)你正是晏平仲善与人交，走函关不肯学鸡叫，没钱呵扯着他跳周桥。"]'),
('yuanqu-7128','宋上皇御断金凤钗・斗鹌鹑','郑延玉','元','元曲','yuanqu','','[]','则这是养剑客临危，报答你田文下梢。',92,'元曲/yuanqu.json','["则这是养剑客临危，报答你田文下梢。", "劝你下李密休慌，请你个伯当放了。", "(邦云)这钱不还，我更待干罢！(正末唱)哎！你个谒鲁肃周瑜好躁暴，恶歆歆攥住系腰。", "待不劝是自己惺惺，待劝呵是他家恼了。"]'),
('yuanqu-7129','宋上皇御断金凤钗・普天乐','郑延玉','元','元曲','yuanqu','','[]','你遇着恶人魔，我值着穷星照。',233,'元曲/yuanqu.json','["你遇着恶人魔，我值着穷星照。", "(云)不争你借了二百钱呵，(唱)我忍饥在今日，受饿到明朝。", "(孤云)哥哥，见义不为无勇也。", "(正末唱)怕不待见义为，争奈家私薄。", "(孤云)君子周人之急，你借与我罢。", "(正末唱)君子周急，我须知道，争奈庞居士，在陋巷箪瓢。", "(云)君子周人之急，我则这二百钱，你将去。", "(孤云)谢了哥哥。", "兀那哥哥，这二百钱你拿去。", "(邦云)你还了我这钱，你休怪，我吃酒去也。", "(下)(孤云)多谢哥哥救我。", "(正末云)你借了这钱去呵，(唱)愁闷杀小生，烦恼杀幼子，冻饿杀多娇！。"]'),
('yuanqu-7130','宋上皇御断金凤钗・尧民歌','郑延玉','元','元曲','yuanqu','','[]','大古是家富小儿娇，我则愁腌日月没柴没米怎生熬。',103,'元曲/yuanqu.json','["大古是家富小儿娇，我则愁腌日月没柴没米怎生熬。", "觅不的粗衣淡饭且淹消，穷秀才工课觅分毫。", "青霄仰面看着高，却不有路终须到。", "(旦云)你养活不的我，写与我一纸休书，我别嫁人去。", "(正末云)等我到家，与你休书。", "(唱)。"]'),
('yuanqu-7131','宋上皇御断金凤钗・三煞','郑延玉','元','元曲','yuanqu','','[]','饿的我肚皮中如火烧，走的我浑身上似水浇。',68,'元曲/yuanqu.json','["饿的我肚皮中如火烧，走的我浑身上似水浇。", "三魂儿未曾着躯壳，惊慌回去心尤跳。", "我可甚买卖归来汗未消，则听的高声叫又道，拿住秀才，险吓杀多娇。"]'),
('yuanqu-7132','宋上皇御断金凤钗・二煞','郑延玉','元','元曲','yuanqu','','[]','你道十日欠九日饥，三顿无一顿饱。',101,'元曲/yuanqu.json','["你道十日欠九日饥，三顿无一顿饱。", "(旦云)想当初造物嫁你这穷厮。", "(正末唱)当日嫁这穷书生，你是乐者为之乐。", "有钱时欢喜无钱时叫，却不道贫不忧愁富不骄。", "则为我不主才天教报，救人急是耽寒之本，顺人情是忍饿之苗。"]'),
('yuanqu-7133','宋上皇御断金凤钗・煞尾','郑延玉','元','元曲','yuanqu','','[]','向千步廊等他不来，五凤楼觅不着。',58,'元曲/yuanqu.json','["向千步廊等他不来，五凤楼觅不着。", "望九重宫里无消耗，干将我二百青蚨落空了。", "(下)(旦云)小二哥，咱回家去来。", "(同下)。"]'),
('yuanqu-7134','宋上皇御断金凤钗・南吕/一枝花','郑延玉','元','元曲','yuanqu','','[]','我当不的春天骤雨淋，受不的夏月斜阳晒。',86,'元曲/yuanqu.json','["我当不的春天骤雨淋，受不的夏月斜阳晒。", "忍不的秋霜寒透屋，住不的冬雪冷书斋。", "这四季苦好难捱，却不道否极后还生泰，轮到我苦尽也苦不来。", "住着破设设坏屋三间，干受了冷清清寒窗十载。"]'),
('yuanqu-7135','宋上皇御断金凤钗・梁州','郑延玉','元','元曲','yuanqu','','[]','我便似箪瓢巷颜回暗宿，却浑如首阳山伯夷清斋。',172,'元曲/yuanqu.json','["我便似箪瓢巷颜回暗宿，却浑如首阳山伯夷清斋。", "我便似绝粮孔子居陈蔡。", "饿杀我也口说珠玉，冻杀我也胸卷江淮。", "昨日失仪在金殿，今日卖诗在长街。", "见一个粗豪士，扯住个英才，我不合鬼擘口审问的明白。", "我遇着庞居士与了二百青蚨，合着孟尝君养三千剑客，撞着赛元达列十二金钗。", "我想来，不该。", "情知这范丹，怎放来生债。", "利又不见，本又不在。", "干与别人救祸灾，好教我无语支划。"]'),
('yuanqu-7136','宋上皇御断金凤钗・隔尾','郑延玉','元','元曲','yuanqu','','[]','我借与他钱呵，搭救出他招贤纳干东洋海。',277,'元曲/yuanqu.json','["我借与他钱呵，搭救出他招贤纳干东洋海。", "他还我钱呵，却是拨出这弃子休妻大会垓。", "(张千云)你收了金钗者，我回大人话去。", "(正末云)生受大哥！(店小二云)吃了茶去。", "(张千云)不必吃茶了。", "(下)(旦云)我收了这金钗者。", "(正末唱)除今后除了家私缴缠外，拴衣做鞋，籴米买柴，(旦云)我也要置些衣服哩！(正末唱)妻也你休逢着的商量，见了的买。", "(云)将一只金钗，与小二哥做房钱。", "小二哥在那里？(店小二云)哥哥，你唤我怎的？(正末云)方才大人还了我十只金钗，我与你一只做房钱。", "(店小二接科，云)我道你不是受贫的人，我还打挣头间房你安下。", "我看茶与你吃，你便搬过来。", "(正末唱)。"]'),
('yuanqu-7137','宋上皇御断金凤钗・贺新郎','郑延玉','元','元曲','yuanqu','','[]','觑着这梢房门一似吓魂台，你如今悄语低言，早则大惊小怪。',433,'元曲/yuanqu.json','["觑着这梢房门一似吓魂台，你如今悄语低言，早则大惊小怪。", "我有钱时，做甚教伊索打火房钱该二百，(店小二云)且由他，怕你少了我的。", "(正末云)小二哥，与你这金钗。", "(唱)我与你火炭也似一只金钗。", "(店小二云)你是个知礼的人，你肯失信？(正末唱)我无钱时，他恶歆歆嗔满怀，还了钱，喜孜孜笑盈腮。", "(店小二云)小人早晚言高语低，耽待些儿。", "(正末唱)更道是小二哥不是处权耽待，(店小二云)多谢了哥哥也。", "(正末唱)可是欲求天外事，须动世间财。", "(店小二云)嫂子，哥哥这一日不曾吃茶饭哩，我去安排些茶饭，与哥哥吃。", "(旦云)可知好哩。", "(店小二慌下)(将茶饭上与旦科，云)嫂子，我安排茶饭来了，着哥哥吃些儿。", "(旦云)生受哥哥来。", "(店小二云)嫂子说那里话，俺便是一家一般。", "嫂子你将过去与哥哥吃，显的你敬心。", "(旦云)好，好，我将过去。", "(旦做托饭见正末科)(正末云)大嫂，你做甚么哩？(旦云)我见秀才不曾吃饭，我着小二哥桉排些茶饭来，你吃些儿。", "(店小二云)哥哥，你用些者。", "(正末云)好世情也呵！(唱)。"]'),
('yuanqu-7138','宋上皇御断金凤钗・骂玉郎','郑延玉','元','元曲','yuanqu','','[]','早迁转波粗茶淡饭黄齑菜，你畅好能打点，会安排，(旦云)秀才，你肚里饥，吃些儿。',73,'元曲/yuanqu.json','["早迁转波粗茶淡饭黄齑菜，你畅好能打点，会安排，(旦云)秀才，你肚里饥，吃些儿。", "(正末唱)便似孟光举案齐眉待。", "你可不道穷秀才，忒不出财，我须实无奈。"]'),
('yuanqu-7139','宋上皇御断金凤钗・采茶歌','郑延玉','元','元曲','yuanqu','','[]','你将我恶抢白，死栽划："将休书疾快写将来！"(店小二云)哥哥，不记旧恶。',73,'元曲/yuanqu.json','["你将我恶抢白，死栽划：\"将休书疾快写将来！\"(店小二云)哥哥，不记旧恶。", "哥哥，你且吃些茶饭。", "(正末唱)将一座冰雪堂翻做敬宾宅，也有春风和气画堂开。"]'),
('yuanqu-7140','宋上皇御断金凤钗・斗虾蟆','郑延玉','元','元曲','yuanqu','','[]','问甚将着行货，做甚买卖，有甚资财？你把行旅招商店开，全没些宽大。',263,'元曲/yuanqu.json','["问甚将着行货，做甚买卖，有甚资财？你把行旅招商店开，全没些宽大。", "问甚乘船跨海，管甚推车搬载？店家不下单客，我做保人知在。", "一更三点左而，千方百计打捱。", "冷冷清清禁街，潜潜等等门外。", "道着全然不睬，劝着没些疾快。", "休得宁奈，休得停待。", "一会巡军朗朗，提将铃来。", "为甚教疾快门开，我须是惯曾为旅偏怜客。", "(店小二云)我看着哥哥面皮，我开开这门。", "(邦入门科，云)你可不下单客？(店小二云)我说则不下单客。", "(邦云)是谁着开门来？(正末云)是小生。", "(邦云)多谢了哥哥。", "(正末还礼科)(唱)我观了模样，觑了面色，七尺身材。", "我这里孜孜的看了，转转的疑猜。"]'),
('yuanqu-7141','宋上皇御断金凤钗・牧羊关','郑延玉','元','元曲','yuanqu','','[]','昨日个金凤钗枣瓤赤，今日个银匙箸雪练也似白，便做道运拙时乖。',269,'元曲/yuanqu.json','["昨日个金凤钗枣瓤赤，今日个银匙箸雪练也似白，便做道运拙时乖。", "时来呵铁也争光，运去后黄金失色。", "兀的是谁人撇下把银匙箸？谁拿了凤头钗？俺正是闭门屋里坐，祸从天上来。", "(杨云)那里不寻你，杀人贼可在这里！兀那厮，你怎生杀了我家六儿，偷了银匙箸，图财致命！你实说来。", "(正末云)小生并然不知道。", "(杨云)你不曾杀了俺家六儿，这银匙箸你怎得来？(正末云)大人可怜见，委实是金钗来。", "(杨云)这厮还口强哩！赃已有了，你还不招，等甚么？左右人，洗剥了打着者！(做打科)(正末云)委实埋的是金钗，不知怎么刨出这东西来？(店小二云)怎生变出这个生活来？(正末唱)。"]'),
('yuanqu-7142','宋上皇御断金凤钗・红芍药','郑延玉','元','元曲','yuanqu','','[]','我将凤头钗亲手自培埋，刨出来怀内忙揣。',72,'元曲/yuanqu.json','["我将凤头钗亲手自培埋，刨出来怀内忙揣。", "我想那戳包儿贼汉，栽排下不义之财。", "我正是慈悲生患害，这一场鬼使神差。", "替别人湿肉伴干柴，没人情官棒好难捱！。"]'),
('yuanqu-7143','宋上皇御断金凤钗・菩萨梁州','郑延玉','元','元曲','yuanqu','','[]','早是这伙公吏又心乖，恶少年好毒害。',147,'元曲/yuanqu.json','["早是这伙公吏又心乖，恶少年好毒害。", "你不是柳盗跖家吊客，则是这穷秀才家横祸非灾。", "不知怎生年月日时，我恰才快早阎王怪，使不着老实终须在。", "(旦云)大人可怜见！(正末唱)不济事，枉分解，休折证，向云阳死去来，眼见得命掩泉台。", "(杨云)不招呵再打！(打科)(正末悲科，云)则是我不合来这状元店里下。", "(唱)。"]'),
('yuanqu-7144','宋上皇御断金凤钗・煞尾','郑延玉','元','元曲','yuanqu','','[]','譬如教天不盖，地不载，居在人海，枉了食不饱，衣不遮，送了世界。',164,'元曲/yuanqu.json','["譬如教天不盖，地不载，居在人海，枉了食不饱，衣不遮，送了世界。", "想昨宵吃剑才，人一般好客待。", "杀人贼你做来，换人赃我捉获。", "我则索屈招致命图财，兀的不屈杀了卖诗的穷秀才！(杨云)杀人贼都有了，小官见圣人走一遭去。", "(率众拥正末下)(店小二云)苦也，付能得了钱，又拿将去了。", "嫂嫂，咱两个看他去来。", "(旦云)男儿也，则被你痛杀我也！(同下)。"]'),
('yuanqu-7145','宋上皇御断金凤钗・双调/新水令','郑延玉','元','元曲','yuanqu','','[]','不由人分说口中词，教我屈招成杀人公事。',172,'元曲/yuanqu.json','["不由人分说口中词，教我屈招成杀人公事。", "我则见愁云迷市井，杀气满京师。", "好教我无语嗟咨，一步步行来，到枉死市。", "(旦慌上，云)兀的不是我男儿？哎哟！男儿也！(刽子云)兀那妇人靠后！(正末云)哥哥可怜见，这个是我浑家。", "(刽子云)兀那秀才。", "你是读书的人，怎生做这般勾当，图财致命也？(正末云)哥哥，小生委实冤屈也！(刽子云)怎生冤枉着你一个？(正末唱)。"]'),
('yuanqu-7146','宋上皇御断金凤钗・驻马听','郑延玉','元','元曲','yuanqu','','[]','揣与我个天来大官司，推为到罪若当刑法命子，判着手来大斩字，那里是死而无怨罪名儿。',121,'元曲/yuanqu.json','["揣与我个天来大官司，推为到罪若当刑法命子，判着手来大斩字，那里是死而无怨罪名儿。", "我想那曹司素状是辰时，便是那阎王注定黄昏死。", "(旦指看的人云)哥哥们，你靠后，看他怎么？(正末云)大嫂你不知。", "(唱)你道他看的主甚意儿，大古是不曾见玉堂金马三学士。"]'),
('yuanqu-7147','宋上皇御断金凤钗・沉醉东风','郑延玉','元','元曲','yuanqu','','[]','没主了这个娇痴小厮，抛闪下软弱妻儿。',62,'元曲/yuanqu.json','["没主了这个娇痴小厮，抛闪下软弱妻儿。", "有我后把你觑当，没我后人轻视。", "谁与你干办家私，捱不过今冬下雪时，您两个不冻死，多应饿死。"]'),
('yuanqu-7148','宋上皇御断金凤钗・雁儿落','郑延玉','元','元曲','yuanqu','','[]','咱人家子不孝是父不慈，咱人家儿忏逆是爷不是。',44,'元曲/yuanqu.json','["咱人家子不孝是父不慈，咱人家儿忏逆是爷不是。", "儿呵，我怎肯教你替死休，宁可爷做事，爷当事。"]'),
('yuanqu-7149','宋上皇御断金凤钗・得胜令','郑延玉','元','元曲','yuanqu','','[]','我好可怜见这小孩儿，(觑旦悲科)(唱)我好不忍见女娇姿。',71,'元曲/yuanqu.json','["我好可怜见这小孩儿，(觑旦悲科)(唱)我好不忍见女娇姿。", "我命窘遭贤妇，我家贫显孝子。", "嘱咐您寻思，遭节朔年至，我死在阴司，你与我烧些钱烈陌儿纸。"]'),
('yuanqu-7150','宋上皇御断金凤钗・川拨棹','郑延玉','元','元曲','yuanqu','','[]','好险些儿，险些儿遭横死，死在参差，命若悬丝。',46,'元曲/yuanqu.json','["好险些儿，险些儿遭横死，死在参差，命若悬丝。", "脑背后立着刽子，长休饭抄了几匙，永别酒饮了一卮。"]'),
('yuanqu-7151','宋上皇御断金凤钗・七兄弟','郑延玉','元','元曲','yuanqu','','[]','自从巳时至午时，多不到半炊时。',49,'元曲/yuanqu.json','["自从巳时至午时，多不到半炊时。", "不想这报我恩的大人为宣使，追我魂的太尉立在阶址，救我命的赦书从天至。"]'),
('yuanqu-7152','宋上皇御断金凤钗・梅花酒','郑延玉','元','元曲','yuanqu','','[]','他道是奉着圣旨，我抹泪揉眵，言语如丝，险断颈分尸。',83,'元曲/yuanqu.json','["他道是奉着圣旨，我抹泪揉眵，言语如丝，险断颈分尸。", "料青天不受私，说不尽口中语。", "(做看招牌科)(唱)觑了这半张红，开款着我瑕疵。", "睁开眼看我时，写着我罪名儿，压着五言诗。"]'),
('yuanqu-7153','宋上皇御断金凤钗・收江南','郑延玉','元','元曲','yuanqu','','[]','呀，原来这犯由牌上金榜挂名时，不想这状元店祸有并来时。',56,'元曲/yuanqu.json','["呀，原来这犯由牌上金榜挂名时，不想这状元店祸有并来时。", "今日个枯树上花有再开时，我则道横死，原来这病龙须有吐云时。"]'),
('yuanqu-7154','宋上皇御断金凤钗・雁儿落','郑延玉','元','元曲','yuanqu','','[]','这二百一，是大人行掌命司，(杨云)大人还了你十只金钗也。',122,'元曲/yuanqu.json','["这二百一，是大人行掌命司，(杨云)大人还了你十只金钗也。", "(正末唱)那十只钗是穷秀才追魂使。", "(杨云)大人借了你二百钱，还了你十只金钗，本利都有了也。", "(正末唱)那得早有本钱有利钱，(云)临了也说我图财致命，着我犯法遭刑也。", "(唱)这的是暗宣赐明宣赐。"]'),
('yuanqu-7155','正宫・塞鸿秋题情','赵莹','元','元曲','yuanqu','','[]','玉人不见徒劳望，相思两地音书旷。',53,'元曲/yuanqu.json','["玉人不见徒劳望，相思两地音书旷。", "挥毫难写断肠文，枕几惟添愁旅况。", "只为美人情，空取时人谤，何时再得相亲傍？。"]'),
('yuanqu-7156','正宫・脱布衫过小梁州草堂中夏日偏宜，正流金烁石天气。素馨花一枝玉','张鸣善','元','元曲','yuanqu','','[]','质，白莲藕样弯琼臂。',46,'元曲/yuanqu.json','["质，白莲藕样弯琼臂。", "门外红尘衮衮飞，飞不到鱼鸟清溪。", "绿阴高柳听黄鹂，幽栖意，料俗客几人知？。"]'),
('yuanqu-7157','幺・山林本是终焉计，用之行舍之藏兮。悼后世，追前辈，对五月五日，','张鸣善','元','元曲','yuanqu','','[]','歌楚些吊湘累。',7,'元曲/yuanqu.json','["歌楚些吊湘累。"]'),
('yuanqu-7158','中吕・普天乐咏世','张鸣善','元','元曲','yuanqu','','[]','洛阳花，梁园月。',368,'元曲/yuanqu.json','["洛阳花，梁园月。", "好花须买，皓月须赊。", "花倚栏干看烂熳开，月曾把酒问团圆夜。", "月有盈亏，花有开谢，想人生最苦离别。", "花谢了三春近也，月缺了中秋到也，人去了何日来也？赠妓口儿甜，庞儿俏。", "性格儿稳重，身子苗条。", "多情杨柳腰，春暖桃花萼。", "见人便厌的拜忽的羞吸的笑，引的人魄散魂消。", "人前面看好，樽席上出色，手掌里擎着。", "遇美海棠娇，梨花嫩。", "春妆成美脸，玉捻就精神。", "柳眉颦翡翠弯，香脸腻胭脂晕。", "款步香尘双鸳印，立东风一朵巫云。", "奄的转身，吸的便晒，森的销魂。", "雨才收，花初谢。", "茶温凤髓，香冷鸡舌。", "半帘杨柳风，一枕梨花月。", "几度凝眸登台榭，望长安不见些些。", "知他是醒也醉也，贫也富也，有也无也。", "既待舍之藏，何用沽诸价？清闲活计，冷淡生涯。", "采灵芝西海边，看黄菊东篱下。", "乐乐陶陶无牵挂，三般儿到处里堪夸。", "或是向东篱看花，或是在东门种瓜，或是去东里为家。", "愁怀雨儿飘，风儿扬。"]'),
('yuanqu-7159','双调・落梅风咏雪','张鸣善','元','元曲','yuanqu','','[]','漫天坠，扑地飞，白占许多田地。',34,'元曲/yuanqu.json','["漫天坠，扑地飞，白占许多田地。", "冻杀吴民都是你！难道是国家祥瑞？套数。"]'),
('yuanqu-7160','醉春风・他若是愁锁翠春山，笑时花近眼。玉娉婷慵整倦妆奁，常好是懒，','张鸣善','元','元曲','yuanqu','','[]','翡翠裙低，凤凰钗重，麝兰香散。',15,'元曲/yuanqu.json','["翡翠裙低，凤凰钗重，麝兰香散。"]'),
('yuanqu-7161','迎仙客・相适到数载余，别离了两三番，则俺那美人儿恰才在这筵席间。','张鸣善','元','元曲','yuanqu','','[]','美酒泛金波，闲歌随象板。',29,'元曲/yuanqu.json','["美酒泛金波，闲歌随象板。", "投至的欢意阑珊，那其间彼各皆分散。"]'),
('yuanqu-7162','普天乐・分散后再相逢，再相逢空长叹。人有愿天心必应，天心应人愿何','张鸣善','元','元曲','yuanqu','','[]','难？纤腰如杨柳枝，粉脸似桃花瓣。',47,'元曲/yuanqu.json','["难？纤腰如杨柳枝，粉脸似桃花瓣。", "桃柳争妍花开绽，见年年桃柳开残。", "人生百年，无心思忖，有限朱颜。"]'),
('yuanqu-7163','十二月・苏小卿风尘意懒，双通叙名利相干。虽不学双生是对手，也合与','张鸣善','元','元曲','yuanqu','','[]','苏氏同班。',21,'元曲/yuanqu.json','["苏氏同班。", "虽葬在黄丘土滩，名播在天上人间。"]'),
('yuanqu-7164','尧民歌・呀！自古来知音相会果应难，争奈这少年心终岁受孤单。休将这','张鸣善','元','元曲','yuanqu','','[]','凤凰栖老碧梧寒，投至的雁鸣莺呖杏花残。',39,'元曲/yuanqu.json','["凤凰栖老碧梧寒，投至的雁鸣莺呖杏花残。", "愁烦，琵琶手倦弹，这埚儿休扭做了浔阳岸。"]'),
('yuanqu-7165','啄木儿煞・花细额上贴，赤绳足下拴。少年心终久相轻慢，坚心无惮，准','张鸣善','元','元曲','yuanqu','','[]','备着洞房花烛报平安。',10,'元曲/yuanqu.json','["备着洞房花烛报平安。"]'),
('yuanqu-7166','越调・金蕉叶怨别','张鸣善','元','元曲','yuanqu','','[]','讲燕赵风流莫比，说秦晋姻缘怎及。',32,'元曲/yuanqu.json','["讲燕赵风流莫比，说秦晋姻缘怎及。", "论吴越精神未已，配南楚仪容最美。"]'),
('yuanqu-7167','调笑令・楚仪，美人兮，薄注樱唇浅画眉。凤钗斜插乌云髻，衬冰绡玉葱','张鸣善','元','元曲','yuanqu','','[]','纤细。',20,'元曲/yuanqu.json','["纤细。", "轻颦浅笑声渐低，这风流几个人知？。"]'),
('yuanqu-7168','秃厮儿・花正好香风细细，柳初柔良夜辉辉，占定个红娇绿柔花月国。花','张鸣善','元','元曲','yuanqu','','[]','簇簇，柳依依，也波相宜。',12,'元曲/yuanqu.json','["簇簇，柳依依，也波相宜。"]'),
('yuanqu-7169','圣药王・花影移，月影移，留花玩月饮琼杯。风力微，酒力微，乘风带酒','张鸣善','元','元曲','yuanqu','','[]','立金梯，风月满樽席。',10,'元曲/yuanqu.json','["立金梯，风月满樽席。"]'),
('yuanqu-7170','络丝娘・三生梦一声唱回，一场舞三生梦里。万劫千年不容易，也是前缘','张鸣善','元','元曲','yuanqu','','[]','前世。',3,'元曲/yuanqu.json','["前世。"]'),
('yuanqu-7171','尾・就今生设下来生誓，来生福是今生所积。拼死在连理树儿边，愿生在','张鸣善','元','元曲','yuanqu','','[]','鸳鸯队儿里。',6,'元曲/yuanqu.json','["鸳鸯队儿里。"]'),
('yuanqu-7172','包待制陈州粜米・仙吕/赏花时','无名氏','元','元曲','yuanqu','','[]','只为那连岁灾荒料不收，致使的一郡苍生强半流，因此上粜米去陈州。',51,'元曲/yuanqu.json','["只为那连岁灾荒料不收，致使的一郡苍生强半流，因此上粜米去陈州。", "你将着孩儿保奏，不知他可也分得帝王忧？。"]'),
('yuanqu-7173','包待制陈州粜米・仙吕/点绛唇','无名氏','元','元曲','yuanqu','','[]','则这官吏知情，外合里应，将穷民并。',61,'元曲/yuanqu.json','["则这官吏知情，外合里应，将穷民并。", "点纸连名，我可便直告到中书省。", "(小忄敝古云)父亲，咱遇着这等官府也说些甚么！(正末唱)。"]'),
('yuanqu-7174','包待制陈州粜米・混江龙','无名氏','元','元曲','yuanqu','','[]','做的个上梁不正，只待要损人利己惹人憎。',79,'元曲/yuanqu.json','["做的个上梁不正，只待要损人利己惹人憎。", "他若是将叫刁蹬，休道我不敢掀腾。", "柔软莫过溪涧水，到了不平地上也高声。", "他也故违了皇宣命，都是些吃仓廒的鼠耗，咂脓血的苍蝇。"]'),
('yuanqu-7175','包待制陈州粜米・天下乐','无名氏','元','元曲','yuanqu','','[]','你比那开封府包龙图少四星。',214,'元曲/yuanqu.json','["你比那开封府包龙图少四星。", "(大斗子云)兀那老子休要胡说，他两个是权豪势要的人，休要惹他。", "(正末唱)卖弄你那官清法正行，多要些也不到的担罪名。", "(二斗子云)这米还尖，再抓了些者。", "(小忄敝古云)父亲，他又□了些去了。", "(正末唱)这壁厢去了半斗，那壁厢□了几升，做的一个轻人来还自轻。", "(二斗子云)你挣着口袋，我量与你么。", "(正末云)你怎么量米哩？俺不是私自来籴米的。", "(大斗子云)你不是私自来籴米，我也是奉官差，不是私自来粜米的。", "(正末唱)。"]'),
('yuanqu-7176','包待制陈州粜米・金盏儿','无名氏','元','元曲','yuanqu','','[]','你道你奉官行，我道你奉私行。',79,'元曲/yuanqu.json','["你道你奉官行，我道你奉私行。", "俺看承的一合米关着八九个人的命，又不比山麋野鹿众人争。", "你正是饿狼口里夺脆骨，乞儿碗底觅残羹。", "我能可折升不折斗，你怎也图利不图名？。"]'),
('yuanqu-7177','包待制陈州粜米・村里迓鼓','无名氏','元','元曲','yuanqu','','[]','只见他金锤落处，恰便似轰雷着顶，打的来满身血迸，教我呵怎生扎挣。',87,'元曲/yuanqu.json','["只见他金锤落处，恰便似轰雷着顶，打的来满身血迸，教我呵怎生扎挣。", "也不知打着的是脊梁，是脑袋，是肩井；但觉的刺牙般酸，剜心般痛，剔骨般疼。", "哎哟，天那！兀的不送了我也这条老命！。"]'),
('yuanqu-7178','包待制陈州粜米・元和令','无名氏','元','元曲','yuanqu','','[]','则俺个籴米的有甚罪名？和你这粜米的也不干净。',97,'元曲/yuanqu.json','["则俺个籴米的有甚罪名？和你这粜米的也不干净。", "(小衙内云)是我打你来，没事没事，由你在那里告我。", "(正末唱)现放着徒流笞杖，做不严刑。", "却不道家家门外千丈坑，则他这得填平处且填平，你可也被人推更不轻。"]'),
('yuanqu-7179','包待制陈州粜米・上马娇','无名氏','元','元曲','yuanqu','','[]','哎，你个萝卜精，头上青(小衙内云)看起来我是野菜，你怎么骂我做萝卜精？(正末唱)坐着个爱钞的寿官厅，面糊盆里专磨镜。',93,'元曲/yuanqu.json','["哎，你个萝卜精，头上青(小衙内云)看起来我是野菜，你怎么骂我做萝卜精？(正末唱)坐着个爱钞的寿官厅，面糊盆里专磨镜。", "(杨金吾云)俺两个至一清廉有名的。", "(正末唱)哎，还道你清。", "清赛玉壶冰。"]'),
('yuanqu-7180','包待制陈州粜米・胜葫芦','无名氏','元','元曲','yuanqu','','[]','都只待遥指空中雁做羹，那个肯为朝廷。',135,'元曲/yuanqu.json','["都只待遥指空中雁做羹，那个肯为朝廷。", "(杨金吾云)你那老匹夫，把朝廷来压我哩。", "我不怕，我不怕。", "(正末唱)有一日受法餐刀正典刑，恁时节，钱财使罄。", "人亡家家破，方悔道不廉能。", "(小衙内云)我见了那穷汉似眼中疔，肉中刺，我要害他，只当捏烂柿一般，值个甚的。", "(正末云)噤声！(唱)。"]'),
('yuanqu-7181','包待制陈州粜米・后庭花','无名氏','元','元曲','yuanqu','','[]','你道穷民是眼内疔，佳人是颏下瘿。',260,'元曲/yuanqu.json','["你道穷民是眼内疔，佳人是颏下瘿。", "(带云)难道你家没王法的？(唱)便容你酒肉摊场吃，谁许你金银上秤秤？(云)孩儿，你也与我告去。", "(小忄敝古云)父亲。", "你看他这般权势，只怕告他不得么。", "(正末唱)儿也你快去告，不须惊。", "(小忄敝古云)父亲要告他，指谁做证见？(正末唱)只指着紫金锤专为照证。", "(小忄敝古云)父亲，证见便有了，却往那里告他去？(正末唱)投词院直至省，将冤屈叫几声，诉出咱这实情，怕没有公与卿，必然的要准行。", "(小忄敝古云)若是不准，再往那里告他？(正末唱)任从他贼丑生，百般家着智能。", "遍衙门告不成。", "也还要上登闻将怨鼓鸣。"]'),
('yuanqu-7182','包待制陈州粜米・赚煞尾','无名氏','元','元曲','yuanqu','','[]','做官的要了钱便糊突，不要钱方清正。',221,'元曲/yuanqu.json','["做官的要了钱便糊突，不要钱方清正。", "多似你这贪污的，枉把皇家禄清。", "(带云)你这害民的贼，也想一想差你开仓粜米，是为着何来？(唱)兀的赈济饥荒你也该自省，怎倒将我一锤儿打坏天灵？(小忄敝古云)父亲，我几时告去？(正末唱)则今日便登程，直到王京，常言道\"厮杀无如父子兵\"。", "拣一个清耿耿明朗朗官人每告整，和那害民的贼徒折证。", "(小忄敝古云)父亲。", "可是那一位大衙门告他去？(正末叹云)若要与我陈州百姓除了这害呵。", "(唱)则除是包龙图那个铁面没人情。", "(下)。"]'),
('yuanqu-7183','包待制陈州粜米・滚绣球','无名氏','元','元曲','yuanqu','','[]','待不要钱呵，怕违了众情；待等要钱呵，又不是咱本谋。',174,'元曲/yuanqu.json','["待不要钱呵，怕违了众情；待等要钱呵，又不是咱本谋。", "只这月俸钱做咱每人情不彀。", "(张千云)老相公平日是个不避权豪势要之人也。", "(正末唱)我和那权豪每结下些山海也似冤仇：曾把个鲁斋郎斩市曹，曾把个葛监军下狱囚，剩吃了些众人每毒咒。", "(张千云)老相公，如今虽然年老，志气还在哩。", "(正末唱)到今日一笔都勾。", "从今后不干己事休开口，我则索会尽人间只点头，倒大来优游。"]'),
('yuanqu-7184','包待制陈州粜米・倘秀才','无名氏','元','元曲','yuanqu','','[]','我从那及第时三十五六，我如今做官到七十也那八九。',196,'元曲/yuanqu.json','["我从那及第时三十五六，我如今做官到七十也那八九。", "岂不闻\"人到中年万事休\"。", "我也曾观唐汉，看春秋，都是俺为官的上手。", "(范学士云)待制做许多年官也，历事多矣。", "(吕夷简云)待制为官，尽忠报国，激浊杨清。", "如今朝里朝外权豪势要之家，闻待制大名，谁不惊惧。", "诚哉，所谓古之直臣也。", "(正末云)量老夫何足挂齿，想前朝有几个贤臣，都皆屈死，似老夫这等粗直，终非保身之道。", "(范学士云)请待制试说一遍咱。", "(正末唱)。"]'),
('yuanqu-7185','包待制陈州粜米・滚绣球','无名氏','元','元曲','yuanqu','','[]','有一个楚屈原在江上死，有一个关龙逢刀下休，有一个纣比干曾将心剖，有一个未央宫屈斩了韩侯。',214,'元曲/yuanqu.json','["有一个楚屈原在江上死，有一个关龙逢刀下休，有一个纣比干曾将心剖，有一个未央宫屈斩了韩侯。", "(吕夷简云)待制，我想张良坐筹帷幄之中，决胜千里之外，辅佐高祖，定了天下。", "见韩信遭诛，彭越被醢，遂辞去侯爵愿从赤松子游，真有先见之明也。", "(正末唱)那张良呵若不是疾归去，(韩魏公云)那越国范蠡，扁舟五湖，却也不弱。", "(正末唱)那范蠡呵若不是暗奔走，这两个都落不的完全尸首。", "我是个漏网鱼，怎再敢吞钩？不如及早归山去，我则怕为官不到头，枉了也干求。"]'),
('yuanqu-7186','包待制陈州粜米・呆骨朵','无名氏','元','元曲','yuanqu','','[]','老人有件事向君王陈奏，只说那权豪每是俺敌头。',104,'元曲/yuanqu.json','["老人有件事向君王陈奏，只说那权豪每是俺敌头。", "(范学士云)那权豪的，老相公待要怎么？(正末唱)他便似打家的强贼。", "俺便似看家的恶狗。", "他待要些钱和物，怎当的这狗儿紧追逐。", "只愿俺今日死，明日亡，惯的他千自在，百自由。"]'),
('yuanqu-7187','包待制陈州粜米・脱布衫','无名氏','元','元曲','yuanqu','','[]','我从来不劣方头，恰便似火上浇油，我偏和那打势力的官人每卯酉，谢大人向朝中保奏。',60,'元曲/yuanqu.json','["我从来不劣方头，恰便似火上浇油，我偏和那打势力的官人每卯酉，谢大人向朝中保奏。", "(刘衙内云)我并不曾保奏你哩。", "(正末唱)。"]'),
('yuanqu-7188','包待制陈州粜米・小梁州','无名氏','元','元曲','yuanqu','','[]','我一点心怀社稷愁，(云)张千，将马来。',66,'元曲/yuanqu.json','["我一点心怀社稷愁，(云)张千，将马来。", "(张千云)理会的。", "(正末唱)则今日便上陈州，既然心去意难留。", "他每都穿连透，我则怕关节儿枉生受。"]'),
('yuanqu-7189','包待制陈州粜米・幺篇','无名氏','元','元曲','yuanqu','','[]','谢圣人肯把黎民救，这剑也，到陈州怎肯干休，敢着你吃一会家生人肉。',52,'元曲/yuanqu.json','["谢圣人肯把黎民救，这剑也，到陈州怎肯干休，敢着你吃一会家生人肉。", "哎！看那个无知禽兽，我只待先斩了逆臣头。"]'),
('yuanqu-7190','包待制陈州粜米・耍孩儿','无名氏','元','元曲','yuanqu','','[]','你积趱的金银过北斗，你指望待天长地久。',112,'元曲/yuanqu.json','["你积趱的金银过北斗，你指望待天长地久。", "看你那于家为国下场头，出言语不识娘羞。", "我须是笔尖上挣□来的千钟禄，你可甚剑锋头博换来的万户侯。", "(衙内云)老府尹。", "我也不怕你。", "(正末唱)你那里休夸口，你虽是一人为害，我与那陈州百姓每分忧。"]'),
('yuanqu-7191','包待制陈州粜米・煞尾','无名氏','元','元曲','yuanqu','','[]','河涯边趱运下些粮，仓廒中囤塌下些筹，只要肥了你私囊，也不管民间瘦。',313,'元曲/yuanqu.json','["河涯边趱运下些粮，仓廒中囤塌下些筹，只要肥了你私囊，也不管民间瘦。", "(带云)我如今到那里呵。", "(唱)敢着他收了蒲蓝罢了斗。", "(同张千下)(刘衙内云)列位老相公，这桩事不好了。", "这老子到那里时，将俺这两个小的肯干罢了也。", "(韩魏公云)衙内，不妨事，你只与学士计较，老夫和吕丞相先回去也。", "(诗云)衙内心中莫要慌，天章学士慢商量；(吕夷简诗云)凤凰飞上梧桐树，自有傍人道短长。", "(同下)(范学士云)刘衙内，你放心。", "老夫就到圣人根前说过，着你亲身为使命告一纸文书，则赦活的不赦死的。", "包你没事便了。", "(衙内云)既如此，多谢了学士。", "(范学士云)你跟着老夫见圣人走一遭去来。", "(诗云)莫愁包待制，先请赦书来；(刘衙内诗云)全凭半张纸，救我一家灾。", "(同下)。"]'),
('yuanqu-7192','包待制陈州粜米・南吕/一枝花','无名氏','元','元曲','yuanqu','','[]','如今那个差的民户喜，也有那干请俸的官人每怨。',92,'元曲/yuanqu.json','["如今那个差的民户喜，也有那干请俸的官人每怨。", "急切里称不了包某的心，百般的纳不下帝王宣，我如今暮景衰年，鞍马上实劳倦。", "如今那普天下人尽言道：\"一个包龙图暗暗的私行，唬得些官吏每兢兢打战。"]'),
('yuanqu-7193','包待制陈州粜米・梁州第七','无名氏','元','元曲','yuanqu','','[]','请俸禄五六的这万贯，杀人到三二十年，随京随府随州县。',169,'元曲/yuanqu.json','["请俸禄五六的这万贯，杀人到三二十年，随京随府随州县。", "自从俺仁君治世，老汉当权，经了这几番刷卷，备细的究出根原。", "都只是庄农每争竞桑田，弟兄每分另家缘。", "俺俺俺，宋朝中大小官员；他他他，剩与你财主每追徵了些利钱；您您您，怎知道穷百姓苦恹恹叫屈声冤，如今的离陈州不远，便有人将咱相凌贱，你也则诈眼儿不看见；骑着马，揣着牌，自向前，休得要摆袖揎拳。"]'),
('yuanqu-7194','包待制陈州粜米・牧羊关','无名氏','元','元曲','yuanqu','','[]','当日离豹尾班多时分，今日在狗腿湾行近远，避甚的马后驴前。',143,'元曲/yuanqu.json','["当日离豹尾班多时分，今日在狗腿湾行近远，避甚的马后驴前。", "我则怕按察司迎着，御史台撞见。", "本是个显要龙图职，怎伴着烟月鬼狐缠。", "可不先犯了个风流罪，落的价葫芦提罢俸钱。", "(旦儿云)老儿，你跟将我去来，我把紫金锤与你看者。", "(正末云)好，好，我跟将姐姐去，则与老汉紫金锤看一看，消灾灭罪咱。", "(唱)。"]'),
('yuanqu-7195','包待制陈州粜米・隔尾','无名氏','元','元曲','yuanqu','','[]','听说罢气的我心头颤，好着我半晌家气堵住口内言。',74,'元曲/yuanqu.json','["听说罢气的我心头颤，好着我半晌家气堵住口内言。", "直将那仓库里皇粮痛作践。", "他便也不怜，我须为百姓每可怜，似肥汉相博，我着他只落的一声儿喘，(同旦儿下)。"]'),
('yuanqu-7196','包待制陈州粜米・乌夜啼','无名氏','元','元曲','yuanqu','','[]','为头儿先吃俺开荒剑，则他那性命不在皇天。',95,'元曲/yuanqu.json','["为头儿先吃俺开荒剑，则他那性命不在皇天。", "刘衙内也。", "可怎生着我行方便？这公事体察完全，不是流传。", "那怕你天章学士有夤缘，就待乞天恩走上金銮殿，只我个包龙图元铁面，但少不得着您名登紫禁，身丧黄泉。"]'),
('yuanqu-7197','包待制陈州粜米・牧羊关','无名氏','元','元曲','yuanqu','','[]','这厮马头前无多说，今日在驿亭中夸大言，信人生不可无权。',121,'元曲/yuanqu.json','["这厮马头前无多说，今日在驿亭中夸大言，信人生不可无权。", "哎！则你个祗侯王乔诈仙也那得仙。", "(张千奠酒科，云)我若不救你两个呵，这酒就是我的命。", "(做见正末怕科，云)兀的不唬杀我也！(正末云唱)唬的来面色如金纸，手脚似风颠。", "老鼠终无胆，猕猴怎坐禅？。"]'),
('yuanqu-7198','包待制陈州粜米・双调/新水令','无名氏','元','元曲','yuanqu','','[]','叩金銮亲奉帝王差，到陈州与民除害。',48,'元曲/yuanqu.json','["叩金銮亲奉帝王差，到陈州与民除害。", "威名连地震，杀气和霜来。", "手执升势剑令牌，哎！你个刘衙内且休怪。"]'),
('yuanqu-7199','包待制陈州粜米・雁儿落','无名氏','元','元曲','yuanqu','','[]','难道你王粉头直恁呆，偏不知包待制多谋策。',41,'元曲/yuanqu.json','["难道你王粉头直恁呆，偏不知包待制多谋策。", "你道是接仓官有大钱，怎么的见府尹无娇态？。"]'),
('yuanqu-7200','包待制陈州粜米・得胜令','无名氏','元','元曲','yuanqu','','[]','呀，你只待钱眼水狠差排，今日个刀口上送尸骸。',74,'元曲/yuanqu.json','["呀，你只待钱眼水狠差排，今日个刀口上送尸骸。", "你犯了萧何律，难宽纵；便自有蒯通谋，怎救解。", "你死也休捱，则俺那势剑如风快；你死也应该，谁着你金锤当酒来。"]'),
('yuanqu-7201','包待制陈州粜米・沽美酒','无名氏','元','元曲','yuanqu','','[]','小衙内做事歹，小忄敝古且宁奈，也是他自结下冤仇怎得开。',41,'元曲/yuanqu.json','["小衙内做事歹，小忄敝古且宁奈，也是他自结下冤仇怎得开。", "非咱忒煞，须偿还你这亲爷债。"]'),
('yuanqu-7202','包待制陈州粜米・太平令','无名氏','元','元曲','yuanqu','','[]','从来个人命事关连天大，怎容他杀生灵似虎如豺。',315,'元曲/yuanqu.json','["从来个人命事关连天大，怎容他杀生灵似虎如豺。", "紫金锤依然还在，也将来敲他脑袋。", "登时间肉拆血洒，受这般罪责，呀，才平定陈州一带。", "(小忄敝古做打衙内科)(正末云)张千，打死了么？(张千云)打死了也。", "(正末云)张千，与我拿下小忄敝古者。", "(张千云)理会的。", "(张千做拿小忄敝古科)(外扮刘衙内赍赦书慌上，诗云)心忙来路远，事急出家门。", "小官刘衙内是也。", "我圣人根前说过，告了一纸赦书，则赦活的不赦死的，星夜到陈州救我两个孩儿。", "左右，留人者，有赦书在此，则赦活的，不赦死的。", "(正末云)张千，死了的是谁？(张千云)死了的是杨金吾、小衙内。", "(正末云)活的是谁？(张千云)是小忄敝古。", "(刘衙内云)呸！恰好赦别人也。", "(正末云)张千，放了小忄敝古者。", "(唱)。"]'),
('yuanqu-7203','降桑椹蔡顺奉母・仙吕/点绛唇','刘唐卿','元','元曲','yuanqu','','[]','见如今雨顺风调，万民安乐，年光好。',84,'元曲/yuanqu.json','["见如今雨顺风调，万民安乐，年光好。", "圣德过尧，则他这文共武行忠孝。", "(旦儿云)蔡顺，是好雪也。", "恰便是银妆成世界，粉填满山川。", "这雪润陇亩，滋禾稼，天下黎民皆喜也。", "(正末唱)。"]'),
('yuanqu-7204','降桑椹蔡顺奉母・混江龙','刘唐卿','元','元曲','yuanqu','','[]','上合天道，常垂甘露润田苗。',69,'元曲/yuanqu.json','["上合天道，常垂甘露润田苗。", "这雪单注着多收五谷，广剩仓廒。", "乡下农民斟村洒，城中上户饮香醪。", "好收成端的民欢乐，托赖着一人有庆，因此上万国来朝。"]');
